<?php
class iN_UPDATES {
	private $db;
	private static $configColumnExistsCache = [];
	private static $settingsCache = [];
	private static $shareTableReady = false;
	private static $scheduledSchemaReadyCache = null;
    private static $adsTablesReady = false;
	private static $columnLengthCache = [];
    private static $tableColumnExistsCache = [];
    private static $settingsKvTableReadyCache = null;
    private static $svgIconMapCache = null;
    private static $mediaStorageConfigCache = null;
    private static $userMediaRowCache = [];
    private static $avatarPathCache = [];
    private static $coverPathCache = [];
    private static $userExistsCache = [];
    private static $isAdminCache = [];
    private static $isSuperAdminCache = [];
    private static $affiliateDataCache = null;
    private static $customCodesCache = [];
    private $lastSubscriptionPaymentOrderKey = null;
    private $lastSubscriptionPaymentId = 0;

	public function __construct($db) {
		$this->db = $db;
	}

	/**
	 * Checks if a column exists on the i_configurations table (results cached per request).
	 */
	private function configColumnExists($column) {
		if (isset(self::$configColumnExistsCache[$column])) {
			return self::$configColumnExistsCache[$column];
		}
		try {
			$exists = DB::col(
				"SELECT COUNT(*) FROM information_schema.COLUMNS WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'i_configurations' AND COLUMN_NAME = ?",
				[$column]
			);
			self::$configColumnExistsCache[$column] = $exists ? true : false;
		} catch (Throwable $e) {
			self::$configColumnExistsCache[$column] = false;
		}
		return self::$configColumnExistsCache[$column];
	}

	public function iN_ConfigColumnExists(string $column): bool {
		return $this->configColumnExists($column);
	}

	public function iN_ConfigColumnsExist(array $columns): bool {
		foreach ($columns as $column) {
			$column = trim((string)$column);
			if ($column === '' || !$this->configColumnExists($column)) {
				return false;
			}
		}
		return true;
	}

    private function settingsKvTableReady(): bool {
        if (self::$settingsKvTableReadyCache !== null) {
            return self::$settingsKvTableReadyCache;
        }
        try {
            DB::one("SELECT setting_key FROM i_settings_kv LIMIT 1");
            self::$settingsKvTableReadyCache = true;
            return true;
        } catch (Throwable $e) {
            // Continue with create-if-missing fallback.
        }
        try {
            DB::exec(
                "CREATE TABLE IF NOT EXISTS i_settings_kv (
                    setting_key varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
                    setting_value longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
                    updated_at int NOT NULL DEFAULT '0',
                    PRIMARY KEY (setting_key)
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci"
            );
            DB::one("SELECT setting_key FROM i_settings_kv LIMIT 1");
            self::$settingsKvTableReadyCache = true;
            return true;
        } catch (Throwable $e) {
            self::$settingsKvTableReadyCache = false;
            return false;
        }
    }

    private function getSettingFromKv(string $key, bool &$found = false) {
        $found = false;
        if ($key === '' || !$this->settingsKvTableReady()) {
            return null;
        }
        try {
            $row = DB::one(
                "SELECT setting_value FROM i_settings_kv WHERE setting_key = ? LIMIT 1",
                [(string)$key]
            );
        } catch (Throwable $e) {
            return null;
        }
        if ($row && array_key_exists('setting_value', $row)) {
            $found = true;
            return $row['setting_value'];
        }
        return null;
    }

    private function setSettingToKv(string $key, string $value): bool {
        if ($key === '' || !$this->settingsKvTableReady()) {
            return false;
        }
        try {
            DB::exec(
                "INSERT INTO i_settings_kv (setting_key, setting_value, updated_at)
                 VALUES (?, ?, ?)
                 ON DUPLICATE KEY UPDATE setting_value = VALUES(setting_value), updated_at = VALUES(updated_at)",
                [(string)$key, (string)$value, (int)time()]
            );
            return true;
        } catch (Throwable $e) {
            return false;
        }
    }

    private function tableColumnExists(string $table, string $column): bool {
        $table = trim($table);
        $column = trim($column);
        if ($table === '' || $column === '') {
            return false;
        }

        $cacheKey = $table . '.' . $column;
        if (isset(self::$tableColumnExistsCache[$cacheKey])) {
            return self::$tableColumnExistsCache[$cacheKey];
        }

        try {
            $exists = DB::col(
                "SELECT COUNT(*) FROM information_schema.COLUMNS WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = ? AND COLUMN_NAME = ?",
                [$table, $column]
            );
            self::$tableColumnExistsCache[$cacheKey] = $exists ? true : false;
        } catch (Throwable $e) {
            self::$tableColumnExistsCache[$cacheKey] = false;
        }

        return self::$tableColumnExistsCache[$cacheKey];
    }

	private function getVarcharLengthLimit(string $table, string $column): ?int {
		$cacheKey = $table . '.' . $column;
		if (isset(self::$columnLengthCache[$cacheKey])) {
			return self::$columnLengthCache[$cacheKey];
		}
		$limit = null;
		try {
			$row = DB::one(
				"SELECT DATA_TYPE, CHARACTER_MAXIMUM_LENGTH FROM information_schema.COLUMNS WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = ? AND COLUMN_NAME = ?",
				[$table, $column]
			);
			if (!empty($row['DATA_TYPE']) && strtolower($row['DATA_TYPE']) === 'varchar') {
				$limit = (int)$row['CHARACTER_MAXIMUM_LENGTH'];
			}
		} catch (Throwable $e) {
			$limit = null;
		}
		self::$columnLengthCache[$cacheKey] = $limit;
		return $limit;
	}

	private function clampStringLength(string $value, ?int $limit): string {
		if (!$limit || $limit < 1) {
			return $value;
		}
		if (function_exists('mb_strlen') && function_exists('mb_substr')) {
			return (mb_strlen($value) > $limit) ? mb_substr($value, 0, $limit) : $value;
		}
		return (strlen($value) > $limit) ? substr($value, 0, $limit) : $value;
	}

	/**
	 * Normalize the desired post type based on the current database schema.
	 * If the column is missing the requested enum value, it safely falls back to 'normal'.
	 *
	 * @param string $postType
	 * @return string
	 */
	private function resolvePostType(string $postType): string {
		$postType = trim($postType) !== '' ? trim($postType) : 'normal';
		try {
			$col = DB::one("SHOW COLUMNS FROM i_posts LIKE 'post_type'");
			if ($col && isset($col['Type'])) {
				$typeDef = (string)$col['Type'];
				if (strpos($typeDef, "'" . $postType . "'") === false) {
					return 'normal';
				}
			}
		} catch (Throwable $e) {
			return 'normal';
		}
		return $postType;
	}

    /**
     * Produce a compact number string (e.g., 1.2K, 3.4M) for UI counters.
     *
     * @param float|int|string|null $number
     * @param int|null              $smallDecimals Decimal places for values < 1000 (null uses settings)
     * @param int|null              $precision     Decimal places for K/M/B values (null uses settings)
     * @return string
     */
    public function formatCompactNumber($number, ?int $smallDecimals = null, ?int $precision = null): string {
        global $currencyDecimalSeparator, $currencyThousandSeparator, $currencyDecimalPlaces;

        if ($number === null || $number === '' || $number === false) {
            return '0';
        }
        if (!is_numeric($number)) {
            return (string)$number;
        }

        $decimalSeparator = isset($currencyDecimalSeparator) ? (string)$currencyDecimalSeparator : '.';
        $thousandSeparator = isset($currencyThousandSeparator) ? (string)$currencyThousandSeparator : ',';
        $defaultDecimals = isset($currencyDecimalPlaces) ? (int)$currencyDecimalPlaces : 2;

        $smallDecimals = $smallDecimals === null ? $defaultDecimals : $smallDecimals;
        $smallDecimals = max(0, min(4, (int)$smallDecimals));

        $precision = $precision === null ? ($defaultDecimals > 0 ? 1 : 0) : $precision;
        $precision = max(0, min(2, (int)$precision));

        $value = (float)$number;
        $absValue = abs($value);

        if ($absValue < 1000) {
            return number_format($value, $smallDecimals, $decimalSeparator, $thousandSeparator);
        }

        $formatCompact = function (float $divider, string $suffix) use ($value, $precision, $decimalSeparator): string {
            $formatted = number_format($value / $divider, $precision, $decimalSeparator, '');
            if ($precision > 0) {
                $formatted = rtrim(rtrim($formatted, '0'), $decimalSeparator);
            }
            return $formatted . $suffix;
        };

        if ($absValue >= 1000000000) {
            return $formatCompact(1000000000, 'B');
        }
        if ($absValue >= 1000000) {
            return $formatCompact(1000000, 'M');
        }
        return $formatCompact(1000, 'K');
    }

    /**
     * Fetch poll related configuration with safe defaults when columns are missing.
     *
     * @return array{status:string,max_options:int,min_options:int}
     */
    private function getPollSettings(): array {
        $defaults = ['status' => '1', 'max_options' => 6, 'min_options' => 2];
        $fields = [];
        if ($this->configColumnExists('poll_system_status')) { $fields[] = 'poll_system_status'; }
        if ($this->configColumnExists('poll_max_options')) { $fields[] = 'poll_max_options'; }
        if ($this->configColumnExists('poll_min_options')) { $fields[] = 'poll_min_options'; }
        if (empty($fields)) {
            return $defaults;
        }
        try {
            $row = DB::one(
                "SELECT " . implode(',', $fields) . " FROM i_configurations WHERE configuration_id = 1"
            );
            if ($row) {
                if (array_key_exists('poll_system_status', $row)) {
                    $defaults['status'] = (string)$row['poll_system_status'];
                }
                if (array_key_exists('poll_max_options', $row) && is_numeric($row['poll_max_options'])) {
                    $defaults['max_options'] = (int)$row['poll_max_options'];
                }
                if (array_key_exists('poll_min_options', $row) && is_numeric($row['poll_min_options'])) {
                    $defaults['min_options'] = (int)$row['poll_min_options'];
                }
            }
        } catch (Throwable $e) {
            // Fallback to defaults when configuration is not ready yet.
        }
        if ($defaults['min_options'] < 2) {
            $defaults['min_options'] = 2;
        }
        if ($defaults['max_options'] < $defaults['min_options']) {
            $defaults['max_options'] = $defaults['min_options'];
        }
        return $defaults;
    }

    /**
     * Fetch campaign related configuration with safe defaults when columns are missing.
     *
     * @return array<string,mixed>
     */
	private function getCampaignSettings(): array {
        $defaults = [
            'status' => '0',
            'policy' => 'all',
            'title_required' => '1',
            'goal_required' => '1',
            'deadline_required' => '1',
            'goal_min' => '50.00',
            'goal_max' => '100000.00',
        ];
			$map = [
            'campaign_feature_status' => 'status',
            'campaign_creator_policy' => 'policy',
            'campaign_title_required' => 'title_required',
            'campaign_goal_required' => 'goal_required',
            'campaign_deadline_required' => 'deadline_required',
            'campaign_goal_min' => 'goal_min',
            'campaign_goal_max' => 'goal_max',
        ];
        $fields = [];
        foreach ($map as $column => $alias) {
            if ($this->configColumnExists($column)) {
                $fields[] = $column;
            }
        }
        if (!empty($fields)) {
            try {
                $row = DB::one(
                    "SELECT " . implode(',', array_unique($fields)) . " FROM i_configurations WHERE configuration_id = 1"
                );
                if ($row) {
                    foreach ($map as $column => $alias) {
                        if (array_key_exists($column, $row)) {
                            $defaults[$alias] = (string)$row[$column];
                        }
                    }
                }
            } catch (Throwable $e) {
                // use defaults
            }
        }
        if (!is_numeric($defaults['goal_min']) || (float)$defaults['goal_min'] < 50) {
            $defaults['goal_min'] = '50.00';
        }
        if (!is_numeric($defaults['goal_max']) || (float)$defaults['goal_max'] < 100) {
            $defaults['goal_max'] = '100000.00';
        }
        if (!in_array($defaults['policy'], ['all', 'verified', 'admin_only'], true)) {
            $defaults['policy'] = 'all';
        }
        return $defaults;
	}

    /**
     * Public accessor for campaign settings.
     *
     * @return array<string,mixed>
     */
    public function iN_GetCampaignSettings(): array {
        return $this->getCampaignSettings();
    }

    /**
     * Fetch community creation settings with safe defaults when columns are missing.
     *
     * @return array{policy:string,free_limit:int}
     */
    private function getCommunityCreationSettings(): array {
        $policy = $this->iN_GetSetting('community_creation_policy', 'paid_only');
        $policy = strtolower(trim((string)$policy));
        if (!in_array($policy, ['paid_only', 'free_only', 'both'], true)) {
            $policy = 'paid_only';
        }
        $limit = $this->iN_GetSetting('community_free_member_limit', 10);
        if (!is_numeric($limit)) {
            $limit = 10;
        }
        $limit = (int)$limit;
        if ($limit < 1) {
            $limit = 1;
        }
        return [
            'policy' => $policy,
            'free_limit' => $limit
        ];
    }

    /**
     * Public accessor for community creation settings.
     *
     * @return array{policy:string,free_limit:int}
     */
    public function iN_GetCommunityCreationSettings(): array {
        return $this->getCommunityCreationSettings();
    }

    /**
     * Check if a user can create a campaign based on policy.
     */
    public function iN_CanUserCreateCampaign(int $userID): bool {
        $settings = $this->getCampaignSettings();
        return $this->canUserCreateCampaignPolicy($userID, $settings);
    }

    /**
     * Campaign creator policy resolver.
     */
    private function canUserCreateCampaignPolicy(int $userID, array $settings): bool {
        $policy = $settings['policy'] ?? 'all';
        if ($policy === 'admin_only') {
            return $this->iN_CheckIsAdmin($userID) == 1;
        }
        if ($policy === 'verified') {
            $row = DB::one("SELECT user_verified_status FROM i_users WHERE iuid = ? LIMIT 1", [$userID]);
            if (!$row) { return false; }
            if ($this->iN_CheckIsAdmin($userID) == 1) {
                return true;
            }
            return isset($row['user_verified_status']) && (string)$row['user_verified_status'] === '1';
        }
        return true;
    }

    /**
     * Retrieve campaign meta by post id.
     */
    public function iN_GetCampaignByPostId(int $postId): ?array {
        if ($postId <= 0) { return null; }
        try {
            $row = DB::one("SELECT * FROM i_campaigns WHERE post_id_fk = ? LIMIT 1", [$postId]);
            if (!$row) { return null; }
            $goal = isset($row['goal_amount']) ? (float)$row['goal_amount'] : 0.0;
            $raised = isset($row['raised_amount']) ? (float)$row['raised_amount'] : 0.0;

            // Fallback: recompute raised from payments if missing/outdated.
            $paymentsSum = (float) DB::col(
                "SELECT SUM(amount) FROM i_user_payments WHERE payed_post_id_fk = ? AND payment_type = 'campaign_donate' AND payment_status = 'ok'",
                [$postId]
            );
            if ($paymentsSum > $raised) {
                $raised = $paymentsSum;
                // Persist the corrected total for future reads.
                DB::exec(
                    "UPDATE i_campaigns SET raised_amount = ?, updated_at = ? WHERE post_id_fk = ? LIMIT 1",
                    [number_format($raised, 2, '.', ''), time(), $postId]
                );
                $row['raised_amount'] = $raised;
            }

            $progress = 0;
            if ($goal > 0) {
                $progressCalc = ($raised / $goal) * 100;
                $progress = min(100, round($progressCalc, 2));
            }
            $deadlineTs = isset($row['deadline_at']) ? (int)$row['deadline_at'] : null;
            $now = time();
            $status = $row['status'] ?? 'pending';
            if ($deadlineTs && $deadlineTs < $now && $status === 'active') {
                $status = 'expired';
            }
            $row['progress'] = $progress;
            $row['status_resolved'] = $status;
            $row['deadline_ts'] = $deadlineTs;
            return $row;
        } catch (Throwable $e) {
            return null;
        }
    }

    /**
     * Fetch campaigns by status for admin listings.
     */
    public function iN_GetCampaignsByStatus(string $status, int $limit = 50): array {
        $allowed = ['pending', 'active', 'rejected', 'expired'];
        if (!in_array($status, $allowed, true)) {
            return [];
        }
        $limit = $limit > 0 ? $limit : 50;
        $sql = "SELECT C.*, U.i_username
                FROM i_campaigns C
                INNER JOIN i_users U ON C.owner_uid_fk = U.iuid
                WHERE C.status = ?
                ORDER BY C.created_at DESC
                LIMIT $limit";
        return DB::all($sql, [$status]);
    }

    /**
     * Update campaign status and set updated_at.
     */
    public function iN_UpdateCampaignStatus(int $campaignId, string $status): bool {
        $allowed = ['pending', 'active', 'rejected', 'expired'];
        if (!in_array($status, $allowed, true) || $campaignId <= 0) {
            return false;
        }
        $campaign = DB::one("SELECT campaign_id FROM i_campaigns WHERE campaign_id = ? LIMIT 1", [$campaignId]);
        if (!$campaign) {
            return false;
        }
        DB::exec("UPDATE i_campaigns SET status = ?, updated_at = ? WHERE campaign_id = ?", [$status, time(), $campaignId]);
        return true;
    }

    /**
     * Campaign donation page summary cards for admin.
     *
     * @return array{total_campaigns:int,live_campaigns:int,total_earnings:float}
     */
    public function iN_GetCampaignDonationAdminStats(int $userID): array {
        if ($this->iN_CheckIsAdmin($userID) != 1) {
            return [
                'total_campaigns' => 0,
                'live_campaigns' => 0,
                'total_earnings' => 0.0,
            ];
        }

        try {
            $now = time();
            $totalCampaigns = (int)(DB::col("SELECT COUNT(*) FROM i_campaigns") ?? 0);
            $liveCampaigns = (int)(DB::col(
                "SELECT COUNT(*) FROM i_campaigns WHERE status = 'active' AND (deadline_at IS NULL OR deadline_at = 0 OR deadline_at > ?)",
                [$now]
            ) ?? 0);
            $totalEarnings = (float)(DB::col(
                "SELECT SUM(amount) FROM i_user_payments WHERE payment_type = 'campaign_donate' AND payment_status = 'ok'"
            ) ?? 0);

            return [
                'total_campaigns' => $totalCampaigns,
                'live_campaigns' => $liveCampaigns,
                'total_earnings' => $totalEarnings,
            ];
        } catch (Throwable $e) {
            return [
                'total_campaigns' => 0,
                'live_campaigns' => 0,
                'total_earnings' => 0.0,
            ];
        }
    }

    /**
     * Get a random preview of donors and total donor count for a campaign post.
     */
    public function iN_GetCampaignDonorPreview(int $postId, int $limit = 5): array {
        global $base_url;
        if ($postId <= 0) {
            return ['total' => 0, 'items' => []];
        }
        $limit = max(1, min(20, $limit));
        $total = (int) DB::col(
            "SELECT COUNT(DISTINCT payer_iuid_fk) FROM i_user_payments WHERE payed_post_id_fk = ? AND payment_type = 'campaign_donate' AND payment_status = 'ok'",
            [$postId]
        );
        $items = [];
        if ($total > 0) {
            $rows = DB::all(
                "SELECT U.iuid,U.i_username,U.i_user_fullname,U.user_avatar, MAX(P.is_anonymous) AS anon_flag
                 FROM i_user_payments P
                 INNER JOIN i_users U ON U.iuid = P.payer_iuid_fk
                 WHERE P.payed_post_id_fk = ? AND P.payment_type = 'campaign_donate' AND P.payment_status = 'ok'
                 GROUP BY U.iuid
                 ORDER BY RAND()
                 LIMIT $limit",
                [$postId]
            );
            if (!empty($rows)) {
                foreach ($rows as $row) {
                    $uid = (int) ($row['iuid'] ?? 0);
                    if ($uid <= 0) {
                        continue;
                    }
                    $isAnon = !empty($row['anon_flag']);
                    $items[] = [
                        'id' => $uid,
                        'username' => $isAnon ? '' : ($row['i_username'] ?? ''),
                        'full_name' => $isAnon ? ($GLOBALS['LANG']['campaign_anonymous'] ?? 'Anonymous') : ($row['i_user_fullname'] ?? ''),
                        'avatar' => $isAnon ? $base_url . 'uploads/avatars/no_gender.png' : $this->iN_UserAvatar($uid, $base_url),
                        'anonymous' => $isAnon ? 1 : 0,
                    ];
                }
            }
        }
        return ['total' => $total, 'items' => $items];
    }

    /**
     * Aggregated donor list for a campaign (grouped by donor).
     */
    public function iN_GetCampaignDonorList(int $postId, int $limit = 200, int $offset = 0): array {
        global $base_url;
        if ($postId <= 0) {
            return ['total' => 0, 'items' => []];
        }
        $limit = max(1, min(500, $limit));
        $offset = max(0, $offset);
        $total = (int) DB::col(
            "SELECT COUNT(DISTINCT payer_iuid_fk) FROM i_user_payments WHERE payed_post_id_fk = ? AND payment_type = 'campaign_donate' AND payment_status = 'ok'",
            [$postId]
        );
        $items = [];
        if ($total > 0) {
            $rows = DB::all(
                "SELECT U.iuid,U.i_username,U.i_user_fullname,U.user_avatar,
                        SUM(P.amount) AS total_amount,
                        MAX(P.payment_time) AS last_time,
                        MAX(P.is_anonymous) AS anon_flag
                 FROM i_user_payments P
                 INNER JOIN i_users U ON U.iuid = P.payer_iuid_fk
                 WHERE P.payed_post_id_fk = ? AND P.payment_type = 'campaign_donate' AND P.payment_status = 'ok'
                 GROUP BY U.iuid
                 ORDER BY last_time DESC
                 LIMIT $offset, $limit",
                [$postId]
            );
            if (!empty($rows)) {
                foreach ($rows as $row) {
                    $uid = (int) ($row['iuid'] ?? 0);
                    if ($uid <= 0) {
                        continue;
                    }
                    $isAnon = !empty($row['anon_flag']);
                    $items[] = [
                        'id' => $uid,
                        'username' => $isAnon ? '' : ($row['i_username'] ?? ''),
                        'full_name' => $isAnon ? ($GLOBALS['LANG']['campaign_anonymous'] ?? 'Anonymous') : ($row['i_user_fullname'] ?? ''),
                        'avatar' => $isAnon ? $base_url . 'uploads/avatars/no_gender.png' : $this->iN_UserAvatar($uid, $base_url),
                        'amount' => number_format((float) ($row['total_amount'] ?? 0), 2, '.', ''),
                        'last_time' => isset($row['last_time']) ? (int) $row['last_time'] : 0,
                        'anonymous' => $isAnon ? 1 : 0
                    ];
                }
            }
        }
        return ['total' => $total, 'items' => $items];
    }

    /**
     * Retrieve scheduled posts configuration with sane defaults.
     *
     * @return array{status:string,max_days:int}
     */
    private function getScheduledSettings(): array {
        $defaults = ['status' => '0', 'max_days' => 30];
        $fields = [];
        if ($this->configColumnExists('scheduled_posts_status')) { $fields[] = 'scheduled_posts_status'; }
        if ($this->configColumnExists('scheduled_max_delay_days')) { $fields[] = 'scheduled_max_delay_days'; }
        if (empty($fields)) {
            return $defaults;
        }
        try {
            $row = DB::one("SELECT " . implode(',', $fields) . " FROM i_configurations WHERE configuration_id = 1");
            if ($row) {
                if (array_key_exists('scheduled_posts_status', $row)) {
                    $defaults['status'] = (string)$row['scheduled_posts_status'];
                }
                if (array_key_exists('scheduled_max_delay_days', $row) && is_numeric($row['scheduled_max_delay_days'])) {
                    $defaults['max_days'] = (int)$row['scheduled_max_delay_days'];
                }
            }
        } catch (Throwable $e) {
            // ignore and fall back to defaults
        }
        if ($defaults['max_days'] < 1) {
            $defaults['max_days'] = 30;
        }
        if ($defaults['max_days'] > 30) {
            $defaults['max_days'] = 30;
        }
        return $defaults;
    }

    /**
     * Check if scheduled columns/table are available in the current schema.
     */
    private function scheduledSchemaReady(): bool {
        if (self::$scheduledSchemaReadyCache !== null) {
            return self::$scheduledSchemaReadyCache;
        }
        try {
            $col = DB::one("SHOW COLUMNS FROM i_posts LIKE 'scheduled_status'");
            $queueExists = DB::col("SELECT COUNT(*) FROM information_schema.TABLES WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'i_scheduled_queue'");
            self::$scheduledSchemaReadyCache = !empty($col) && $queueExists;
        } catch (Throwable $e) {
            self::$scheduledSchemaReadyCache = false;
        }
        return self::$scheduledSchemaReadyCache;
    }

    /**
     * Build a safe WHERE clause to hide scheduled posts from non-owners.
     *
     * @return array{0:string,1:array}
     */
    private function scheduledVisibilityClause(?int $viewerId = null, string $alias = 'P'): array {
        $safeAlias = preg_replace('/[^a-zA-Z0-9_]/', '', $alias);
        if ($safeAlias === '') { $safeAlias = 'P'; }
        $clause = "({$safeAlias}.scheduled_status IS NULL OR {$safeAlias}.scheduled_status = 'published'";
        $params = [];
        if (!empty($viewerId)) {
            $clause .= " OR {$safeAlias}.post_owner_id = ?";
            $params[] = (int)$viewerId;
        }
        $clause .= ")";
        return [$clause, $params];
    }
