	public function iN_NormalizeStoryReactionSet($raw, array $fallback = []): array {
		$raw = trim((string)$raw);
		$items = [];
		if ($raw !== '') {
			$raw = str_replace([',', ';', '|', '/'], ' ', $raw);
			$raw = preg_replace('/\s+/', ' ', $raw);
			$parts = explode(' ', $raw);
			foreach ($parts as $part) {
				$part = trim($part);
				if ($part === '') {
					continue;
				}
				if (!in_array($part, $items, true)) {
					$items[] = $part;
				}
				if (count($items) >= 10) {
					break;
				}
			}
		}
		if (empty($items) && !empty($fallback)) {
			$items = $fallback;
		}
		return $items;
	}

	public function iN_StoryReactionSetToString(array $reactions): string {
		$reactions = array_values(array_filter($reactions, 'strlen'));
		return implode(',', $reactions);
	}

	public function iN_GetStoryDefaultReactions(): array {
		$default = ['❤️', '🔥', '😂', '😮', '👏'];
		$raw = (string)$this->iN_GetSetting('story_default_reactions', '');
		$list = $this->iN_NormalizeStoryReactionSet($raw, $default);
		return !empty($list) ? $list : $default;
	}

	public function iN_IsCreatorBulkEnabled(): bool {
		$enabled = $this->iN_GetSetting('creator_bulk_messaging_enabled', '1');
		return (string)$enabled === '1';
	}

	public function iN_IsObsOverlayEnabled(): bool {
		$status = (string)$this->iN_GetSetting('obs_overlay_module_status', 'yes');
		return $status === 'yes';
	}

	public function iN_GetObsOverlayMaxTotal(): int {
		$max = $this->iN_GetSetting('obs_overlay_max_total', 5);
		if (!is_numeric($max)) {
			return 5;
		}
		$max = (int)$max;
		if ($max < 1) {
			$max = 1;
		}
		if ($max > 50) {
			$max = 50;
		}
		return $max;
	}

	public function iN_GetObsOverlayMaxActive(): int {
		$max = $this->iN_GetSetting('obs_overlay_max_active', 5);
		if (!is_numeric($max)) {
			return 5;
		}
		$max = (int)$max;
		if ($max < 1) {
			$max = 1;
		}
		if ($max > 50) {
			$max = 50;
		}
		return $max;
