	public function iN_GetCreatorBulkDailyLimit(): int {
		$limit = $this->iN_GetSetting('creator_bulk_daily_limit', 3);
		if (!is_numeric($limit)) {
			return 3;
		}
		$limit = (int)$limit;
		return $limit < 0 ? 0 : $limit;
	}

	public function iN_CountCreatorCampaignsToday($creatorId): int {
		$creatorId = (int)$creatorId;
		if ($creatorId <= 0) {
			return 0;
		}
		$start = strtotime('today');
		$end = $start + 86400;
		$count = DB::col(
			"SELECT COUNT(*) FROM i_bulk_campaigns WHERE created_by_iuid_fk = ? AND created_at >= ? AND created_at < ?",
			[$creatorId, $start, $end]
		);
		return $count ? (int)$count : 0;
	}

	public function iN_CanCreatorCreateCampaignToday($creatorId): bool {
		$limit = $this->iN_GetCreatorBulkDailyLimit();
		if ($limit <= 0) {
			return true;
		}
		$count = $this->iN_CountCreatorCampaignsToday($creatorId);
		return $count < $limit;
	}
