    private function iN_GetActiveSvgIconMap() {
        if (self::$svgIconMapCache !== null) {
            return self::$svgIconMapCache;
        }

        self::$svgIconMapCache = [];
        $rows = DB::all("SELECT icon_id, icon_code FROM i_svg_icons WHERE icon_status = '1'");
        if (!empty($rows)) {
            foreach ($rows as $row) {
                $id = isset($row['icon_id']) ? (int)$row['icon_id'] : 0;
                if ($id < 1 || !isset($row['icon_code'])) {
                    continue;
                }
                self::$svgIconMapCache[$id] = $row['icon_code'];
            }
        }

        return self::$svgIconMapCache;
    }

