    private function iN_GetMediaStorageConfig() {
        if (self::$mediaStorageConfigCache !== null) {
            return self::$mediaStorageConfigCache;
        }

        $config = [
            's3_status' => isset($GLOBALS['s3Status']) ? (string)$GLOBALS['s3Status'] : '0',
            'was_status' => isset($GLOBALS['WasStatus']) ? (string)$GLOBALS['WasStatus'] : '0',
            'ocean_status' => isset($GLOBALS['digitalOceanStatus']) ? (string)$GLOBALS['digitalOceanStatus'] : '0',
            's3_bucket' => isset($GLOBALS['s3Bucket']) ? (string)$GLOBALS['s3Bucket'] : '',
            's3_region' => isset($GLOBALS['s3Region']) ? (string)$GLOBALS['s3Region'] : '',
            'was_bucket' => isset($GLOBALS['WasBucket']) ? (string)$GLOBALS['WasBucket'] : '',
            'was_region' => isset($GLOBALS['WasRegion']) ? (string)$GLOBALS['WasRegion'] : '',
            'ocean_space_name' => isset($GLOBALS['oceanspace_name']) ? (string)$GLOBALS['oceanspace_name'] : '',
            'ocean_region' => isset($GLOBALS['oceanregion']) ? (string)$GLOBALS['oceanregion'] : '',
        ];

        $needsFallback = !isset($GLOBALS['s3Status']) || !isset($GLOBALS['WasStatus']) || !isset($GLOBALS['digitalOceanStatus']);
        if (
            ($config['s3_status'] === '1' && ($config['s3_bucket'] === '' || $config['s3_region'] === ''))
            || ($config['was_status'] === '1' && ($config['was_bucket'] === '' || $config['was_region'] === ''))
            || ($config['ocean_status'] === '1' && ($config['ocean_space_name'] === '' || $config['ocean_region'] === ''))
        ) {
            $needsFallback = true;
        }

        if ($needsFallback) {
            $row = DB::one("SELECT s3_status,was_status,ocean_status,s3_bucket,s3_region,was_bucket,was_region,ocean_space_name,ocean_region FROM i_configurations WHERE configuration_id = 1");
            if (!empty($row)) {
                foreach ($config as $key => $val) {
                    if (isset($row[$key]) && $row[$key] !== null && $row[$key] !== '') {
                        $config[$key] = (string)$row[$key];
                    }
                }
            }
        }

        self::$mediaStorageConfigCache = $config;
        return self::$mediaStorageConfigCache;
    }

    private function iN_GetUserMediaRow($uid) {
        $userID = (int)$uid;
        if ($userID < 1) {
            return null;
        }
        if (array_key_exists($userID, self::$userMediaRowCache)) {
            return self::$userMediaRowCache[$userID];
        }

        $row = DB::one("SELECT user_avatar, user_cover, login_with, user_gender FROM i_users WHERE iuid = ? LIMIT 1", [$userID]);
        self::$userMediaRowCache[$userID] = (!empty($row) && is_array($row)) ? $row : null;
        return self::$userMediaRowCache[$userID];
    }

    private function iN_MediaPathCacheKey($uid, $imageID) {
        return ((int)$uid) . ':' . ((int)$imageID);
    }

    private function iN_InvalidateUserMediaCaches($uid) {
        $userID = (int)$uid;
        if ($userID < 1) {
            return;
        }
        unset(self::$userMediaRowCache[$userID]);
        $prefix = $userID . ':';
        foreach (array_keys(self::$avatarPathCache) as $key) {
            if (strpos((string)$key, $prefix) === 0) {
                unset(self::$avatarPathCache[$key]);
            }
        }
        foreach (array_keys(self::$coverPathCache) as $key) {
            if (strpos((string)$key, $prefix) === 0) {
                unset(self::$coverPathCache[$key]);
            }
        }
    }

    public function iN_PreloadUserMediaPathMaps(array $userIDs): void {
        $ids = $this->iN_NormalizePositiveIntList($userIDs);
        if (empty($ids)) {
            return;
        }
        $profiles = $this->iN_GetUsersBasicProfileMap($ids);
        if (empty($profiles)) {
            return;
        }

        $avatarIDs = [];
        $coverIDs = [];
        $userAvatarMap = [];
        $userCoverMap = [];

        foreach ($profiles as $uid => $profileRow) {
            $profileUID = (int)$uid;
            if ($profileUID > 0) {
                self::$userMediaRowCache[$profileUID] = [
                    'user_avatar' => isset($profileRow['user_avatar']) ? $profileRow['user_avatar'] : null,
                    'user_cover' => isset($profileRow['user_cover']) ? $profileRow['user_cover'] : null,
                    'login_with' => isset($profileRow['login_with']) ? $profileRow['login_with'] : null,
                    'user_gender' => isset($profileRow['user_gender']) ? $profileRow['user_gender'] : null,
                ];
            }

            $avatarRaw = isset($profileRow['user_avatar']) ? (string)$profileRow['user_avatar'] : '';
            if ($avatarRaw !== '' && ctype_digit($avatarRaw)) {
                $avatarID = (int)$avatarRaw;
                if ($avatarID > 0) {
                    $avatarIDs[$avatarID] = $avatarID;
                    $userAvatarMap[(int)$uid] = $avatarID;
                }
            }

            $coverRaw = isset($profileRow['user_cover']) ? (string)$profileRow['user_cover'] : '';
            if ($coverRaw !== '' && ctype_digit($coverRaw)) {
                $coverID = (int)$coverRaw;
                if ($coverID > 0) {
                    $coverIDs[$coverID] = $coverID;
                    $userCoverMap[(int)$uid] = $coverID;
                }
            }
        }

        if (!empty($avatarIDs) && !empty($userAvatarMap)) {
            $uidPlaceholders = implode(',', array_fill(0, count($ids), '?'));
            $avatarPlaceholders = implode(',', array_fill(0, count($avatarIDs), '?'));
            $params = array_merge($ids, array_values($avatarIDs));
            $rows = DB::all(
                "SELECT iuid_fk, avatar_id, avatar_path
                 FROM i_user_avatars
                 WHERE iuid_fk IN ($uidPlaceholders) AND avatar_id IN ($avatarPlaceholders)",
                $params
            );
            $avatarPathMap = [];
            if (!empty($rows)) {
                foreach ($rows as $row) {
                    $uid = isset($row['iuid_fk']) ? (int)$row['iuid_fk'] : 0;
                    $avatarID = isset($row['avatar_id']) ? (int)$row['avatar_id'] : 0;
                    if ($uid < 1 || $avatarID < 1) {
                        continue;
                    }
                    $avatarPathMap[$this->iN_MediaPathCacheKey($uid, $avatarID)] = isset($row['avatar_path']) ? $row['avatar_path'] : null;
                }
            }
            foreach ($userAvatarMap as $uid => $avatarID) {
                $key = $this->iN_MediaPathCacheKey($uid, $avatarID);
                self::$avatarPathCache[$key] = array_key_exists($key, $avatarPathMap) ? $avatarPathMap[$key] : null;
            }
        }

        if (!empty($coverIDs) && !empty($userCoverMap)) {
            $uidPlaceholders = implode(',', array_fill(0, count($ids), '?'));
            $coverPlaceholders = implode(',', array_fill(0, count($coverIDs), '?'));
            $params = array_merge($ids, array_values($coverIDs));
            $rows = DB::all(
                "SELECT iuid_fk, cover_id, cover_path
                 FROM i_user_covers
                 WHERE iuid_fk IN ($uidPlaceholders) AND cover_id IN ($coverPlaceholders)",
                $params
            );
            $coverPathMap = [];
            if (!empty($rows)) {
                foreach ($rows as $row) {
                    $uid = isset($row['iuid_fk']) ? (int)$row['iuid_fk'] : 0;
                    $coverID = isset($row['cover_id']) ? (int)$row['cover_id'] : 0;
                    if ($uid < 1 || $coverID < 1) {
                        continue;
                    }
                    $coverPathMap[$this->iN_MediaPathCacheKey($uid, $coverID)] = isset($row['cover_path']) ? $row['cover_path'] : null;
                }
            }
            foreach ($userCoverMap as $uid => $coverID) {
                $key = $this->iN_MediaPathCacheKey($uid, $coverID);
                self::$coverPathCache[$key] = array_key_exists($key, $coverPathMap) ? $coverPathMap[$key] : null;
            }
        }
    }

