    public function iN_GetUsersBasicProfileMap(array $userIDs) {
        $ids = $this->iN_NormalizePositiveIntList($userIDs);
        if (empty($ids)) {
            return [];
        }
        $placeholders = implode(',', array_fill(0, count($ids), '?'));
        $rows = DB::all(
            "SELECT iuid, user_avatar, user_cover, login_with, user_gender, u_bio, profile_category
             FROM i_users
             WHERE iuid IN ($placeholders)",
            $ids
        );
        $map = [];
        if (!empty($rows)) {
            foreach ($rows as $row) {
                $uid = isset($row['iuid']) ? (int)$row['iuid'] : 0;
                if ($uid < 1) {
                    continue;
                }
                $map[$uid] = $row;
            }
        }
        return $map;
    }

