	public function iN_UserAvatar($uid, $base_url) {
        $uid = (int)$uid;
		$row = $this->iN_GetUserMediaRow($uid);
		$rowAvatar = isset($row['user_avatar']) ? $row['user_avatar'] : NULL;
		$loginWith = isset($row['login_with']) ? $row['login_with'] : NULL;
		$avatarPath = $this->iN_GetUploadedAvatarURL($uid, $rowAvatar);
		$userGender = isset($row['user_gender']) ? $row['user_gender'] : NULL;
		if (!empty($rowAvatar)) {
			if (!empty($loginWith) && !is_numeric($rowAvatar)) {
				$data = $rowAvatar;
			} else {
				if ($avatarPath && function_exists('storage_public_url')) {
					return storage_public_url($avatarPath);
				}
                $storage = $this->iN_GetMediaStorageConfig();
				$s3Status = isset($storage['s3_status']) ? $storage['s3_status'] : '0';
				$wasStatus = isset($storage['was_status']) ? $storage['was_status'] : '0';
				$oceanStatus = isset($storage['ocean_status']) ? $storage['ocean_status'] : '0';
				if (!$avatarPath) {
					$data = $this->iN_JoinBaseUrlAndPath($base_url, $rowAvatar);
				} else if ($s3Status == 1 && !empty($storage['s3_bucket']) && !empty($storage['s3_region'])) {
					$data = 'https://' . $storage['s3_bucket'] . '.s3.' . $storage['s3_region'] . '.amazonaws.com/' . $avatarPath;
				}else if($wasStatus == 1 && !empty($storage['was_bucket']) && !empty($storage['was_region'])){
					$data = 'https://' . $storage['was_bucket'] . '.s3.' . $storage['was_region'] . '.wasabisys.com/' . $avatarPath;
				}else if($oceanStatus == 1 && !empty($storage['ocean_space_name']) && !empty($storage['ocean_region'])){
					$data = 'https://'.$storage['ocean_space_name'].'.'.$storage['ocean_region'].'.digitaloceanspaces.com/'. $avatarPath;
				} else {
					if ($avatarPath) {
						$data = $this->iN_JoinBaseUrlAndPath($base_url, $avatarPath);
					} else {
						$data = $this->iN_JoinBaseUrlAndPath($base_url, $rowAvatar);
					}
				}
			}
			return $data;
		} else {
			if ($userGender == 'male') {
				$data = $base_url . "uploads/avatars/d-avatar.jpg";
				return $data;
			} else if ($userGender == 'female') {
				$data = $base_url . "uploads/avatars/f-avatar.jpg";
				return $data;
			} else if ($userGender == 'couple') {
				$data = $base_url . "uploads/avatars/g-couple.png";
				return $data;
			} else {
				$data = $this->iN_JoinBaseUrlAndPath($base_url, "uploads/avatars/no_gender.png");
				return $data;
			}
		}
	}
