			} else if ($s3Status == 1 && !empty($storage['s3_bucket']) && !empty($storage['s3_region'])) {
				$data = 'https://' . $storage['s3_bucket'] . '.s3.' . $storage['s3_region'] . '.amazonaws.com/' . $coverPath;
			}else if($wasStatus == 1 && !empty($storage['was_bucket']) && !empty($storage['was_region'])){
				$data = 'https://' . $storage['was_bucket'] . '.s3.' . $storage['was_region'] . '.wasabisys.com/' . $coverPath;
			}else if($oceanStatus == 1 && !empty($storage['ocean_space_name']) && !empty($storage['ocean_region'])){
				$data = 'https://'.$storage['ocean_space_name'].'.'.$storage['ocean_region'].'.digitaloceanspaces.com/'. $coverPath;
