	public function iN_GetModeratorPermissionDefinitions(): array {
        $packages = $this->iN_GetModeratorPermissionPackages();
        $definitions = [];
        foreach ($packages as $packageData) {
            $pages = isset($packageData['pages']) && is_array($packageData['pages']) ? $packageData['pages'] : [];
            foreach ($pages as $pageData) {
                $pageLabel = isset($pageData['label']) ? (string)$pageData['label'] : '';
                $features = isset($pageData['features']) && is_array($pageData['features']) ? $pageData['features'] : [];
                foreach ($features as $featureData) {
                    $permissionKey = isset($featureData['key']) ? (string)$featureData['key'] : '';
                    $featureLabel = isset($featureData['label']) ? (string)$featureData['label'] : '';
                    if ($permissionKey === '') {
                        continue;
                    }
                    $definitions[$permissionKey] = trim($pageLabel . ' - ' . $featureLabel);
                }
            }
        }
        return $definitions;
	}
