	private function iN_NormalizePermissionSlug(string $value): string {
        $value = strtolower(trim($value));
        $value = preg_replace('/[^a-z0-9_.-]/', '', $value);
        return str_replace(['.', '-'], '_', (string)$value);
	}
	private function iN_GetModeratorPageAccessPermissionKey(string $pageSlug): string {
        $normalizedSlug = $this->iN_NormalizePermissionSlug($pageSlug);
        return 'page_' . $normalizedSlug . '_access';
	}
	private function iN_GetModeratorPageActionPermissionKey(string $pageSlug): string {
        $normalizedSlug = $this->iN_NormalizePermissionSlug($pageSlug);
        return 'page_' . $normalizedSlug . '_actions';
	}
	private function iN_GetAdminPageLabelFromSlug(string $pageSlug): string {
        global $LANG;
        $pageSlug = $this->iN_NormalizeAdminPageSlug($pageSlug);
        if ($pageSlug === '') {
            return '';
        }
        $snakeCase = strtolower((string)preg_replace('/([a-z])([A-Z])/', '$1_$2', $pageSlug));
        $candidates = array_unique([
            $pageSlug,
            strtolower($pageSlug),
            $snakeCase,
            str_replace('-', '_', $pageSlug),
            str_replace('.', '_', $pageSlug)
        ]);
        foreach ($candidates as $candidate) {
            if (isset($LANG[$candidate]) && $LANG[$candidate] !== '') {
                return (string)$LANG[$candidate];
            }
        }
        $humanized = preg_replace('/([a-z])([A-Z])/', '$1 $2', $pageSlug);
        $humanized = str_replace(['_', '-', '.'], ' ', (string)$humanized);
        $humanized = preg_replace('/\s+/', ' ', trim((string)$humanized));
        return ucwords((string)$humanized);
	}
	public function iN_GetModeratorPermissionPackages(): array {
        $pagePermissionMap = $this->iN_GetModeratorAdminPagePermissionMap();
        $sectionLabels = $this->iN_GetModeratorPermissionSectionLabels();
        $legacySectionMap = $this->iN_GetModeratorLegacyPermissionSectionMap();
        $featureDefinitions = $this->iN_GetModeratorFeatureDefinitions();
        $packages = [];
        foreach ($sectionLabels as $sectionKey => $sectionLabel) {
            $packages[(string)$sectionKey] = [
                'label' => (string)$sectionLabel,
                'pages' => []
            ];
        }
        foreach ($pagePermissionMap as $pageSlug => $legacyPermissionKey) {
            $normalizedPageSlug = $this->iN_NormalizeAdminPageSlug((string)$pageSlug);
            if ($normalizedPageSlug === '') {
                continue;
            }
            $sectionKey = isset($legacySectionMap[$legacyPermissionKey]) ? (string)$legacySectionMap[$legacyPermissionKey] : 'system';
            if (!isset($packages[$sectionKey])) {
                $packages[$sectionKey] = [
                    'label' => $sectionLabels['system'] ?? 'System',
                    'pages' => []
                ];
            }
            $packages[$sectionKey]['pages'][] = [
                'slug' => $normalizedPageSlug,
                'label' => $this->iN_GetAdminPageLabelFromSlug($normalizedPageSlug),
                'features' => [
                    [
                        'type' => 'access',
                        'key' => $this->iN_GetModeratorPageAccessPermissionKey($normalizedPageSlug),
                        'label' => $featureDefinitions['access']['label'],
                        'description' => $featureDefinitions['access']['description']
                    ],
                    [
                        'type' => 'actions',
                        'key' => $this->iN_GetModeratorPageActionPermissionKey($normalizedPageSlug),
                        'label' => $featureDefinitions['actions']['label'],
                        'description' => $featureDefinitions['actions']['description']
                    ]
                ]
            ];
        }
        foreach ($packages as $sectionKey => $sectionData) {
            $pages = isset($sectionData['pages']) && is_array($sectionData['pages']) ? $sectionData['pages'] : [];
            usort($pages, static function ($a, $b) {
                $labelA = isset($a['label']) ? (string)$a['label'] : '';
                $labelB = isset($b['label']) ? (string)$b['label'] : '';
                return strcasecmp($labelA, $labelB);
            });
            $packages[$sectionKey]['pages'] = $pages;
        }
        return $packages;
	}
	private function iN_GetDefaultModeratorPermissions(): array {
        $definitions = $this->iN_GetModeratorPermissionDefinitions();
        $defaults = [];
        foreach ($definitions as $permissionKey => $label) {
            $defaults[(string)$permissionKey] = '0';
        }
        return $defaults;
	}
	private function iN_NormalizeModeratorPermissionInput(array $permissions): array {
        $normalized = $this->iN_GetDefaultModeratorPermissions();
        foreach ($permissions as $permissionKey => $permissionValue) {
            $permissionKey = (string)$permissionKey;
            if (!array_key_exists($permissionKey, $normalized)) {
                continue;
            }
            $normalized[$permissionKey] = (string)$permissionValue === '1' ? '1' : '0';
        }
        return $normalized;
	}
	public function iN_GetModeratorPermissions($moderatorID): array {
        $moderatorID = (int)$moderatorID;
        $defaults = $this->iN_GetDefaultModeratorPermissions();
        if ($moderatorID <= 0 || !$this->iN_TableExists('i_moderator_permissions')) {
            return $defaults;
        }
        $rows = DB::all(
            "SELECT permission_key, permission_value FROM i_moderator_permissions WHERE moderator_id = ?",
            [$moderatorID]
        );
        if (empty($rows)) {
            return $defaults;
        }
        foreach ($rows as $row) {
            $permissionKey = isset($row['permission_key']) ? (string)$row['permission_key'] : '';
            if ($permissionKey === '' || !array_key_exists($permissionKey, $defaults)) {
                continue;
            }
            $defaults[$permissionKey] = (string)($row['permission_value'] ?? '0') === '1' ? '1' : '0';
        }
        return $defaults;
	}
	public function iN_SetModeratorPermissions($moderatorID, array $permissions, $updatedBy = null): bool {
        $moderatorID = (int)$moderatorID;
        if ($moderatorID <= 0 || !$this->iN_TableExists('i_moderator_permissions')) {
            return false;
        }
        $normalized = $this->iN_NormalizeModeratorPermissionInput($permissions);
        $now = time();
        $updatedBy = $updatedBy !== null ? (int)$updatedBy : null;
        try {
            DB::begin();
            foreach ($normalized as $permissionKey => $permissionValue) {
                DB::exec(
                    "INSERT INTO i_moderator_permissions
                        (moderator_id, permission_key, permission_value, updated_by, created_at, updated_at)
                     VALUES (?,?,?,?,?,?)
                     ON DUPLICATE KEY UPDATE
                        permission_value = VALUES(permission_value),
                        updated_by = VALUES(updated_by),
                        updated_at = VALUES(updated_at)",
                    [
                        $moderatorID,
                        (string)$permissionKey,
                        (string)$permissionValue,
                        $updatedBy,
                        $now,
                        $now
                    ]
                );
            }
            DB::commit();
            return true;
        } catch (Throwable $e) {
            DB::rollBack();
            return false;
        }
	}
	public function iN_ClearModeratorPermissions($moderatorID): bool {
        $moderatorID = (int)$moderatorID;
        if ($moderatorID <= 0 || !$this->iN_TableExists('i_moderator_permissions')) {
            return false;
        }
        DB::exec("DELETE FROM i_moderator_permissions WHERE moderator_id = ?", [$moderatorID]);
        return true;
	}
	public function iN_ModeratorHasPermission($moderatorID, $permissionKey): bool {
        $moderatorID = (int)$moderatorID;
        $permissionKey = (string)$permissionKey;
        if ($moderatorID <= 0 || $permissionKey === '') {
            return false;
        }
        $permissions = $this->iN_GetModeratorPermissions($moderatorID);
        if (array_key_exists($permissionKey, $permissions)) {
            return isset($permissions[$permissionKey]) && (string)$permissions[$permissionKey] === '1';
        }
        if (!$this->iN_TableExists('i_moderator_permissions')) {
            return false;
        }
        $value = DB::col(
            "SELECT permission_value FROM i_moderator_permissions WHERE moderator_id = ? AND permission_key = ? LIMIT 1",
            [$moderatorID, $permissionKey]
        );
        return (string)$value === '1';
	}
	private function iN_NormalizeAdminPageSlug(string $pageSlug): string {
        $pageSlug = trim($pageSlug);
        if ($pageSlug === '') {
            return '';
        }
        $pageSlug = preg_replace('/\.php$/i', '', $pageSlug);
        return preg_replace('/[^a-zA-Z0-9_.-]/', '', (string)$pageSlug);
	}
