	private function iN_ModeratorUsesPagePermissionModel($moderatorID): bool {
        $moderatorID = (int)$moderatorID;
        if ($moderatorID <= 0 || !$this->iN_TableExists('i_moderator_permissions')) {
            return false;
        }
        $hasRow = DB::col(
            "SELECT 1 FROM i_moderator_permissions
             WHERE moderator_id = ?
             AND permission_key LIKE 'page\\_%\\_access' ESCAPE '\\\\'
             LIMIT 1",
