	public function iN_CanModeratorAccessAdminPage($moderatorID, $pageSlug): bool {
        $moderatorID = (int)$moderatorID;
        if ($moderatorID <= 0 || !$this->iN_CheckIsModerator($moderatorID)) {
            return false;
        }
        $pageSlug = $this->iN_NormalizeAdminPageSlug((string)$pageSlug);
        if ($pageSlug === '') {
            return false;
        }
        $accessPermissionKey = $this->iN_GetModeratorPageAccessPermissionKey($pageSlug);
        if ($this->iN_ModeratorHasPermission($moderatorID, $accessPermissionKey)) {
            return true;
        }
        $usesPagePermissionModel = $this->iN_ModeratorUsesPagePermissionModel($moderatorID);
        if ($usesPagePermissionModel) {
            return false;
        }
        $pageMap = $this->iN_GetModeratorAdminPagePermissionMap();
        if (!isset($pageMap[$pageSlug])) {
            return false;
        }
        return $this->iN_ModeratorHasPermission($moderatorID, (string)$pageMap[$pageSlug]);
	}
	public function iN_GetFirstAccessibleModeratorAdminPage($moderatorID): string {
        $moderatorID = (int)$moderatorID;
        if ($moderatorID <= 0 || !$this->iN_CheckIsModerator($moderatorID)) {
            return '';
        }
        $pageMap = $this->iN_GetModeratorAdminPagePermissionMap();
        foreach ($pageMap as $pageSlug => $legacyPermissionKey) {
            $normalizedPageSlug = $this->iN_NormalizeAdminPageSlug((string)$pageSlug);
            if ($normalizedPageSlug === '') {
                continue;
            }
            if ($this->iN_CanModeratorAccessAdminPage($moderatorID, $normalizedPageSlug)) {
                return $normalizedPageSlug;
            }
        }
        return '';
	}
