	public function iN_CanModeratorRunAdminAction($moderatorID, $actionType): bool {
        $moderatorID = (int)$moderatorID;
        if ($moderatorID <= 0 || !$this->iN_CheckIsModerator($moderatorID)) {
            return false;
        }
        $actionType = trim((string)$actionType);
        if ($actionType === '') {
            return false;
        }
        $actionPageMap = $this->iN_GetModeratorAdminActionPageMap();
        if (isset($actionPageMap[$actionType])) {
            $pageSlug = $this->iN_NormalizeAdminPageSlug((string)$actionPageMap[$actionType]);
            if ($pageSlug !== '') {
                $hasPageAccess = $this->iN_ModeratorHasPermission(
                    $moderatorID,
                    $this->iN_GetModeratorPageAccessPermissionKey($pageSlug)
                );
                $hasActionPermission = $this->iN_ModeratorHasPermission(
                    $moderatorID,
                    $this->iN_GetModeratorPageActionPermissionKey($pageSlug)
                );
                if ($hasPageAccess && $hasActionPermission) {
                    return true;
                }
            }
        }
        $usesPagePermissionModel = $this->iN_ModeratorUsesPagePermissionModel($moderatorID);
        if ($usesPagePermissionModel) {
            return false;
        }
        $actionMap = $this->iN_GetModeratorAdminActionPermissionMap();
        if (!isset($actionMap[$actionType])) {
            return false;
        }
        $permissionKey = (string)$actionMap[$actionType];
        return $this->iN_ModeratorHasPermission($moderatorID, $permissionKey);
	}
	/*Get Total Unreaded notifications */
	public function iN_GetNewNotificationSum($uid) {
		$uid = (int)$uid;
		if ($this->iN_CheckUserExist($uid) == 1) {
            $val = DB::col("SELECT COUNT(*) FROM i_user_notifications WHERE not_own_iuid = ? AND not_status = '0'", [$uid]);
            return (int)$val;
		}
		return false;
	}
	/*Get All Notifications*/
	public function iN_GetAllNotificationList($uid, $limit) {
		$uid = (int)$uid; $limit = (int)$limit;
		if ($this->iN_CheckUserExist($uid) == 1) {
            $sql = "SELECT * FROM i_user_notifications N FORCE INDEX(ixForceID)
                INNER JOIN i_users U FORCE INDEX(ixForceUser) ON N.not_own_iuid = U.iuid
                WHERE not_own_iuid = ? AND not_status IN('0','1') AND not_show_hide <> '1' ORDER BY N.not_id DESC LIMIT $limit";
            $rows = DB::all($sql, [$uid]);
            return !empty($rows) ? $rows : false;
		}
	}

	/*Update User Notification Status*/
	public function iN_UpdateNotificationStatus($uid) {
		$uid = (int)$uid;
		if ($this->iN_CheckUserExist($uid) == 1) {
            DB::exec("UPDATE i_user_notifications SET not_status = '1' WHERE not_own_iuid = ?", [$uid]);
            DB::exec("UPDATE i_users SET notification_read_status = '0' WHERE iuid = ?", [$uid]);
            return true;
		}
		return false;
	}
	/*Check Notification ID Exist*/
	public function iN_CheckNotificationIDExist($notID) {
        return (bool) DB::col("SELECT 1 FROM i_user_notifications WHERE not_id = ? LIMIT 1", [(int)$notID]);
	}
	/*Get More Notifications*/
	public function iN_GetMoreNotificationList($uid, $limit, $lastID) {
		$uid = (int)$uid; $limit = (int)$limit; $lastID = (int)$lastID;
		$moreData = '';
		if ($lastID) { $moreData = ' AND N.not_id < ' . $lastID . ' '; }
		if ($this->iN_CheckUserExist($uid) == 1 && $this->iN_CheckNotificationIDExist($lastID) == 1) {
            $sql = "SELECT * FROM i_user_notifications N FORCE INDEX(ixForceID)
                INNER JOIN i_users U FORCE INDEX(ixForceUser) ON N.not_own_iuid = U.iuid
                WHERE not_own_iuid = ? AND not_status IN('0','1') $moreData ORDER BY N.not_id DESC LIMIT $limit";
            $rows = DB::all($sql, [$uid]);
            return !empty($rows) ? $rows : null;
		}
	}

public function iN_CheckPostIDExist($postID) {
        return (bool) DB::col("SELECT 1 FROM i_posts WHERE post_id = ? LIMIT 1", [(int)$postID]);
}

public function iN_CheckImageIDExist($ImageID, $userID) {
        return (bool) DB::col("SELECT 1 FROM i_user_uploads WHERE iuid_fk = ? AND upload_id = ? LIMIT 1", [(int)$userID, (int)$ImageID]);
}

public function iN_UpdateWhoCanSeePost($uid, $whoID) {
        if ($this->iN_CheckUserExist($uid) == 1) {
            DB::exec("UPDATE i_users SET post_who_can_see = ? WHERE iuid = ?", [(string)$whoID, (int)$uid]);
            return true;
        }
        return false;
}
	/*INSERT UPLOADED FILES FROM UPLOADS TABLE*/
	public function iN_INSERTUploadedFiles($uid, $filePath, $tumbnailPath, $fileXPath, $ext) {
        $uploadTime = time();
        $userIP = $_SERVER['REMOTE_ADDR'] ?? '';
        // Fallback: if thumbnail path not generated, reuse original so listings don't break
        if (empty($tumbnailPath)) {
            $tumbnailPath = $filePath;
        }
        DB::exec(
            "INSERT INTO i_user_uploads (iuid_fk, uploaded_file_path, upload_tumbnail_file_path, uploaded_x_file_path, uploaded_file_ext, upload_time, ip)
             VALUES (?, ?, ?, ?, ?, ?, ?)",
            [(int)$uid, (string)$filePath, (string)$tumbnailPath, (string)$fileXPath, (string)$ext, $uploadTime, (string)$userIP]
        );
        return (int) DB::lastId();
}

public function iN_GetUploadedFilesIDs($uid, $imageName) {
        if (!$imageName) { return false; }
        $row = DB::one("SELECT upload_id, uploaded_file_path, upload_tumbnail_file_path FROM i_user_uploads WHERE iuid_fk = ? ORDER BY upload_id DESC LIMIT 1", [(int)$uid]);
        return $row ?: false;
}
    /*INSERT NEW POST AND GET REAL TIME*/
    public function iN_InsertNewPost($uid, $postText, $urlSlug, $postFiles, $postWhoCanSee, $hashTags, $pointAmount, $autoApprovePostStatus, $postType = 'normal', ?int $scheduledAt = null, string $scheduledStatus = 'published') {
        $time = time();
        $userIP = $_SERVER['REMOTE_ADDR'] ?? '';
        $allowedStatuses = ['pending', 'queued', 'published', 'failed'];
        $normalizedScheduledStatus = in_array($scheduledStatus, $allowedStatuses, true) ? $scheduledStatus : 'published';
        $isScheduled = $scheduledAt && $normalizedScheduledStatus !== 'published';
        $postStatus = '1';
        if (!empty($postFiles) && trim($postFiles) === '') { $postStatus = '1'; }
        if ($postWhoCanSee == '4' && $autoApprovePostStatus == 'no') { $postStatus = '2'; }
        if ($isScheduled) { $postStatus = '2'; }
        $postType = $this->resolvePostType($postType);
        DB::exec(
            "INSERT INTO i_posts (post_owner_id,post_text,post_file,post_created_time,scheduled_at,post_creator_ip,who_can_see,post_status,scheduled_status,url_slug,hashtags,post_wanted_credit,post_type)
             VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?)",
            [
                (int)$uid,
                (string)$postText,
                (string)$postFiles,
                $time,
                $isScheduled ? (int)$scheduledAt : null,
                (string)$userIP,
                (string)$postWhoCanSee,
                (string)$postStatus,
                (string)$normalizedScheduledStatus,
                (string)$urlSlug,
                (string)$hashTags,
                (string)$pointAmount,
                (string)$postType
            ]
        );
        $linkSelect = $this->iN_PostLinkPreviewSelect();
        $result = DB::one(
            "SELECT P.post_id,P.shared_post_id,P.post_pined,P.post_owner_id,P.post_text,P.hashtags{$linkSelect},P.post_file,P.post_created_time,P.scheduled_at,P.who_can_see,P.post_want_status,P.post_wanted_credit,P.url_slug,P.post_status,P.scheduled_status,P.post_type,P.comment_status,U.payout_method,U.iuid,U.i_username,U.i_user_fullname,U.user_avatar,U.user_gender,U.payout_method,U.last_login_time,U.user_verified_status,U.thanks_for_tip
             FROM i_posts P FORCE INDEX(ixForcePostOwner)
             INNER JOIN i_users U FORCE INDEX(ixForceUser) ON P.post_owner_id = U.iuid
             WHERE post_status IN('0','1','2') ORDER BY P.post_id DESC LIMIT 1"
        );
        $newPostID = $result['post_id'] ?? null;
        if ($newPostID && !$isScheduled) { $this->iN_InsertPostActivity($uid, 'newPost', $newPostID, $time); }
        return $result;
    }

    /**
     * Create a new campaign post and campaign meta record.
     *
     * @param int $uid
     * @param array $data
     * @param string $autoApprovePostStatus
     * @return array|false
     */
    public function iN_InsertNewCampaignPost(int $uid, array $data, string $autoApprovePostStatus) {
        $settings = $this->getCampaignSettings();
        if (($settings['status'] ?? '0') !== '1') {
            return ['error' => 'campaign_disabled'];
        }
        if (!$this->canUserCreateCampaignPolicy($uid, $settings)) {
            return ['error' => 'campaign_permission'];
        }
        $title = isset($data['title']) ? trim((string)$data['title']) : '';
        $summary = isset($data['summary']) ? trim((string)$data['summary']) : '';
        $goalRaw = isset($data['goal']) ? (string)$data['goal'] : '';
        $minRaw = isset($data['min_amount']) ? (string)$data['min_amount'] : '';
        $maxRaw = isset($data['max_amount']) ? (string)$data['max_amount'] : '';
        $deadlineRaw = isset($data['deadline']) ? trim((string)$data['deadline']) : '';
        $coverId = isset($data['cover_upload_id']) ? (int)$data['cover_upload_id'] : 0;
        $goalMinSetting = isset($settings['goal_min']) ? (float)$settings['goal_min'] : 50.0;
        if ($goalMinSetting < 50) { $goalMinSetting = 50.0; }
        $goalMaxSetting = isset($settings['goal_max']) ? (float)$settings['goal_max'] : 0.0;

        if ($settings['title_required'] === '1' && $title === '') { return ['error' => 'campaign_title_required']; }
        if ($settings['goal_required'] === '1' && $goalRaw === '') { return ['error' => 'campaign_goal_required']; }
        if ($settings['deadline_required'] === '1' && $deadlineRaw === '') { return ['error' => 'campaign_deadline_required']; }

        $goal = null;
        if ($goalRaw !== '') {
            $goal = filter_var($goalRaw, FILTER_VALIDATE_FLOAT);
            if ($goal === false || $goal <= 0) { return ['error' => 'campaign_goal_invalid']; }
        } else { $goal = 0; }
        if ($goal !== null && $goal > 0) {
            if ($goal < $goalMinSetting) { return ['error' => 'campaign_goal_below_min']; }
            if ($goalMaxSetting > 0 && $goal > $goalMaxSetting) { return ['error' => 'campaign_goal_above_max']; }
        }

        $minAmount = null;
        if ($minRaw !== '') {
            $minAmount = filter_var($minRaw, FILTER_VALIDATE_FLOAT);
            if ($minAmount === false || $minAmount < 0) { return ['error' => 'campaign_min_amount_invalid']; }
        }
        $maxAmount = null;
        if ($maxRaw !== '') {
            $maxAmount = filter_var($maxRaw, FILTER_VALIDATE_FLOAT);
            if ($maxAmount === false || $maxAmount < 0) { return ['error' => 'campaign_max_amount_invalid']; }
        }
        if ($goal !== null && $goal > 0 && $maxAmount !== null && $maxAmount > $goal) {
            return ['error' => 'campaign_max_exceeds_goal'];
        }
        if ($minAmount !== null && $maxAmount !== null && $maxAmount < $minAmount) {
            return ['error' => 'campaign_amount_range'];
        }
        $deadline = null;
        if ($deadlineRaw !== '') {
            if (is_numeric($deadlineRaw)) {
                $deadline = (int)$deadlineRaw;
            } else {
                $parsedDeadline = strtotime($deadlineRaw);
                if ($parsedDeadline !== false) {
                    $deadline = $parsedDeadline;
                }
            }
            if (!$deadline || $deadline <= time()) {
                return ['error' => 'campaign_deadline_invalid'];
            }
        }

        $postFile = '';
        if ($coverId > 0) {
            $checkCover = $this->iN_GetUploadedFileDetails($coverId);
            $uploadedFileID = isset($checkCover['upload_id']) ? (int)$checkCover['upload_id'] : null;
            if (!$uploadedFileID || (int)$checkCover['iuid_fk'] !== $uid) {
                return ['error' => 'campaign_cover_invalid'];
            }
            $this->iN_UpdateUploadStatus($uploadedFileID);
            $postFile = (string)$uploadedFileID;
        }

        $userIP = $_SERVER['REMOTE_ADDR'] ?? '';
        $time = time();
        $postStatus = ($autoApprovePostStatus === 'no') ? '2' : '1';
        $slugSource = $title !== '' ? $title : ($summary !== '' ? $summary : $this->random_code(8));
        $slug = $this->url_slugies(mb_substr($slugSource, 0, 55, "utf-8"));
        $hashTags = $this->url_Hash($this->iN_hashtag($summary));

        DB::begin();
        try {
            DB::exec(
                "INSERT INTO i_posts (post_owner_id,post_text,post_file,post_created_time,post_creator_ip,who_can_see,post_status,url_slug,hashtags,post_wanted_credit,post_type)
                 VALUES (?,?,?,?,?,?,?,?,?,?,?)",
                [
                    (int)$uid,
                    (string)$summary,
                    (string)$postFile,
                    $time,
                    (string)$userIP,
                    '1',
                    (string)$postStatus,
                    (string)$slug,
                    (string)$hashTags,
                    '',
                    'campaign'
                ]
            );
            $postId = (int) DB::lastId();
            DB::exec(
                "INSERT INTO i_campaigns (post_id_fk, owner_uid_fk, title, summary, goal_amount, min_amount, max_amount, deadline_at, cover_upload_id, status, created_at, updated_at)
                 VALUES (?,?,?,?,?,?,?,?,?,?,?,?)",
                [
                    $postId,
                    (int)$uid,
                    (string)$title,
                    (string)$summary,
                    number_format((float)$goal, 2, '.', ''),
                    $minAmount !== null ? number_format((float)$minAmount, 2, '.', '') : null,
                    $maxAmount !== null ? number_format((float)$maxAmount, 2, '.', '') : null,
                    $deadline,
                    $coverId > 0 ? $coverId : null,
                    $postStatus === '1' ? 'active' : 'pending',
                    $time,
                    $time
                ]
            );
            DB::commit();
        } catch (Throwable $e) {
            DB::rollBack();
            return ['error' => 'campaign_create_failed'];
        }

        $linkSelect = $this->iN_PostLinkPreviewSelect();
        $result = DB::one(
            "SELECT P.post_id,P.shared_post_id,P.post_pined,P.post_owner_id,P.post_text,P.hashtags{$linkSelect},P.post_file,P.post_created_time,P.who_can_see,P.post_want_status,P.url_slug,P.post_wanted_credit,P.post_status,P.post_type,P.comment_status,U.payout_method,U.iuid,U.i_username,U.i_user_fullname,U.user_avatar,U.user_gender,U.payout_method,U.last_login_time,U.user_verified_status,U.thanks_for_tip
             FROM i_posts P FORCE INDEX(ixForcePostOwner)
             INNER JOIN i_users U FORCE INDEX(ixForceUser) ON P.post_owner_id = U.iuid
            WHERE P.post_id = ? LIMIT 1",
            [$postId]
        );
        if ($result && $postStatus === '1') {
            $this->iN_InsertPostActivity($uid, 'newPost', $postId, $time);
        }
        if ($result) {
            $result['campaign_id'] = DB::col("SELECT campaign_id FROM i_campaigns WHERE post_id_fk = ? LIMIT 1", [$postId]);
        }
        return $result;
    }

	/**
	 * Create a new poll post together with poll options inside a single transaction.
	 * Returns ['error' => '...'] on validation/storage failures.
	 */
    public function iN_InsertNewPollPost($uid, $postText, $urlSlug, array $options, $postWhoCanSee, $hashTags, $pointAmount, $autoApprovePostStatus, $postFiles = '', ?int $scheduledAt = null, string $scheduledStatus = 'published') {
        $settings = $this->getPollSettings();
        if ($settings['status'] !== '1') {
            return ['error' => 'poll_disabled'];
        }
        $userIP = $_SERVER['REMOTE_ADDR'] ?? '';
        $time = time();
        $postStatus = '1';
        if ($postWhoCanSee == '4' && $autoApprovePostStatus == 'no') { $postStatus = '2'; }
        $allowedStatuses = ['pending', 'queued', 'published', 'failed'];
        $normalizedScheduledStatus = in_array($scheduledStatus, $allowedStatuses, true) ? $scheduledStatus : 'published';
        $isScheduled = $scheduledAt && $normalizedScheduledStatus !== 'published';
        if ($isScheduled) { $postStatus = '2'; }

        // Normalize and validate poll options
        $normalizedOptions = [];
        foreach ($options as $option) {
            $opt = trim((string)$option);
            if ($opt !== '') {
                $normalizedOptions[] = $opt;
            }
        }
        $normalizedOptions = array_values(array_unique($normalizedOptions));
        if (count($normalizedOptions) > $settings['max_options']) {
            return ['error' => 'max_options'];
        }
        if (count($normalizedOptions) < $settings['min_options']) {
            return ['error' => 'min_options'];
        }

        $postType = $this->resolvePostType('poll');
        if ($postType !== 'poll') {
            return ['error' => 'poll_schema'];
        }
        DB::begin();
        try {
            DB::exec(
                "INSERT INTO i_posts (post_owner_id,post_text,post_file,post_created_time,scheduled_at,post_creator_ip,who_can_see,post_status,scheduled_status,url_slug,hashtags,post_wanted_credit,post_type)
                 VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?)",
                [
                    (int)$uid,
                    (string)$postText,
                    (string)$postFiles,
                    $time,
                    $isScheduled ? (int)$scheduledAt : null,
                    (string)$userIP,
                    (string)$postWhoCanSee,
                    (string)$postStatus,
                    (string)$normalizedScheduledStatus,
                    (string)$urlSlug,
                    (string)$hashTags,
                    (string)$pointAmount,
                    (string)$postType
                ]
            );
            $postId = (int) DB::lastId();
            DB::exec(
                "INSERT INTO i_polls (post_id_fk, question, status, created_at, updated_at) VALUES (?,?,?,?,?)",
                [$postId, (string)$postText, 'active', $time, $time]
            );
            $pollId = (int) DB::lastId();
            $order = 1;
            foreach ($normalizedOptions as $optionText) {
                DB::exec(
                    "INSERT INTO i_poll_options (poll_id_fk, option_text, option_order, votes_count, status, created_at, updated_at)
                     VALUES (?,?,?,?,?,?,?)",
                    [$pollId, (string)$optionText, $order, 0, 'active', $time, $time]
                );
                $order++;
            }
            DB::commit();
        } catch (Throwable $e) {
            DB::rollBack();
            return ['error' => 'poll_create_failed'];
        }

        $linkSelect = $this->iN_PostLinkPreviewSelect();
        $result = DB::one(
            "SELECT P.post_id,P.shared_post_id,P.post_pined,P.post_owner_id,P.post_text,P.hashtags{$linkSelect},P.post_file,P.post_created_time,P.scheduled_at,P.who_can_see,P.post_want_status,P.url_slug,P.post_wanted_credit,P.post_status,P.scheduled_status,P.post_type,P.comment_status,U.payout_method,U.iuid,U.i_username,U.i_user_fullname,U.user_avatar,U.user_gender,U.payout_method,U.last_login_time,U.user_verified_status,U.thanks_for_tip
             FROM i_posts P FORCE INDEX(ixForcePostOwner)
             INNER JOIN i_users U FORCE INDEX(ixForceUser) ON P.post_owner_id = U.iuid
            WHERE P.post_id = ? LIMIT 1",
            [$postId]
        );
        if ($result) {
            if (!$isScheduled) {
                $this->iN_InsertPostActivity($uid, 'newPost', $postId, $time);
            }
            if (!empty($postFiles)) {
                $this->iN_UpdateUploadStatus($postFiles);
            }
            $result['poll_id'] = $pollId;
        }
        return $result;
    }

    /**
     * Create or refresh a scheduled queue entry for a post.
     */
    public function iN_SaveScheduledQueue(int $postId, int $runAt): bool {
        if (!$this->scheduledSchemaReady() || $postId <= 0 || $runAt <= 0) {
            return false;
        }
        $now = time();
        DB::exec("DELETE FROM i_scheduled_queue WHERE post_id_fk = ?", [$postId]);
        DB::exec(
            "INSERT INTO i_scheduled_queue (post_id_fk, run_at, status, attempts, created_at, updated_at)
             VALUES (?,?,?,?,?,?)",
            [$postId, $runAt, 'pending', 0, $now, $now]
        );
        DB::exec(
            "UPDATE i_posts SET scheduled_at = ?, scheduled_status = 'pending', post_status = '2' WHERE post_id = ?",
            [$runAt, $postId]
        );
        return true;
    }

    /**
     * Remove scheduled queue rows and optionally reset post schedule fields.
     */
    public function iN_ClearScheduledQueue(int $postId, bool $resetPost = false): void {
        if (!$this->scheduledSchemaReady() || $postId <= 0) {
            return;
        }
        DB::exec("DELETE FROM i_scheduled_queue WHERE post_id_fk = ?", [$postId]);
        if ($resetPost) {
            DB::exec(
                "UPDATE i_posts SET scheduled_at = NULL, scheduled_status = 'published' WHERE post_id = ?",
                [$postId]
            );
        }
    }

    /**
     * Publish a scheduled post immediately and mark its queue item as done.
     */
    public function iN_PublishScheduledPost(int $postId, ?int $activityTime = null): bool {
        if (!$this->scheduledSchemaReady() || $postId <= 0) {
            return false;
        }
        $post = DB::one("SELECT post_owner_id FROM i_posts WHERE post_id = ? LIMIT 1", [$postId]);
        if (!$post || !isset($post['post_owner_id'])) {
            return false;
        }
        $time = $activityTime ?? time();
        DB::exec(
            "UPDATE i_posts SET post_status = '1', scheduled_status = 'published' WHERE post_id = ?",
            [$postId]
        );
        DB::exec(
            "UPDATE i_scheduled_queue SET status = 'done', updated_at = ?, last_error = NULL WHERE post_id_fk = ?",
            [$time, $postId]
        );
        $this->iN_InsertPostActivity((int)$post['post_owner_id'], 'newPost', $postId, $time);
        return true;
    }

    /**
     * Mark a scheduled post as failed together with its queue row.
     */
    public function iN_FailScheduledPost(int $postId, string $error, ?int $queueId = null): void {
        if (!$this->scheduledSchemaReady() || $postId <= 0) {
            return;
        }
        $time = time();
        DB::exec(
            "UPDATE i_posts SET scheduled_status = 'failed' WHERE post_id = ?",
            [$postId]
        );
        $params = [(string)$error, $time];
        $where = "post_id_fk = ?";
        if (!empty($queueId)) {
            $where = "id = ?";
            $params[] = (int)$queueId;
        } else {
            $params[] = $postId;
        }
        DB::exec(
            "UPDATE i_scheduled_queue SET status = 'failed', attempts = attempts + 1, last_error = ?, updated_at = ? WHERE $where",
            $params
        );
    }

    /**
     * Fetch due scheduled queue items ready to be published.
     */
    public function iN_GetDueScheduledQueue(int $limit = 10): array {
        if (!$this->scheduledSchemaReady()) {
            return [];
        }
        $limit = (int)$limit;
        if ($limit < 1) { $limit = 10; }
        $now = time();
        $sql = "SELECT Q.*, P.post_owner_id, P.scheduled_status, P.post_status
                FROM i_scheduled_queue Q
                INNER JOIN i_posts P ON Q.post_id_fk = P.post_id
                WHERE Q.status = 'pending' AND Q.run_at <= ? AND P.scheduled_status IN('pending','queued')
                ORDER BY Q.run_at ASC
                LIMIT $limit";
        $rows = DB::all($sql, [$now]);
        return !empty($rows) ? $rows : [];
    }

    /**
     * Cancel scheduled publication while keeping the post for review.
     */
    public function iN_CancelScheduledPost(int $postId): bool {
        if (!$this->scheduledSchemaReady() || $postId <= 0) {
            return false;
        }
        DB::exec("DELETE FROM i_scheduled_queue WHERE post_id_fk = ?", [$postId]);
        DB::exec(
            "UPDATE i_posts SET scheduled_status = 'failed', scheduled_at = NULL, post_status = '2' WHERE post_id = ?",
            [$postId]
        );
        return true;
    }

    /**
     * List scheduled posts for admin panel.
     *
     * @return array<int, array<string, mixed>>
     */
    public function iN_ListScheduledPosts(array $statuses, int $limit, int $page): array {
        if (!$this->scheduledSchemaReady()) {
            return [];
        }
        $allowed = ['pending','processing','done','failed'];
        $filtered = array_values(array_intersect($statuses, $allowed));
        if (empty($filtered)) {
            $filtered = ['pending','failed'];
        }
        $limit = (int)$limit;
        $page = (int)$page;
        if ($limit < 1) { $limit = 15; }
        if ($page < 1) { $page = 1; }
        $offset = ($page - 1) * $limit;
        $placeholders = implode(',', array_fill(0, count($filtered), '?'));
        $sql = "SELECT Q.*, P.post_owner_id, P.post_text, P.post_status, P.scheduled_status, P.scheduled_at, P.post_created_time, P.who_can_see, P.post_type,
                       U.iuid, U.i_username, U.i_user_fullname, U.user_avatar
                FROM i_scheduled_queue Q
                INNER JOIN i_posts P ON Q.post_id_fk = P.post_id
                INNER JOIN i_users U ON P.post_owner_id = U.iuid
                WHERE Q.status IN ($placeholders)
                ORDER BY Q.run_at ASC
                LIMIT $limit OFFSET $offset";
        $rows = DB::all($sql, $filtered);
        return !empty($rows) ? $rows : [];
    }

    /**
     * Count scheduled posts for pagination.
     */
    public function iN_CountScheduledPosts(array $statuses): int {
        if (!$this->scheduledSchemaReady()) {
            return 0;
        }
        $allowed = ['pending','processing','done','failed'];
        $filtered = array_values(array_intersect($statuses, $allowed));
        if (empty($filtered)) {
            $filtered = ['pending','failed'];
        }
        $placeholders = implode(',', array_fill(0, count($filtered), '?'));
        $val = DB::col(
            "SELECT COUNT(*) FROM i_scheduled_queue WHERE status IN ($placeholders)",
            $filtered
        );
        return $val ? (int)$val : 0;
    }
	/*Get All Friens and My Posts*/
    public function iN_AllFriendsPosts($uid, $lastPostID, $showingPost) {
        $showingPosts = (int)($showingPost ?? 0);
        $params = [(int)$uid];
        $more = '';
        if (!empty($lastPostID)) { $more = ' AND P.post_id < ? '; $params[] = (int)$lastPostID; }
        [$scheduledSql, $scheduledParams] = $this->scheduledVisibilityClause($uid, 'P');
        $linkSelect = $this->iN_PostLinkPreviewSelect();
        $sql = "SELECT DISTINCT P.post_id,P.shared_post_id,P.post_pined,P.comment_status,
                P.post_owner_id,P.post_text,P.post_file,P.post_created_time,P.scheduled_at,P.scheduled_status,
                P.who_can_see,P.post_want_status,P.url_slug,P.post_wanted_credit,
                P.post_status,P.post_type,P.hashtags{$linkSelect},
                U.iuid,U.i_username,U.i_user_fullname,U.user_avatar,U.user_gender,
                U.payout_method,U.last_login_time,U.user_verified_status,
                U.thanks_for_tip,U.user_frame,U.profile_category
            FROM i_friends F
            INNER JOIN i_posts P ON P.post_owner_id = F.fr_two AND P.post_type NOT IN('reels')
            INNER JOIN i_users U ON P.post_owner_id = U.iuid AND U.uStatus IN('1','3') AND F.fr_status IN('me','flwr','subscriber')
            WHERE F.fr_one = ? $more AND $scheduledSql
            ORDER BY P.post_id DESC
            LIMIT $showingPosts";
        $rows = DB::all($sql, array_merge($params, $scheduledParams));
        return !empty($rows) ? $rows : null;
    }
    public function iN_AllFriendsPostsOut($lastPostID, $showingPost) {
        $showingPosts = (int)$showingPost;
        $where = '';
        $params = [];
        if (!empty($lastPostID)) { $where = 'WHERE P.post_id < ?'; $params[] = (int)$lastPostID; }
        [$scheduledSql, $scheduledParams] = $this->scheduledVisibilityClause(null, 'P');
        $filter = $where ? $where . ' AND ' . $scheduledSql : 'WHERE ' . $scheduledSql;
        $linkSelect = $this->iN_PostLinkPreviewSelect();
        $sql = "SELECT DISTINCT
                P.post_id, P.post_type, P.shared_post_id, P.post_pined, P.comment_status,
                P.post_owner_id, P.post_text, P.hashtags, P.post_file, P.post_created_time, P.scheduled_at, P.scheduled_status,
                P.who_can_see, P.post_want_status, P.url_slug, P.post_wanted_credit, P.post_status{$linkSelect},
                U.iuid, U.i_username, U.i_user_fullname, U.user_avatar, U.user_gender,
                U.payout_method, U.last_login_time, U.user_verified_status, U.thanks_for_tip
            FROM i_friends F FORCE INDEX(ixFriend)
            INNER JOIN i_posts P FORCE INDEX (ixForcePostOwner)
                ON P.post_owner_id = F.fr_two AND P.post_type NOT IN('reels')
            INNER JOIN i_users U FORCE INDEX (ixForceUser)
                ON P.post_owner_id = U.iuid AND U.uStatus IN('1','3') AND F.fr_status IN('me', 'flwr', 'subscriber')
            $filter
            ORDER BY P.post_id DESC
            LIMIT $showingPosts";
        $rows = DB::all($sql, array_merge($params, $scheduledParams));
        return !empty($rows) ? $rows : null;
    }

    public function iN_GetPostComments($postID, $second) {
        $limit = '';
        if (!empty($second) && is_numeric($second)) {
            $offset = (int)$second;
            $limit = " LIMIT $offset,2";
        }
        $commentLinkSelect = $this->iN_CommentLinkPreviewSelect();
        $sql = "SELECT C.com_id,C.comment_uid_fk,C.comment_post_id_fk,C.comment,C.comment_time,C.comment_file,C.sticker_url,C.gif_url,C.parent_comment_id{$commentLinkSelect},
                       U.iuid,U.i_username,U.i_user_fullname,U.user_avatar,U.user_gender,U.last_login_time,U.user_verified_status,U.user_frame
                FROM i_post_comments C FORCE INDEX(ixComment)
                INNER JOIN i_users U FORCE INDEX(ixForceUser)
                  ON C.comment_uid_fk = U.iuid AND U.uStatus IN('1','3')
                WHERE C.comment_post_id_fk = ?
                  AND IFNULL(C.is_hidden, '0') = '0'
                  AND (C.parent_comment_id IS NULL OR C.parent_comment_id = 0)
                ORDER BY C.com_id ASC" . $limit;
        $rows = DB::all($sql, [(int)$postID]);
        return !empty($rows) ? $rows : null;
    }

    public function iN_GetCommentReplies($commentID) {
        $commentLinkSelect = $this->iN_CommentLinkPreviewSelect();
        $sql = "SELECT C.com_id,C.comment_uid_fk,C.comment_post_id_fk,C.comment,C.comment_time,C.comment_file,C.sticker_url,C.gif_url,C.parent_comment_id{$commentLinkSelect},
                       U.iuid,U.i_username,U.i_user_fullname,U.user_avatar,U.user_gender,U.last_login_time,U.user_verified_status,U.user_frame,
                       PU.iuid AS parent_iuid, PU.i_username AS parent_username, PU.i_user_fullname AS parent_fullname
                FROM i_post_comments C
                INNER JOIN i_users U FORCE INDEX(ixForceUser)
                  ON C.comment_uid_fk = U.iuid AND U.uStatus IN('1','3')
                LEFT JOIN i_post_comments P ON C.parent_comment_id = P.com_id
                LEFT JOIN i_users PU ON P.comment_uid_fk = PU.iuid
                WHERE C.parent_comment_id = ? AND IFNULL(C.is_hidden, '0') = '0'
                ORDER BY C.com_id ASC";
        $rows = DB::all($sql, [(int)$commentID]);
        return !empty($rows) ? $rows : null;
    }
