    private function iN_NormalizePositiveIntList(array $ids) {
        $normalized = [];
        foreach ($ids as $id) {
            $intID = (int)$id;
            if ($intID > 0) {
                $normalized[$intID] = $intID;
            }
        }
        return array_values($normalized);
    }

    public function iN_GetRelationsMapForUser($userOne, array $userTargets) {
        $ownerID = (int)$userOne;
        if ($ownerID < 1) {
            return [];
        }
        $targetIDs = $this->iN_NormalizePositiveIntList($userTargets);
        if (empty($targetIDs)) {
            return [];
        }
        $placeholders = implode(',', array_fill(0, count($targetIDs), '?'));
        $params = array_merge([$ownerID], $targetIDs);
        $rows = DB::all("SELECT fr_two, fr_status FROM i_friends WHERE fr_one = ? AND fr_two IN ($placeholders)", $params);
        $map = [];
        if (!empty($rows)) {
            foreach ($rows as $row) {
                $targetID = isset($row['fr_two']) ? (int)$row['fr_two'] : 0;
                if ($targetID < 1) {
                    continue;
                }
                $map[$targetID] = isset($row['fr_status']) ? $row['fr_status'] : null;
            }
        }
        return $map;
    }

