	public function iN_CheckCommentLikedBefore($userID, $postID, $commentID) {
		return (bool) DB::col("SELECT 1 FROM i_post_comment_likes WHERE c_like_post_id = ? AND c_like_iuid_fk = ? AND c_like_comment_id = ? LIMIT 1", [(int)$postID, (int)$userID, (int)$commentID]);
	}

	public function iN_LikePost($userID, $postID) {
		$time = time();
		$userIP = $_SERVER['REMOTE_ADDR'] ?? '';
		if ($this->iN_CheckUserExist($userID) == 1 && $this->iN_CheckPostIDExist($postID) == 1) {
			if ($this->iN_CheckPostLikedBefore($userID, $postID) == 1) {
				DB::exec("DELETE FROM i_post_likes WHERE post_id_fk = ? AND iuid_fk = ?", [(int)$postID, (int)$userID]);
				$this->iN_DeletePostLikeActivity($userID, $postID);
				return false;
			} else {
				$this->iN_InsertPostLikeActivity($userID, 'postLike',$postID, $time);
				DB::exec("INSERT INTO i_post_likes (post_id_fk,iuid_fk,like_time,user_ip) VALUES (?,?,?,?)", [(int)$postID,(int)$userID,$time,(string)$userIP]);
				return true;
			}
		}
	}

	public function iN_GetAllPostDetails($postID) {
        if (!isset($postID) || !is_numeric($postID)) {
            return false;
        }

        if ($this->iN_CheckPostIDExist($postID) == '1') {
            $linkSelect = $this->iN_PostLinkPreviewSelect();
            $sql = "SELECT DISTINCT
                    P.post_id, P.shared_post_id, P.post_pined, P.url_slug, P.comment_status, P.hashtags,
                    P.post_owner_id, P.post_text, P.post_file, P.post_created_time, P.scheduled_at, P.scheduled_status, P.who_can_see,
                    P.post_want_status, P.post_wanted_credit, P.post_status, P.post_type{$linkSelect},
                    U.iuid, U.i_username, U.i_user_fullname, U.user_avatar, U.user_gender,
                    U.payout_method, U.thanks_for_tip, U.last_login_time, U.user_verified_status,
                    U.profile_status, U.uStatus, U.user_frame
                FROM i_friends F FORCE INDEX(ixFriend)
                INNER JOIN i_posts P FORCE INDEX (ixForcePostOwner) ON P.post_owner_id = F.fr_two
                INNER JOIN i_users U FORCE INDEX (ixForceUser) ON P.post_owner_id = U.iuid AND U.uStatus IN('1','3') AND F.fr_status IN('me','flwr','subscriber')
                WHERE P.post_id = ? ORDER BY P.post_id";
            return DB::one($sql, [(int)$postID]);
        } else {
            return false;
        }
    }

    /**
     * Check if the current user can view a poll belonging to the given post.
     */
    private function canUserViewPoll(int $postId, ?int $currentUserId = null, ?array $postRow = null): bool {
        $post = $postRow ?: DB::one(
            "SELECT post_owner_id, who_can_see, post_status FROM i_posts WHERE post_id = ? LIMIT 1",
            [$postId]
        );
        if (!$post) {
            return false;
        }

        $ownerId = isset($post['post_owner_id']) ? (int) $post['post_owner_id'] : 0;
        $whoCanSee = isset($post['who_can_see']) ? (string) $post['who_can_see'] : '1';
        $postStatus = isset($post['post_status']) ? (string) $post['post_status'] : '0';

        global $userType;
        $isAdmin = isset($userType) && (string) $userType === '2';
        if ($isAdmin) {
            return true;
        }

        if ($ownerId > 0 && $currentUserId && $ownerId === (int) $currentUserId) {
            return true;
        }
        if (!in_array($postStatus, ['0', '1'], true)) {
            return false;
        }

        $relationship = null;
        if ($currentUserId) {
            $relationship = $this->iN_GetRelationsipBetweenTwoUsers($currentUserId, $ownerId);
        }

        switch ($whoCanSee) {
            case '1':
                return true;
            case '2':
                return in_array($relationship, ['me', 'flwr', 'subscriber'], true);
            case '3':
                return in_array($relationship, ['me', 'subscriber'], true);
            case '4':
                if (in_array($relationship, ['me', 'subscriber'], true)) {
                    return true;
                }
                if (!$currentUserId) {
                    return false;
                }
                return $this->iN_CheckUserPurchasedThisPost($currentUserId, $postId);
            default:
                return false;
        }
    }

    /**
     * Internal helper to assemble poll detail payload (options, totals, user vote).
     */
    private function buildPollDetails(int $pollId, ?int $currentUserId = null): ?array {
        if ($pollId <= 0) { return null; }
        $poll = DB::one("SELECT poll_id, post_id_fk, status FROM i_polls WHERE poll_id = ? LIMIT 1", [$pollId]);
        if (!$poll) { return null; }

        $postRow = DB::one(
            "SELECT post_owner_id, who_can_see, post_status FROM i_posts WHERE post_id = ? LIMIT 1",
            [(int) $poll['post_id_fk']]
        );
        if (!$postRow || !$this->canUserViewPoll((int) $poll['post_id_fk'], $currentUserId, $postRow)) {
            return null;
        }

        $options = DB::all(
            "SELECT option_id, option_text, votes_count, status, option_order
             FROM i_poll_options WHERE poll_id_fk = ? ORDER BY option_order ASC, option_id ASC",
            [$pollId]
        );
        if (empty($options)) {
            return [
                'poll_id' => (int)$pollId,
                'post_id' => (int)$poll['post_id_fk'],
                'status' => $poll['status'] ?? 'active',
                'total_votes' => 0,
                'options' => [],
                'user_vote' => null,
                'enabled' => $this->getPollSettings()['status'] === '1',
                'has_removed_options' => false,
            ];
        }

        $recentVotes = DB::all(
            "SELECT option_id_fk, voter_uid_fk FROM i_poll_votes WHERE poll_id_fk = ? ORDER BY vote_time DESC LIMIT 60",
            [$pollId]
        );
        $recentMap = [];
        $avatarCache = [];
        global $base_url;
        if ($recentVotes) {
            foreach ($recentVotes as $recent) {
                $optId = isset($recent['option_id_fk']) ? (int)$recent['option_id_fk'] : 0;
                $uid = isset($recent['voter_uid_fk']) ? (int)$recent['voter_uid_fk'] : 0;
                if ($optId <= 0 || $uid <= 0) {
                    continue;
                }
                if (!isset($recentMap[$optId])) {
                    $recentMap[$optId] = [];
                }
                if (count($recentMap[$optId]) >= 3) {
                    continue;
                }
                if (!isset($avatarCache[$uid])) {
                    $avatarCache[$uid] = $this->iN_UserAvatar($uid, $base_url);
                }
                $recentMap[$optId][] = [
                    'user_id' => $uid,
                    'avatar' => $avatarCache[$uid],
                ];
            }
        }

        $totalVotes = 0;
        $cleanOptions = [];
        $hasRemovedOptions = false;
        foreach ($options as $option) {
            if (($option['status'] ?? '') !== 'active') {
                $hasRemovedOptions = true;
                continue;
            }
            $votes = (int)($option['votes_count'] ?? 0);
            $totalVotes += $votes;
            $recentVoters = $recentMap[$option['option_id']] ?? [];
            $cleanOptions[] = [
                'option_id' => (int)$option['option_id'],
                'option_text' => $option['option_text'],
                'votes' => $votes,
                'votes_label' => $this->formatCompactNumber($votes),
                'recent_voters' => $recentVoters,
            ];
        }

        $userVote = null;
        if ($currentUserId && $this->iN_CheckUserExist($currentUserId) == 1) {
            $voteRow = DB::one(
                "SELECT option_id_fk FROM i_poll_votes WHERE poll_id_fk = ? AND voter_uid_fk = ? LIMIT 1",
                [$pollId, (int)$currentUserId]
            );
            if (!empty($voteRow['option_id_fk'])) {
                $userVote = (int)$voteRow['option_id_fk'];
            }
        }

        foreach ($cleanOptions as $key => $option) {
            $percentage = $totalVotes > 0 ? round(($option['votes'] / $totalVotes) * 100, 1) : 0;
            $cleanOptions[$key]['percentage'] = $percentage;
            $cleanOptions[$key]['voted'] = ($userVote !== null && $userVote === (int)$option['option_id']);
        }

        return [
            'poll_id' => (int)$pollId,
            'post_id' => (int)$poll['post_id_fk'],
            'status' => $poll['status'] ?? 'active',
            'total_votes' => $totalVotes,
            'options' => $cleanOptions,
            'user_vote' => $userVote,
            'enabled' => $this->getPollSettings()['status'] === '1',
            'has_removed_options' => $hasRemovedOptions,
        ];
    }

    public function iN_GetPollDetailsByPostId($postId, $currentUserId = null) {
        $poll = DB::one("SELECT poll_id FROM i_polls WHERE post_id_fk = ? LIMIT 1", [(int)$postId]);
        if (!$poll || !isset($poll['poll_id'])) { return null; }
        return $this->buildPollDetails((int)$poll['poll_id'], $currentUserId);
    }

    /**
     * Public wrapper to check if a user can view a poll for a given post.
     */
    public function iN_CanViewPollForPost(int $postId, ?int $currentUserId = null): bool {
        return $this->canUserViewPoll($postId, $currentUserId);
    }

    public function iN_GetPollDetailsByPollId($pollId, $currentUserId = null) {
        return $this->buildPollDetails((int)$pollId, $currentUserId);
    }

    /**
     * Persist a vote for a poll option. Returns poll data or ['error' => code].
     */
    public function iN_SubmitPollVote($pollId, $optionId, $userId) {
        $settings = $this->getPollSettings();
        if ($settings['status'] !== '1') { return ['error' => 'poll_disabled']; }
        if ($this->iN_CheckUserExist($userId) != 1) { return ['error' => 'user_not_found']; }
        $user = $this->iN_GetUserDetails($userId);
        if (!isset($user['uStatus']) || !in_array((string)$user['uStatus'], ['1', '3'], true)) {
            return ['error' => 'restricted_user'];
        }

        $poll = DB::one("SELECT poll_id, post_id_fk, status FROM i_polls WHERE poll_id = ? LIMIT 1", [(int)$pollId]);
        if (!$poll || ($poll['status'] ?? '') !== 'active') { return ['error' => 'poll_closed']; }

        $pollPost = DB::one(
            "SELECT post_owner_id, who_can_see, post_status FROM i_posts WHERE post_id = ? LIMIT 1",
            [(int) ($poll['post_id_fk'] ?? 0)]
        );
        if (!$pollPost || !$this->canUserViewPoll((int) ($poll['post_id_fk'] ?? 0), $userId, $pollPost)) {
            return ['error' => 'poll_locked'];
        }

        $option = DB::one(
            "SELECT option_id,poll_id_fk,status FROM i_poll_options WHERE option_id = ? AND poll_id_fk = ? LIMIT 1",
            [(int)$optionId, (int)$pollId]
        );
        if (!$option || ($option['status'] ?? '') !== 'active') {
            return ['error' => 'option_missing'];
        }

        $already = DB::one(
            "SELECT option_id_fk FROM i_poll_votes WHERE poll_id_fk = ? AND voter_uid_fk = ? LIMIT 1",
            [(int)$pollId, (int)$userId]
        );
        if ($already && isset($already['option_id_fk'])) {
            return ['error' => 'already_voted', 'option_id' => (int)$already['option_id_fk']];
        }

        DB::begin();
        try {
            DB::exec(
                "INSERT INTO i_poll_votes (poll_id_fk, option_id_fk, voter_uid_fk, voter_ip, vote_time)
                 VALUES (?,?,?,?,?)",
                [(int)$pollId, (int)$optionId, (int)$userId, (string)($_SERVER['REMOTE_ADDR'] ?? ''), time()]
            );
            DB::exec("UPDATE i_poll_options SET votes_count = votes_count + 1 WHERE option_id = ?", [(int)$optionId]);
            DB::commit();
        } catch (Throwable $e) {
            DB::rollBack();
            return ['error' => 'vote_failed'];
        }
        return $this->iN_GetPollDetailsByPollId((int)$pollId, $userId);
    }

    /**
     * Ensure the share token table exists (safe to call multiple times).
     */
	private function ensureShareTokenTable() {
		if (self::$shareTableReady) { return; }
		try {
			$exists = DB::col("SELECT 1 FROM information_schema.TABLES WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'i_share_tokens' LIMIT 1");
			if (!$exists) {
                DB::exec("CREATE TABLE IF NOT EXISTS i_share_tokens (
                    token_id INT UNSIGNED NOT NULL AUTO_INCREMENT,
                    token VARCHAR(64) NOT NULL UNIQUE,
                    post_id INT UNSIGNED NOT NULL,
                    created_by INT UNSIGNED DEFAULT NULL,
                    created_at INT UNSIGNED NOT NULL,
                    expires_at INT UNSIGNED NOT NULL,
                    PRIMARY KEY (token_id),
                    INDEX idx_post_exp (post_id, expires_at)
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");
            } else {
                $col = DB::one("SHOW COLUMNS FROM i_share_tokens LIKE 'expires_at'");
                if (!$col) {
                    DB::exec("ALTER TABLE i_share_tokens ADD expires_at INT UNSIGNED NOT NULL AFTER created_at");
                }
                $createdBy = DB::one("SHOW COLUMNS FROM i_share_tokens LIKE 'created_by'");
                if (!$createdBy) {
                    DB::exec("ALTER TABLE i_share_tokens ADD created_by INT UNSIGNED DEFAULT NULL AFTER post_id");
                }
                $postIdx = DB::one("SHOW INDEX FROM i_share_tokens WHERE Key_name = 'idx_post_exp'");
                if (!$postIdx) {
                    DB::exec("CREATE INDEX idx_post_exp ON i_share_tokens (post_id, expires_at)");
                }
            }
        } catch (Throwable $e) {
            // Fail silently; the caller will gracefully fall back.
		}
		self::$shareTableReady = true;
	}

    /**
     * Remove PHP tags and trim ad code snippets.
     *
     * @param string $code
     * @return string
     */
    private function sanitizeAdSnippet(string $code): string {
        $code = str_replace(["<?php", "<?", "?>"], '', $code);
        $code = trim($code);
        if (strlen($code) > 20000) {
            $code = substr($code, 0, 20000);
        }
        return $code;
    }

    /**
     * Build a simple Adsense snippet for migration purposes.
     *
     * @param string $clientId
     * @param string $slotId
     * @param string $size
     * @return string
     */
    private function buildAdsenseSnippet(string $clientId, string $slotId, string $size = 'responsive'): string {
        if ($clientId === '' || $slotId === '') {
            return '';
        }
        $style = $this->adsenseStyleFromSize($size);
        $attrs = 'data-ad-client="' . htmlspecialchars($clientId, ENT_QUOTES, 'UTF-8') . '" data-ad-slot="' . htmlspecialchars($slotId, ENT_QUOTES, 'UTF-8') . '"';
        if ($size === 'responsive') {
            $attrs .= ' data-ad-format="auto" data-full-width-responsive="true"';
        }
        return '<ins class="adsbygoogle" style="' . htmlspecialchars($style, ENT_QUOTES, 'UTF-8') . '" ' . $attrs . '></ins><script>(adsbygoogle=window.adsbygoogle||[]).push({});</script>';
    }

    /**
     * Translate size presets into inline style.
     *
     * @param string $size
     * @return string
     */
    private function adsenseStyleFromSize(string $size): string {
        $size = $size ?: 'responsive';
        if ($size === 'responsive') {
            return 'display:block;text-align:center;';
        }
        if (preg_match('/^(\\d{2,4})x(\\d{2,4})$/', $size, $m)) {
            $w = (int) $m[1];
            $h = (int) $m[2];
            return 'display:block;width:' . $w . 'px;height:' . $h . 'px;margin:0 auto;';
        }
        return 'display:block;text-align:center;';
    }

    /**
     * Ensure Ads tables exist (placements and codes).
     */
    private function ensureAdsTables(): void {
        if (self::$adsTablesReady) { return; }
        try {
            DB::exec("CREATE TABLE IF NOT EXISTS i_ads_placements (
                placement_id INT UNSIGNED NOT NULL AUTO_INCREMENT,
                placement_key VARCHAR(100) NOT NULL UNIQUE,
                placement_title VARCHAR(150) NOT NULL,
                placement_desc TEXT NULL,
                placement_status TINYINT(1) NOT NULL DEFAULT 1,
                inline_frequency INT UNSIGNED NOT NULL DEFAULT 0,
                inline_offset INT UNSIGNED NOT NULL DEFAULT 0,
                created_at INT UNSIGNED NOT NULL,
                updated_at INT UNSIGNED NOT NULL,
                PRIMARY KEY (placement_id),
                INDEX idx_status (placement_status)
            ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

            DB::exec("CREATE TABLE IF NOT EXISTS i_ads_codes (
                code_id INT UNSIGNED NOT NULL AUTO_INCREMENT,
                placement_id INT UNSIGNED NOT NULL,
                provider_name VARCHAR(120) NOT NULL,
                code_snippet MEDIUMTEXT NOT NULL,
                status TINYINT(1) NOT NULL DEFAULT 1,
                is_default TINYINT(1) NOT NULL DEFAULT 0,
                created_at INT UNSIGNED NOT NULL,
                updated_at INT UNSIGNED NOT NULL,
                PRIMARY KEY (code_id),
                INDEX idx_placement_default (placement_id, is_default),
                INDEX idx_placement_status (placement_id, status),
                CONSTRAINT fk_ads_codes_placement FOREIGN KEY (placement_id) REFERENCES i_ads_placements(placement_id) ON DELETE CASCADE
            ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");
            self::$adsTablesReady = true;
        } catch (Throwable $e) {
            self::$adsTablesReady = false;
        }
    }

    /**
     * Migrate existing Adsense config into the new ads tables (one-time, if empty).
     */
    private function migrateLegacyAdsenseToAds(): void {
        global $adsenseStatus, $adsenseClientId, $adsenseSlotTop, $adsenseSlotInline, $adsenseSlotFooter, $adsenseSlotSidebar, $adsenseInlineFrequency, $adsenseInlineOffset, $adsenseTopSize, $adsenseInlineSize, $adsenseFooterSize, $adsenseSidebarSize;
        $this->ensureAdsTables();
        if (!self::$adsTablesReady) {
            return;
        }
        try {
            $existing = (int) DB::col("SELECT COUNT(*) FROM i_ads_placements");
            if ($existing > 0) {
                return;
            }
        } catch (Throwable $e) {
            return;
        }

        if (!isset($adsenseStatus) || (string)$adsenseStatus !== '1' || empty($adsenseClientId)) {
            return;
        }

        $now = time();
        $placements = [];
        $codes = [];

        $placements[] = [
            'key' => 'header_top',
            'title' => 'Header / Top',
            'desc' => 'Legacy Adsense top placement',
            'status' => !empty($adsenseSlotTop) ? 1 : 0,
            'freq' => 0,
            'offset' => 0,
            'size' => $adsenseTopSize ?? 'responsive',
            'slot' => $adsenseSlotTop ?? ''
        ];
        $placements[] = [
            'key' => 'inline_feed',
            'title' => 'Inline (feed)',
            'desc' => 'Legacy Adsense inline placement',
            'status' => !empty($adsenseSlotInline) ? 1 : 0,
            'freq' => isset($adsenseInlineFrequency) ? (int)$adsenseInlineFrequency : 0,
            'offset' => isset($adsenseInlineOffset) ? (int)$adsenseInlineOffset : 0,
            'size' => $adsenseInlineSize ?? 'responsive',
            'slot' => $adsenseSlotInline ?? ''
        ];
        $placements[] = [
            'key' => 'footer',
            'title' => 'Footer',
            'desc' => 'Legacy Adsense footer placement',
            'status' => !empty($adsenseSlotFooter) ? 1 : 0,
            'freq' => 0,
            'offset' => 0,
            'size' => $adsenseFooterSize ?? 'responsive',
            'slot' => $adsenseSlotFooter ?? ''
        ];
        $placements[] = [
            'key' => 'sidebar',
            'title' => 'Sidebar',
            'desc' => 'Legacy Adsense sidebar placement',
            'status' => !empty($adsenseSlotSidebar) ? 1 : 0,
            'freq' => 0,
            'offset' => 0,
            'size' => $adsenseSidebarSize ?? 'responsive',
            'slot' => $adsenseSlotSidebar ?? ''
        ];

        foreach ($placements as $placement) {
            try {
                DB::exec(
                    "INSERT INTO i_ads_placements (placement_key, placement_title, placement_desc, placement_status, inline_frequency, inline_offset, created_at, updated_at)
                     VALUES (?, ?, ?, ?, ?, ?, ?, ?)",
                    [
                        (string)$placement['key'],
                        (string)$placement['title'],
                        (string)$placement['desc'],
                        (int)$placement['status'],
                        (int)$placement['freq'],
                        (int)$placement['offset'],
                        $now,
                        $now
                    ]
                );
                $placementId = DB::lastInsertId();
                if (!empty($placement['slot'])) {
                    $snippet = $this->buildAdsenseSnippet((string)$adsenseClientId, (string)$placement['slot'], (string)$placement['size']);
                    if ($snippet !== '') {
                        DB::exec(
                            "INSERT INTO i_ads_codes (placement_id, provider_name, code_snippet, status, is_default, created_at, updated_at)
                             VALUES (?, ?, ?, 1, 1, ?, ?)",
                            [
                                (int)$placementId,
                                'Google AdSense',
                                $snippet,
                                $now,
                                $now
                            ]
                        );
                    }
                }
            } catch (Throwable $e) {
                // continue with next placement
            }
        }
    }

    /**
     * Create (or reuse) a share token for a post. Returns token string on success.
     */
    public function iN_CreateShareTokenForPost($postID, $userID = null, $ttlSeconds = 604800) {
        $postID = (int)$postID;
        if (!$postID || $this->iN_CheckPostIDExist($postID) != '1') {
            return null;
        }

        $this->ensureShareTokenTable();
        $now = time();
        $expires = $now + (int)$ttlSeconds;

        try {
            if (function_exists('random_int') && random_int(1, 50) === 25) {
                DB::exec("DELETE FROM i_share_tokens WHERE expires_at < ?", [$now]);
            }
            $existing = DB::one("SELECT token FROM i_share_tokens WHERE post_id = ? AND expires_at > ? ORDER BY created_at DESC LIMIT 1", [$postID, $now]);
            if (!empty($existing['token'])) {
                return $existing['token'];
            }

            $token = bin2hex(random_bytes(16));
            DB::exec(
                "INSERT INTO i_share_tokens (token, post_id, created_by, created_at, expires_at) VALUES (?, ?, ?, ?, ?)",
                [(string)$token, $postID, $userID ? (int)$userID : null, $now, $expires]
            );
            return $token;
        } catch (Throwable $e) {
            return null;
        }
    }

    /**
     * Resolve a share token to its post (and validate expiry).
     */
    public function iN_GetPostIdFromShareToken($token) {
        if (!$token) { return null; }
        $this->ensureShareTokenTable();
        try {
            $row = DB::one("SELECT post_id, expires_at FROM i_share_tokens WHERE token = ? LIMIT 1", [(string)$token]);
            if (!$row) { return null; }
            if (!empty($row['expires_at']) && (int)$row['expires_at'] < time()) {
                return null;
            }
            return (int)$row['post_id'];
        } catch (Throwable $e) {
            return null;
        }
    }

    /**
     * Build a full share URL for a post (falls back to null if token creation fails).
     */
    public function iN_GetShareUrlForPost($postID, $baseUrl, $userID = null, $ttlSeconds = 604800) {
        $token = $this->iN_CreateShareTokenForPost($postID, $userID, $ttlSeconds);
        if ($token) {
            return rtrim($baseUrl, '/') . '/share/' . $token;
        }
        return null;
    }

    /**
     * Fetch minimal post/user data for share previews without relationship gating.
     */
    public function iN_GetPostForSharePreview($postID) {
        $postID = (int)$postID;
        if (!$postID) { return null; }

        $linkSelect = $this->iN_PostLinkPreviewSelect();
        $sql = "SELECT P.post_id, P.url_slug, P.post_text, P.post_file, P.who_can_see, P.post_want_status,
                       P.post_wanted_credit, P.post_status, P.post_type, P.post_owner_id{$linkSelect},
                       U.i_username, U.i_user_fullname, U.user_avatar, U.user_gender, U.profile_status
                FROM i_posts P
                INNER JOIN i_users U ON P.post_owner_id = U.iuid
                WHERE P.post_id = ? AND P.post_status IN('0','1','2') LIMIT 1";
        return DB::one($sql, [$postID]);
    }

	public function iN_ReShare_Post($userID, $postID, $postDetails) {
		$time = time();
		$userIP = $_SERVER['REMOTE_ADDR'] ?? '';
		if ($this->iN_CheckUserExist($userID) == '1' && $this->iN_CheckPostIDExist($postID) == '1') {
			DB::exec(
				"INSERT INTO i_posts (post_owner_id,post_text,post_created_time,shared_post_id,post_creator_ip)
				 SELECT ?, ?, ?, ?, ? FROM i_posts WHERE post_id = ?",
				[(int)$userID, (string)$postDetails, $time, (int)$postID, (string)$userIP, (int)$postID]
			);
			return true;
		}
		return false;
	}

