	public function iN_CheckFileIDExist($fileID) {
		return (bool) DB::col("SELECT 1 FROM i_user_uploads WHERE upload_id = ? LIMIT 1", [(int)$fileID]);
	}
		/*Delete File Before Publish Post*/
		public function iN_DeleteFile($userID, $fileID) {
			if ($this->iN_CheckUserExist($userID) != '1') {
				return false;
			}

			$row = DB::one(
				"SELECT uploaded_file_path, upload_tumbnail_file_path, uploaded_x_file_path
				 FROM i_user_uploads WHERE upload_id = ? AND iuid_fk = ? LIMIT 1",
				[(int)$fileID, (int)$userID]
			);

			if (!$row) {
				return false;
			}

			$paths = [
				$row['uploaded_file_path'] ?? '',
				$row['uploaded_x_file_path'] ?? '',
				$row['upload_tumbnail_file_path'] ?? '',
			];

			$useRemote = function_exists('storage_is_remote') ? storage_is_remote() : false;
			foreach ($paths as $path) {
				$path = trim((string) $path);
				if ($path === '' || strpos($path, 'uploads/') !== 0) {
					continue;
				}
				if ($useRemote && function_exists('storage_delete')) {
					@storage_delete($path);
				} else {
					$full = dirname(__DIR__) . '/' . ltrim($path, '/');
					@unlink($full);
				}
			}

			DB::exec("DELETE FROM i_user_uploads WHERE upload_id = ? AND iuid_fk = ?", [(int)$fileID, (int)$userID]);
			return true;
		}
	public function iN_fetchDataFromURL($url = '') {
		if (empty($url)) {
			return false;
		}
		$ch = curl_init($url);
		curl_setopt($ch, CURLOPT_POST, false);
		curl_setopt($ch, CURLOPT_FOLLOWLOCATION, true);
		curl_setopt($ch, CURLOPT_SSL_VERIFYHOST, 0);
		curl_setopt($ch, CURLOPT_SSL_VERIFYPEER, 0);
		curl_setopt($ch, CURLOPT_USERAGENT, "Mozilla/5.0 (Windows; U; Windows NT 5.0; en-US; rv:1.7.12) Gecko/20050915 Firefox/1.0.7");
		curl_setopt($ch, CURLOPT_HEADER, false);
		curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
		curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
		curl_setopt($ch, CURLOPT_CONNECTTIMEOUT, 5);
		curl_setopt($ch, CURLOPT_TIMEOUT, 5);
		return curl_exec($ch);
	}

	public function iN_ExtractFirstUrlFromText(string $text): ?string {
		if ($text === '' || stripos($text, 'http') === false) {
			return null;
		}
		$regex = '~\bhttps?://[^\s<>()"]+~i';
		if (!preg_match($regex, $text, $match)) {
			return null;
		}
		$url = rtrim($match[0], ".,);!?\"'");
		return filter_var($url, FILTER_VALIDATE_URL) ? $url : null;
	}

	public function iN_GetLinkPreviewFromText(string $text): ?array {
		$url = $this->iN_ExtractFirstUrlFromText($text);
		if ($url === null) {
			return null;
		}
		$preview = $this->iN_FetchLinkPreview($url);
		if ($preview !== null) {
			return $preview;
		}
		return $this->iN_BuildFallbackPreviewFromUrl($url);
	}

	public function iN_BuildFallbackPreviewFromUrl(string $url): ?array {
		$url = trim($url);
		if ($url === '' || !filter_var($url, FILTER_VALIDATE_URL)) {
			return null;
		}
		$parts = parse_url($url);
		if (
			!$parts ||
			empty($parts['scheme']) ||
			empty($parts['host']) ||
			!in_array(strtolower((string) $parts['scheme']), ['http', 'https'], true)
		) {
			return null;
		}
		$domain = (string) $parts['host'];
		if ($domain === 'localhost') {
			return null;
		}
		if (filter_var($domain, FILTER_VALIDATE_IP) && !$this->iN_IsPublicIp($domain)) {
			return null;
		}
		$title = '';
		if (!empty($parts['path']) && $parts['path'] !== '/') {
			$title = trim((string) $parts['path'], '/');
			$title = rawurldecode($title);
			$title = str_replace('-', ' ', $title);
			$title = str_replace('/', ' / ', $title);
			$title = preg_replace('/\s+/', ' ', $title);
		}
		if ($title === '') {
			$title = $domain;
		}
		$title = $this->iN_SanitizePreviewText($title, 255);
		if ($title === '') {
			return null;
		}
		return [
			'link_url' => $url,
			'link_domain' => $domain,
			'link_title' => $title,
			'link_description' => '',
			'link_image' => ''
		];
	}

	public function iN_TruncateLinkText(string $html, int $maxLen = 50): string {
		if ($html === '' || $maxLen < 1 || stripos($html, '<a') === false) {
			return $html;
		}
		$maxLen = (int) $maxLen;
		if ($maxLen < 4) {
			$maxLen = 4;
		}
		libxml_use_internal_errors(true);
		$dom = new DOMDocument();
		$loaded = $dom->loadHTML(
			'<?xml encoding="UTF-8">' . $html,
			LIBXML_HTML_NOIMPLIED | LIBXML_HTML_NODEFDTD
		);
		if (!$loaded) {
			libxml_clear_errors();
			return $html;
		}
		foreach ($dom->getElementsByTagName('a') as $link) {
			$text = trim((string) $link->textContent);
			$len = mb_strlen($text);
			if ($len > $maxLen) {
				$cut = $maxLen - 3;
				$link->nodeValue = mb_substr($text, 0, $cut) . '...';
			}
		}
		$result = $dom->saveHTML();
		libxml_clear_errors();
		return $result ?: $html;
	}

	public function iN_SavePostLinkPreview(int $postId, array $preview): bool {
		if ($postId <= 0) {
			return false;
		}
		if (!$this->iN_HasPostLinkPreviewColumns()) {
			return false;
		}
		$linkUrl = trim((string) ($preview['link_url'] ?? ''));
		if ($linkUrl === '') {
			return false;
		}
		$linkDomain = trim((string) ($preview['link_domain'] ?? ''));
		$linkTitle = trim((string) ($preview['link_title'] ?? ''));
		$linkDescription = trim((string) ($preview['link_description'] ?? ''));
		$linkImage = trim((string) ($preview['link_image'] ?? ''));

		$linkUrl = mb_substr($linkUrl, 0, 2048);
		$linkDomain = mb_substr($linkDomain, 0, 255);
		$linkTitle = mb_substr($linkTitle, 0, 255);
		$linkDescription = mb_substr($linkDescription, 0, 500);
		$linkImage = mb_substr($linkImage, 0, 2048);

		DB::exec(
			"UPDATE i_posts
			 SET link_url = ?, link_domain = ?, link_title = ?, link_description = ?, link_image = ?, link_fetched_at = ?
			 WHERE post_id = ? LIMIT 1",
			[
				$linkUrl,
				$linkDomain !== '' ? $linkDomain : null,
				$linkTitle !== '' ? $linkTitle : null,
				$linkDescription !== '' ? $linkDescription : null,
				$linkImage !== '' ? $linkImage : null,
				time(),
				$postId
			]
		);
		return true;
	}

