	private function iN_FetchLinkPreview(string $url): ?array {
		$url = trim($url);
		if (!$this->iN_IsSafePreviewUrl($url)) {
			return null;
		}

		$maxBytes = 512000;
		$buffer = '';
		$ch = curl_init($url);
		curl_setopt($ch, CURLOPT_RETURNTRANSFER, false);
		curl_setopt($ch, CURLOPT_FOLLOWLOCATION, true);
		curl_setopt($ch, CURLOPT_MAXREDIRS, 3);
		curl_setopt($ch, CURLOPT_CONNECTTIMEOUT, 5);
		curl_setopt($ch, CURLOPT_TIMEOUT, 8);
		curl_setopt($ch, CURLOPT_USERAGENT, 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/123.0.0.0 Safari/537.36');
		curl_setopt($ch, CURLOPT_PROTOCOLS, CURLPROTO_HTTP | CURLPROTO_HTTPS);
		curl_setopt($ch, CURLOPT_REDIR_PROTOCOLS, CURLPROTO_HTTP | CURLPROTO_HTTPS);
		curl_setopt($ch, CURLOPT_SSL_VERIFYHOST, 2);
		curl_setopt($ch, CURLOPT_SSL_VERIFYPEER, true);
		curl_setopt($ch, CURLOPT_WRITEFUNCTION, function ($ch, $data) use (&$buffer, $maxBytes) {
			$len = strlen($data);
			if (strlen($buffer) + $len > $maxBytes) {
				$remaining = $maxBytes - strlen($buffer);
				if ($remaining > 0) {
					$buffer .= substr($data, 0, $remaining);
				}
				return 0;
			}
			$buffer .= $data;
			return $len;
		});

		$execOk = curl_exec($ch);
		$errno = curl_errno($ch);
		$info = curl_getinfo($ch);
		curl_close($ch);

		if ($errno && $errno !== CURLE_WRITE_ERROR) {
			return null;
		}
		if ($execOk === false && $buffer === '') {
			return null;
		}
		$httpCode = (int) ($info['http_code'] ?? 0);
		if ($httpCode >= 400) {
			return null;
		}
		$contentType = (string) ($info['content_type'] ?? '');
		if ($contentType !== '' && stripos($contentType, 'text/html') === false && stripos($contentType, 'application/xhtml') === false) {
			return null;
		}

		$finalUrl = (string) ($info['url'] ?? $url);
		if (!$this->iN_IsSafePreviewUrl($finalUrl)) {
			return null;
		}
		$primaryIp = (string) ($info['primary_ip'] ?? '');
		if ($primaryIp !== '' && !$this->iN_IsPublicIp($primaryIp)) {
			return null;
		}
		if ($buffer === '') {
			return null;
		}
		return $this->iN_ParseLinkPreviewHtml($buffer, $url, $finalUrl);
	}

	private function iN_ParseLinkPreviewHtml(string $html, string $originalUrl, string $finalUrl): ?array {
		$encodedHtml = mb_convert_encoding($html, 'UTF-8', 'UTF-8, ISO-8859-1, ISO-8859-9, WINDOWS-1254');
		libxml_use_internal_errors(true);
		$dom = new DOMDocument();
		$loaded = $dom->loadHTML('<?xml encoding="UTF-8">' . $encodedHtml);
		libxml_clear_errors();
		if (!$loaded) {
			return null;
		}

		$meta = [];
		foreach ($dom->getElementsByTagName('meta') as $tag) {
			$property = strtolower(trim((string) $tag->getAttribute('property')));
			$name = strtolower(trim((string) $tag->getAttribute('name')));
			$content = trim((string) $tag->getAttribute('content'));
			if ($content === '') {
				continue;
			}
			if ($property !== '') {
				$meta[$property] = $content;
			}
			if ($name !== '') {
				$meta[$name] = $content;
			}
		}

		$title = '';
		$titleNodes = $dom->getElementsByTagName('title');
		if ($titleNodes->length > 0) {
			$title = (string) $titleNodes->item(0)->textContent;
		}

		$previewUrl = $meta['og:url'] ?? $finalUrl;
		$previewUrl = $this->iN_NormalizePreviewUrl($previewUrl, $finalUrl);
		if ($previewUrl === '' || !filter_var($previewUrl, FILTER_VALIDATE_URL)) {
			$previewUrl = $finalUrl;
		}

		$title = $meta['og:title'] ?? ($meta['twitter:title'] ?? $title);
		$description = $meta['og:description'] ?? ($meta['twitter:description'] ?? ($meta['description'] ?? ''));
		$image = $meta['og:image'] ?? ($meta['og:image:url'] ?? ($meta['twitter:image'] ?? ''));
		$image = $this->iN_NormalizePreviewUrl($image, $previewUrl);

		if ($image === '' || $title === '' || $description === '') {
			$jsonPreview = $this->iN_ExtractPreviewFromJsonScripts($dom, $previewUrl);
			if ($image === '' && !empty($jsonPreview['image'])) {
				$image = $jsonPreview['image'];
			}
			if ($title === '' && !empty($jsonPreview['title'])) {
				$title = $jsonPreview['title'];
			}
			if ($description === '' && !empty($jsonPreview['description'])) {
				$description = $jsonPreview['description'];
			}
		}

		if ($image === '' && $this->iN_IsTikTokUrl($previewUrl)) {
			$oembed = $this->iN_FetchTikTokOembed($previewUrl);
			if ($oembed) {
				if ($image === '' && !empty($oembed['link_image'])) {
					$image = $oembed['link_image'];
				}
				if ($title === '' && !empty($oembed['link_title'])) {
					$title = $oembed['link_title'];
				}
				if ($description === '' && !empty($oembed['link_description'])) {
					$description = $oembed['link_description'];
				}
			}
		}

		$title = $this->iN_SanitizePreviewText($title, 255);
		$description = $this->iN_SanitizePreviewText($description, 500);
		$domain = parse_url($previewUrl, PHP_URL_HOST) ?: (parse_url($originalUrl, PHP_URL_HOST) ?: '');

		if ($image !== '' && !filter_var($image, FILTER_VALIDATE_URL)) {
			$image = '';
		}
		if ($title === '' && $description === '' && $image === '') {
			return null;
		}

		return [
			'link_url' => $previewUrl,
			'link_domain' => $domain,
			'link_title' => $title,
			'link_description' => $description,
			'link_image' => $image,
		];
	}

	private function iN_ExtractPreviewFromJsonScripts(DOMDocument $dom, string $baseUrl): array {
		$preview = [
			'image' => '',
			'title' => '',
			'description' => ''
		];
		$scriptNodes = $dom->getElementsByTagName('script');
		foreach ($scriptNodes as $script) {
			$type = strtolower(trim((string) $script->getAttribute('type')));
			$id = strtolower(trim((string) $script->getAttribute('id')));
			$readable = $type === 'application/ld+json'
				|| ($type === 'application/json' && in_array($id, ['__next_data__', 'sigi_state'], true));
			if (!$readable) {
				continue;
			}
			$payload = trim((string) $script->textContent);
			if ($payload === '') {
				continue;
			}
			$decoded = json_decode($payload, true);
			if (!is_array($decoded)) {
				continue;
			}
			$found = $this->iN_FindPreviewInJson($decoded, $baseUrl);
			if ($preview['image'] === '' && !empty($found['image'])) {
				$preview['image'] = $found['image'];
			}
			if ($preview['title'] === '' && !empty($found['title'])) {
				$preview['title'] = $found['title'];
			}
			if ($preview['description'] === '' && !empty($found['description'])) {
				$preview['description'] = $found['description'];
			}
			if ($preview['image'] !== '' && $preview['title'] !== '' && $preview['description'] !== '') {
				break;
			}
		}
		return $preview;
	}

	private function iN_FindPreviewInJson(array $data, string $baseUrl): array {
		$found = [
			'image' => '',
			'title' => '',
			'description' => ''
		];
		$limit = 1000;
		$depthLimit = 8;
		$count = 0;
		$this->iN_WalkPreviewJson($data, $baseUrl, $found, $count, 0, $limit, $depthLimit);
		return $found;
	}

	private function iN_WalkPreviewJson($node, string $baseUrl, array &$found, int &$count, int $depth, int $limit, int $depthLimit): void {
		if ($count >= $limit || $depth > $depthLimit || (is_string($node) && $node === '')) {
			return;
		}
		$count++;
		if (is_array($node)) {
			foreach ($node as $key => $value) {
				if (is_string($key)) {
					$lower = strtolower($key);
					if ($found['image'] === '' && $this->iN_IsPreviewImageKey($lower)) {
						$img = $this->iN_PickPreviewUrl($value, $baseUrl);
						if ($img !== '') {
							$found['image'] = $img;
						}
					}
					if ($found['title'] === '' && $this->iN_IsPreviewTitleKey($lower) && is_string($value)) {
						$found['title'] = $this->iN_SanitizePreviewText($value, 255);
					}
					if ($found['description'] === '' && $this->iN_IsPreviewDescriptionKey($lower) && is_string($value)) {
						$found['description'] = $this->iN_SanitizePreviewText($value, 500);
					}
				}
				if ($found['image'] !== '' && $found['title'] !== '' && $found['description'] !== '') {
					return;
				}
				if (is_array($value)) {
					$this->iN_WalkPreviewJson($value, $baseUrl, $found, $count, $depth + 1, $limit, $depthLimit);
				}
			}
		}
	}

	private function iN_IsPreviewImageKey(string $key): bool {
		return in_array($key, [
			'thumbnailurl',
			'thumbnail_url',
			'image',
			'imageurl',
			'image_url',
			'cover',
			'coverurl',
			'cover_url',
			'poster',
			'posterurl',
			'poster_url',
			'sharecover',
			'share_cover'
		], true);
	}

	private function iN_IsPreviewTitleKey(string $key): bool {
		return in_array($key, ['title', 'name'], true);
	}

	private function iN_IsPreviewDescriptionKey(string $key): bool {
		return in_array($key, ['description', 'desc', 'summary', 'caption'], true);
	}

	private function iN_PickPreviewUrl($value, string $baseUrl): string {
		if (is_string($value)) {
			return $this->iN_NormalizePreviewUrl($value, $baseUrl);
		}
		if (is_array($value)) {
			if (isset($value['url']) && is_string($value['url'])) {
				return $this->iN_NormalizePreviewUrl($value['url'], $baseUrl);
			}
			if (isset($value['src']) && is_string($value['src'])) {
				return $this->iN_NormalizePreviewUrl($value['src'], $baseUrl);
			}
			foreach ($value as $item) {
				if (is_string($item)) {
					return $this->iN_NormalizePreviewUrl($item, $baseUrl);
				}
			}
		}
		return '';
	}

	private function iN_IsTikTokUrl(string $url): bool {
		$host = strtolower((string) (parse_url($url, PHP_URL_HOST) ?? ''));
		return $host === 'tiktok.com' || substr($host, -11) === '.tiktok.com';
	}

	private function iN_FetchTikTokOembed(string $url): ?array {
		if (!$this->iN_IsTikTokUrl($url)) {
			return null;
		}
		$endpoint = 'https://www.tiktok.com/oembed?url=' . rawurlencode($url);
		$ch = curl_init($endpoint);
		curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
		curl_setopt($ch, CURLOPT_CONNECTTIMEOUT, 5);
		curl_setopt($ch, CURLOPT_TIMEOUT, 8);
		curl_setopt($ch, CURLOPT_SSL_VERIFYHOST, 2);
		curl_setopt($ch, CURLOPT_SSL_VERIFYPEER, true);
		curl_setopt($ch, CURLOPT_USERAGENT, 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/123.0.0.0 Safari/537.36');
		$response = curl_exec($ch);
		$httpCode = (int) curl_getinfo($ch, CURLINFO_HTTP_CODE);
		curl_close($ch);

		if ($response === false || $httpCode >= 400) {
			return null;
		}
		$data = json_decode($response, true);
		if (!is_array($data)) {
			return null;
		}
		$image = isset($data['thumbnail_url']) ? trim((string) $data['thumbnail_url']) : '';
		$title = isset($data['title']) ? trim((string) $data['title']) : '';
		$desc = isset($data['author_name']) ? trim((string) $data['author_name']) : '';

		return [
			'link_title' => $title !== '' ? $title : '',
			'link_description' => $desc !== '' ? $desc : '',
			'link_image' => $image !== '' ? $image : ''
		];
	}

	private function iN_NormalizePreviewUrl(string $url, string $baseUrl): string {
		$url = trim(html_entity_decode($url, ENT_QUOTES | ENT_HTML5, 'UTF-8'));
		if ($url === '') {
			return '';
		}
		if (strpos($url, '//') === 0) {
			$scheme = parse_url($baseUrl, PHP_URL_SCHEME) ?: 'https';
			return $scheme . ':' . $url;
		}
		if (preg_match('~^https?://~i', $url)) {
			return $url;
		}
		$parts = parse_url($baseUrl);
		if (!$parts || empty($parts['scheme']) || empty($parts['host'])) {
			return '';
		}
		$root = $parts['scheme'] . '://' . $parts['host'];
		if (!empty($parts['port'])) {
			$root .= ':' . (int) $parts['port'];
		}
		if (strpos($url, '/') === 0) {
			return $root . $url;
		}
		$path = isset($parts['path']) ? (string) $parts['path'] : '/';
		$dir = trim(str_replace('\\', '/', dirname($path)), '/');
		if ($dir !== '') {
			$root .= '/' . $dir;
		}
		return $root . '/' . ltrim($url, '/');
	}

	private function iN_SanitizePreviewText(string $text, int $maxLen): string {
		$text = html_entity_decode($text, ENT_QUOTES | ENT_HTML5, 'UTF-8');
		$text = preg_replace('/\s+/', ' ', trim(strip_tags($text)));
		if ($maxLen > 0 && mb_strlen($text) > $maxLen) {
			$text = mb_substr($text, 0, $maxLen);
		}
		return $text;
	}

	private function iN_IsSafePreviewUrl(string $url): bool {
		if (!filter_var($url, FILTER_VALIDATE_URL)) {
			return false;
		}
		$parts = parse_url($url);
		if (!$parts || empty($parts['scheme']) || empty($parts['host'])) {
			return false;
		}
		$scheme = strtolower((string) $parts['scheme']);
		if (!in_array($scheme, ['http', 'https'], true)) {
			return false;
		}
		$port = $parts['port'] ?? null;
		if ($port !== null && !in_array((int) $port, [80, 443], true)) {
			return false;
		}
		$host = (string) $parts['host'];
		if ($host === 'localhost') {
			return false;
		}
		if (filter_var($host, FILTER_VALIDATE_IP)) {
			return $this->iN_IsPublicIp($host);
		}
		return $this->iN_HostResolvesToPublicIp($host);
	}

	private function iN_IsPublicIp(string $ip): bool {
		return filter_var($ip, FILTER_VALIDATE_IP, FILTER_FLAG_NO_PRIV_RANGE | FILTER_FLAG_NO_RES_RANGE) !== false;
	}

	private function iN_HostResolvesToPublicIp(string $host): bool {
		$records = dns_get_record($host, DNS_A | DNS_AAAA);
		if (is_array($records) && !empty($records)) {
			foreach ($records as $record) {
				$ip = $record['ip'] ?? ($record['ipv6'] ?? '');
				if ($ip !== '' && $this->iN_IsPublicIp($ip)) {
					return true;
				}
			}
			return false;
		}
		$ip = gethostbyname($host);
		if ($ip !== $host) {
			return $this->iN_IsPublicIp($ip);
		}
		return false;
	}
