    /**
     * Update poll question and options for an existing poll post.
     *
     * @param int   $userID
     * @param int   $postID
     * @param string $editedText
     * @param string $hashTags
     * @param string $editSlug
     * @param array $options
     * @return array
     */
    public function iN_UpdatePollPost($userID, $postID, $editedText, $hashTags, $editSlug, array $options) {
        $settings = $this->getPollSettings();
        if ($settings['status'] !== '1') {
            return ['error' => 'poll_disabled'];
        }
        if ($this->iN_CheckUserExist($userID) != 1 || $this->iN_CheckPostIDExist($postID) != 1) {
            return ['error' => 'poll_missing'];
        }

        $post = DB::one("SELECT post_owner_id, post_type FROM i_posts WHERE post_id = ? LIMIT 1", [(int)$postID]);
        if (!$post || ($post['post_type'] ?? '') !== 'poll') {
            return ['error' => 'poll_not_allowed'];
        }
        $isAdmin = $this->iN_CheckIsAdmin($userID) == 1;
        if (!$isAdmin && (int)$post['post_owner_id'] !== (int)$userID) {
            return ['error' => 'poll_not_allowed'];
        }

        $normalizedOptions = [];
        foreach ($options as $option) {
            $optionText = '';
            $optionId = null;
            if (is_array($option)) {
                $optionText = isset($option['text']) ? trim((string)$option['text']) : '';
                $optionId = isset($option['id']) && is_numeric($option['id']) ? (int)$option['id'] : null;
            } else {
                $optionText = trim((string)$option);
            }
            if ($optionText === '') {
                continue;
            }
            $normalizedOptions[] = ['id' => $optionId, 'text' => $optionText];
        }
        $uniqueOptions = [];
        $optionTexts = [];
        foreach ($normalizedOptions as $option) {
            $textKey = mb_strtolower($option['text'], 'UTF-8');
            if (isset($optionTexts[$textKey])) {
                continue;
            }
            $optionTexts[$textKey] = true;
            $uniqueOptions[] = $option;
        }
        $optionCount = count($uniqueOptions);
        if ($optionCount < $settings['min_options']) {
            return ['error' => 'poll_min_options'];
        }
        if ($optionCount > $settings['max_options']) {
            return ['error' => 'poll_max_options'];
        }

        $poll = DB::one("SELECT poll_id FROM i_polls WHERE post_id_fk = ? LIMIT 1", [(int)$postID]);
        if (!$poll || !isset($poll['poll_id'])) {
            return ['error' => 'poll_missing'];
        }
        $pollId = (int)$poll['poll_id'];

        $existingOptions = DB::all("SELECT option_id FROM i_poll_options WHERE poll_id_fk = ?", [$pollId]);
        $existingMap = [];
        if ($existingOptions) {
            foreach ($existingOptions as $existingOption) {
                $existingMap[(int)$existingOption['option_id']] = true;
            }
        }

        $time = time();
        DB::begin();
        try {
            if ($isAdmin) {
                DB::exec("UPDATE i_posts SET post_text = ?, url_slug = ?, hashtags = ? WHERE post_id = ?", [(string)$editedText, (string)$editSlug, (string)$hashTags, (int)$postID]);
            } else {
                DB::exec("UPDATE i_posts SET post_text = ?, url_slug = ?, hashtags = ? WHERE post_owner_id = ? AND post_id = ?", [(string)$editedText, (string)$editSlug, (string)$hashTags, (int)$userID, (int)$postID]);
            }
            DB::exec("UPDATE i_polls SET question = ?, updated_at = ? WHERE poll_id = ?", [(string)$editedText, $time, $pollId]);

            $usedOptionIds = [];
            $order = 1;
            foreach ($uniqueOptions as $option) {
                $optionId = $option['id'];
                $optionText = $option['text'];
                if ($optionId && isset($existingMap[$optionId])) {
                    DB::exec(
                        "UPDATE i_poll_options SET option_text = ?, option_order = ?, status = 'active', updated_at = ? WHERE option_id = ? AND poll_id_fk = ?",
                        [(string)$optionText, $order, $time, (int)$optionId, (int)$pollId]
                    );
                    $usedOptionIds[] = (int)$optionId;
                } else {
                    DB::exec(
                        "INSERT INTO i_poll_options (poll_id_fk, option_text, option_order, votes_count, status, created_at, updated_at)
                         VALUES (?,?,?,?,?,?,?)",
                        [(int)$pollId, (string)$optionText, $order, 0, 'active', $time, $time]
                    );
                    $usedOptionIds[] = (int) DB::lastId();
                }
                $order++;
            }

            foreach ($existingMap as $optionId => $_) {
                if (!in_array($optionId, $usedOptionIds, true)) {
                    DB::exec("DELETE FROM i_poll_votes WHERE option_id_fk = ?", [(int)$optionId]);
                    DB::exec("DELETE FROM i_poll_options WHERE option_id = ? AND poll_id_fk = ?", [(int)$optionId, (int)$pollId]);
                }
            }

            DB::commit();
        } catch (Throwable $e) {
            DB::rollBack();
            return ['error' => 'poll_update_failed'];
        }

        return [
            'status' => 'success',
            'poll' => $this->iN_GetPollDetailsByPollId($pollId, $userID),
        ];
    }

    /**
     * Remove all poll records linked to a post to prevent orphaned rows.
     */
    private function deletePollDataForPost($postID): void {
        $poll = DB::one("SELECT poll_id FROM i_polls WHERE post_id_fk = ? LIMIT 1", [(int)$postID]);
        if (!$poll || !isset($poll['poll_id'])) {
            return;
        }
        $pollId = (int)$poll['poll_id'];
        DB::exec("DELETE FROM i_poll_votes WHERE poll_id_fk = ?", [$pollId]);
        DB::exec("DELETE FROM i_poll_options WHERE poll_id_fk = ?", [$pollId]);
        DB::exec("DELETE FROM i_polls WHERE poll_id = ?", [$pollId]);
    }
	/*Delete Post From Data*/
    public function iN_DeletePost($userID, $postID) {
        if ($this->iN_CheckUserExist($userID) == 1 && $this->iN_CheckPostIDExist($postID) == 1) {
            $getPostFileIDs = $this->iN_GetAllPostDetails($postID);
            $postFileIDs = isset($getPostFileIDs['post_file']) ? $getPostFileIDs['post_file'] : null;
            if ($postFileIDs) {
                $trimValue = rtrim((string)$postFileIDs, ',');
                $explodeFiles = $trimValue !== '' ? array_unique(explode(',', $trimValue)) : [];
                $useRemote = function_exists('storage_is_remote') ? storage_is_remote() : false;
                foreach ($explodeFiles as $explodeFile) {
                    $theFileID = $this->iN_GetUploadedFileDetails($explodeFile);
                    if (!$theFileID) { continue; }
                    $uploadedFileID = $theFileID['upload_id'] ?? null;
                    $uploadedFilePath = $theFileID['uploaded_file_path'] ?? '';
                    $uploadedTumbnailFilePath = $theFileID['upload_tumbnail_file_path'] ?? '';
                    $uploadedFilePathX = $theFileID['uploaded_x_file_path'] ?? '';
	                    if ($useRemote && function_exists('storage_delete')) {
	                        @storage_delete($uploadedFilePath);
	                        @storage_delete($uploadedFilePathX);
	                        @storage_delete($uploadedTumbnailFilePath);
	                    } else {
	                        foreach ([$uploadedFilePath, $uploadedFilePathX, $uploadedTumbnailFilePath] as $p) {
	                            $p = trim((string) $p);
	                            if ($p === '' || strpos($p, 'uploads/') !== 0) {
	                                continue;
	                            }
	                            $full = dirname(__DIR__) . '/' . ltrim($p, '/');
	                            @unlink($full);
	                        }
	                    }
                    if (!empty($uploadedFileID)) {
                        DB::exec("DELETE FROM i_user_uploads WHERE upload_id = ? AND iuid_fk = ?", [(int)$uploadedFileID, (int)$userID]);
                    }
                }
            }
            $this->deletePollDataForPost($postID);
            $this->iN_ClearScheduledQueue((int)$postID);
            if ($this->iN_CheckIsAdmin($userID) == 1) {
                DB::exec("DELETE FROM i_posts WHERE post_id = ?", [(int)$postID]);
                return true;
            } else {
                DB::exec("DELETE FROM i_posts WHERE post_id = ? AND post_owner_id = ?", [(int)$postID, (int)$userID]);
                return true;
            }
        }
        return false;
    }
