	/*Insert New Comment*/
    public function iN_insertNewComment($userID, $postID, $comment, $stickerID, $gifUrl, $parentCommentID = null) {
        $get = $this->iN_GetAllPostDetails($postID);
        $checkUser_Blocked = $this->iN_CheckUserBlocked($get['post_owner_id'], $userID);
        $commenterBlockedPostOwner = $this->iN_CheckUserBlocked($userID, $get['post_owner_id']);
        if ($this->iN_CheckUserExist($userID) == 1 && $this->iN_CheckPostIDExist($postID) == 1 && $checkUser_Blocked != 1 && $commenterBlockedPostOwner != 1) {
            $parentCommentID = (int)$parentCommentID;
            if ($parentCommentID > 0) {
                $parentCommentData = $this->iN_GetCommentDetails($parentCommentID);
                if (!$parentCommentData || (int)($parentCommentData['comment_post_id_fk'] ?? 0) !== (int)$postID) {
                    return false;
                }
                $parentRootId = (int)($parentCommentData['parent_comment_id'] ?? 0);
                if ($parentRootId > 0) {
                    $parentCommentID = $parentRootId;
                }
            }
            $dataStickerUrl = '';
            $dataGifUrl = '';
            if ($stickerID) {
                if ($this->iN_CheckStickerIDExist($stickerID) == 1) {
                    $stickerURL = $this->iN_getSticker($stickerID);
                    $dataStickerUrl = $stickerURL['sticker_url'];
                } else { return false; }
            } else if ($gifUrl) {
                $dataGifUrl = $gifUrl;
                $dataStickerUrl = '';
            }
            $time = time();
            if ($this->iN_CheckIsAdmin($userID) == 1 || $this->iN_CheckPostCommentStatus($postID) == 1 || $this->iN_CheckPostOwnerStatus($userID, $postID) == 1) {
                $parentValue = $parentCommentID > 0 ? $parentCommentID : null;
                DB::exec("INSERT INTO i_post_comments (comment_post_id_fk, comment_uid_fk, comment_time, comment, sticker_url, gif_url, parent_comment_id) VALUES (?,?,?,?,?,?,?)",
                    [(int)$postID, (int)$userID, $time, (string)$comment, (string)$dataStickerUrl, (string)$dataGifUrl, $parentValue]
                );
                $commentLinkSelect = $this->iN_CommentLinkPreviewSelect();
                $row = DB::one(
                    "SELECT C.com_id,C.comment_uid_fk,C.comment_post_id_fk,C.comment,C.comment_time,C.comment_file,C.sticker_url,C.gif_url,C.parent_comment_id{$commentLinkSelect},
                            U.iuid,U.i_username,U.i_user_fullname,U.user_avatar,U.user_gender,U.last_login_time,U.user_verified_status,U.i_user_email
                     FROM i_post_comments C FORCE INDEX(ixComment)
                     INNER JOIN i_users U FORCE INDEX(ixForceUser) ON C.comment_uid_fk = U.iuid AND U.uStatus IN('1','3')
                     WHERE C.comment_post_id_fk = ? AND C.comment_uid_fk = ? ORDER BY C.com_id DESC LIMIT 1",
                    [(int)$postID, (int)$userID]
                );
                if ($row && $this->iN_HasCommentLinkPreviewColumns()) {
                    $commentText = trim((string) $comment);
                    $hasMedia = $dataStickerUrl !== '' || $dataGifUrl !== '';
                    if ($commentText !== '' && !$hasMedia) {
                        $preview = $this->iN_GetLinkPreviewFromText($commentText);
                        if ($preview) {
                            $this->iN_SaveCommentLinkPreview((int) $row['com_id'], $preview);
                            $row = array_merge($row, $preview);
                        } else {
                            $this->iN_ClearCommentLinkPreview((int) $row['com_id']);
                        }
                    } else {
                        $this->iN_ClearCommentLinkPreview((int) $row['com_id']);
                    }
                }
                return $row ?: false;
            }
            return false;
        }
        return false;
    }
