	/*Insert Community Notification*/
    public function iN_InsertCommunityNotification($fromUserID, $toUserID, array $communityData, $notificationType, $postID = null, array $extraPayload = []) {
        static $hasPayloadColumn = null;
        $fromUserID = (int)$fromUserID;
        $toUserID = (int)$toUserID;
        $communityID = (int)($communityData['id'] ?? $communityData['community_id'] ?? 0);
        if ($fromUserID <= 0 || $toUserID <= 0 || $communityID <= 0) {
            return false;
        }
        if ($fromUserID === $toUserID) {
            return false;
        }
        $payload = [
            'community_id' => $communityID,
            'community_name' => (string)($communityData['title'] ?? ''),
            'community_slug' => (string)($communityData['slug'] ?? '')
        ];
        if (!empty($extraPayload)) {
            $payload = array_merge($payload, $extraPayload);
        }
        if ($hasPayloadColumn === null) {
            $hasPayloadColumn = (bool) DB::col(
                "SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'i_user_notifications' AND COLUMN_NAME = 'not_payload' LIMIT 1"
            );
        }
        $payloadJson = json_encode($payload, JSON_UNESCAPED_UNICODE);
        $time = time();
        if ($hasPayloadColumn) {
            DB::exec(
                "INSERT INTO i_user_notifications (not_iuid, not_post_id, not_own_iuid, not_type, not_payload, not_not_type, not_time) VALUES (?,?,?,?,?,?,?)",
                [
                    $fromUserID,
                    $postID !== null ? (int)$postID : 0,
                    $toUserID,
                    'text',
                    $payloadJson,
                    (string)$notificationType,
                    $time
                ]
            );
        } else {
            $shortPayload = json_encode(['community_id' => $communityID], JSON_UNESCAPED_UNICODE);
            DB::exec(
                "INSERT INTO i_user_notifications (not_iuid, not_post_id, not_own_iuid, not_type, not_not_type, not_time) VALUES (?,?,?,?,?,?)",
                [
                    $fromUserID,
                    $postID !== null ? (int)$postID : 0,
                    $toUserID,
                    $shortPayload,
                    (string)$notificationType,
                    $time
                ]
            );
        }
        DB::exec("UPDATE i_users SET notification_read_status = '1' WHERE iuid = ?", [(int)$toUserID]);
        return true;
    }
