     */
    public function iN_InsertNotificationForCampaignDecision(int $fromUserId, int $toUserId, int $campaignId, bool $approved, int $postId = 0): bool {
        if ($fromUserId <= 0 || $toUserId <= 0 || $campaignId <= 0) {
            return false;
        }
        $time = time();
        $type = $approved ? 'campaign_approved' : 'campaign_rejected';
        DB::exec(
            "INSERT INTO i_user_notifications (not_iuid, not_own_iuid, not_not_type, not_post_id, not_time) VALUES (?,?,?,?,?)",
            [(int)$fromUserId, (int)$toUserId, (string)$type, (int)$postId, (int)$time]
        );
        DB::exec("UPDATE i_users SET notification_read_status = '1' WHERE iuid = ?", [(int)$toUserId]);
        return true;
    }

    /**
     * Insert notification for a campaign donation.
     */
    public function iN_InsertNotificationForCampaignDonation(int $fromUserId, int $toUserId, int $postId, float $amount): bool {
        if ($fromUserId <= 0 || $toUserId <= 0 || $postId <= 0 || $amount <= 0) {
            return false;
        }
        $time = time();
        $note = 'donated:' . number_format($amount, 2, '.', '');
        DB::exec(
            "INSERT INTO i_user_notifications (not_iuid, not_own_iuid, not_not_type, not_post_id, not_time, not_type) VALUES (?,?,?,?,?,?)",
            [
                (int)$fromUserId,
                (int)$toUserId,
                'campaign_donate',
                (int)$postId,
                (int)$time,
                $note
            ]
        );
        DB::exec("UPDATE i_users SET notification_read_status = '1' WHERE iuid = ?", [(int)$toUserId]);
        return true;
    }
