	/*Report Comment*/
public function iN_InsertReportedComment($userID, $commentID, $postID) {
        if ($this->iN_CheckUserExist($userID) == 1 && $this->iN_CheckPostIDExist($postID) == 1 && $this->iN_CheckCommentIDExistUniq($commentID)) {
            $time = time();
            if ($this->iN_CheckCommentReportedBefore($userID, $commentID) == 1) {
                DB::exec("DELETE FROM i_comment_reports WHERE reported_comment = ? AND iuid_fk = ?", [(int)$commentID,(int)$userID]);
                return 'un';
            } else {
                DB::exec("INSERT INTO i_comment_reports (reported_comment, iuid_fk, report_time, comment_post_id_fk) VALUES (?,?,?,?)", [(int)$commentID,(int)$userID,$time,(int)$postID]);
                return 'rep';
            }
        } else {return false;}
}
	/*Check Message Reported Before*/
	public function iN_CheckMessageReportedBefore($userID, $messageID) {
		return (bool) DB::col("SELECT 1 FROM i_message_reports WHERE reported_message = ? AND iuid_fk = ? LIMIT 1", [(int)$messageID, (int)$userID]);
	}
	/*Report Message*/
	public function iN_InsertReportedMessage($userID, $messageID, $chatID) {
        $userID = (int)$userID;
        $messageID = (int)$messageID;
        $chatID = (int)$chatID;
        if ($this->iN_CheckUserExist($userID) != 1 || $this->iN_CheckChatIDExist($chatID) != 1 || $this->iN_CheckChatUserOwnersID($userID, $chatID) != 1) {
            return false;
        }

        $messageData = DB::one(
            "SELECT con_id, chat_id_fk, user_one FROM i_chat_conversations WHERE con_id = ? AND chat_id_fk = ? LIMIT 1",
            [$messageID, $chatID]
        );
        if (!$messageData) {
            return false;
        }

        $messageOwnerID = (int)($messageData['user_one'] ?? 0);
        if ($messageOwnerID <= 0 || $messageOwnerID === $userID) {
            return false;
        }

        $time = time();
        if ($this->iN_CheckMessageReportedBefore($userID, $messageID) == 1) {
            DB::exec("DELETE FROM i_message_reports WHERE reported_message = ? AND iuid_fk = ?", [$messageID, $userID]);
            return 'un';
        }

        DB::exec(
            "INSERT INTO i_message_reports (reported_message, reported_chat_id_fk, reported_message_owner_id, iuid_fk, report_time) VALUES (?,?,?,?,?)",
            [$messageID, $chatID, $messageOwnerID, $userID, $time]
        );
        return 'rep';
	}
	/*Get Comment*/
public function iN_GetCommentFromID($userID, $commentID, $postID) {
        if ($this->iN_CheckUserExist($userID) == 1 && $this->iN_CheckCommentIDExistUniq($commentID) == 1 && $this->iN_CheckPostIDExist($postID) == 1) {
            if ($this->iN_CheckIsAdmin($userID) == 1) {
                return DB::one("SELECT * FROM i_post_comments WHERE com_id = ?", [(int)$commentID]);
            } else {
                return DB::one("SELECT * FROM i_post_comments WHERE com_id = ? AND comment_uid_fk = ?", [(int)$commentID,(int)$userID]);
            }
        } else { return false; }
}
	/*Save Update Comment Text*/
public function iN_UpdateComment($userID, $postID, $commentID, $editedText) {
        if ($this->iN_CheckUserExist($userID) == 1 && $this->iN_CheckPostIDExist($postID) == 1 && $this->iN_CheckCommentIDExistUniq($commentID) == 1) {
            try {
                if ($this->iN_CheckIsAdmin($userID) == 1) {
                    DB::exec("UPDATE i_post_comments SET comment = ? WHERE com_id = ?", [(string)$editedText,(int)$commentID]);
                } else {
                    DB::exec("UPDATE i_post_comments SET comment = ? WHERE com_id = ? AND comment_uid_fk = ?", [(string)$editedText,(int)$commentID,(int)$userID]);
                }
                if ($this->iN_HasCommentLinkPreviewColumns()) {
                    $commentText = trim((string) $editedText);
                    if ($commentText !== '') {
                        $preview = $this->iN_GetLinkPreviewFromText($commentText);
                        if ($preview) {
                            $this->iN_SaveCommentLinkPreview((int) $commentID, $preview);
                        } else {
                            $this->iN_ClearCommentLinkPreview((int) $commentID);
                        }
                    } else {
                        $this->iN_ClearCommentLinkPreview((int) $commentID);
                    }
                }
                return true;
            } catch (Throwable $e) {
                return false;
            }
        } else { return false; }
}
