    public function iN_TotalPostsMap(array $userIDs) {
        $ids = $this->iN_NormalizePositiveIntList($userIDs);
        if (empty($ids)) {
            return [];
        }
        $placeholders = implode(',', array_fill(0, count($ids), '?'));
        $rows = DB::all(
            "SELECT post_owner_id AS uid, COUNT(*) AS total
             FROM i_posts
             WHERE post_owner_id IN ($placeholders)
             GROUP BY post_owner_id",
            $ids
        );
        $map = [];
        if (!empty($rows)) {
            foreach ($rows as $row) {
                $uid = isset($row['uid']) ? (int)$row['uid'] : 0;
                if ($uid > 0) {
                    $map[$uid] = isset($row['total']) ? (int)$row['total'] : 0;
                }
            }
        }
        return $map;
    }
