    /**
     * Ensure i_user_subscriptions.payment_method enum supports a given gateway.
     *
     * @param string $paymentMethod
     * @return void
     */
    private function iN_EnsureSubscriptionPaymentMethodSupports($paymentMethod) {
        static $checked = [];
        $paymentMethod = (string)$paymentMethod;
        if ($paymentMethod === '') {
            return;
        }
        if (isset($checked[$paymentMethod])) {
            return;
        }
        $column = DB::one("SHOW COLUMNS FROM i_user_subscriptions LIKE 'payment_method'");
        if ($column && isset($column['Type'])) {
            if (preg_match("/^enum\\((.*)\\)$/i", $column['Type'], $matches)) {
                $enumBody = $matches[1];
                $values = str_getcsv($enumBody, ',', "'", "\\");
                if (!in_array($paymentMethod, $values, true)) {
                    $values[] = $paymentMethod;
                    $values = array_values(array_unique(array_map('strval', $values)));
                    $enumList = implode(',', array_map(function ($value) {
                        return "'" . str_replace("'", "\\'", $value) . "'";
                    }, $values));
                    DB::exec("ALTER TABLE i_user_subscriptions MODIFY payment_method enum($enumList) NOT NULL DEFAULT 'stripe'");
                }
            }
        }
        $checked[$paymentMethod] = true;
    }

    private function iN_ResolvePaymentOptionFromMethod(string $paymentMethod): string
    {
        $method = strtolower(trim($paymentMethod));
        $aliases = [
            'point' => 'wallet',
            'points' => 'wallet',
            'authorizenet' => 'authorize-net',
            'coinpayments' => 'coinpayment',
        ];
        $resolved = $aliases[$method] ?? $method;
        if ($resolved === '') {
            $resolved = 'wallet';
        }

        $allowedOptions = [];
        try {
            $column = DB::one("SHOW COLUMNS FROM i_user_payments LIKE 'payment_option'");
            if ($column && isset($column['Type']) && preg_match("/^enum\\((.*)\\)$/i", (string)$column['Type'], $matches)) {
                $allowedOptions = str_getcsv($matches[1], ',', "'", "\\");
                $allowedOptions = array_values(array_filter(array_map('strtolower', $allowedOptions), function ($value) {
                    return $value !== '';
                }));
            }
        } catch (Throwable $e) {
            $allowedOptions = [];
        }

        if (empty($allowedOptions) || in_array($resolved, $allowedOptions, true)) {
            return $resolved;
        }
        if (in_array('wallet', $allowedOptions, true)) {
            return 'wallet';
        }
        if (in_array('stripe', $allowedOptions, true)) {
            return 'stripe';
        }
        return (string)$allowedOptions[0];
    }

    private function iN_GenerateSubscriptionOrderKey(string $prefix = 'sub'): string
    {
        $prefix = preg_replace('/[^a-z0-9_]+/i', '', strtolower($prefix));
        if ($prefix === '') {
            $prefix = 'sub';
        }
        try {
            return $prefix . '_' . bin2hex(random_bytes(8));
        } catch (Throwable $e) {
            return $prefix . '_' . uniqid('', true);
        }
    }

    private function iN_RecordSubscriptionPayment(
        int $payerId,
        int $payedId,
        string $paymentMethod,
        float $amount,
        string $currency,
        string $scope = 'profile',
        ?int $scopeRefId = null,
        ?string $orderKey = null,
        ?string $gatewayReference = null,
        float $adminEarning = 0.0,
        float $userEarning = 0.0,
        float $agencyEarning = 0.0,
        float $fee = 0.0,
        float $agencyFee = 0.0,
        $agencyId = null
    ): ?int {
        $this->lastSubscriptionPaymentOrderKey = null;
        $this->lastSubscriptionPaymentId = 0;

        if ($payerId <= 0 || $payedId <= 0) {
            return null;
        }

        $scope = in_array($scope, ['profile', 'community', 'community_plan'], true) ? $scope : 'profile';
        $paymentOption = $this->iN_ResolvePaymentOptionFromMethod($paymentMethod);
        $amountValue = max(0.0, (float)$amount);
        $amountString = number_format($amountValue, 2, '.', '');
        $currencyCode = strtoupper(trim($currency));
        if ($currencyCode === '') {
            $currencyCode = strtoupper((string)($GLOBALS['defaultCurrency'] ?? 'USD'));
        }
        if ($currencyCode === '') {
            $currencyCode = 'USD';
        }
        $time = time();
        $resolvedOrderKey = trim((string)$orderKey);

        $existingRow = null;
        if ($resolvedOrderKey !== '') {
            $existingRow = DB::one(
                "SELECT payment_id, order_key, payment_status FROM i_user_payments WHERE order_key = ? AND payment_type = 'subscription' LIMIT 1",
                [$resolvedOrderKey]
            );
        }
        if (!$existingRow) {
            $recentThreshold = $time - 3600;
            $existingRow = DB::one(
                "SELECT payment_id, order_key, payment_status
                 FROM i_user_payments
                 WHERE payer_iuid_fk = ? AND payed_iuid_fk = ? AND payment_type = 'subscription' AND payment_option = ? AND payment_time >= ?
                 ORDER BY payment_id DESC
                 LIMIT 1",
                [$payerId, $payedId, $paymentOption, $recentThreshold]
            );
        }

        if ($existingRow && empty($resolvedOrderKey)) {
            $resolvedOrderKey = (string)($existingRow['order_key'] ?? '');
        }
        if ($resolvedOrderKey === '') {
            $resolvedOrderKey = $this->iN_GenerateSubscriptionOrderKey($scope === 'community_plan' ? 'community_plan' : 'community_sub');
        }

        $paymentId = 0;
        if ($existingRow && !empty($existingRow['payment_id'])) {
            $paymentId = (int)$existingRow['payment_id'];
            $updateFields = [
                "payer_iuid_fk = ?",
                "payed_iuid_fk = ?",
                "order_key = ?",
                "payment_option = ?",
                "payment_time = ?",
                "payment_status = 'ok'",
                "amount = ?",
                "currency = ?"
            ];
            $updateParams = [
                $payerId,
                $payedId,
                $resolvedOrderKey,
                $paymentOption,
                $time,
                $amountString,
                $currencyCode
            ];

            if ($this->tableColumnExists('i_user_payments', 'fee')) {
                $updateFields[] = "fee = ?";
                $updateParams[] = number_format((float)$fee, 2, '.', '');
            }
            if ($this->tableColumnExists('i_user_payments', 'agency_fee')) {
                $updateFields[] = "agency_fee = ?";
                $updateParams[] = number_format((float)$agencyFee, 2, '.', '');
            }
            if ($this->tableColumnExists('i_user_payments', 'admin_earning')) {
                $updateFields[] = "admin_earning = ?";
                $updateParams[] = number_format((float)$adminEarning, 2, '.', '');
            }
            if ($this->tableColumnExists('i_user_payments', 'agency_earning')) {
                $updateFields[] = "agency_earning = ?";
                $updateParams[] = number_format((float)$agencyEarning, 2, '.', '');
            }
            if ($this->tableColumnExists('i_user_payments', 'user_earning')) {
                $updateFields[] = "user_earning = ?";
                $updateParams[] = number_format((float)$userEarning, 2, '.', '');
            }
            if ($this->tableColumnExists('i_user_payments', 'agency_id_fk')) {
                $updateFields[] = "agency_id_fk = ?";
                $updateParams[] = $agencyId;
            }
            if ($this->tableColumnExists('i_user_payments', 'subscription_scope')) {
                $updateFields[] = "subscription_scope = ?";
                $updateParams[] = $scope;
            }
            if ($this->tableColumnExists('i_user_payments', 'subscription_ref_id')) {
                $updateFields[] = "subscription_ref_id = ?";
                $updateParams[] = $scopeRefId;
            }
            if ($gatewayReference !== null && $gatewayReference !== '' && $this->tableColumnExists('i_user_payments', 'invoice_number')) {
                $updateFields[] = "invoice_number = CASE WHEN invoice_number IS NULL OR invoice_number = '' THEN ? ELSE invoice_number END";
                $updateParams[] = (string)$gatewayReference;
            }
            $updateParams[] = $paymentId;
            DB::exec("UPDATE i_user_payments SET " . implode(', ', $updateFields) . " WHERE payment_id = ?", $updateParams);
        } else {
            $insertColumns = [
                'payer_iuid_fk',
                'payed_iuid_fk',
                'order_key',
                'payment_type',
                'payment_option',
                'payment_time',
                'payment_status',
                'amount',
                'currency'
            ];
            $insertValues = [
                $payerId,
                $payedId,
                $resolvedOrderKey,
                'subscription',
                $paymentOption,
                $time,
                'ok',
                $amountString,
                $currencyCode
            ];

            if ($this->tableColumnExists('i_user_payments', 'fee')) {
                $insertColumns[] = 'fee';
                $insertValues[] = number_format((float)$fee, 2, '.', '');
            }
            if ($this->tableColumnExists('i_user_payments', 'agency_fee')) {
                $insertColumns[] = 'agency_fee';
                $insertValues[] = number_format((float)$agencyFee, 2, '.', '');
            }
            if ($this->tableColumnExists('i_user_payments', 'admin_earning')) {
                $insertColumns[] = 'admin_earning';
                $insertValues[] = number_format((float)$adminEarning, 2, '.', '');
            }
            if ($this->tableColumnExists('i_user_payments', 'agency_earning')) {
                $insertColumns[] = 'agency_earning';
                $insertValues[] = number_format((float)$agencyEarning, 2, '.', '');
            }
            if ($this->tableColumnExists('i_user_payments', 'user_earning')) {
                $insertColumns[] = 'user_earning';
                $insertValues[] = number_format((float)$userEarning, 2, '.', '');
            }
            if ($this->tableColumnExists('i_user_payments', 'agency_id_fk')) {
                $insertColumns[] = 'agency_id_fk';
                $insertValues[] = $agencyId;
            }
            if ($this->tableColumnExists('i_user_payments', 'subscription_scope')) {
                $insertColumns[] = 'subscription_scope';
                $insertValues[] = $scope;
            }
            if ($this->tableColumnExists('i_user_payments', 'subscription_ref_id')) {
                $insertColumns[] = 'subscription_ref_id';
                $insertValues[] = $scopeRefId;
            }
            if ($gatewayReference !== null && $gatewayReference !== '' && $this->tableColumnExists('i_user_payments', 'invoice_number')) {
                $insertColumns[] = 'invoice_number';
                $insertValues[] = (string)$gatewayReference;
            }

            $placeholders = implode(',', array_fill(0, count($insertColumns), '?'));
            DB::exec(
                "INSERT INTO i_user_payments (" . implode(',', $insertColumns) . ") VALUES ($placeholders)",
                $insertValues
            );
            $paymentId = (int)DB::lastId();
        }

        if ($paymentId > 0 && $amountValue > 0) {
            $this->iN_AssignInvoiceToPayment($paymentId, $payerId, $amountValue, $currencyCode);
        }

        $this->lastSubscriptionPaymentOrderKey = $resolvedOrderKey;
        $this->lastSubscriptionPaymentId = $paymentId;
        return $paymentId > 0 ? $paymentId : null;
    }

    public function iN_GetLastSubscriptionPaymentOrderKey(): ?string
    {
        $orderKey = trim((string)$this->lastSubscriptionPaymentOrderKey);
        return $orderKey !== '' ? $orderKey : null;
    }

    public function iN_GetLastSubscriptionPaymentID(): int
    {
        return (int)$this->lastSubscriptionPaymentId;
    }
	/*Insert User Subscription*/
public function iN_InsertUserSubscription($userID, $subscribedUserID, $planType, $subscriberName, $subscrID, $custID, $planIDs, $planAmount, $adminEarning, $userNetEarning, $planCurrency, $planinterval, $planIntervalCount, $subscriberEmail, $plancreated, $current_period_start, $current_period_end, $planStatus) {
		if ($this->iN_CheckUserExist($userID) == 1 && $this->iN_CheckUserExist($subscribedUserID) == 1) {
            $this->iN_EnsureSubscriptionPaymentMethodSupports($planType);
            $planAmountValue = (float)$planAmount;
            $adminFeeRate = isset($GLOBALS['adminFee']) ? (float)$GLOBALS['adminFee'] : 0.0;
            $split = $this->iN_CalculateAgencySplit($subscribedUserID, $planAmountValue, $adminFeeRate);
            $adminEarning = $split['admin_earning'];
            $userNetEarning = $split['creator_net'];
            $agencyId = $split['agency_id'];
            $agencyFee = $split['agency_fee'];
            $agencyEarning = $split['agency_earning'];
            DB::exec(
                "INSERT INTO i_user_subscriptions (iuid_fk, subscribed_iuid_fk, subscriber_name, payment_method, payment_subscription_id, customer_id, plan_id, plan_amount, admin_earning, agency_earning, user_net_earning, plan_amount_currency, plan_interval, plan_interval_count, payer_email, created, plan_period_start, plan_period_end, status, subscription_scope, subscription_ref_id, agency_id_fk, fee, agency_fee)
                 VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)",
                [
                    (int)$userID, (int)$subscribedUserID, (string)$subscriberName, (string)$planType, (string)$subscrID, (string)$custID,
                    (string)$planIDs, (string)$planAmount, (string)$adminEarning, (string)$agencyEarning, (string)$userNetEarning, (string)$planCurrency,
                    (string)$planinterval, (string)$planIntervalCount, (string)$subscriberEmail, (string)$plancreated,
                    (string)$current_period_start, (string)$current_period_end, (string)$planStatus, 'profile', null,
                    $agencyId, (string)$adminFeeRate, (string)$agencyFee
                ]
            );
            $time = time();
            $isFollower = (bool) DB::col("SELECT 1 FROM i_friends WHERE fr_one = ? AND fr_two = ? AND fr_status = 'flwr' LIMIT 1", [(int)$userID, (int)$subscribedUserID]);
            if ($isFollower) {
                DB::exec("UPDATE i_friends SET fr_status = 'subscriber', fr_time = ? WHERE fr_one = ? AND fr_two = ?", [$time, (int)$userID, (int)$subscribedUserID]);
            } else if (!$this->iN_CheckUserIsInSubscriber($userID, $subscribedUserID)) {
                DB::exec("INSERT INTO i_friends (fr_one, fr_two, fr_status, fr_time) VALUES (?,?, 'subscriber', ?)", [(int)$userID, (int)$subscribedUserID, $time]);
            }
            return true;
        }
	}
