    public function iN_GetCommunityBySlug($slug, $includeInactive = false) {
        $slug = (string)$slug;
        if ($slug === '') {
            return null;
        }
        $statusSql = $includeInactive ? "" : " AND status = 'active'";
        return DB::one("SELECT * FROM communities WHERE slug = ?{$statusSql} LIMIT 1", [$slug]);
    }

    public function iN_GenerateCommunitySlug($title) {
        $slugSource = mb_substr((string)$title, 0, 80, "utf-8");
        $base = $this->url_slugies($slugSource);
        if ($base === '') {
            $base = 'community';
        }
        $slug = $base;
        $attempt = 0;
        while ($attempt < 10) {
            $exists = (bool) DB::col("SELECT 1 FROM communities WHERE slug = ? LIMIT 1", [$slug]);
            if (!$exists) {
                return $slug;
            }
            $attempt++;
            $slug = $base . '-' . $this->random_code(5);
        }
        return $base . '-' . $this->random_code(8);
    }

    public function iN_CreateCommunity($ownerID, $title, $category, $description, $coverImage, $subscriptionRequired, $monthlyPrice, $memberLimit) {
        if ($this->iN_CheckUserExist($ownerID) != 1) {
            return false;
        }
        $subscriptionRequired = in_array((string)$subscriptionRequired, ['0', '1'], true) ? (string)$subscriptionRequired : '1';
        $slug = $this->iN_GenerateCommunitySlug($title);
        $now = date('Y-m-d H:i:s');
        $limitValue = ($memberLimit !== null && (int)$memberLimit > 0) ? (int)$memberLimit : null;
        $inserted = DB::exec(
            "INSERT INTO communities (owner_user_id, title, slug, category, description, cover_image, subscription_required, monthly_price, member_limit, status, created_at, updated_at)
             VALUES (?,?,?,?,?,?,?,?,?, 'active', ?, ?)",
            [
                (int)$ownerID,
                (string)$title,
                (string)$slug,
                (string)$category,
                $description !== null ? (string)$description : null,
                $coverImage !== null ? (string)$coverImage : null,
                $subscriptionRequired,
                (string)$monthlyPrice,
                $limitValue,
                $now,
                $now
            ]
        );
        if ($inserted > 0) {
            return (int) DB::lastId();
        }
        return false;
    }

