    public function iN_UpdateCommunity($communityID, array $data) {
        if (!$this->iN_CheckCommunityExist($communityID)) {
            return false;
        }
        $fields = [];
        $params = [];
        $map = [
            'title' => 'title',
            'category' => 'category',
            'description' => 'description',
            'cover_image' => 'cover_image',
            'avatar_image' => 'avatar_image',
            'monthly_price' => 'monthly_price',
            'member_limit' => 'member_limit',
            'posting_enabled' => 'posting_enabled',
            'posting_policy' => 'posting_policy',
            'comment_policy' => 'comment_policy',
            'subscription_required' => 'subscription_required',
            'access_policy' => 'access_policy',
            'status' => 'status'
        ];
        foreach ($map as $key => $column) {
            if (array_key_exists($key, $data)) {
                $fields[] = "{$column} = ?";
                $params[] = $data[$key];
            }
        }
        if (empty($fields)) {
            return false;
        }
        $fields[] = "updated_at = ?";
        $params[] = date('Y-m-d H:i:s');
        $params[] = (int)$communityID;
        DB::exec("UPDATE communities SET " . implode(', ', $fields) . " WHERE id = ?", $params);
        return true;
    }

    public function iN_GetCommunitiesForAdmin($limit = 100) {
        $limit = (int)$limit;
        if ($limit < 1) {
            $limit = 100;
        }
        $rows = DB::all(
            "SELECT c.*, u.i_username, u.i_user_fullname
             FROM communities c
             LEFT JOIN i_users u ON c.owner_user_id = u.iuid
             ORDER BY c.created_at DESC
             LIMIT ?",
            [$limit]
        );
        return !empty($rows) ? $rows : [];
    }

    public function iN_GetCommunityMembersCount($communityID, $status = 'active') {
        if (!$this->iN_CheckCommunityExist($communityID)) {
            return 0;
        }
        return (int) DB::col(
            "SELECT COUNT(*)
             FROM community_memberships m
             INNER JOIN communities c ON c.id = m.community_id
             LEFT JOIN i_user_subscriptions s ON s.subscription_id = m.subscription_id AND s.iuid_fk = m.user_id
             WHERE m.community_id = ? AND m.status = ?
               AND (
                    c.subscription_required = '0'
                    OR (
                        m.subscription_id IS NOT NULL
                        AND s.subscription_id IS NOT NULL
                        AND s.status = 'active'
                        AND s.finished = '0'
                        AND s.subscription_scope = 'community'
                        AND (s.subscription_ref_id = m.community_id OR s.subscription_ref_id IS NULL)
                    )
               )",
            [(int)$communityID, (string)$status]
        );
    }

