    public function iN_IsCommunityPaidMember($communityID, $userID) {
        return (bool) DB::col(
            "SELECT 1
             FROM community_memberships m
             INNER JOIN i_user_subscriptions s ON s.subscription_id = m.subscription_id AND s.iuid_fk = m.user_id
             WHERE m.community_id = ? AND m.user_id = ? AND m.status = 'active'
               AND m.subscription_id IS NOT NULL
               AND s.status = 'active'
               AND s.finished = '0'
               AND s.subscription_scope = 'community'
               AND (s.subscription_ref_id = m.community_id OR s.subscription_ref_id IS NULL)
             LIMIT 1",
            [(int)$communityID, (int)$userID]
        );
    }

    public function iN_IsCommunityAccessMember(array $communityData, $userID) {
        $communityID = (int)($communityData['id'] ?? 0);
        if ($communityID <= 0 || (int)$userID <= 0) {
            return false;
        }
        $subscriptionRequired = (string)($communityData['subscription_required'] ?? '1');
        if ($subscriptionRequired === '1') {
            return $this->iN_IsCommunityPaidMember($communityID, $userID);
        }
        return $this->iN_IsCommunityMember($communityID, $userID);
    }

    public function iN_CanAccessCommunity(array $communityData, $userID, $isAdmin = false, $isModerator = false) {
        $communityID = (int)($communityData['id'] ?? 0);
        if ($communityID <= 0 || (int)$userID <= 0) {
            return false;
        }
        if ((int)($communityData['owner_user_id'] ?? 0) === (int)$userID) {
            return true;
        }
        if ($isAdmin || $isModerator) {
            return true;
        }
        return $this->iN_IsCommunityAccessMember($communityData, $userID);
    }

    public function iN_CreateCommunityMembership($communityID, $userID, $subscriptionID, $status, $startedAt = null, $endedAt = null) {
        $now = date('Y-m-d H:i:s');
        $startedAt = $startedAt ?: $now;
        DB::exec(
            "INSERT INTO community_memberships (community_id, user_id, subscription_id, status, started_at, ended_at, created_at)
             VALUES (?,?,?,?,?,?,?)
             ON DUPLICATE KEY UPDATE subscription_id = VALUES(subscription_id), status = VALUES(status), started_at = VALUES(started_at), ended_at = VALUES(ended_at)",
            [
                (int)$communityID,
                (int)$userID,
                $subscriptionID !== null ? (int)$subscriptionID : null,
                (string)$status,
                (string)$startedAt,
                $endedAt !== null ? (string)$endedAt : null,
                $now
            ]
        );
        return true;
