    public function iN_GetCommunityMembers($communityID, $limit = 50) {
        $communityID = (int)$communityID;
        $limit = (int)$limit;
        $limitSql = '';
        $params = [$communityID];
        if ($limit > 0) {
            $limitSql = ' LIMIT ?';
            $params[] = $limit;
        }
        $rows = DB::all(
            "SELECT m.user_id, m.status, m.created_at,
                    u.i_username, u.i_user_fullname, u.user_avatar,
                    r.status AS restriction_status
             FROM community_memberships m
             INNER JOIN communities c ON c.id = m.community_id
             INNER JOIN i_users u ON m.user_id = u.iuid AND u.uStatus IN('1','3')
             LEFT JOIN i_user_subscriptions s ON s.subscription_id = m.subscription_id AND s.iuid_fk = m.user_id
             LEFT JOIN community_member_restrictions r
               ON r.community_id = m.community_id AND r.user_id = m.user_id
             WHERE m.community_id = ? AND m.status = 'active'
               AND (
                    c.subscription_required = '0'
                    OR (
                        m.subscription_id IS NOT NULL
                        AND s.subscription_id IS NOT NULL
                        AND s.status = 'active'
                        AND s.finished = '0'
                        AND s.subscription_scope = 'community'
                        AND (s.subscription_ref_id = m.community_id OR s.subscription_ref_id IS NULL)
                    )
               )
             ORDER BY m.created_at DESC{$limitSql}",
            $params
        );
        return !empty($rows) ? $rows : [];
    }

    public function iN_GetCommunityModerationUsers($communityID, $limit = 50) {
        $communityID = (int)$communityID;
        $limit = (int)$limit;
        if ($limit < 1) {
            $limit = 50;
        }
        $rows = DB::all(
            "SELECT u.iuid AS user_id, u.i_username, u.i_user_fullname, u.user_avatar,
                    IFNULL(r.status, 'active') AS restriction_status,
                    IFNULL(mc.reshare_disabled, '0') AS reshare_disabled,
                    IFNULL(mc.post_disabled, '0') AS post_disabled,
                    IFNULL(mc.comment_disabled, '0') AS comment_disabled,
                    mc.view_until,
                    IFNULL(mc.view_permanent, '0') AS view_permanent,
                    IF(m.user_id IS NULL, 0, 1) AS is_member,
                    COALESCE(r.updated_at, r.created_at, mc.updated_at, m.created_at) AS sort_time
             FROM i_users u
             LEFT JOIN community_memberships m
               ON m.community_id = ? AND m.user_id = u.iuid AND m.status = 'active'
             LEFT JOIN community_member_restrictions r
               ON r.community_id = ? AND r.user_id = u.iuid
             LEFT JOIN community_member_controls mc
               ON mc.community_id = ? AND mc.user_id = u.iuid
             WHERE (m.user_id IS NOT NULL OR r.user_id IS NOT NULL OR mc.user_id IS NOT NULL)
             AND u.uStatus IN('1','3')
             ORDER BY is_member DESC, sort_time DESC
             LIMIT {$limit}",
            [$communityID, $communityID, $communityID]
        );
        return !empty($rows) ? $rows : [];
    }

    public function iN_GetCommunityModerationCandidates($userID, $limit = 24) {
        $userID = (int)$userID;
        $limit = (int)$limit;
        if ($limit < 1) {
            $limit = 24;
        }
        $rows = DB::all(
            "SELECT * FROM (
                SELECT DISTINCT u.iuid, u.i_username, u.i_user_fullname, u.user_avatar
                FROM i_friends f
                INNER JOIN i_users u ON f.fr_two = u.iuid AND u.uStatus IN('1','3')
                WHERE f.fr_one = ? AND f.fr_status = 'flwr' AND u.iuid <> ?
                UNION
                SELECT DISTINCT u.iuid, u.i_username, u.i_user_fullname, u.user_avatar
                FROM i_friends f
                INNER JOIN i_users u ON f.fr_one = u.iuid AND u.uStatus IN('1','3')
                WHERE f.fr_two = ? AND f.fr_status = 'flwr' AND u.iuid <> ?
            ) AS candidates
            ORDER BY iuid DESC
            LIMIT {$limit}",
            [$userID, $userID, $userID, $userID]
        );
        return !empty($rows) ? $rows : [];
    }

    public function iN_SearchCommunityModerationCandidates($userID, $searchKey, $limit = 24) {
        $userID = (int)$userID;
        $limit = (int)$limit;
        if ($limit < 1) {
            $limit = 24;
        }
        $searchKey = trim((string)$searchKey);
        if ($searchKey === '') {
            return [];
        }
        $likeKey = '%' . $searchKey . '%';
        $rows = DB::all(
            "SELECT * FROM (
                SELECT DISTINCT u.iuid, u.i_username, u.i_user_fullname, u.user_avatar
                FROM i_friends f
                INNER JOIN i_users u ON f.fr_two = u.iuid AND u.uStatus IN('1','3')
                WHERE f.fr_one = ? AND f.fr_status = 'flwr' AND u.iuid <> ?
                  AND (u.i_username LIKE ? OR u.i_user_fullname LIKE ?)
                UNION
                SELECT DISTINCT u.iuid, u.i_username, u.i_user_fullname, u.user_avatar
                FROM i_friends f
                INNER JOIN i_users u ON f.fr_one = u.iuid AND u.uStatus IN('1','3')
                WHERE f.fr_two = ? AND f.fr_status = 'flwr' AND u.iuid <> ?
                  AND (u.i_username LIKE ? OR u.i_user_fullname LIKE ?)
            ) AS candidates
            ORDER BY iuid DESC
            LIMIT {$limit}",
            [$userID, $userID, $likeKey, $likeKey, $userID, $userID, $likeKey, $likeKey]
        );
        return !empty($rows) ? $rows : [];
    }

    public function iN_SearchCommunityModeratorCandidates($searchKey, $limit = 24) {
        $limit = (int)$limit;
        if ($limit < 1) {
            $limit = 24;
        }
        $searchKey = trim((string)$searchKey);
