            return [];
        }
        $likeKey = '%' . $searchKey . '%';
        $rows = DB::all(
            "SELECT iuid, i_username, i_user_fullname, user_avatar
             FROM i_users
             WHERE uStatus IN('1','3')
               AND (i_username LIKE ? OR i_user_fullname LIKE ?)
             ORDER BY iuid DESC
             LIMIT {$limit}",
            [$likeKey, $likeKey]
        );
        return !empty($rows) ? $rows : [];
    }

