            'can_manage_view_timeout' => !empty($permissions['can_manage_view_timeout']) ? '1' : '0',
            'can_manage_media' => !empty($permissions['can_manage_media']) ? '1' : '0'
        ];
        DB::exec(
            "INSERT INTO community_moderators
                (community_id, user_id, assigned_by, can_manage_members, can_manage_posts, can_manage_comments, can_manage_reshare, can_manage_view_timeout, can_manage_media, created_at, updated_at)
             VALUES (?,?,?,?,?,?,?,?,?,?,?)
             ON DUPLICATE KEY UPDATE
