                can_manage_view_timeout = VALUES(can_manage_view_timeout),
                can_manage_media = VALUES(can_manage_media),
                updated_at = VALUES(updated_at)",
            [
                (int)$communityID,
                (int)$userID,
                $assignedBy !== null ? (int)$assignedBy : null,
                $flags['can_manage_members'],
                $flags['can_manage_posts'],
                $flags['can_manage_comments'],
                $flags['can_manage_reshare'],
                $flags['can_manage_view_timeout'],
                $flags['can_manage_media'],
                $now,
                $now
            ]
        );
        return true;
    }

