    public function iN_SetCommunityMemberControl($communityID, $userID, array $data, $moderatorID) {
        $current = $this->iN_GetCommunityMemberControl($communityID, $userID);
        $reshareDisabled = array_key_exists('reshare_disabled', $data)
            ? ((string)$data['reshare_disabled'] === '1' ? '1' : '0')
            : ((string)($current['reshare_disabled'] ?? '0') === '1' ? '1' : '0');
        $postDisabled = array_key_exists('post_disabled', $data)
            ? ((string)$data['post_disabled'] === '1' ? '1' : '0')
            : ((string)($current['post_disabled'] ?? '0') === '1' ? '1' : '0');
        $commentDisabled = array_key_exists('comment_disabled', $data)
            ? ((string)$data['comment_disabled'] === '1' ? '1' : '0')
            : ((string)($current['comment_disabled'] ?? '0') === '1' ? '1' : '0');
        $viewUntil = array_key_exists('view_until', $data)
            ? ($data['view_until'] !== null ? (string)$data['view_until'] : null)
            : ($current['view_until'] ?? null);
        $viewPermanent = array_key_exists('view_permanent', $data)
            ? ((string)$data['view_permanent'] === '1' ? '1' : '0')
            : ((string)($current['view_permanent'] ?? '0') === '1' ? '1' : '0');
        $now = date('Y-m-d H:i:s');
        DB::exec(
            "INSERT INTO community_member_controls
                (community_id, user_id, reshare_disabled, post_disabled, comment_disabled, view_until, view_permanent, created_by, created_at, updated_at)
             VALUES (?,?,?,?,?,?,?,?,?,?)
             ON DUPLICATE KEY UPDATE
                reshare_disabled = VALUES(reshare_disabled),
                post_disabled = VALUES(post_disabled),
                comment_disabled = VALUES(comment_disabled),
                view_until = VALUES(view_until),
                view_permanent = VALUES(view_permanent),
                created_by = VALUES(created_by),
                updated_at = VALUES(updated_at)",
            [
                (int)$communityID,
                (int)$userID,
                $reshareDisabled,
                $postDisabled,
                $commentDisabled,
                $viewUntil,
                $viewPermanent,
                $moderatorID !== null ? (int)$moderatorID : null,
                $now,
                $now
            ]
        );
        return true;
    }

