    public function iN_GetCommunityViewRestriction($communityID, $userID) {
        $row = DB::one(
            "SELECT view_until, view_permanent FROM community_member_controls WHERE community_id = ? AND user_id = ? LIMIT 1",
            [(int)$communityID, (int)$userID]
        );
        if (!$row) {
            return [
                'restricted' => false,
                'view_until' => null,
                'view_permanent' => false,
                'has_control' => false
            ];
        }
        $viewPermanent = (string)($row['view_permanent'] ?? '0') === '1';
        $viewUntil = $row['view_until'] ?? null;
        $restricted = $viewPermanent;
        if (!$restricted && !empty($viewUntil)) {
            $restricted = strtotime((string)$viewUntil) > time();
        }
        return [
            'restricted' => $restricted,
            'view_until' => $viewUntil,
            'view_permanent' => $viewPermanent,
            'has_control' => true
        ];
    }

