            [$communityID, $userID]
        );
        if ($hasControl) {
            return true;
        }
        return (bool) DB::col(
            "SELECT 1 FROM community_member_restrictions WHERE community_id = ? AND user_id = ? LIMIT 1",
            [$communityID, $userID]
        );
    }

    public function iN_GetCommunityTimeoutOptions(array $communityData): array {
        $defaults = ['1', '3', '7', '30', 'permanent'];
        $raw = trim((string)($communityData['moderation_timeout_options'] ?? ''));
        if ($raw === '') {
            return $defaults;
        }
        $parts = array_filter(array_map('trim', explode(',', $raw)));
        $filtered = [];
        foreach ($parts as $part) {
            if (in_array($part, $defaults, true)) {
                $filtered[] = $part;
            }
        }
        if (empty($filtered)) {
            return $defaults;
        }
        return array_values(array_unique($filtered));
    }

    public function iN_LogCommunityModeratorAction($communityID, $moderatorID, $actionType, array $targets = [], array $data = []) {
