                (community_id, moderator_id, action_type, target_user_id, target_post_id, target_comment_id, action_data, created_at)
             VALUES (?,?,?,?,?,?,?,?)",
            [
                (int)$communityID,
                (int)$moderatorID,
                (string)$actionType,
                isset($targets['user_id']) ? (int)$targets['user_id'] : null,
                isset($targets['post_id']) ? (int)$targets['post_id'] : null,
                isset($targets['comment_id']) ? (int)$targets['comment_id'] : null,
                $payload,
                $now
            ]
        );
        return (int) DB::lastId();
    }

