    public function iN_GetCommunityPostMetaByPostIds(array $postIds): array {
        $postIds = array_values(array_filter(array_map('intval', $postIds)));
        if (empty($postIds)) {
            return [];
        }
        $placeholders = implode(',', array_fill(0, count($postIds), '?'));
        $rows = DB::all(
            "SELECT cp.post_id, cp.is_hidden, cp.hidden_by, cp.hidden_at,
                    c.id AS community_id, c.title, c.slug, c.category, c.moderation_enabled
             FROM community_posts cp
             INNER JOIN communities c ON cp.community_id = c.id
             WHERE cp.post_id IN ({$placeholders})",
            $postIds
        );
        $meta = [];
        foreach ($rows as $row) {
            $meta[(int)$row['post_id']] = $row;
        }
        return $meta;
    }

