    public function iN_GetCommunityPosts($communityID, $viewerID, $lastPostID, $showingPost) {
        $communityID = (int)$communityID;
        $showingPosts = (int)$showingPost;
        $params = [$communityID];
        $more = '';
        if (!empty($lastPostID)) {
            $more = ' AND P.post_id < ?';
            $params[] = (int)$lastPostID;
        }
        [$scheduledSql, $scheduledParams] = $this->scheduledVisibilityClause($viewerID ? (int)$viewerID : null, 'P');
        $linkSelect = $this->iN_PostLinkPreviewSelect();
        $sql = "SELECT DISTINCT P.post_id,P.shared_post_id,P.post_pined,P.comment_status,
                P.post_owner_id,P.post_text,P.post_file,P.post_created_time,P.scheduled_at,P.scheduled_status,
                P.who_can_see,P.post_want_status,P.url_slug,P.post_wanted_credit,
                P.post_status,P.post_type,P.hashtags{$linkSelect},
                U.iuid,U.i_username,U.i_user_fullname,U.user_avatar,U.user_gender,
                U.payout_method,U.last_login_time,U.user_verified_status,
                U.thanks_for_tip,U.user_frame,U.profile_category
            FROM community_posts CP
            INNER JOIN i_posts P ON CP.post_id = P.post_id AND P.post_type NOT IN('reels')
            INNER JOIN i_users U ON P.post_owner_id = U.iuid AND U.uStatus IN('1','3')
            WHERE CP.community_id = ? AND IFNULL(CP.is_hidden, '0') = '0' $more AND $scheduledSql
            ORDER BY P.post_id DESC
            LIMIT $showingPosts";
        $rows = DB::all($sql, array_merge($params, $scheduledParams));
        return !empty($rows) ? $rows : null;
    }

    public function iN_GetCommunityMediaPreviews($communityID, $viewerID, $limit = 24) {
        $communityID = (int)$communityID;
        $viewerID = (int)$viewerID;
        $limit = (int)$limit;
        if ($limit < 1) {
            $limit = 12;
        }
        if ($limit > 48) {
            $limit = 48;
        }
        $params = [$communityID];
        [$scheduledSql, $scheduledParams] = $this->scheduledVisibilityClause($viewerID ?: null, 'P');
        $sql = "SELECT DISTINCT P.post_id, P.url_slug, P.post_file, P.post_type
            FROM community_posts CP
            INNER JOIN i_posts P ON CP.post_id = P.post_id AND P.post_type NOT IN('reels')
            WHERE CP.community_id = ? AND IFNULL(CP.is_hidden, '0') = '0'
              AND P.post_status = '1' AND P.post_file <> '' AND P.post_file IS NOT NULL
              AND $scheduledSql
            ORDER BY P.post_id DESC
            LIMIT $limit";
        $rows = DB::all($sql, array_merge($params, $scheduledParams));
        return !empty($rows) ? $rows : null;
    }

    public function iN_InsertCommunitySubscription($subscriberID, $communityID, $ownerID, $subscriberName, $paymentMethod, $subscrID, $custID, $planIDs, $planAmount, $adminEarning, $userNetEarning, $planCurrency, $planinterval, $planIntervalCount, $subscriberEmail, $plancreated, $current_period_start, $current_period_end, $planStatus) {
        if ($this->iN_CheckUserExist($subscriberID) != 1 || !$this->iN_CheckCommunityExist($communityID)) {
            return false;
        }
        $this->lastSubscriptionPaymentOrderKey = null;
        $this->lastSubscriptionPaymentId = 0;
        $this->iN_EnsureSubscriptionPaymentMethodSupports($paymentMethod);
        $planAmountValue = (float)$planAmount;
        $adminFeeRate = isset($GLOBALS['adminFee']) ? (float)$GLOBALS['adminFee'] : 0.0;
        $split = $this->iN_CalculateAgencySplit($ownerID, $planAmountValue, $adminFeeRate);
        $adminEarning = $split['admin_earning'];
        $userNetEarning = $split['creator_net'];
        $agencyId = $split['agency_id'];
        $agencyFee = $split['agency_fee'];
        $agencyEarning = $split['agency_earning'];
        DB::exec(
            "INSERT INTO i_user_subscriptions (iuid_fk, subscribed_iuid_fk, subscriber_name, payment_method, payment_subscription_id, customer_id, plan_id, plan_amount, admin_earning, agency_earning, user_net_earning, plan_amount_currency, plan_interval, plan_interval_count, payer_email, created, plan_period_start, plan_period_end, status, subscription_scope, subscription_ref_id, agency_id_fk, fee, agency_fee)
             VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)",
            [
                (int)$subscriberID,
                (int)$ownerID,
                (string)$subscriberName,
                (string)$paymentMethod,
                (string)$subscrID,
                (string)$custID,
                (string)$planIDs,
                (string)$planAmount,
                (string)$adminEarning,
                (string)$agencyEarning,
                (string)$userNetEarning,
                (string)$planCurrency,
                (string)$planinterval,
                (string)$planIntervalCount,
                (string)$subscriberEmail,
                (string)$plancreated,
                (string)$current_period_start,
                (string)$current_period_end,
                (string)$planStatus,
                'community',
                (int)$communityID,
                $agencyId,
                (string)$adminFeeRate,
                (string)$agencyFee
            ]
        );
        $subscriptionId = (int) DB::lastId();
        if ($subscriptionId > 0) {
            $this->iN_CreateCommunityMembership($communityID, $subscriberID, $subscriptionId, 'active', $current_period_start, $current_period_end);
            $communityData = $this->iN_GetCommunityById($communityID);
            if ($communityData) {
                $this->iN_InsertCommunityNotification($subscriberID, (int)$ownerID, $communityData, 'community_subscribe');
            }
            $this->iN_RecordSubscriptionPayment(
                (int)$subscriberID,
                (int)$ownerID,
                (string)$paymentMethod,
                (float)$planAmountValue,
                (string)$planCurrency,
                'community',
                (int)$communityID,
                (string)$subscrID,
                (string)$subscrID,
                (float)$adminEarning,
                (float)$userNetEarning,
                (float)$agencyEarning,
                (float)$adminFeeRate,
                (float)$agencyFee,
                $agencyId
            );
            return $subscriptionId;
        }
        return false;
    }

