    public function iN_InsertCommunitySubscriptionWithPoint($subscriberID, $communityID, $ownerID, $subscriberName, $planAmount, $adminEarning, $userNetEarning, $planCurrency, $planinterval, $planIntervalCount, $subscriberEmail, $plancreated, $current_period_start, $current_period_end, $planStatus) {
        if ($this->iN_CheckUserExist($subscriberID) != 1 || !$this->iN_CheckCommunityExist($communityID)) {
            return false;
        }
        $this->lastSubscriptionPaymentOrderKey = null;
        $this->lastSubscriptionPaymentId = 0;
        $planPointAmount = (float)$planAmount;
        $adminFeeRate = isset($GLOBALS['adminFee']) ? (float)$GLOBALS['adminFee'] : 0.0;
        $grossAmount = (float)$adminEarning + (float)$userNetEarning;
        if ($grossAmount <= 0) {
            $grossAmount = $planPointAmount;
        }
        $split = $this->iN_CalculateAgencySplit($ownerID, $grossAmount, $adminFeeRate);
        $adminEarning = $split['admin_earning'];
        $userNetEarning = $split['creator_net'];
        $agencyId = $split['agency_id'];
        $agencyFee = $split['agency_fee'];
        $agencyEarning = $split['agency_earning'];
        $subscriptionId = 0;
        try {
            DB::begin();
            DB::exec(
                "INSERT INTO i_user_subscriptions(iuid_fk, subscribed_iuid_fk, subscriber_name, payment_method, plan_amount, admin_earning, agency_earning, user_net_earning, plan_amount_currency, plan_interval, plan_interval_count, payer_email, created, plan_period_start, plan_period_end, status, subscription_scope, subscription_ref_id, agency_id_fk, fee, agency_fee)
                 VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)",
                [
                    (int)$subscriberID,
                    (int)$ownerID,
                    (string)$subscriberName,
                    'point',
                    (string)$planAmount,
                    (string)$adminEarning,
                    (string)$agencyEarning,
                    (string)$userNetEarning,
                    (string)$planCurrency,
                    (string)$planinterval,
                    (string)$planIntervalCount,
                    (string)$subscriberEmail,
                    (string)$plancreated,
                    (string)$current_period_start,
                    (string)$current_period_end,
                    (string)$planStatus,
                    'community',
                    (int)$communityID,
                    $agencyId,
                    (string)$adminFeeRate,
                    (string)$agencyFee
                ]
            );
            $subscriptionId = (int) DB::lastId();
            if ($subscriptionId > 0) {
                $this->iN_CreateCommunityMembership($communityID, $subscriberID, $subscriptionId, 'active', $current_period_start, $current_period_end);
                DB::exec("UPDATE i_users SET wallet_money = wallet_money + ? WHERE iuid = ?", [(string)$userNetEarning, (int)$ownerID]);
                DB::exec("UPDATE i_users SET wallet_points = wallet_points - ? WHERE iuid = ?", [(string)$planPointAmount, (int)$subscriberID]);
                $communityData = $this->iN_GetCommunityById($communityID);
                if ($communityData) {
                    $this->iN_InsertCommunityNotification($subscriberID, (int)$ownerID, $communityData, 'community_subscribe');
                }
            }
            DB::commit();
        } catch (Throwable $e) {
            DB::rollBack();
            return false;
        }
        if ($subscriptionId > 0) {
            $this->iN_RecordSubscriptionPayment(
                (int)$subscriberID,
                (int)$ownerID,
                'point',
                (float)$grossAmount,
                (string)$planCurrency,
                'community',
                (int)$communityID,
                null,
                null,
                (float)$adminEarning,
                (float)$userNetEarning,
                (float)$agencyEarning,
                (float)$adminFeeRate,
                (float)$agencyFee,
                $agencyId
            );
            return true;
        }
        return false;
    }

