    /**
     * Create a YooKassa payment via API.
     *
     * @param string $shopId
     * @param string $secretKey
     * @param array $payload
     * @param string $idempotenceKey
     * @return array{error:bool,message?:string,data?:array}
     */
    private function iN_CreateYooKassaPaymentRequest(string $shopId, string $secretKey, array $payload, string $idempotenceKey = ''): array
    {
        $endpoint = 'https://api.yookassa.ru/v3/payments';
        $headers = [
            'Accept: application/json',
            'Content-Type: application/json',
            'Authorization: Basic ' . base64_encode($shopId . ':' . $secretKey),
        ];
        if ($idempotenceKey !== '') {
            $headers[] = 'Idempotence-Key: ' . $idempotenceKey;
        }

        $ch = curl_init($endpoint);
        curl_setopt_array($ch, [
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_HTTPHEADER => $headers,
            CURLOPT_TIMEOUT => 30,
            CURLOPT_POST => true,
            CURLOPT_POSTFIELDS => json_encode($payload),
        ]);
        $responseBody = curl_exec($ch);
        $curlError = curl_error($ch);
        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
        curl_close($ch);

        if ($curlError) {
            return ['error' => true, 'message' => $curlError];
        }

        $decoded = json_decode((string)$responseBody, true);
        if (json_last_error() !== JSON_ERROR_NONE) {
            return ['error' => true, 'message' => 'Invalid YooKassa response'];
        }

        if ($httpCode >= 400) {
            return [
                'error' => true,
                'message' => $decoded['description'] ?? $decoded['message'] ?? 'YooKassa request failed',
                'data' => $decoded,
            ];
        }

        return ['error' => false, 'data' => $decoded];
    }

    /**
     * Traffic-triggered renewal runner for YooKassa subscriptions.
     *
     * @return int
     */
    public function iN_RunYooKassaRenewalRunner(): int
    {
        $now = time();
        $cooldownSeconds = 300;
        $lockSeconds = 120;
        $subscriptionLockSeconds = 900;
        $limit = 3;

        if (
            !$this->configColumnExists('runner_last_at')
            || !$this->configColumnExists('runner_lock_until')
        ) {
            return 0;
        }

        $paymentMethodRow = DB::one(
            "SELECT yookassa_payment_mode, yookassa_active_pasive, yookassa_test_shop_id, yookassa_test_secret_key, yookassa_live_shop_id, yookassa_live_secret_key, yookassa_currency
             FROM i_payment_methods WHERE payment_method_id = 1 LIMIT 1"
        );
        if (!$paymentMethodRow || (int)($paymentMethodRow['yookassa_active_pasive'] ?? 0) !== 1) {
            return 0;
        }

        $testMode = (int)($paymentMethodRow['yookassa_payment_mode'] ?? 0) !== 1;
        $shopId = $testMode ? (string)($paymentMethodRow['yookassa_test_shop_id'] ?? '') : (string)($paymentMethodRow['yookassa_live_shop_id'] ?? '');
        $secretKey = $testMode ? (string)($paymentMethodRow['yookassa_test_secret_key'] ?? '') : (string)($paymentMethodRow['yookassa_live_secret_key'] ?? '');
        if ($shopId === '' || $secretKey === '') {
            return 0;
        }
        $defaultCurrency = strtoupper((string)($paymentMethodRow['yookassa_currency'] ?? 'RUB'));
        if ($defaultCurrency === '') {
            $defaultCurrency = 'RUB';
        }

        $lockUpdated = DB::exec(
            "UPDATE i_configurations SET runner_last_at = ?, runner_lock_until = ?
             WHERE configuration_id = 1
               AND (runner_lock_until IS NULL OR runner_lock_until < ?)
               AND (runner_last_at IS NULL OR runner_last_at < ?)",
            [$now, $now + $lockSeconds, $now, $now - $cooldownSeconds]
        );
        if ($lockUpdated < 1) {
            return 0;
        }

        $rows = DB::all(
            "SELECT subscription_id, iuid_fk, subscribed_iuid_fk, subscription_scope, subscription_ref_id, plan_id, plan_amount, plan_amount_currency,
                    plan_interval, plan_interval_count, plan_period_end, payment_subscription_id
             FROM i_user_subscriptions
             WHERE payment_method = 'yookassa'
               AND status = 'active'
               AND finished = '0'
               AND plan_period_end IS NOT NULL
               AND UNIX_TIMESTAMP(plan_period_end) <= ?
               AND (renewal_lock_until IS NULL OR renewal_lock_until < ?)
             ORDER BY plan_period_end ASC
             LIMIT {$limit}",
            [$now, $now]
        );
        if (!$rows) {
            return 0;
        }

        $created = 0;
        foreach ($rows as $row) {
            $subscriptionId = (int)($row['subscription_id'] ?? 0);
            if ($subscriptionId <= 0) {
                continue;
            }

            $locked = DB::exec(
                "UPDATE i_user_subscriptions SET renewal_attempted_at = ?, renewal_lock_until = ?
                 WHERE subscription_id = ? AND (renewal_lock_until IS NULL OR renewal_lock_until < ?)",
                [$now, $now + $subscriptionLockSeconds, $subscriptionId, $now]
            );
            if ($locked < 1) {
                continue;
            }

            $paymentMethodId = trim((string)($row['payment_subscription_id'] ?? ''));
            if ($paymentMethodId === '') {
                continue;
            }

            $amount = (float)($row['plan_amount'] ?? 0);
            if ($amount <= 0) {
                continue;
            }

            try {
                $orderKey = bin2hex(random_bytes(8));
                $idempotenceKey = bin2hex(random_bytes(16));
            } catch (Throwable $e) {
                $orderKey = uniqid('yks_renew_', true);
                $idempotenceKey = uniqid('yks_renew_idem_', true);
            }

            $currency = strtoupper((string)($row['plan_amount_currency'] ?? $defaultCurrency));
            if ($currency === '') {
                $currency = $defaultCurrency;
            }
            $amountFormatted = number_format($amount, 2, '.', '');

            $subscriberId = (int)($row['iuid_fk'] ?? 0);
            $creatorId = (int)($row['subscribed_iuid_fk'] ?? 0);
            $scope = (string)($row['subscription_scope'] ?? 'profile');
            $interval = (string)($row['plan_interval'] ?? 'month');
            $intervalCount = (int)($row['plan_interval_count'] ?? 1);
            if ($intervalCount < 1) {
                $intervalCount = 1;
            }

            $metadata = [
                'subscription_scope' => $scope,
                'subscription_id' => $subscriptionId,
                'plan_id' => (string)($row['plan_id'] ?? ''),
                'plan_interval' => $interval,
                'plan_interval_count' => $intervalCount,
                'subscriber_id' => $subscriberId,
                'creator_id' => $creatorId,
                'order_key' => $orderKey,
            ];
            if ($scope === 'community') {
                $metadata['community_id'] = (int)($row['subscription_ref_id'] ?? 0);
            }

            $paymentRowId = null;
            try {
                DB::exec(
                    "INSERT INTO i_user_payments (payer_iuid_fk, payed_iuid_fk, order_key, payment_type, payment_option, payment_time, payment_status, amount, currency)
                     VALUES (?,?,?,?,?,?,?, ?, ?)",
                    [
                        $subscriberId > 0 ? $subscriberId : null,
                        $creatorId > 0 ? $creatorId : null,
                        (string)$orderKey,
                        'subscription',
                        'yookassa',
                        (int)$now,
                        'pending',
                        (string)$amountFormatted,
                        (string)$currency
                    ]
                );
                $paymentRowId = (int)DB::lastId();
            } catch (Throwable $e) {
                continue;
            }

            $payload = [
                'amount' => [
                    'value' => $amountFormatted,
                    'currency' => $currency,
                ],
                'capture' => true,
                'description' => 'Subscription renewal',
                'metadata' => $metadata,
                'payment_method_id' => $paymentMethodId,
                'confirmation' => null,
            ];

            $response = $this->iN_CreateYooKassaPaymentRequest($shopId, $secretKey, $payload, $idempotenceKey);
            if (!empty($response['error'])) {
                if ($paymentRowId) {
                    DB::exec("DELETE FROM i_user_payments WHERE payment_id = ?", [$paymentRowId]);
                }
                continue;
            }

            $paymentId = $response['data']['id'] ?? '';
            if ($paymentId === '') {
                if ($paymentRowId) {
                    DB::exec("DELETE FROM i_user_payments WHERE payment_id = ?", [$paymentRowId]);
                }
                continue;
            }

            if ($paymentRowId) {
                DB::exec(
                    "UPDATE i_user_payments SET yookassa_payment_id = ?, yookassa_idempotence_key = ? WHERE payment_id = ?",
                    [(string)$paymentId, (string)$idempotenceKey, (int)$paymentRowId]
                );
            }

            $created++;
        }

        return $created;
    }

    public function iN_GetCommunityDirectory($viewerID, $limit = 12, $offset = 0) {
        $viewerID = (int)$viewerID;
        $limit = (int)$limit;
        if ($limit < 1) {
            $limit = 12;
        }
        $offset = (int)$offset;
        if ($offset < 0) {
            $offset = 0;
        }
        return DB::all(
            "SELECT c.*,
                    (SELECT COUNT(*) FROM community_memberships m WHERE m.community_id = c.id AND m.status = 'active') AS member_count,
                    (SELECT 1 FROM community_memberships m2 WHERE m2.community_id = c.id AND m2.user_id = ? AND m2.status = 'active' LIMIT 1) AS is_member,
                    (SELECT 1 FROM community_moderators m3 WHERE m3.community_id = c.id AND m3.user_id = ? LIMIT 1) AS is_moderator,
                    IF(
                        EXISTS(SELECT 1 FROM community_member_controls mc WHERE mc.community_id = c.id AND mc.user_id = ?)
                        OR EXISTS(SELECT 1 FROM community_member_restrictions mr WHERE mr.community_id = c.id AND mr.user_id = ?),
                        1,
                        0
                    ) AS is_moderation_listed
             FROM communities c
             WHERE c.status = 'active'
             ORDER BY c.created_at DESC
             LIMIT ? OFFSET ?",
            [$viewerID, $viewerID, $viewerID, $viewerID, $limit, $offset]
        );
    }
		public function iN_AllUserProfilePosts($uid, $lastPostID, $showingPost, $viewerId = null) {
			$uid = (int) $uid;
			$showingPosts = (int) $showingPost;
			$params = [$uid];
			$lastParams = [];
			$w = '';
	        [$scheduledSql, $scheduledParams] = $this->scheduledVisibilityClause($viewerId ? (int) $viewerId : null, 'P');
			if (!empty($lastPostID)) {
				$w = ' AND P.post_id < ?';
				$lastParams[] = (int) $lastPostID;
			}
			$sql = "SELECT DISTINCT P.*,U.*
			FROM i_friends F
				INNER JOIN i_posts P ON P.post_owner_id = F.fr_two
				INNER JOIN i_users U ON P.post_owner_id = U.iuid AND U.uStatus IN('1','3') AND F.fr_status IN('me', 'flwr', 'subscriber')
			WHERE P.post_owner_id = ? AND P.post_pined = '0' AND $scheduledSql $w
			ORDER BY P.post_id DESC LIMIT $showingPosts";
			$rows = DB::all($sql, array_merge($params, $scheduledParams, $lastParams));
			return !empty($rows) ? $rows : null;
		}
