		/*Insert Payout Settings*/
	public function iN_SetPayout($userID, $paypalEmail, $bankAccount, $defaultMethod, array $payoutMethodData = array()) {
			if ($this->iN_CheckUserExist($userID) == 1) {
				$this->iN_EnsureBankPayoutColumns();
				$updateFields = array(
					'payout_method' => (string)$defaultMethod,
					'payout_status' => '2'
				);
				if ((string)$defaultMethod === 'paypal') {
					$updateFields['paypal_email'] = (string)$paypalEmail;
				}
				if ((string)$defaultMethod === 'bank') {
					$updateFields['bank_account'] = (string)$bankAccount;
				}
				$methodDetailColumnMap = array(
					'payoneer_email' => 'payoneer_email',
					'zelle_email' => 'zelle_email',
					'western_union_full_name' => 'western_union_full_name',
					'western_union_document_id' => 'western_union_document_id',
					'bitcoin_wallet_address' => 'bitcoin_wallet_address',
					'mercadopago_alias' => 'mercadopago_alias',
					'mercadopago_cvu' => 'mercadopago_cvu',
					'bank_country' => 'bank_country',
					'iban_number' => 'iban_number',
					'routing_number' => 'routing_number',
					'account_number' => 'account_number',
					'account_holder_name' => 'account_holder_name',
					'phone_country_code' => 'phone_country_code',
					'phone_number' => 'phone_number',
					'street_address' => 'street_address',
					'country' => 'bank_address_country',
					'state' => 'bank_address_state',
					'city' => 'bank_address_city',
					'postal_code' => 'postal_code'
				);
				foreach ($methodDetailColumnMap as $dataKey => $columnName) {
					if (!array_key_exists($dataKey, $payoutMethodData)) {
						continue;
					}
					if (!$this->iN_TableColumnExists('i_users', $columnName)) {
						continue;
					}
					$updateFields[$columnName] = (string)$payoutMethodData[$dataKey];
				}
				$setParts = array();
				$params = array();
				foreach ($updateFields as $column => $value) {
					$setParts[] = $column . ' = ?';
					$params[] = $value;
				}
				$params[] = (int)$userID;
	            DB::exec("UPDATE i_users SET " . implode(', ', $setParts) . " WHERE iuid = ?", $params);
	            // Auto-submit for admin verification after payout setup
	            DB::exec("UPDATE i_users SET validation_status = '1' WHERE iuid = ? AND validation_status = '0'", [(int)$userID]);
	            return true;
	        } else {
	            return false;
	        }
		}
	/*Update Profile*/
public function iN_UpdateProfile($userID, $fulname, $bio, $newUsername, $birthDay, $profileCategory, $gender, $tipNot) {
		if ($this->iN_CheckUserExist($userID) == 1) {
            $fields = [
                'i_username' => (string)$newUsername,
                'i_user_fullname' => (string)$fulname,
                'user_gender' => (string)$gender,
                'profile_category' => (string)$profileCategory,
                'u_bio' => (string)$bio,
            ];
            if ($birthDay) {
                $fields['birthday'] = $this->iN_CorrectDateFormat($birthDay);
            }
            $fields['thanks_for_tip'] = $tipNot ? (string)$tipNot : null;

            $sets = [];
            $params = [];
            foreach ($fields as $col => $val) { $sets[] = "$col = ?"; $params[] = $val; }
            $params[] = (int)$userID;
            $sql = "UPDATE i_users SET " . implode(', ', $sets) . " WHERE iuid = ?";
            DB::exec($sql, $params);
            return true;
        } else {return false;}
	}
