	/*Check User Password is Valid*/
public function iN_CheckUserPasswordAndUpdateIfIsValid($userID, $pass, $email) {
        if ($this->iN_CheckUserExist($userID) != 1) {
            return false;
        }

        $row = DB::one("SELECT i_password FROM i_users WHERE iuid = ? LIMIT 1", [(int)$userID]);
        if (!$row || !isset($row['i_password'])) {
            return false;
        }

        $storedHash = (string)$row['i_password'];

        $isValid = false;
        if (strlen($storedHash) >= 60 && (str_starts_with($storedHash, '$2y$') || str_starts_with($storedHash, '$argon2'))) {
            $isValid = password_verify($pass, $storedHash);
        } else {
            $legacy = sha1(md5($pass));
            $isValid = hash_equals($storedHash, $legacy);
            if ($isValid) {
                $newHash = password_hash($pass, PASSWORD_DEFAULT);
                DB::exec("UPDATE i_users SET i_password = ? WHERE iuid = ?", [$newHash, (int)$userID]);
            }
        }

        if (!$isValid) {
            return false;
        }

        DB::exec("UPDATE i_users SET i_user_email = ? WHERE iuid = ?", [(string)$email, (int)$userID]);
        return true;
	}
