	/*Buy Post*/
public function iN_BuyPost($userID, $userPostOwnerID, $PurchasePostID, $amount, $adminEarning, $userEarning, $fee, $credit) {

		if ($this->iN_CheckUserExist($userID) == '1' && $this->iN_CheckUserExist($userPostOwnerID) == '1' && $this->iN_CheckPostIDExist($PurchasePostID) == '1' && $this->iN_CheckUserPurchasedThisPost($userID, $PurchasePostID) == '0') {
			$time = time();
            $split = $this->iN_CalculateAgencySplit($userPostOwnerID, $amount, $fee);
            $adminEarning = $split['admin_earning'];
            $userEarning = $split['creator_net'];
            $agencyId = $split['agency_id'];
            $agencyFee = $split['agency_fee'];
            $agencyEarning = $split['agency_earning'];
			DB::exec("INSERT INTO i_user_payments (payer_iuid_fk, payed_iuid_fk, agency_id_fk, payed_post_id_fk, payment_type, payment_time, payment_status, amount, fee, agency_fee, admin_earning, agency_earning, user_earning)
                        VALUES (?,?,?,?, 'post', ?, 'ok', ?, ?, ?, ?, ?, ?)",
                        [(int)$userID, (int)$userPostOwnerID, $agencyId, (int)$PurchasePostID, $time, (string)$amount, (string)$fee, (string)$agencyFee, (string)$adminEarning, (string)$agencyEarning, (string)$userEarning]
                );
            $paymentId = (int) DB::lastId();
			DB::exec("UPDATE i_users SET wallet_points = wallet_points - ? WHERE iuid = ?", [(string)$credit, (int)$userID]);
			DB::exec("UPDATE i_users SET wallet_money = wallet_money + ? WHERE iuid = ?", [(string)$userEarning, (int)$userPostOwnerID]);
            if ($paymentId > 0) {
                $currency = $GLOBALS['defaultCurrency'] ?? 'USD';
                $this->iN_AssignInvoiceToPayment($paymentId, (int)$userID, (float)$amount, $currency);
            }
			return true;
		} else {
			return false;
		}
	}
