	/*Update User Typing*/
	public function iN_UpdateTypingStatus($userID, $conversationID, $time) {
		if ($this->iN_CheckUserExist($userID) == '1' && $this->iN_CheckChatIDExist($conversationID) == '1') {
            $chatData = $this->iN_GetChatUserIDs($conversationID);
            if (!$chatData) {
                return;
            }
            $typingField = ((int)$chatData['user_one'] === (int)$userID) ? 'typing_user_one' : 'typing_user_two';
			DB::exec("UPDATE i_chat_users SET {$typingField} = ? WHERE chat_id = ?", [(string)$time, (int)$conversationID]);
		}
	}
