	/**
	 * Build visibility filters for user listings based on block/restrict and country privacy.
	 * @param int|null $viewerId
	 * @param string|null $viewerCountryCode
	 * @param string $userAlias
	 * @return array{0: array, 1: array}
	 */
	protected function iN_BuildUserVisibilityFilter($viewerId, $viewerCountryCode, $userAlias = 'U') {
		$alias = preg_replace('/[^a-zA-Z0-9_]/', '', (string)$userAlias);
		if ($alias === '') {
			$alias = 'U';
		}
		$viewerId = (int)($viewerId ?? 0);
		$clauses = [];
		$params = [];

		if ($viewerId > 0) {
			$clauses[] = "NOT EXISTS (
				SELECT 1 FROM i_user_blocks ub
				WHERE (ub.blocker_iuid = {$alias}.iuid AND ub.blocked_iuid = ?)
				   OR (ub.blocker_iuid = ? AND ub.blocked_iuid = {$alias}.iuid)
				LIMIT 1
			)";
			$params[] = $viewerId;
			$params[] = $viewerId;
		}

		$country = strtoupper(trim((string)$viewerCountryCode));
		if ($country !== '' && preg_match('/^[A-Z]{2}$/', $country)) {
			$clauses[] = "NOT EXISTS (
				SELECT 1 FROM i_user_blocked_countries bc
				WHERE bc.b_iuid_fk = {$alias}.iuid AND bc.b_country = ?
				LIMIT 1
			)";
			$params[] = $country;
		}

		return [$clauses, $params];
	}
	/*Search User*/
public function iN_GetSearchResult($key, $showingNumberOfPost, $Users, $viewerId = null, $viewerCountryCode = null) {
        $limit = (int)$showingNumberOfPost;
        $like = '%' . $key . '%';
        [$visibilityClauses, $visibilityParams] = $this->iN_BuildUserVisibilityFilter($viewerId, $viewerCountryCode, 'U');
        $visibilitySql = !empty($visibilityClauses) ? ' AND ' . implode(' AND ', $visibilityClauses) : '';
        if ($Users == 'yes') {
            $sql = "SELECT U.* FROM i_users U WHERE (U.i_username LIKE ? OR U.i_user_fullname LIKE ? OR U.i_username LIKE ? OR U.i_user_fullname LIKE ?) AND U.uStatus IN('1','3') AND U.certification_status = '2' AND U.validation_status = '2' AND U.condition_status = '2' AND U.fees_status = '2' AND U.payout_status = '2' $visibilitySql ORDER BY U.iuid LIMIT $limit";
        } else {
            $sql = "SELECT U.* FROM i_users U WHERE (U.i_username LIKE ? OR U.i_user_fullname LIKE ? OR U.i_username LIKE ? OR U.i_user_fullname LIKE ?) AND U.uStatus IN('1','3') $visibilitySql ORDER BY U.iuid LIMIT $limit";
        }
        return DB::all($sql, array_merge([$like, $like, $like, $like], $visibilityParams));
    }
	/*Create a Conversation and Insert First Message Between Users*/
public function iN_CreateConverationAndInsertFirstMessage($userID, $user, $firstMessage) {
        if ($this->iN_CheckUserExist($user) == 1 && $this->iN_CheckUserExist($userID) == 1 && $this->iN_CheckConversationStartedBeforeBetweenUsers($userID, $user) == 0) {
            DB::exec("INSERT INTO i_chat_users (user_one, user_two) VALUES (?,?)", [(int)$userID, (int)$user]);
            $row = DB::one("SELECT chat_id FROM i_chat_users WHERE user_one = ? AND user_two = ? ORDER BY chat_id DESC LIMIT 1", [(int)$userID, (int)$user]);
            if ($row) {
                $chatID = (int)$row['chat_id'];
                $time = time();
                DB::exec("INSERT INTO i_chat_conversations (chat_id_fk, user_one, user_two, message, time) VALUES (?,?,?,?,?)", [$chatID, (int)$userID, (int)$user, (string)$firstMessage, $time]);
                return $chatID;
            }
            return false;
        } else { return false; }
    }
	/*Get Conversation ID Between Two Users*/
public function iN_GetConverationID($userIDone, $userIDTwo) {
        if ($this->iN_CheckUserExist($userIDone) == 1 && $this->iN_CheckUserExist($userIDTwo) == 1) {
            $row = DB::one("SELECT chat_id FROM i_chat_users WHERE (user_one = ? AND user_two = ?) OR (user_one = ? AND user_two = ?) ORDER BY chat_id DESC LIMIT 1", [(int)$userIDone, (int)$userIDTwo, (int)$userIDTwo, (int)$userIDone]);
            return $row ? (int)$row['chat_id'] : false;
        }
    }
