    public function iN_UpdateUserWebPushStatus($userID, $status): bool {
        if ($this->iN_CheckUserExist($userID) != 1) {
            return false;
        }
        if (!$this->tableColumnExists('i_users', 'web_push_enabled')) {
            return false;
        }

        $normalized = ((string)$status === '1') ? '1' : '0';
        DB::exec("UPDATE i_users SET web_push_enabled = ? WHERE iuid = ?", [$normalized, (int)$userID]);
        return true;
    }

    public function iN_GetUserWebPushStatus($userID): string {
        if ($this->iN_CheckUserExist($userID) != 1) {
