    /*Update profile info visibility (per-field)*/
    public function iN_UpdateProfileInfoVisibility($userID, $field, $status) {
        $allowedFields = [
            'show_profile_gender' => 'show_profile_gender',
            'show_profile_age' => 'show_profile_age',
            'show_profile_birthdate' => 'show_profile_birthdate',
            'show_profile_category' => 'show_profile_category',
            'show_profile_likes' => 'show_profile_likes',
            'show_profile_comments' => 'show_profile_comments',
            'show_profile_bio' => 'show_profile_bio',
            'show_profile_social' => 'show_profile_social',
        ];
        if (!isset($allowedFields[$field])) {
            return false;
        }
        if ($this->iN_CheckUserExist($userID) == 1) {
            $safeStatus = $status === '1' ? '1' : '0';
            $column = $allowedFields[$field];
            DB::exec("UPDATE i_users SET {$column} = ? WHERE iuid = ?", [(string)$safeStatus,(int)$userID]);
            return true;
        }
        return false;
    }
