	/*Update Site Limit Values*/
    public function iN_UpdateLimitValues($userID,
        $friendActivityShowTimeLimit,
        $friendActivityShowLimit,
        $TrendPostShowLimit,
        $sugProductShowLimit,
    $sugUserShowLimit,
    $oneSignalStatus,
    $oneSignalApiKey,
    $oneSignalRestApiKey,
    $reCaptchaStatus,
    $reCaptchaSiteKey,
    $reCaptchaSecretKey,
    $postCreateLimit,
    $blockCountryStatus,
    $fileLimit,
    $lengthLimit,
    $postShowLimit,
    $paginatonLimit,
    $approvalFileExtension,
    $availableUploadFileExtensions,
    $bulkMessageFileExtensions,
	    $bulkMessagePriceMin,
	    $bulkMessagePriceMax,
	    $ffmpegPath,
	    $ffprobePath,
	    $storyAudioUploadMode,
	    $unavailableUserNames,
	    $messageScrollNumber,
	    $adsShowLimit,
	    $reelsFeatureStatus,
    $maxVideoDuration,
    $pollSystemStatus = '1',
    $pollMaxOptions = 6,
        $pollMinOptions = 2,
        $scheduledPostsStatus = '0',
        $scheduledMaxDelayDays = 30,
        $quickActionsLayout = 'popup',
        $campaignFeatureStatus = '0',
        $campaignTitleRequired = '1',
        $campaignGoalRequired = '1',
        $campaignDeadlineRequired = '1',
        $campaignCreatorPolicy = 'all',
        $campaignGoalMin = '50.00',
        $campaignGoalMax = '0',
        $blogFeatureStatus = '1',
        $blogReactionsStatus = '1',
        $blogShareStatus = '1',
        $blogSidebarAdsStatus = '1',
        $storyDefaultReactions = '',
        $trendHashtagsStatus = '1',
        $trendHashtagsLimit = 10
    ) {
        if ($this->iN_CheckIsAdmin($userID) == 1) {
            $bulkMessageFileExtensions = $bulkMessageFileExtensions !== '' ? $bulkMessageFileExtensions : $availableUploadFileExtensions;
            $updates = [
                'activity_show_time_limit' => (int)$friendActivityShowTimeLimit,
                'activity_show_limit' => (int)$friendActivityShowLimit,
                'howManyDaysTrend' => (int)$TrendPostShowLimit,
                'showingNumberOfProduct' => (int)$sugProductShowLimit,
                'showingNumberOfSuggestedUser' => (int)$sugUserShowLimit,
                'g_recaptcha_status' => (string)$reCaptchaStatus,
                'g_recaptcha_site_key' => (string)$reCaptchaSiteKey,
                'g_recaptcha_secret_key' => (string)$reCaptchaSecretKey,
                'normal_user_can_post' => (string)$postCreateLimit,
                'available_verification_file_extensions' => (string)$approvalFileExtension,
                'available_file_extensions' => (string)$availableUploadFileExtensions,
                'available_file_size' => (string)$fileLimit,
                'available_length' => (string)$lengthLimit,
                'load_more_limit' => (string)$postShowLimit,
                'pagination_limit' => (int)$paginatonLimit,
                'ffmpeg_path' => (string)$ffmpegPath,
                'disallowed_usernames' => (string)$unavailableUserNames,
                'one_signal_api' => (string)$oneSignalApiKey,
                'one_signal_rest_api' => (string)$oneSignalRestApiKey,
                'one_signal_status' => (string)$oneSignalStatus,
                'load_more_message_limit' => (string)$messageScrollNumber,
                'showingNumberOfAds' => (string)$adsShowLimit,
            ];

            if ($this->configColumnExists('ffmpeg_probe')) {
                $updates['ffmpeg_probe'] = (string)$ffprobePath;
            }
            if ($this->configColumnExists('story_audio_upload_mode')) {
                $mode = in_array((string)$storyAudioUploadMode, ['mp3_only', 'ffmpeg_mp3'], true)
                    ? (string)$storyAudioUploadMode
                    : 'mp3_only';
                $updates['story_audio_upload_mode'] = $mode;
            }
            if ($this->configColumnExists('available_bulk_message_file_extensions')) {
                $updates['available_bulk_message_file_extensions'] = (string)$bulkMessageFileExtensions;
            }
            if ($this->configColumnExists('bulk_message_private_price_min') || $this->configColumnExists('bulk_message_private_price_max')) {
                $minPrice = is_numeric($bulkMessagePriceMin) ? (float)$bulkMessagePriceMin : 0.0;
                $maxPrice = is_numeric($bulkMessagePriceMax) ? (float)$bulkMessagePriceMax : 0.0;
                if ($minPrice < 0) { $minPrice = 0.0; }
                if ($maxPrice < 0) { $maxPrice = 0.0; }
                if ($maxPrice > 0 && $maxPrice < $minPrice) { $maxPrice = $minPrice; }
                if ($this->configColumnExists('bulk_message_private_price_min')) {
                    $updates['bulk_message_private_price_min'] = number_format($minPrice, 2, '.', '');
                }
                if ($this->configColumnExists('bulk_message_private_price_max')) {
                    $updates['bulk_message_private_price_max'] = number_format($maxPrice, 2, '.', '');
                }
            }
            if ($this->configColumnExists('reels_feature_status')) {
                $updates['reels_feature_status'] = (string)$reelsFeatureStatus;
            }
            if ($this->configColumnExists('max_video_duration')) {
                $updates['max_video_duration'] = (string)$maxVideoDuration;
            }
            if ($this->configColumnExists('poll_system_status')) {
                $updates['poll_system_status'] = (string)$pollSystemStatus;
            }
            if ($this->configColumnExists('poll_max_options')) {
                $updates['poll_max_options'] = (int)$pollMaxOptions;
            }
            if ($this->configColumnExists('poll_min_options')) {
                $updates['poll_min_options'] = (int)$pollMinOptions;
            }
            if ($this->configColumnExists('scheduled_posts_status')) {
                $updates['scheduled_posts_status'] = (string)$scheduledPostsStatus;
            }
            if ($this->configColumnExists('scheduled_max_delay_days')) {
                $updates['scheduled_max_delay_days'] = (int)max(1, $scheduledMaxDelayDays);
            }
            if ($this->configColumnExists('quick_actions_layout')) {
                $layout = in_array((string)$quickActionsLayout, ['popup', 'inline'], true) ? (string)$quickActionsLayout : 'popup';
                $updates['quick_actions_layout'] = $layout;
            }
            if ($this->configColumnExists('campaign_feature_status')) {
                $updates['campaign_feature_status'] = (string)$campaignFeatureStatus === '1' ? '1' : '0';
            }
            if ($this->configColumnExists('campaign_title_required')) {
                $updates['campaign_title_required'] = (string)$campaignTitleRequired === '1' ? '1' : '0';
            }
            if ($this->configColumnExists('campaign_goal_required')) {
                $updates['campaign_goal_required'] = (string)$campaignGoalRequired === '1' ? '1' : '0';
            }
            if ($this->configColumnExists('campaign_deadline_required')) {
                $updates['campaign_deadline_required'] = (string)$campaignDeadlineRequired === '1' ? '1' : '0';
            }
            if ($this->configColumnExists('campaign_goal_min')) {
                $minGoal = (float)$campaignGoalMin;
                if ($minGoal < 50) { $minGoal = 50; }
                $updates['campaign_goal_min'] = number_format($minGoal, 2, '.', '');
            }
            if ($this->configColumnExists('campaign_goal_max')) {
                $maxGoal = (float)$campaignGoalMax;
                if ($maxGoal < 0) { $maxGoal = 0; }
                $updates['campaign_goal_max'] = number_format($maxGoal, 2, '.', '');
            }
            $normalizedPolicy = 'all';
            if (in_array((string)$campaignCreatorPolicy, ['all', 'verified', 'admin_only'], true)) {
                $normalizedPolicy = (string)$campaignCreatorPolicy;
            }
            if ($this->configColumnExists('campaign_creator_policy')) {
                $updates['campaign_creator_policy'] = $normalizedPolicy;
            }
            if ($this->configColumnExists('blog_feature_status')) {
                $updates['blog_feature_status'] = (string)$blogFeatureStatus === '1' ? '1' : '0';
            }
            if ($this->configColumnExists('blog_reactions_status')) {
                $updates['blog_reactions_status'] = (string)$blogReactionsStatus === '1' ? '1' : '0';
            }
            if ($this->configColumnExists('blog_share_status')) {
                $updates['blog_share_status'] = (string)$blogShareStatus === '1' ? '1' : '0';
            }
            if ($this->configColumnExists('blog_sidebar_ads_status')) {
                $updates['blog_sidebar_ads_status'] = (string)$blogSidebarAdsStatus === '1' ? '1' : '0';
            }
            if ($this->configColumnExists('story_default_reactions')) {
                $updates['story_default_reactions'] = (string)$storyDefaultReactions;
            }
            if ($this->configColumnExists('trend_hashtags_status')) {
                $updates['trend_hashtags_status'] = (string)$trendHashtagsStatus === '1' ? '1' : '0';
            }
            if ($this->configColumnExists('showingNumberOfTrendHashtags')) {
                $trendLimit = (int)$trendHashtagsLimit;
                if ($trendLimit < 1) { $trendLimit = 1; }
                if ($trendLimit > 30) { $trendLimit = 30; }
                $updates['showingNumberOfTrendHashtags'] = $trendLimit;
            }

            $setParts = [];
            $params = [];
            foreach ($updates as $column => $value) {
                $setParts[] = $column . '=?';
                $params[] = $value;
            }

            $sql = "UPDATE i_configurations SET " . implode(', ', $setParts) . " WHERE configuration_id=1";
            DB::exec($sql, $params);
            return true;
        } else { return false; }
}

