    public function iN_CreateAdPlacement(int $userID, array $data) {
        if ($this->iN_CheckIsAdmin($userID) != 1) {
            return false;
        }
        $this->ensureAdsTables();
        $key = strtolower(trim((string)($data['placement_key'] ?? '')));
        if (!preg_match('/^[a-z0-9_-]{3,64}$/', $key)) {
            return false;
        }
        $title = trim((string)($data['placement_title'] ?? ''));
        if ($title === '') { $title = ucfirst(str_replace('_', ' ', $key)); }
        $desc = trim((string)($data['placement_desc'] ?? ''));
        $status = isset($data['placement_status']) && (string)$data['placement_status'] === '1' ? 1 : 0;
        $freq = isset($data['inline_frequency']) ? (int)$data['inline_frequency'] : 0;
        $offset = isset($data['inline_offset']) ? (int)$data['inline_offset'] : 0;
        $freq = ($freq < 0 || $freq > 100) ? 0 : $freq;
        $offset = ($offset < 0 || $offset > 100) ? 0 : $offset;
        $now = time();
        try {
            $exists = DB::col("SELECT 1 FROM i_ads_placements WHERE placement_key = ? LIMIT 1", [$key]);
            if ($exists) {
                return false;
            }
            DB::exec(
                "INSERT INTO i_ads_placements (placement_key, placement_title, placement_desc, placement_status, inline_frequency, inline_offset, created_at, updated_at)
                 VALUES (?, ?, ?, ?, ?, ?, ?, ?)",
                [$key, $title, $desc, $status, $freq, $offset, $now, $now]
            );
            return DB::lastInsertId();
        } catch (Throwable $e) {
            return false;
        }
    }

    public function iN_UpdateAdPlacement(int $userID, int $placementId, array $data): bool {
        if ($this->iN_CheckIsAdmin($userID) != 1) {
            return false;
        }
        $this->ensureAdsTables();
        $placement = $this->iN_GetAdPlacementById($placementId);
        if (!$placement) {
            return false;
        }
        $key = strtolower(trim((string)($data['placement_key'] ?? $placement['placement_key'])));
        if (!preg_match('/^[a-z0-9_-]{3,64}$/', $key)) {
            $key = $placement['placement_key'];
        }
        try {
            $exists = DB::col("SELECT placement_id FROM i_ads_placements WHERE placement_key = ? AND placement_id <> ? LIMIT 1", [$key, (int)$placementId]);
            if ($exists) {
                $key = $placement['placement_key'];
            }
        } catch (Throwable $e) {
            $key = $placement['placement_key'];
        }
        $title = trim((string)($data['placement_title'] ?? $placement['placement_title']));
        if ($title === '') { $title = $placement['placement_title']; }
        $desc = trim((string)($data['placement_desc'] ?? $placement['placement_desc']));
        $status = isset($data['placement_status']) ? ((string)$data['placement_status'] === '1' ? 1 : 0) : (int)$placement['placement_status'];
        $freq = isset($data['inline_frequency']) ? (int)$data['inline_frequency'] : (int)$placement['inline_frequency'];
        $offset = isset($data['inline_offset']) ? (int)$data['inline_offset'] : (int)$placement['inline_offset'];
        $freq = ($freq < 0 || $freq > 100) ? 0 : $freq;
        $offset = ($offset < 0 || $offset > 100) ? 0 : $offset;
        $now = time();
        try {
            DB::exec(
                "UPDATE i_ads_placements SET placement_key = ?, placement_title = ?, placement_desc = ?, placement_status = ?, inline_frequency = ?, inline_offset = ?, updated_at = ? WHERE placement_id = ?",
                [$key, $title, $desc, $status, $freq, $offset, $now, (int)$placementId]
            );
            return true;
        } catch (Throwable $e) {
            return false;
        }
    }

