    public function iN_CreateAdCode(int $userID, array $data) {
        if ($this->iN_CheckIsAdmin($userID) != 1) {
            return false;
        }
        $this->ensureAdsTables();
        $placementId = isset($data['placement_id']) ? (int)$data['placement_id'] : 0;
        if ($placementId < 1 || !$this->iN_GetAdPlacementById($placementId)) {
            return false;
        }
        $provider = trim((string)($data['provider_name'] ?? 'Custom'));
        if ($provider === '') { $provider = 'Custom'; }
        $codeSnippet = $this->sanitizeAdSnippet((string)($data['code_snippet'] ?? ''));
        if ($codeSnippet === '') {
            return false;
        }
        $status = isset($data['status']) && (string)$data['status'] === '1' ? 1 : 0;
        $isDefault = isset($data['is_default']) && (string)$data['is_default'] === '1' ? 1 : 0;
        $now = time();
        try {
            if ($isDefault) {
                DB::exec("UPDATE i_ads_codes SET is_default = 0 WHERE placement_id = ?", [(int)$placementId]);
            }
            DB::exec(
                "INSERT INTO i_ads_codes (placement_id, provider_name, code_snippet, status, is_default, created_at, updated_at)
                 VALUES (?, ?, ?, ?, ?, ?, ?)",
                [(int)$placementId, $provider, $codeSnippet, $status, $isDefault, $now, $now]
            );
            return DB::lastInsertId();
        } catch (Throwable $e) {
            return false;
        }
    }

    public function iN_UpdateAdCode(int $userID, int $codeId, array $data): bool {
        if ($this->iN_CheckIsAdmin($userID) != 1) {
            return false;
        }
        $this->ensureAdsTables();
        try {
            $existing = DB::one("SELECT * FROM i_ads_codes WHERE code_id = ? LIMIT 1", [(int)$codeId]);
            if (!$existing) {
                return false;
            }
            $placementId = isset($data['placement_id']) ? (int)$data['placement_id'] : (int)$existing['placement_id'];
            if (!$this->iN_GetAdPlacementById($placementId)) {
                $placementId = (int)$existing['placement_id'];
            }
            $provider = trim((string)($data['provider_name'] ?? $existing['provider_name']));
            if ($provider === '') { $provider = $existing['provider_name']; }
            $codeSnippet = isset($data['code_snippet']) ? $this->sanitizeAdSnippet((string)$data['code_snippet']) : $existing['code_snippet'];
            if ($codeSnippet === '') {
                $codeSnippet = $existing['code_snippet'];
            }
            $status = isset($data['status']) ? ((string)$data['status'] === '1' ? 1 : 0) : (int)$existing['status'];
            $isDefault = isset($data['is_default']) ? ((string)$data['is_default'] === '1' ? 1 : 0) : (int)$existing['is_default'];
            $now = time();
            if ($isDefault) {
                DB::exec("UPDATE i_ads_codes SET is_default = 0 WHERE placement_id = ?", [$placementId]);
            }
            DB::exec(
                "UPDATE i_ads_codes SET placement_id = ?, provider_name = ?, code_snippet = ?, status = ?, is_default = ?, updated_at = ? WHERE code_id = ?",
                [$placementId, $provider, $codeSnippet, $status, $isDefault, $now, (int)$codeId]
            );
            return true;
        } catch (Throwable $e) {
            return false;
        }
    }

    public function iN_DeleteAdCode(int $userID, int $codeId): bool {
        if ($this->iN_CheckIsAdmin($userID) != 1) {
            return false;
        }
        $this->ensureAdsTables();
        try {
            DB::exec("DELETE FROM i_ads_codes WHERE code_id = ?", [(int)$codeId]);
            return true;
        } catch (Throwable $e) {
            return false;
        }
    }

    public function iN_SetActiveAdCode(int $userID, int $codeId): bool {
        if ($this->iN_CheckIsAdmin($userID) != 1) {
            return false;
        }
        $this->ensureAdsTables();
        try {
            $code = DB::one("SELECT code_id, placement_id FROM i_ads_codes WHERE code_id = ? LIMIT 1", [(int)$codeId]);
            if (!$code) {
                return false;
            }
            DB::exec("UPDATE i_ads_codes SET is_default = 0 WHERE placement_id = ?", [(int)$code['placement_id']]);
            DB::exec("UPDATE i_ads_codes SET is_default = 1, status = 1 WHERE code_id = ?", [(int)$codeId]);
            return true;
        } catch (Throwable $e) {
            return false;
        }
    }

    public function iN_GetActiveAdByPlacementKey(string $placementKey): ?array {
        $this->ensureAdsTables();
        $this->migrateLegacyAdsenseToAds();
        try {
            $placement = DB::one(
                "SELECT * FROM i_ads_placements WHERE placement_key = ? AND placement_status = 1 LIMIT 1",
                [(string)$placementKey]
            );
            if (!$placement) {
                return null;
            }
            $active = DB::one(
                "SELECT * FROM i_ads_codes WHERE placement_id = ? AND status = 1 AND is_default = 1 ORDER BY updated_at DESC LIMIT 1",
                [(int)$placement['placement_id']]
            );
            if (!$active) {
                $active = DB::one(
                    "SELECT * FROM i_ads_codes WHERE placement_id = ? AND status = 1 ORDER BY updated_at DESC LIMIT 1",
                    [(int)$placement['placement_id']]
                );
            }
            if (!$active) {
                return array_merge($placement, [
                    'code_snippet' => '',
                    'code_provider' => '',
                    'code_status' => 0,
                    'code_id' => null,
                    'is_default_code' => 0
                ]);
            }
            $activeMapped = [
                'code_id' => $active['code_id'] ?? null,
                'code_provider' => $active['provider_name'] ?? '',
                'code_snippet' => $active['code_snippet'] ?? '',
                'code_status' => isset($active['status']) ? (int)$active['status'] : 0,
                'is_default_code' => isset($active['is_default']) ? (int)$active['is_default'] : 0,
                'code_updated_at' => $active['updated_at'] ?? null
            ];
            return array_merge($placement, $activeMapped);
        } catch (Throwable $e) {
            return null;
        }
    }

    public function iN_HasAdsenseAds(): bool {
        $this->ensureAdsTables();
        try {
            $val = DB::col("SELECT COUNT(*) FROM i_ads_codes C INNER JOIN i_ads_placements P ON P.placement_id = C.placement_id AND P.placement_status = 1 WHERE C.status = 1 AND LOWER(C.provider_name) LIKE '%adsense%'");
            return (int)$val > 0;
        } catch (Throwable $e) {
            return false;
        }
    }

    /**
     * Update Google Adsense settings (DB + file fallback).
     *
     * @param int   $userID
     * @param array $payload
     * @return bool
     */
    public function iN_UpdateAdsenseSettings($userID, array $payload) {
        if ($this->iN_CheckIsAdmin($userID) != 1) {
            return false;
        }
        $normalized = [
            'adsense_status' => isset($payload['status']) && $payload['status'] === '1' ? '1' : '0',
            'adsense_client_id' => isset($payload['client_id']) ? (string)$payload['client_id'] : '',
            'adsense_slot_top' => isset($payload['slot_top']) ? (string)$payload['slot_top'] : '',
            'adsense_slot_inline' => isset($payload['slot_inline']) ? (string)$payload['slot_inline'] : '',
            'adsense_slot_footer' => isset($payload['slot_footer']) ? (string)$payload['slot_footer'] : '',
            'adsense_slot_sidebar' => isset($payload['slot_sidebar']) ? (string)$payload['slot_sidebar'] : '',
            'adsense_inline_frequency' => isset($payload['inline_frequency']) ? (int)$payload['inline_frequency'] : 4,
            'adsense_inline_offset' => isset($payload['inline_offset']) ? (int)$payload['inline_offset'] : 1,
            'adsense_top_size' => isset($payload['top_size']) ? (string)$payload['top_size'] : 'responsive',
            'adsense_inline_size' => isset($payload['inline_size']) ? (string)$payload['inline_size'] : 'responsive',
            'adsense_footer_size' => isset($payload['footer_size']) ? (string)$payload['footer_size'] : 'responsive',
            'adsense_sidebar_size' => isset($payload['sidebar_size']) ? (string)$payload['sidebar_size'] : 'responsive',
            'adsense_updated_at' => time(),
        ];

        $updates = [];
        foreach ($normalized as $column => $value) {
            if ($this->configColumnExists($column)) {
                $updates[$column] = $value;
            }
        }

        if (!empty($updates)) {
            $setParts = [];
            $params = [];
            foreach ($updates as $column => $value) {
                $setParts[] = $column . '=?';
                $params[] = $value;
            }
            DB::exec("UPDATE i_configurations SET " . implode(', ', $setParts) . " WHERE configuration_id = 1", $params);
        }

        $exportPath = __DIR__ . '/adsense_config.php';
        $export = "<?php\n// Auto-generated Adsense settings on " . date('c') . "\nif (!isset(\$inc) || !is_array(\$inc)) { \$inc = []; }\n";
        foreach ($normalized as $column => $value) {
            $export .= "\$inc['" . $column . "'] = '" . addslashes((string)$value) . "';\n";
        }
        $export .= "?>\n";
        @file_put_contents($exportPath, $export, LOCK_EX);

        return true;
    }
