    public function iN_UpdateCampaignAdmin(int $adminUserId, int $postId, array $data): bool {
        if ($this->iN_CheckIsAdmin($adminUserId) != 1 || $this->iN_CheckPostIDExist($postId) != 1) {
            return false;
        }
        $campaignRow = DB::one("SELECT campaign_id, status, goal_amount FROM i_campaigns WHERE post_id_fk = ? LIMIT 1", [$postId]);
        if (!$campaignRow) {
            return false;
        }
        $settings = $this->getCampaignSettings();
        $goalMinSetting = isset($settings['goal_min']) ? (float)$settings['goal_min'] : 50.0;
        if ($goalMinSetting < 50) { $goalMinSetting = 50.0; }
        $goalMaxSetting = isset($settings['goal_max']) ? (float)$settings['goal_max'] : 0.0;

        $title = isset($data['title']) ? trim((string)$data['title']) : null;
        $summary = isset($data['summary']) ? trim((string)$data['summary']) : null;
        $goal = isset($data['goal']) ? (float)str_replace(',', '.', preg_replace('/[^0-9.,-]/', '', (string)$data['goal'])) : null;
        $min = isset($data['min']) ? (float)str_replace(',', '.', preg_replace('/[^0-9.,-]/', '', (string)$data['min'])) : null;
        $max = isset($data['max']) ? (float)str_replace(',', '.', preg_replace('/[^0-9.,-]/', '', (string)$data['max'])) : null;
        $deadlineInput = isset($data['deadline']) ? trim((string)$data['deadline']) : '';
        $deadlineTs = $deadlineInput !== '' ? strtotime($deadlineInput) : null;
        $status = isset($data['status']) ? trim((string)$data['status']) : '';
        $coverId = isset($data['cover']) && $data['cover'] !== '' ? (int)$data['cover'] : null;

        $allowedStatus = array('pending', 'active', 'expired', 'rejected');
        if (!in_array($status, $allowedStatus, true)) {
            $status = $campaignRow['status'];
        }

        $sqlParts = [];
        $params = [];

        if ($title !== null) { $sqlParts[] = "title = ?"; $params[] = $title; }
        if ($summary !== null) { $sqlParts[] = "summary = ?"; $params[] = $summary; }
        $currentGoal = isset($campaignRow['goal_amount']) ? (float)$campaignRow['goal_amount'] : 0.0;
        if ($goal !== null) {
            if ($goal < $goalMinSetting) { $goal = $goalMinSetting; }
            if ($goalMaxSetting > 0 && $goal > $goalMaxSetting) { $goal = $goalMaxSetting; }
            $sqlParts[] = "goal_amount = ?"; $params[] = number_format($goal, 2, '.', '');
        }
        if ($min !== null || $min === 0.0) { $sqlParts[] = "min_amount = ?"; $params[] = $min !== null ? number_format($min, 2, '.', '') : null; }
        if ($max !== null || $max === 0.0) {
            $goalClamp = ($goal !== null && $goal > 0) ? $goal : $currentGoal;
            if ($goalClamp > 0 && $max > $goalClamp) {
                $max = $goalClamp;
            }
            $sqlParts[] = "max_amount = ?"; $params[] = $max !== null ? number_format($max, 2, '.', '') : null;
        }
        if ($deadlineInput !== '') { $sqlParts[] = "deadline_at = ?"; $params[] = $deadlineTs ? (int)$deadlineTs : null; }
        $sqlParts[] = "status = ?"; $params[] = $status;
        $sqlParts[] = "updated_at = ?"; $params[] = time();
        if ($coverId !== null) { $sqlParts[] = "cover_upload_id = ?"; $params[] = $coverId; }

        if (empty($sqlParts)) {
            return true;
        }

        $setClause = implode(', ', $sqlParts);
        $params[] = (int)$campaignRow['campaign_id'];

        DB::exec("UPDATE i_campaigns SET $setClause WHERE campaign_id = ?", $params);

        // Sync post_status with campaign status for visibility.
        if ($status === 'active') {
            DB::exec("UPDATE i_posts SET post_status = '1' WHERE post_id = ?", [$postId]);
        } elseif ($status === 'rejected') {
            DB::exec("UPDATE i_posts SET post_status = '0' WHERE post_id = ?", [$postId]);
        }

        return true;
    }
		/*Delete Post*/
		public function iN_DeletePremiumPostBeforeApprove($userID, $postID) {
			if ($this->iN_CheckIsAdmin($userID) == 1 && $this->iN_CheckPostIDExist($postID) == 1) {
				$getPostFileIDs = $this->iN_GetAllPostDetails($postID);
				$postFileIDs = isset($getPostFileIDs['post_file']) ? $getPostFileIDs['post_file'] : NULL;
				if ($postFileIDs) {
					$trimValue = rtrim($postFileIDs, ',');
					$explodeFiles = explode(',', $trimValue);
					$explodeFiles = array_unique($explodeFiles);
					$useRemote = function_exists('storage_is_remote') ? storage_is_remote() : false;
					foreach ($explodeFiles as $explodeFile) {
						$theFileID = $this->iN_GetUploadedFileDetails($explodeFile);
						if (!$theFileID) {
							continue;
						}
						$uploadedFileID = $theFileID['upload_id'] ?? null;
						$uploadedFilePath = $theFileID['uploaded_file_path'] ?? '';
						$uploadedFilePathX = $theFileID['uploaded_x_file_path'] ?? '';

						if ($useRemote && function_exists('storage_delete')) {
							@storage_delete($uploadedFilePath);
							@storage_delete($uploadedFilePathX);
						} else {
							foreach ([$uploadedFilePath, $uploadedFilePathX] as $p) {
								$p = trim((string) $p);
								if ($p === '' || strpos($p, 'uploads/') !== 0) {
									continue;
								}
								$full = dirname(__DIR__) . '/' . ltrim($p, '/');
								@unlink($full);
							}
						}

						if (!empty($uploadedFileID)) {
							DB::exec("DELETE FROM i_user_uploads WHERE upload_id = ?", [(int) $uploadedFileID]);
						}
					}
				}
	            $this->iN_ClearScheduledQueue((int)$postID);
				DB::exec("DELETE FROM i_posts WHERE post_id = ?", [(int)$postID]);
				return true;
		} else {
			return false;
		}
	}
