	/*Get Custom Codes*/
	public function iN_GetCustomCodes($cID) {
        $codeID = (int)$cID;
        if ($codeID < 1) {
            return false;
        }
        if (array_key_exists($codeID, self::$customCodesCache)) {
            return self::$customCodesCache[$codeID];
        }
		$row = DB::one("SELECT custom_code FROM i_custom_codes WHERE custom_id = ?", [$codeID]);
        self::$customCodesCache[$codeID] = $row ? $row['custom_code'] : false;
        return self::$customCodesCache[$codeID];
	}
	/*Update Custom*/
	public function iN_UpdateCustomCodes($userID, $customCssCode, $cID) {
		$cID = (int)$cID;
		if ($this->iN_CheckIsAdmin($userID) == 1) {
			$codeRow = DB::one("SELECT custom_id FROM i_custom_codes WHERE custom_id = ? LIMIT 1", [$cID]);
			if ($codeRow) {
				DB::exec("UPDATE i_custom_codes SET custom_code = ? WHERE custom_id = ?", [(string)$customCssCode, $cID]);
			} else {
				DB::exec("INSERT INTO i_custom_codes (custom_id, custom_code) VALUES (?, ?)", [$cID, (string)$customCssCode]);
			}
            unset(self::$customCodesCache[$cID]);
			return true;
		} else {
			return false;
		}
	}
