	public function iN_AddNewLanguageFromData($userID, $langKey) {
		if ($this->iN_CheckIsAdmin($userID) == 1) {
			DB::exec("INSERT INTO i_langs(lang_name, lang_status) VALUES(?, '0')", [(string)$langKey]);
			return true;
