	/*Delete Language*/
	public function iN_DeleteLanguage($userID, $langID) {
		if ($this->iN_CheckIsAdmin($userID) == 1 && !empty($this->iN_CheckLangIDExistWithoutStatus($langID))) {
			DB::exec("DELETE FROM i_langs WHERE lang_id = ?", [(int)$langID]);
