	/*All Posts*/
public function iN_AllTypeOfUsersList($userID, $paginationLimit, $page, $searchValue) {
		$userID = (int)$userID;
		$paginationLimit = (int)$paginationLimit;
		$page = (int)$page;
		$start_from = ($page - 1) * $paginationLimit;
		$where = '';
		$params = [];
		if (!empty($searchValue)){
           $like = '%'.$searchValue.'%';
           $where = "WHERE (i_user_email LIKE ? OR i_username LIKE ? OR i_user_fullname LIKE ?)";
           $params = [$like,$like,$like];
		}
		if ($this->iN_CheckIsAdmin($userID) == 1) {
			$sql = "SELECT * FROM i_users $where ORDER BY iuid DESC LIMIT $start_from, $paginationLimit";
			$rows = DB::all($sql, $params);
			return !empty($rows) ? $rows : null;
		}
}
	/*Update Some User Profile*/
public function iN_UpdateUserProfile($userID, $updatedUser, $updateVerification, $updateUserType, $updateUserWallet) {
		if ($this->iN_CheckIsAdmin($userID) == 1 && $this->iN_CheckUserExist($updatedUser) == 1) {
			if ($updateVerification == '2') {
				DB::exec("UPDATE i_users SET email_verify_status = 'yes' , verify_key = NULL , user_verified_status = '1', certification_status = '2', validation_status = '2', condition_status = '2', fees_status = '2', payout_status = '2', userType = ?, wallet_points = ? WHERE iuid = ?",
                        [(string)$updateUserType,(string)$updateUserWallet,(int)$updatedUser]);
				return true;
			} else if ($updateVerification == '1') {
				DB::exec("UPDATE i_users SET certification_status = '2', validation_status = '1', userType = ?, wallet_points = ? WHERE iuid = ?",
                        [(string)$updateUserType,(string)$updateUserWallet,(int)$updatedUser]);
				return true;
			} else {
				DB::exec("UPDATE i_users SET certification_status = '0', validation_status = '0', condition_status = '0', fees_status = '0', payout_status = '0', userType = ?, wallet_points = ? WHERE iuid = ?",
                        [(string)$updateUserType,(string)$updateUserWallet,(int)$updatedUser]);
				return true;
			}
		} else {
			return false;
		}
}
	/*Delete User*/
	public function iN_DeleteUser($userID, $deleteUserID) {
		if ($this->iN_CheckIsAdmin($userID) == 1 && $this->iN_CheckUserExist($deleteUserID) == 1) {
			return $this->iN_HardDeleteUserById((int)$deleteUserID);
		}
		return false;
	}

	private function iN_TableExists($tableName) {
		try {
			$exists = DB::col(
				"SELECT COUNT(*) FROM information_schema.TABLES WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = ?",
				[(string)$tableName]
			);
			return !empty($exists);
		} catch (Throwable $e) {
			return false;
		}
	}

	private function iN_TableColumnExists($tableName, $columnName) {
		try {
			$exists = DB::col(
				"SELECT COUNT(*) FROM information_schema.COLUMNS
				 WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = ? AND COLUMN_NAME = ?",
				[(string)$tableName, (string)$columnName]
			);
			return !empty($exists);
		} catch (Throwable $e) {
			return false;
		}
	}

	private function iN_NormalizeUploadPath($path) {
		$path = str_replace('\\', '/', trim((string)$path));
		$path = ltrim($path, '/');
		if ($path === '' || strpos($path, '../') !== false || strpos($path, 'uploads/') !== 0) {
			return '';
		}
		return $path;
	}

	private function iN_DeleteUploadedPath($path) {
		$path = $this->iN_NormalizeUploadPath($path);
		if ($path === '') {
			return;
		}
		$useRemote = function_exists('storage_is_remote') ? storage_is_remote() : false;
		if ($useRemote && function_exists('storage_delete')) {
			@storage_delete($path);
			return;
		}
		$fullPath = dirname(__DIR__) . '/' . $path;
		@unlink($fullPath);
	}

	private function iN_ExtractUploadPathsFromValue($value) {
		$paths = [];
		if (is_array($value)) {
			foreach ($value as $item) {
				$paths = array_merge($paths, $this->iN_ExtractUploadPathsFromValue($item));
			}
			return $paths;
		}
		$text = trim((string)$value);
		if ($text === '') {
			return $paths;
		}
		$text = str_replace('\\/', '/', $text);
		if (preg_match_all('/uploads\/[A-Za-z0-9_\/\-\.\%\+\(\)\[\]]+/u', $text, $matches)) {
			foreach ($matches[0] as $match) {
				$normalized = $this->iN_NormalizeUploadPath($match);
				if ($normalized !== '') {
					$paths[] = $normalized;
				}
			}
		}
		return array_values(array_unique($paths));
	}

	private function iN_AppendUploadPathsFromRows(array &$paths, array $rows, array $columns) {
		foreach ($rows as $row) {
			foreach ($columns as $column) {
				if (!array_key_exists($column, $row)) {
					continue;
				}
				$paths = array_merge($paths, $this->iN_ExtractUploadPathsFromValue($row[$column]));
			}
		}
	}

	private function iN_FilterExportRowByAllowList($row, array $allowList) {
		if (!is_array($row)) {
			return [];
		}
		$filtered = [];
		foreach ($allowList as $column) {
			if (array_key_exists($column, $row)) {
				$filtered[$column] = $row[$column];
			}
		}
		return $filtered;
	}

	private function iN_FilterExportRowsByAllowList(array $rows, array $allowList) {
		$result = [];
		foreach ($rows as $row) {
			if (!is_array($row)) {
				continue;
			}
			$result[] = $this->iN_FilterExportRowByAllowList($row, $allowList);
		}
		return $result;
	}

	private function iN_MaskExportValue($value, $prefix = 1, $suffix = 2) {
		$text = trim((string)$value);
		if ($text === '') {
			return '';
		}
		$length = strlen($text);
		$prefix = max(0, (int)$prefix);
		$suffix = max(0, (int)$suffix);
		if ($length <= ($prefix + $suffix)) {
			return str_repeat('*', max(4, $length));
		}
		$hiddenLength = max(4, $length - ($prefix + $suffix));
		$tail = $suffix > 0 ? substr($text, -$suffix) : '';
		return substr($text, 0, $prefix) . str_repeat('*', $hiddenLength) . $tail;
	}

	private function iN_MaskExportEmail($email) {
		$email = trim((string)$email);
		if ($email === '') {
			return '';
		}
		if (strpos($email, '@') === false) {
			return $this->iN_MaskExportValue($email, 1, 1);
		}
		$parts = explode('@', $email, 2);
		$localPart = isset($parts[0]) ? $parts[0] : '';
		$domainPart = isset($parts[1]) ? $parts[1] : '';
		return $this->iN_MaskExportValue($localPart, 1, 0) . '@' . $domainPart;
	}

	private function iN_HashExportReference($value) {
		$text = trim((string)$value);
		if ($text === '') {
			return '';
		}
		return 'sha256:' . substr(hash('sha256', $text), 0, 24);
	}

	private function iN_EncodeExportPayload($payload, $jsonFlags) {
		$encoded = json_encode($payload, $jsonFlags);
		if ($encoded !== false) {
			return (string)$encoded;
		}
		$fallback = json_encode(
			[
				'error' => 'encoding_failed',
				'generated_at' => time()
			],
			$jsonFlags
		);
		if ($fallback === false) {
			return '{"error":"encoding_failed"}';
		}
		return (string)$fallback;
	}

	private function iN_IsAssocArray($value) {
		if (!is_array($value)) {
			return false;
		}
		return array_keys($value) !== range(0, count($value) - 1);
	}

	private function iN_NormalizeExportNullValues($value, $nullReplacement = '-') {
		if ($value === null) {
			return $nullReplacement;
		}
		if (is_string($value) && strtolower(trim($value)) === 'null') {
			return $nullReplacement;
		}
		if (is_array($value)) {
			$normalized = [];
			foreach ($value as $key => $item) {
				$normalized[$key] = $this->iN_NormalizeExportNullValues($item, $nullReplacement);
			}
			return $normalized;
		}
		return $value;
	}

	private function iN_TransformExportKeyName($key) {
		$key = trim((string)$key);
		if ($key === '') {
			return 'f_unknown';
		}
		$manualMap = [
			'iuid' => 'user_id',
			'iuid_fk' => 'user_id',
			'uid_fk' => 'user_id',
			'fr_one' => 'connection_user_a',
			'fr_two' => 'connection_user_b',
			'fr_id' => 'connection_id',
			'fr_status' => 'connection_status',
			'fr_time' => 'connection_time',
			'com_id' => 'comment_id',
			'comment_uid_fk' => 'comment_user_id',
			'comment_post_id_fk' => 'comment_post_id',
			'payment_id' => 'transaction_id',
			'payout_id' => 'payout_id',
			'subscription_id' => 'subscription_record_id',
			's_id' => 'story_id',
			'pr_id' => 'product_id',
			'con_id_fk' => 'conversation_id',
			'upload_id' => 'media_id',
			'avatar_id' => 'avatar_id',
			'cover_id' => 'cover_id'
		];
		if (isset($manualMap[$key])) {
			return 'f_' . $manualMap[$key];
		}
		$normalized = strtolower($key);
		if (strpos($normalized, 'i_') === 0) {
			$normalized = substr($normalized, 2);
		}
		if (strpos($normalized, 'pr_') === 0) {
			$normalized = 'product_' . substr($normalized, 3);
		}
		if (strpos($normalized, 'com_') === 0) {
			$normalized = 'comment_' . substr($normalized, 4);
		}
		if (strpos($normalized, 'payed_') === 0) {
			$normalized = 'paid_' . substr($normalized, 6);
		}
		if (substr($normalized, -3) === '_fk') {
			$normalized = substr($normalized, 0, -3) . '_id';
		}
		$normalized = preg_replace('/[^a-z0-9_]/', '_', $normalized);
		$normalized = preg_replace('/_+/', '_', $normalized);
		$normalized = trim((string)$normalized, '_');
		if ($normalized === '') {
			$normalized = 'field';
		}
		return 'f_' . $normalized;
	}

	private function iN_TransformExportPayloadStructure($payload) {
		if (!is_array($payload)) {
			return $this->iN_NormalizeExportNullValues($payload, '-');
		}
		$payload = $this->iN_NormalizeExportNullValues($payload, '-');
		if (!$this->iN_IsAssocArray($payload)) {
			$list = [];
			foreach ($payload as $item) {
				$list[] = $this->iN_TransformExportPayloadStructure($item);
			}
			return $list;
		}
		$result = [];
		foreach ($payload as $key => $value) {
			$newKey = $this->iN_TransformExportKeyName((string)$key);
			$result[$newKey] = $this->iN_TransformExportPayloadStructure($value);
		}
		return $result;
	}

	private function iN_GetExportDatasetAlias($datasetKey) {
		$map = [
			'profile' => 'account_overview',
			'payments' => 'financial_activity',
			'payouts' => 'withdrawal_history',
			'bank_payments' => 'bank_request_log',
			'subscriptions' => 'subscription_activity',
			'posts' => 'content_posts',
			'comments' => 'content_comments',
			'uploads' => 'media_upload_log',
			'avatars' => 'profile_avatar_log',
			'covers' => 'profile_cover_log',
			'stories' => 'story_activity',
			'conversation_uploads' => 'message_media_log',
			'products' => 'product_activity',
			'friends' => 'connection_activity'
		];
		$key = trim((string)$datasetKey);
		if (isset($map[$key])) {
			return $map[$key];
		}
		return preg_replace('/[^a-z0-9_]/', '_', strtolower($key));
	}

	private function iN_EnsureAccountExportProtection($exportBaseDir) {
		$exportBaseDir = rtrim((string)$exportBaseDir, '/');
		if ($exportBaseDir === '') {
			return false;
		}
		if (!is_dir($exportBaseDir) && !@mkdir($exportBaseDir, 0755, true) && !is_dir($exportBaseDir)) {
			return false;
		}
		$htaccessPath = $exportBaseDir . '/.htaccess';
		if (!is_file($htaccessPath)) {
			$rules = "Options -Indexes\n"
				. "<IfModule mod_authz_core.c>\n"
				. "Require all denied\n"
				. "</IfModule>\n"
				. "<IfModule !mod_authz_core.c>\n"
				. "Deny from all\n"
				. "</IfModule>\n";
			if (@file_put_contents($htaccessPath, $rules, LOCK_EX) === false) {
				return false;
			}
		}
		$indexPath = $exportBaseDir . '/index.html';
		if (!is_file($indexPath) && @file_put_contents($indexPath, '', LOCK_EX) === false) {
			return false;
		}
		return true;
	}

	private function iN_DeleteUserExportFiles($userID) {
		if (!$this->iN_TableExists('i_user_exports')) {
			return;
		}
		try {
			$rows = DB::all("SELECT file_path FROM i_user_exports WHERE iuid_fk = ?", [(int)$userID]);
			foreach ($rows as $row) {
				$this->iN_DeleteUploadedPath($row['file_path'] ?? '');
			}
		} catch (Throwable $e) {
			// Ignore export cleanup errors during hard delete.
		}
	}

	private function iN_HardDeleteUserById($deleteUserID) {
		$uid = (int)$deleteUserID;
		if ($uid <= 0 || $this->iN_CheckUserExist($uid) != 1) {
			return false;
		}

		$pathsToDelete = [];
		try {
			$uploadRows = DB::all(
				"SELECT uploaded_file_path, upload_tumbnail_file_path, uploaded_x_file_path
				 FROM i_user_uploads WHERE iuid_fk = ?",
				[$uid]
			);
			$this->iN_AppendUploadPathsFromRows($pathsToDelete, $uploadRows, ['uploaded_file_path', 'upload_tumbnail_file_path', 'uploaded_x_file_path']);

			$avatarRows = DB::all("SELECT avatar_path FROM i_user_avatars WHERE iuid_fk = ?", [$uid]);
			$this->iN_AppendUploadPathsFromRows($pathsToDelete, $avatarRows, ['avatar_path']);

			$coverRows = DB::all("SELECT cover_path FROM i_user_covers WHERE iuid_fk = ?", [$uid]);
			$this->iN_AppendUploadPathsFromRows($pathsToDelete, $coverRows, ['cover_path']);

			$storyRows = DB::all(
				"SELECT uploaded_file_path, upload_tumbnail_file_path, uploaded_x_file_path
				 FROM i_user_stories WHERE uid_fk = ?",
				[$uid]
			);
			$this->iN_AppendUploadPathsFromRows($pathsToDelete, $storyRows, ['uploaded_file_path', 'upload_tumbnail_file_path', 'uploaded_x_file_path']);

			$convRows = DB::all(
				"SELECT uploaded_file_path, uploaded_x_file_path
				 FROM i_user_conversation_uploads WHERE iuid_fk = ?",
				[$uid]
			);
			$this->iN_AppendUploadPathsFromRows($pathsToDelete, $convRows, ['uploaded_file_path', 'uploaded_x_file_path']);

			$verRows = DB::all(
				"SELECT id_card, photo_of_card FROM i_verification_requests WHERE iuid_fk = ?",
				[$uid]
			);
			$this->iN_AppendUploadPathsFromRows($pathsToDelete, $verRows, ['id_card', 'photo_of_card']);

			$productRows = DB::all("SELECT pr_files, pr_downlodable_files FROM i_user_product_posts WHERE iuid_fk = ?", [$uid]);
			$this->iN_AppendUploadPathsFromRows($pathsToDelete, $productRows, ['pr_files', 'pr_downlodable_files']);

			$postRows = DB::all("SELECT post_file FROM i_posts WHERE post_owner_id = ?", [$uid]);
			$this->iN_AppendUploadPathsFromRows($pathsToDelete, $postRows, ['post_file']);

			$commentRows = DB::all("SELECT comment_file FROM i_post_comments WHERE comment_uid_fk = ?", [$uid]);
			$this->iN_AppendUploadPathsFromRows($pathsToDelete, $commentRows, ['comment_file']);

			if ($this->iN_TableExists('communities')) {
				$communityRows = DB::all("SELECT cover_image FROM communities WHERE owner_user_id = ?", [$uid]);
				$this->iN_AppendUploadPathsFromRows($pathsToDelete, $communityRows, ['cover_image']);
			}

			if ($this->iN_TableExists('i_user_exports')) {
				$exportRows = DB::all("SELECT file_path FROM i_user_exports WHERE iuid_fk = ?", [$uid]);
				$this->iN_AppendUploadPathsFromRows($pathsToDelete, $exportRows, ['file_path']);
			}
		} catch (Throwable $e) {
			// Best-effort file cleanup only.
		}

		$pathsToDelete = array_values(array_unique($pathsToDelete));
		foreach ($pathsToDelete as $path) {
			$this->iN_DeleteUploadedPath($path);
		}
		$this->iN_DeleteUserExportFiles($uid);

		try {
			DB::begin();
			DB::exec("DELETE FROM i_chat_conversations WHERE user_one = ? OR user_two = ?", [$uid, $uid]);
			DB::exec("DELETE FROM i_chat_users WHERE user_one = ? OR user_two = ?", [$uid, $uid]);
			DB::exec("DELETE FROM i_comment_reports WHERE iuid_fk = ?", [$uid]);
			DB::exec("DELETE FROM i_friends WHERE fr_one = ? OR fr_two = ?", [$uid, $uid]);
			if ($this->scheduledSchemaReady()) {
				DB::exec("DELETE FROM i_scheduled_queue WHERE post_id_fk IN (SELECT post_id FROM i_posts WHERE post_owner_id = ?)", [$uid]);
			}
			DB::exec("DELETE FROM i_posts WHERE post_owner_id = ?", [$uid]);
			DB::exec("DELETE FROM i_post_comments WHERE comment_uid_fk = ?", [$uid]);
			DB::exec("DELETE FROM i_post_comment_likes WHERE c_like_iuid_fk = ?", [$uid]);
			DB::exec("DELETE FROM i_post_likes WHERE iuid_fk = ?", [$uid]);
			DB::exec("DELETE FROM i_post_reports WHERE iuid_fk = ?", [$uid]);
			DB::exec("DELETE FROM i_saved_posts WHERE iuid_fk = ?", [$uid]);
			DB::exec("DELETE FROM i_sessions WHERE session_uid = ?", [$uid]);
			DB::exec("DELETE FROM i_user_avatars WHERE iuid_fk = ?", [$uid]);
			DB::exec("DELETE FROM i_user_blocks WHERE blocker_iuid = ? OR blocked_iuid = ?", [$uid, $uid]);
			DB::exec("DELETE FROM i_user_conversation_uploads WHERE iuid_fk = ?", [$uid]);
			DB::exec("DELETE FROM i_user_covers WHERE iuid_fk = ?", [$uid]);
			DB::exec("DELETE FROM i_stories_seen WHERE i_seen_uid_fk = ?", [$uid]);
			DB::exec("DELETE FROM i_stories_seen WHERE i_seen_storie_id IN (SELECT s_id FROM i_user_stories WHERE uid_fk = ?)", [$uid]);
			DB::exec("DELETE FROM i_user_stories WHERE uid_fk = ?", [$uid]);
			DB::exec("DELETE FROM i_user_notifications WHERE not_iuid = ? OR not_own_iuid = ?", [$uid, $uid]);
			DB::exec("DELETE FROM i_user_product_posts WHERE iuid_fk = ?", [$uid]);
			DB::exec("DELETE FROM i_user_subscribe_plans WHERE iuid_fk = ?", [$uid]);
			DB::exec("DELETE FROM i_user_subscriptions WHERE iuid_fk = ? OR subscribed_iuid_fk = ?", [$uid, $uid]);
			DB::exec("DELETE FROM i_user_uploads WHERE iuid_fk = ?", [$uid]);
			DB::exec("DELETE FROM i_verification_requests WHERE iuid_fk = ?", [$uid]);
			DB::exec("DELETE FROM i_user_activity WHERE uid_fk = ?", [$uid]);
			DB::exec("DELETE FROM i_user_payments WHERE payer_iuid_fk = ? OR payed_iuid_fk = ? OR payed_profile_id_fk = ?", [$uid, $uid, $uid]);
			DB::exec("DELETE FROM i_user_payouts WHERE iuid_fk = ?", [$uid]);
			DB::exec("DELETE FROM i_bank_payments WHERE iuid_fk = ?", [$uid]);
			DB::exec("DELETE FROM i_user_frames WHERE f_puchased_user_id = ? OR f_purchaser_user_id = ?", [$uid, $uid]);
			DB::exec("DELETE FROM i_mentions WHERE m_uid_fk = ? OR m_user_owner = ?", [$uid, $uid]);

			if ($this->iN_TableExists('community_memberships')) {
				DB::exec("DELETE FROM community_memberships WHERE user_id = ?", [$uid]);
				if ($this->iN_TableExists('communities')) {
					DB::exec("DELETE FROM community_memberships WHERE community_id IN (SELECT id FROM communities WHERE owner_user_id = ?)", [$uid]);
				}
			}
			if ($this->iN_TableExists('communities')) {
				DB::exec("DELETE FROM communities WHERE owner_user_id = ?", [$uid]);
			}
			if ($this->iN_TableExists('i_user_exports')) {
				DB::exec("DELETE FROM i_user_exports WHERE iuid_fk = ?", [$uid]);
			}
			if ($this->iN_TableExists('i_user_deletion_requests')) {
				DB::exec(
					"UPDATE i_user_deletion_requests
					 SET request_status = 'completed', completed_at = ?
					 WHERE iuid_fk = ? AND request_status = 'pending'",
					[time(), $uid]
				);
			}
			DB::exec("DELETE FROM i_users WHERE iuid = ?", [$uid]);
			DB::commit();
			return true;
		} catch (Throwable $e) {
			DB::rollBack();
			return false;
		}
	}

	public function iN_GetPendingAccountDeletion($userID) {
		$uid = (int)$userID;
		if ($uid <= 0 || !$this->iN_TableExists('i_user_deletion_requests')) {
			return null;
		}
		return DB::one(
			"SELECT * FROM i_user_deletion_requests
			 WHERE iuid_fk = ? AND request_status = 'pending'
			 ORDER BY request_id DESC LIMIT 1",
			[$uid]
		);
	}

	public function iN_RequestAccountDeletion($userID, $graceDays = 14) {
		$uid = (int)$userID;
		$graceDays = (int)$graceDays;
		if ($uid <= 0 || $this->iN_CheckUserExist($uid) != 1) {
			return ['status' => 'error'];
		}
		if (!$this->iN_TableExists('i_user_deletion_requests')) {
			return ['status' => 'schema_missing'];
		}
		$user = DB::one("SELECT iuid, userType, uStatus FROM i_users WHERE iuid = ? LIMIT 1", [$uid]);
		if (!$user) {
			return ['status' => 'error'];
		}
		if ((string)($user['userType'] ?? '') === '2') {
			return ['status' => 'not_allowed'];
		}
		$pending = $this->iN_GetPendingAccountDeletion($uid);
		if ($pending) {
			return [
				'status' => 'already_pending',
				'delete_after' => (int)($pending['delete_after'] ?? 0)
			];
		}

		$now = time();
		$graceSeconds = $graceDays > 0 ? ($graceDays * 86400) : (14 * 86400);
		$deleteAfter = $now + $graceSeconds;
		$currentStatus = (string)($user['uStatus'] ?? '3');
		$previousStatus = in_array($currentStatus, ['1', '3'], true) ? $currentStatus : '3';
		$requestToken = '';
		if (function_exists('random_bytes')) {
			try {
				$requestToken = bin2hex(random_bytes(16));
			} catch (Throwable $e) {
				$requestToken = '';
			}
		}
		if ($requestToken === '') {
			$requestToken = substr(hash('sha256', uniqid((string)$uid, true) . microtime(true)), 0, 32);
		}

		try {
			DB::begin();
			DB::exec(
				"INSERT INTO i_user_deletion_requests
				 (iuid_fk, request_status, requested_at, delete_after, previous_u_status, request_token)
				 VALUES (?, 'pending', ?, ?, ?, ?)",
				[$uid, $now, $deleteAfter, $previousStatus, $requestToken]
			);
			DB::exec("UPDATE i_users SET uStatus = '2' WHERE iuid = ?", [$uid]);
			DB::exec("DELETE FROM i_sessions WHERE session_uid = ?", [$uid]);
			DB::commit();
			return [
				'status' => 'ok',
				'delete_after' => $deleteAfter
			];
		} catch (Throwable $e) {
			DB::rollBack();
			return ['status' => 'error'];
		}
	}

	public function iN_CancelAccountDeletion($userID, $reason = 'manual') {
		$uid = (int)$userID;
		if ($uid <= 0 || !$this->iN_TableExists('i_user_deletion_requests')) {
			return false;
		}
		$pending = $this->iN_GetPendingAccountDeletion($uid);
		if (!$pending) {
			return false;
		}

		$restoreStatus = (string)($pending['previous_u_status'] ?? '3');
		if (!in_array($restoreStatus, ['1', '3'], true)) {
			$restoreStatus = '3';
		}
		$cancelReason = trim((string)$reason);
		if ($cancelReason === '') {
			$cancelReason = 'manual';
		}
		$now = time();
		try {
			DB::begin();
			DB::exec(
				"UPDATE i_user_deletion_requests
				 SET request_status = 'cancelled', canceled_at = ?, cancel_reason = ?
				 WHERE request_id = ? AND request_status = 'pending'",
				[$now, $cancelReason, (int)$pending['request_id']]
			);
			DB::exec("UPDATE i_users SET uStatus = ? WHERE iuid = ?", [$restoreStatus, $uid]);
			DB::commit();
			return true;
		} catch (Throwable $e) {
			DB::rollBack();
			return false;
		}
	}

	public function iN_CancelAccountDeletionOnLogin($userID) {
		return $this->iN_CancelAccountDeletion((int)$userID, 'auto_login');
	}

	public function iN_ProcessDueAccountDeletions($limit = 25) {
		$limit = (int)$limit;
		if ($limit < 1) {
			$limit = 25;
		}
		if (!$this->iN_TableExists('i_user_deletion_requests')) {
			return ['processed' => 0, 'failed' => 0];
		}
		$now = time();
		$rows = DB::all(
			"SELECT request_id, iuid_fk
			 FROM i_user_deletion_requests
			 WHERE request_status = 'pending' AND delete_after <= ?
			 ORDER BY request_id ASC
			 LIMIT {$limit}",
			[$now]
		);
		$processed = 0;
		$failed = 0;
		foreach ($rows as $row) {
			$requestID = (int)($row['request_id'] ?? 0);
			$uid = (int)($row['iuid_fk'] ?? 0);
			if ($requestID <= 0 || $uid <= 0) {
				continue;
			}
			if ($this->iN_CheckUserExist($uid) != 1) {
				DB::exec(
					"UPDATE i_user_deletion_requests
					 SET request_status = 'completed', completed_at = ?
					 WHERE request_id = ?",
					[$now, $requestID]
				);
				$processed++;
				continue;
			}
			if ($this->iN_HardDeleteUserById($uid)) {
				DB::exec(
					"UPDATE i_user_deletion_requests
					 SET request_status = 'completed', completed_at = ?
					 WHERE request_id = ?",
					[$now, $requestID]
				);
				$processed++;
			} else {
				$failed++;
			}
		}
		return ['processed' => $processed, 'failed' => $failed];
	}

	public function iN_GetLatestAccountExport($userID) {
		$uid = (int)$userID;
		if ($uid <= 0 || !$this->iN_TableExists('i_user_exports')) {
			return null;
		}
		$now = time();
		try {
			DB::exec(
				"UPDATE i_user_exports SET status = 'expired'
				 WHERE status = 'ready' AND expires_at > 0 AND expires_at < ?",
				[$now]
			);
		} catch (Throwable $e) {
			// Keep going even if status refresh fails.
		}
		return DB::one(
			"SELECT * FROM i_user_exports
			 WHERE iuid_fk = ? AND status = 'ready'
			 ORDER BY export_id DESC LIMIT 1",
			[$uid]
		);
	}

	public function iN_GetUserAccountExportByToken($userID, $token) {
		$uid = (int)$userID;
		$token = trim((string)$token);
		if (
			$uid <= 0 ||
			$token === '' ||
			!preg_match('/^[a-f0-9]{24,64}$/', $token) ||
			!$this->iN_TableExists('i_user_exports')
		) {
			return null;
		}
		$row = DB::one(
			"SELECT * FROM i_user_exports WHERE iuid_fk = ? AND export_token = ? LIMIT 1",
			[$uid, $token]
		);
		if (!$row) {
			return null;
		}
		if ((string)($row['status'] ?? '') !== 'ready') {
			return null;
		}
		$now = time();
		$expiresAt = (int)($row['expires_at'] ?? 0);
		if ($expiresAt > 0 && $expiresAt < $now) {
			DB::exec("UPDATE i_user_exports SET status = 'expired' WHERE export_id = ?", [(int)$row['export_id']]);
			return null;
		}
		$filePath = $this->iN_NormalizeUploadPath($row['file_path'] ?? '');
		if ($filePath === '') {
			return null;
		}
		$absolutePath = dirname(__DIR__) . '/' . $filePath;
		if (!is_file($absolutePath)) {
			DB::exec("UPDATE i_user_exports SET status = 'expired' WHERE export_id = ?", [(int)$row['export_id']]);
			return null;
		}
		$row['file_path'] = $filePath;
		$row['absolute_path'] = $absolutePath;
		return $row;
	}

	public function iN_MarkAccountExportDownloaded($exportID) {
		if (!$this->iN_TableExists('i_user_exports')) {
			return false;
		}
		DB::exec("UPDATE i_user_exports SET downloaded_at = ? WHERE export_id = ?", [time(), (int)$exportID]);
		return true;
	}

	public function iN_CreateAccountExport($userID, $baseUrl = '') {
		$uid = (int)$userID;
		if ($uid <= 0 || $this->iN_CheckUserExist($uid) != 1) {
			return ['status' => 'error'];
		}
		if (!$this->iN_TableExists('i_user_exports')) {
			return ['status' => 'schema_missing'];
		}
		if (!class_exists('ZipArchive')) {
			return ['status' => 'zip_unavailable'];
		}

		$now = time();
		$exportStart = microtime(true);
		try {
			DB::exec(
				"UPDATE i_user_exports SET status = 'expired'
				 WHERE status = 'ready' AND expires_at > 0 AND expires_at < ?",
				[$now]
			);
		} catch (Throwable $e) {
			// ignore
		}

		$token = '';
		$suffix = '';
		if (function_exists('random_bytes')) {
			try {
				$token = bin2hex(random_bytes(24));
				$suffix = bin2hex(random_bytes(4));
			} catch (Throwable $e) {
				$token = '';
				$suffix = '';
			}
		}
		if ($token === '') {
			$token = substr(hash('sha256', uniqid((string)$uid, true) . microtime(true)), 0, 48);
		}
		if ($suffix === '') {
			$suffix = substr(hash('sha256', uniqid((string)$uid, true) . microtime(true)), 0, 8);
		}

		$exportBaseRelative = 'uploads/account_exports';
		$exportBaseAbsolute = dirname(__DIR__) . '/' . $exportBaseRelative;
		if (!$this->iN_EnsureAccountExportProtection($exportBaseAbsolute)) {
			return ['status' => 'error'];
		}

		$relativeDir = $exportBaseRelative . '/' . date('Y-m-d');
		$absoluteDir = dirname(__DIR__) . '/' . $relativeDir;
		if (!is_dir($absoluteDir) && !@mkdir($absoluteDir, 0755, true) && !is_dir($absoluteDir)) {
			return ['status' => 'error'];
		}

		$fileName = 'account_export_' . $uid . '_' . $now . '_' . $suffix . '.zip';
		$relativePath = $relativeDir . '/' . $fileName;
		$absolutePath = $absoluteDir . '/' . $fileName;

		$zip = new ZipArchive();
		if ($zip->open($absolutePath, ZipArchive::CREATE | ZipArchive::OVERWRITE) !== true) {
			return ['status' => 'error'];
		}

		$jsonFlags = JSON_UNESCAPED_UNICODE
			| JSON_UNESCAPED_SLASHES
			| JSON_PRETTY_PRINT
			| JSON_HEX_TAG
			| JSON_HEX_AMP
			| JSON_HEX_APOS
			| JSON_HEX_QUOT;
		if (defined('JSON_INVALID_UTF8_SUBSTITUTE')) {
			$jsonFlags |= JSON_INVALID_UTF8_SUBSTITUTE;
		}

		$ensureRows = function ($rows) {
			return is_array($rows) ? $rows : [];
		};

		$profileAllowList = [
			'iuid',
