				'pr_question_answer'
			]
		);

		$friendRows = $ensureRows(DB::all(
			"SELECT * FROM i_friends WHERE fr_one = ? OR fr_two = ? ORDER BY fr_id DESC",
			[$uid, $uid]
		));
		$datasets['friends'] = $this->iN_FilterExportRowsByAllowList(
			$friendRows,
			[
				'fr_id',
				'fr_one',
				'fr_two',
				'fr_time',
				'fr_status'
			]
		);

		$this->iN_AppendUploadPathsFromRows($uploadPaths, $datasets['uploads'], ['uploaded_file_path', 'upload_tumbnail_file_path', 'uploaded_x_file_path']);
		$this->iN_AppendUploadPathsFromRows($uploadPaths, $datasets['avatars'], ['avatar_path']);
		$this->iN_AppendUploadPathsFromRows($uploadPaths, $datasets['covers'], ['cover_path']);
		$this->iN_AppendUploadPathsFromRows($uploadPaths, $datasets['stories'], ['uploaded_file_path', 'upload_tumbnail_file_path', 'uploaded_x_file_path']);
		$this->iN_AppendUploadPathsFromRows($uploadPaths, $datasets['conversation_uploads'], ['uploaded_file_path', 'uploaded_x_file_path']);
		$this->iN_AppendUploadPathsFromRows($uploadPaths, $datasets['posts'], ['post_file']);
		$this->iN_AppendUploadPathsFromRows($uploadPaths, $datasets['comments'], ['comment_file']);
		$this->iN_AppendUploadPathsFromRows($uploadPaths, $datasets['products'], ['pr_files', 'pr_downlodable_files']);
		$this->iN_AppendUploadPathsFromRows($uploadPaths, $datasets['bank_payments'], ['receipt_file_path']);

		$jsonChecksums = [];
		$usedDatasetAliases = [];
		foreach ($datasets as $name => $data) {
			$datasetAlias = $this->iN_GetExportDatasetAlias($name);
			$datasetAlias = preg_replace('/[^a-z0-9_]/', '_', strtolower(trim((string)$datasetAlias)));
			if ($datasetAlias === '') {
				$datasetAlias = 'dataset';
			}
			$baseAlias = $datasetAlias;
			$aliasIndex = 1;
			while (isset($usedDatasetAliases[$datasetAlias])) {
				$aliasIndex++;
				$datasetAlias = $baseAlias . '_' . $aliasIndex;
			}
			$usedDatasetAliases[$datasetAlias] = true;
			$entryPath = 'data/' . $datasetAlias . '.json';
			$safePayload = $this->iN_TransformExportPayloadStructure($data);
			$payload = $this->iN_EncodeExportPayload($safePayload, $jsonFlags);
			$zip->addFromString($entryPath, $payload);
			$jsonChecksums[] = [
				'path' => $entryPath,
				'sha256' => hash('sha256', $payload),
				'bytes' => strlen($payload)
			];
		}

		$fileManifest = [];
		$fileChecksums = [];
		$uploadPaths = array_values(array_unique($uploadPaths));
		foreach ($uploadPaths as $path) {
			$normalized = $this->iN_NormalizeUploadPath($path);
			if ($normalized === '') {
				continue;
			}
			$fullPath = dirname(__DIR__) . '/' . $normalized;
			if (!is_file($fullPath)) {
				$fileManifest[] = [
					'path' => $normalized,
					'status' => 'missing'
				];
				continue;
			}
			$safeName = preg_replace('/[^A-Za-z0-9._-]/', '_', basename($normalized));
			$archiveName = 'files/' . substr(md5($normalized), 0, 12) . '_' . $safeName;
			$zip->addFile($fullPath, $archiveName);
			$fileSizeBytes = @filesize($fullPath);
			$fileSizeBytes = $fileSizeBytes !== false ? (int)$fileSizeBytes : 0;
			$fileSha = @hash_file('sha256', $fullPath);
			$fileManifest[] = [
				'path' => $normalized,
				'status' => 'included',
				'archive' => $archiveName,
				'sha256' => $fileSha !== false ? (string)$fileSha : '-',
				'bytes' => $fileSizeBytes
			];
			$fileChecksums[] = [
				'path' => $archiveName,
				'source_path' => $normalized,
				'sha256' => $fileSha !== false ? (string)$fileSha : '-',
				'bytes' => $fileSizeBytes
			];
		}

		$fileManifestPath = 'data/file_manifest.json';
		$fileManifestPayload = $this->iN_EncodeExportPayload(
			$this->iN_NormalizeExportNullValues($fileManifest, '-'),
			$jsonFlags
		);
		$zip->addFromString($fileManifestPath, $fileManifestPayload);
		$jsonChecksums[] = [
			'path' => $fileManifestPath,
			'sha256' => hash('sha256', $fileManifestPayload),
			'bytes' => strlen($fileManifestPayload)
		];

		$securityNotice = [
			'export_format' => 'json+zip',
			'privacy_mode' => 'data_minimization_with_redaction',
			'what_is_redacted' => [
				'password_hashes',
				'device_tokens',
				'reset_verification_keys',
				'payment_tokens',
				'third_party_billing_identifiers'
			],
			'security_recommendation' => 'Store this archive in a private location and delete it after use.'
		];
		$securityNoticePath = 'data/security_notice.json';
		$securityNoticePayload = $this->iN_EncodeExportPayload(
			$this->iN_NormalizeExportNullValues($securityNotice, '-'),
			$jsonFlags
		);
		$zip->addFromString($securityNoticePath, $securityNoticePayload);
		$jsonChecksums[] = [
			'path' => $securityNoticePath,
			'sha256' => hash('sha256', $securityNoticePayload),
			'bytes' => strlen($securityNoticePayload)
		];

		$exportMeta = [
			'user_id' => $uid,
			'generated_at' => $now,
			'generated_at_iso' => gmdate('c', $now),
			'export_schema_version' => 3,
			'grace_delete_rule' => '14_days_auto_cancel_on_login',
			'archive_expiration_days' => 7
		];
		$exportMetaPath = 'data/export_meta.json';
		$exportMetaPayload = $this->iN_EncodeExportPayload(
			$this->iN_NormalizeExportNullValues($exportMeta, '-'),
			$jsonFlags
		);
		$zip->addFromString($exportMetaPath, $exportMetaPayload);
		$jsonChecksums[] = [
			'path' => $exportMetaPath,
			'sha256' => hash('sha256', $exportMetaPayload),
			'bytes' => strlen($exportMetaPayload)
		];

		$integrityManifest = [
			'hash_algorithm' => 'sha256',
			'json_files' => $jsonChecksums,
			'file_entries' => $fileChecksums
		];
		$zip->addFromString(
			'data/integrity_manifest.json',
			$this->iN_EncodeExportPayload($this->iN_NormalizeExportNullValues($integrityManifest, '-'), $jsonFlags)
		);
		if ($zip->close() !== true) {
			@unlink($absolutePath);
			return ['status' => 'error'];
		}
		@chmod($absolutePath, 0600);

		$fileSize = @filesize($absolutePath);
		$fileSize = $fileSize ? (int)$fileSize : 0;
		$generationSeconds = (int)max(1, round(microtime(true) - $exportStart));
		$expiresAt = $now + (7 * 86400);
		$hasGenerationColumn = $this->iN_TableColumnExists('i_user_exports', 'generation_seconds');

		try {
			DB::begin();
			DB::exec("UPDATE i_user_exports SET status = 'expired' WHERE iuid_fk = ? AND status = 'ready'", [$uid]);
			if ($hasGenerationColumn) {
				DB::exec(
					"INSERT INTO i_user_exports
					 (iuid_fk, export_token, file_path, file_size, generation_seconds, status, created_at, expires_at)
					 VALUES (?, ?, ?, ?, ?, 'ready', ?, ?)",
					[$uid, $token, $relativePath, $fileSize, $generationSeconds, $now, $expiresAt]
				);
			} else {
				DB::exec(
					"INSERT INTO i_user_exports
					 (iuid_fk, export_token, file_path, file_size, status, created_at, expires_at)
					 VALUES (?, ?, ?, ?, 'ready', ?, ?)",
					[$uid, $token, $relativePath, $fileSize, $now, $expiresAt]
				);
			}
			DB::commit();
		} catch (Throwable $e) {
			DB::rollBack();
			@unlink($absolutePath);
			return ['status' => 'error'];
		}

		$basePrefix = trim((string)$baseUrl) !== '' ? rtrim((string)$baseUrl, '/') . '/' : '';
		$downloadUrl = $basePrefix . 'requests/request.php?f=downloadAccountExport&token=' . rawurlencode($token);
		return [
			'status' => 'ok',
			'download_url' => $downloadUrl,
			'delete_after' => $expiresAt,
			'expires_at' => $expiresAt,
			'created_at' => $now,
			'file_size' => $fileSize,
			'generation_seconds' => $generationSeconds
		];
	}
