    /* Blog */
    private function normalizeBlogStatus(string $status): string {
        $status = strtolower(trim($status));
        return in_array($status, ['draft', 'published'], true) ? $status : 'draft';
    }

    private function generateUniqueBlogSlug(string $slug, ?int $excludeId = null): string {
        $base = $this->url_slugies($slug);
        if ($base === '') {
            $base = 'blog-' . uniqid();
        }
        $candidate = $base;
        $i = 1;
        while (true) {
            $params = [$candidate];
            $sql = "SELECT blog_id FROM i_blog_posts WHERE slug = ?";
            if ($excludeId !== null) {
                $sql .= " AND blog_id <> ?";
                $params[] = (int) $excludeId;
            }
            $exists = DB::one($sql, $params);
            if (!$exists) {
                break;
            }
            $candidate = $base . '-' . $i;
            $i++;
            if ($i > 50) {
                $candidate = $base . '-' . uniqid();
                break;
            }
        }
        return $candidate;
    }

    public function iN_CheckBlogExistsById(int $blogID): bool {
        return (bool) DB::col("SELECT 1 FROM i_blog_posts WHERE blog_id = ? LIMIT 1", [(int) $blogID]);
    }

    public function iN_CheckBlogExistsBySlug(string $slug): bool {
        return (bool) DB::col("SELECT 1 FROM i_blog_posts WHERE slug = ? LIMIT 1", [$slug]);
    }

    public function iN_CreateBlogPost(int $userID, array $data) {
        if ($this->iN_CheckIsAdmin($userID) != 1) {
            return false;
        }
        $title = trim((string) ($data['title'] ?? ''));
        if ($title === '') {
            return false;
        }
        $rawSlug = trim((string) ($data['slug'] ?? $title));
        $slug = $this->generateUniqueBlogSlug($rawSlug);
        $excerpt = trim((string) ($data['excerpt'] ?? ''));
        if (function_exists('mb_substr')) {
            $excerpt = mb_substr($excerpt, 0, 500, "utf-8");
        }
        $content = (string) ($data['content_html'] ?? '');
        $content = $this->xss_clean($content);
        $status = $this->normalizeBlogStatus((string) ($data['status'] ?? 'draft'));
        $isFeatured = in_array((string) ($data['is_featured'] ?? '0'), ['1', 'true', 'yes', 'on'], true) ? '1' : '0';
        $allowReactions = in_array((string) ($data['allow_reactions'] ?? '1'), ['0', '1'], true) ? (string) $data['allow_reactions'] : '1';
        $coverUploadId = isset($data['cover_upload_id']) && is_numeric($data['cover_upload_id']) ? (int) $data['cover_upload_id'] : null;
        $coverUrl = isset($data['cover_url']) && filter_var($data['cover_url'], FILTER_VALIDATE_URL) ? trim((string) $data['cover_url']) : '';
        $metaTitle = trim((string) ($data['meta_title'] ?? ''));
        if (function_exists('mb_substr')) {
            $metaTitle = mb_substr($metaTitle, 0, 255, "utf-8");
        }
        $metaDescription = trim((string) ($data['meta_description'] ?? ''));
        if (function_exists('mb_substr')) {
            $metaDescription = mb_substr($metaDescription, 0, 500, "utf-8");
        }
        $now = time();
        $publishedAt = null;
        if ($status === 'published') {
            $rawPublished = isset($data['published_at']) ? (int) $data['published_at'] : $now;
            $publishedAt = $rawPublished > 0 ? $rawPublished : $now;
        }
        DB::exec(
            "INSERT INTO i_blog_posts (author_id,title,slug,excerpt,content_html,cover_upload_id,cover_url,status,is_featured,published_at,created_at,updated_at,meta_title,meta_description,allow_reactions)
             VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)",
            [
                (int) $userID,
                (string) $title,
                (string) $slug,
                (string) $excerpt,
                (string) $content,
                $coverUploadId,
                (string) $coverUrl,
                (string) $status,
                (string) $isFeatured,
                $publishedAt,
                $now,
                $now,
                (string) $metaTitle,
                (string) $metaDescription,
                (string) $allowReactions
            ]
        );
        return (int) DB::lastId();
    }

    public function iN_UpdateBlogPost(int $userID, int $blogID, array $data) {
        if ($this->iN_CheckIsAdmin($userID) != 1 || !$this->iN_CheckBlogExistsById($blogID)) {
            return false;
        }
        $row = DB::one("SELECT * FROM i_blog_posts WHERE blog_id = ? LIMIT 1", [(int) $blogID]);
        if (!$row) {
            return false;
        }
        $title = trim((string) ($data['title'] ?? $row['title']));
        if ($title === '') {
            return false;
        }
        $rawSlug = trim((string) ($data['slug'] ?? $row['slug']));
        $slug = $this->generateUniqueBlogSlug($rawSlug, $blogID);
        $excerpt = trim((string) ($data['excerpt'] ?? $row['excerpt']));
        if (function_exists('mb_substr')) {
            $excerpt = mb_substr($excerpt, 0, 500, "utf-8");
        }
        $content = (string) ($data['content_html'] ?? $row['content_html']);
        $content = $this->xss_clean($content);
        $status = $this->normalizeBlogStatus((string) ($data['status'] ?? $row['status']));
        $isFeatured = in_array((string) ($data['is_featured'] ?? $row['is_featured']), ['1', 'true', 'yes', 'on'], true) ? '1' : '0';
        $allowReactions = in_array((string) ($data['allow_reactions'] ?? $row['allow_reactions']), ['0', '1'], true) ? (string) $data['allow_reactions'] : $row['allow_reactions'];
        $coverUploadId = isset($data['cover_upload_id']) && is_numeric($data['cover_upload_id']) ? (int) $data['cover_upload_id'] : $row['cover_upload_id'];
        $coverUrl = isset($data['cover_url']) && filter_var($data['cover_url'], FILTER_VALIDATE_URL) ? trim((string) $data['cover_url']) : (string) $row['cover_url'];
        $metaTitle = trim((string) ($data['meta_title'] ?? $row['meta_title']));
        if (function_exists('mb_substr')) {
            $metaTitle = mb_substr($metaTitle, 0, 255, "utf-8");
        }
        $metaDescription = trim((string) ($data['meta_description'] ?? $row['meta_description']));
        if (function_exists('mb_substr')) {
            $metaDescription = mb_substr($metaDescription, 0, 500, "utf-8");
        }
        $publishedAt = $row['published_at'];
        if ($status === 'published') {
            $rawPublished = isset($data['published_at']) ? (int) $data['published_at'] : ($row['published_at'] ?? time());
            $publishedAt = $rawPublished > 0 ? $rawPublished : time();
        } else {
            $publishedAt = null;
        }
        $now = time();
        DB::exec(
            "UPDATE i_blog_posts SET title = ?, slug = ?, excerpt = ?, content_html = ?, cover_upload_id = ?, cover_url = ?, status = ?, is_featured = ?, published_at = ?, updated_at = ?, meta_title = ?, meta_description = ?, allow_reactions = ?
             WHERE blog_id = ?",
            [
                (string) $title,
                (string) $slug,
                (string) $excerpt,
                (string) $content,
                $coverUploadId,
                (string) $coverUrl,
                (string) $status,
                (string) $isFeatured,
                $publishedAt,
                $now,
                (string) $metaTitle,
                (string) $metaDescription,
                (string) $allowReactions,
                (int) $blogID
            ]
        );
        return true;
    }

    public function iN_DeleteBlogPost(int $userID, int $blogID): bool {
        if ($this->iN_CheckIsAdmin($userID) != 1 || !$this->iN_CheckBlogExistsById($blogID)) {
            return false;
        }
        DB::exec("DELETE FROM i_blog_reactions WHERE blog_id = ?", [(int) $blogID]);
        DB::exec("DELETE FROM i_blog_posts WHERE blog_id = ?", [(int) $blogID]);
        return true;
    }

    public function iN_GetBlogPostById(int $blogID) {
        return DB::one("SELECT * FROM i_blog_posts WHERE blog_id = ? LIMIT 1", [(int) $blogID]);
    }

    public function iN_GetBlogPostBySlug(string $slug, bool $onlyPublished = false) {
        $params = [$slug];
        $sql = "SELECT * FROM i_blog_posts WHERE slug = ?";
        if ($onlyPublished) {
            $sql .= " AND status = 'published' AND (published_at IS NULL OR published_at <= ?)";
            $params[] = time();
        }
        $sql .= " LIMIT 1";
        return DB::one($sql, $params);
    }

    public function iN_GetBlogListAdmin(int $userID, int $paginationLimit, int $page, string $search = '', string $status = 'all') {
        if ($this->iN_CheckIsAdmin($userID) != 1) {
            return false;
        }
        $page = $page < 1 ? 1 : $page;
        $start_from = ($page - 1) * $paginationLimit;
        $where = [];
        $params = [];
        if ($search !== '') {
            $where[] = "(title LIKE ? OR excerpt LIKE ?)";
            $like = '%' . $search . '%';
            $params[] = $like;
            $params[] = $like;
        }
        $status = strtolower($status);
        if (in_array($status, ['draft', 'published'], true)) {
            $where[] = "status = ?";
            $params[] = $status;
        }
        $whereSql = '';
        if (!empty($where)) {
            $whereSql = 'WHERE ' . implode(' AND ', $where);
        }
        $sql = "SELECT * FROM i_blog_posts $whereSql ORDER BY created_at DESC LIMIT $start_from, $paginationLimit";
        $rows = DB::all($sql, $params);
        return !empty($rows) ? $rows : null;
    }

    public function iN_GetBlogListAdminCount(string $search = '', string $status = 'all'): int {
        $where = [];
        $params = [];
        if ($search !== '') {
            $where[] = "(title LIKE ? OR excerpt LIKE ?)";
            $like = '%' . $search . '%';
            $params[] = $like;
            $params[] = $like;
        }
        $status = strtolower($status);
        if (in_array($status, ['draft', 'published'], true)) {
            $where[] = "status = ?";
            $params[] = $status;
        }
        $whereSql = '';
        if (!empty($where)) {
            $whereSql = 'WHERE ' . implode(' AND ', $where);
        }
        $val = DB::col("SELECT COUNT(*) FROM i_blog_posts $whereSql", $params);
        return $val !== false ? (int) $val : 0;
    }

    public function iN_PublicBlogList(int $limit, int $page, string $search = '') {
        $limit = $limit < 1 ? 10 : $limit;
        $page = $page < 1 ? 1 : $page;
        $start_from = ($page - 1) * $limit;
        $where = ["status = 'published'", "(published_at IS NULL OR published_at <= ?)"];
        $params = [time()];
        if ($search !== '') {
            $where[] = "(title LIKE ? OR excerpt LIKE ?)";
            $like = '%' . $search . '%';
            $params[] = $like;
            $params[] = $like;
        }
        $whereSql = 'WHERE ' . implode(' AND ', $where);
        $sql = "SELECT * FROM i_blog_posts $whereSql ORDER BY published_at DESC, created_at DESC LIMIT $start_from, $limit";
        $rows = DB::all($sql, $params);
        return !empty($rows) ? $rows : null;
    }

    public function iN_PublicBlogFeatured(int $limit = 1) {
        $limit = $limit < 1 ? 1 : $limit;
        $sql = "SELECT * FROM i_blog_posts WHERE status = 'published' AND (published_at IS NULL OR published_at <= ?) ORDER BY is_featured DESC, published_at DESC, created_at DESC LIMIT $limit";
        $rows = DB::all($sql, [time()]);
        return !empty($rows) ? $rows : null;
    }

    public function iN_IncrementBlogView(int $blogID, int $userID = 0, ?string $ip = null): bool {
        $blogID = (int) $blogID;
        if ($blogID < 1) {
            return false;
        }
        $userID = (int) $userID;
        $ip = $ip !== null ? trim($ip) : $this->iN_GetIPAddress();
        $ipHash = $userID > 0 ? null : ($ip !== '' ? hash('sha256', $ip) : null);
        $inserted = DB::exec(
            "INSERT IGNORE INTO i_blog_views (blog_id,iuid_fk,ip_hash,created_at) VALUES (?,?,?,?)",
            [$blogID, $userID > 0 ? $userID : 0, $ipHash, time()]
        );
        if ($inserted > 0) {
            DB::exec("UPDATE i_blog_posts SET view_count = IFNULL(view_count, 0) + 1 WHERE blog_id = ?", [$blogID]);
            return true;
        }
        return false;
    }

    public function iN_BlogReactionCounts(int $blogID): array {
        $rows = DB::all("SELECT reaction, COUNT(*) as total FROM i_blog_reactions WHERE blog_id = ? GROUP BY reaction", [(int) $blogID]);
        $data = ['like' => 0, 'dislike' => 0];
        if ($rows) {
            foreach ($rows as $row) {
                $type = $row['reaction'] ?? '';
                if ($type === 'like' || $type === 'dislike') {
                    $data[$type] = (int) $row['total'];
                }
            }
        }
        return $data;
    }

    public function iN_UserBlogReaction(int $uid, int $blogID): ?string {
        $row = DB::one("SELECT reaction FROM i_blog_reactions WHERE blog_id = ? AND iuid_fk = ? LIMIT 1", [(int) $blogID, (int) $uid]);
        return $row ? (string) $row['reaction'] : null;
    }

    public function iN_ToggleBlogReaction(int $uid, int $blogID, string $reaction) {
        $reaction = ($reaction === 'dislike') ? 'dislike' : 'like';
        if (!$this->iN_CheckUserExist($uid) || !$this->iN_CheckBlogExistsById($blogID)) {
            return false;
        }
        $row = DB::one("SELECT reaction_id, reaction FROM i_blog_reactions WHERE blog_id = ? AND iuid_fk = ? LIMIT 1", [(int) $blogID, (int) $uid]);
        $now = time();
        if ($row) {
            if ($row['reaction'] === $reaction) {
                DB::exec("DELETE FROM i_blog_reactions WHERE reaction_id = ?", [(int) $row['reaction_id']]);
                return ['status' => 'removed', 'reaction' => $reaction];
            }
            DB::exec("UPDATE i_blog_reactions SET reaction = ?, created_at = ? WHERE reaction_id = ?", [(string) $reaction, $now, (int) $row['reaction_id']]);
            return ['status' => 'updated', 'reaction' => $reaction];
        }
        DB::exec("INSERT INTO i_blog_reactions (blog_id,iuid_fk,reaction,created_at) VALUES (?,?,?,?)", [(int) $blogID, (int) $uid, (string) $reaction, $now]);
        return ['status' => 'created', 'reaction' => $reaction];
    }

