    public function iN_UpdatePaymentBeta($userID, $column, $mode) {
        if ($this->iN_CheckIsAdmin($userID) != 1) {
            return false;
        }
        $allowedColumns = [
            'paypal_beta',
            'bitpay_beta',
            'stripe_beta',
            'authorizenet_beta',
            'iyzico_beta',
            'razorpay_beta',
            'paystack_beta',
            'ccbill_beta',
            'coinpayments_beta',
            'mercadopago_beta',
            'yookassa_beta',
            'epoch_beta',
            'moneroo_beta',
            'nowpayments_beta',
            'paysafecard_beta',
            'bank_beta'
        ];
        if (!in_array($column, $allowedColumns, true)) {
            return false;
        }
        $columnCheck = DB::one("SHOW COLUMNS FROM i_payment_methods LIKE '{$column}'");
        if (!$columnCheck) {
            DB::exec("ALTER TABLE i_payment_methods ADD {$column} enum('0','1') NOT NULL DEFAULT '0'");
        }
        DB::exec("UPDATE i_payment_methods SET {$column} = ? WHERE payment_method_id = 1", [(string)$mode]);
        return true;
    }
