	public function xss_clean($data) {
		// Fix &entity\n;
		$data = str_replace(array('&amp;', '&lt;', '&gt;'), array('&amp;amp;', '&amp;lt;', '&amp;gt;'), $data);
		$data = preg_replace('/(&#*\w+)[\x00-\x20]+;/u', '$1;', $data);
		$data = preg_replace('/(&#x*[0-9A-F]+);*/iu', '$1;', $data);
		$data = html_entity_decode($data, ENT_COMPAT, 'UTF-8');

		// Remove any attribute starting with "on" or xmlns
		$data = preg_replace('#(<[^>]+?[\x00-\x20"\'])(?:on|xmlns)[^>]*+>#iu', '$1>', $data);

		// Remove javascript: and vbscript: protocols
		$data = preg_replace('#([a-z]*)[\x00-\x20]*=[\x00-\x20]*([`\'"]*)[\x00-\x20]*j[\x00-\x20]*a[\x00-\x20]*v[\x00-\x20]*a[\x00-\x20]*s[\x00-\x20]*c[\x00-\x20]*r[\x00-\x20]*i[\x00-\x20]*p[\x00-\x20]*t[\x00-\x20]*:#iu', '$1=$2nojavascript...', $data);
		$data = preg_replace('#([a-z]*)[\x00-\x20]*=([\'"]*)[\x00-\x20]*v[\x00-\x20]*b[\x00-\x20]*s[\x00-\x20]*c[\x00-\x20]*r[\x00-\x20]*i[\x00-\x20]*p[\x00-\x20]*t[\x00-\x20]*:#iu', '$1=$2novbscript...', $data);
		$data = preg_replace('#([a-z]*)[\x00-\x20]*=([\'"]*)[\x00-\x20]*-moz-binding[\x00-\x20]*:#u', '$1=$2nomozbinding...', $data);

		// Anti-XSS: Removes IE-only XSS vectors such as 'expression(...)' used within inline style attributes.
		$data = preg_replace('#(<[^>]+?)style[\x00-\x20]*=[\x00-\x20]*[`\'"]*.*?expression[\x00-\x20]*\([^>]*+>#i', '$1>', $data);
		$data = preg_replace('#(<[^>]+?)style[\x00-\x20]*=[\x00-\x20]*[`\'"]*.*?behaviour[\x00-\x20]*\([^>]*+>#i', '$1>', $data);
		$data = preg_replace('#(<[^>]+?)style[\x00-\x20]*=[\x00-\x20]*[`\'"]*.*?s[\x00-\x20]*c[\x00-\x20]*r[\x00-\x20]*i[\x00-\x20]*p[\x00-\x20]*t[\x00-\x20]*:*[^>]*+>#iu', '$1>', $data);

		// Remove namespaced elements (we do not need them)
		$data = preg_replace('#</*\w+:\w[^>]*+>#i', '', $data);

		do {
			$old_data = $data;
			$data = preg_replace('#</*(?:applet|b(?:ase|gsound|link)|embed|frame(?:set)?|i(?:frame|layer)|l(?:ayer|ink)|meta|object|s(?:cript|tyle)|title|xml)[^>]*+>#i', '', $data);
		} while ($old_data !== $data);

		return $data;
	}
	public function iN_SanitizeSvgIcon($svg) {
        if (!is_string($svg)) {
            $svg = (string)$svg;
        }
        $svg = trim($svg);
        if ($svg === '') {
            return '';
        }

        $svg = str_replace("\0", '', $svg);
        $svg = preg_replace('/<\?xml.*?\?>/is', '', $svg);
        $svg = preg_replace('/<!DOCTYPE.*?>/is', '', $svg);
        $svg = preg_replace('/<!ENTITY.*?>/is', '', $svg);

        if (preg_match('/<svg\b[^>]*>.*<\/svg>/is', $svg, $match)) {
            $svg = $match[0];
        }

        $allowedTags = array(
            'svg', 'g', 'path', 'circle', 'rect', 'line', 'polyline', 'polygon', 'ellipse',
            'defs', 'lineargradient', 'radialgradient', 'stop', 'clippath', 'mask', 'use',
            'title', 'desc', 'symbol', 'pattern'
        );
        $allowedAttrs = array(
            'xmlns', 'xmlns:xlink', 'xml:space', 'viewbox', 'width', 'height', 'fill',
            'fill-rule', 'fill-opacity', 'stroke', 'stroke-width', 'stroke-linecap',
            'stroke-linejoin', 'stroke-miterlimit', 'stroke-dasharray', 'stroke-dashoffset',
            'stroke-opacity', 'd', 'x', 'y', 'x1', 'y1', 'x2', 'y2', 'cx', 'cy', 'r', 'rx',
            'ry', 'points', 'transform', 'opacity', 'class', 'id', 'preserveaspectratio',
            'clip-rule', 'clip-path', 'mask', 'maskunits', 'maskcontentunits',
            'shape-rendering', 'text-rendering', 'image-rendering', 'vector-effect',
            'gradientunits', 'gradienttransform', 'spreadmethod', 'offset', 'stop-color',
            'stop-opacity', 'href', 'xlink:href', 'aria-hidden', 'role', 'focusable', 'style',
            'version', 'enable-background'
        );

        $doc = new DOMDocument();
        $previous = libxml_use_internal_errors(true);
        $loaded = $doc->loadXML($svg, LIBXML_NONET | LIBXML_NOERROR | LIBXML_NOWARNING);
        libxml_clear_errors();
        libxml_use_internal_errors($previous);

        if (!$loaded || !$doc->documentElement) {
            $allowedTagsString = '<svg><g><path><circle><rect><line><polyline><polygon><ellipse><defs><linearGradient><radialGradient><stop><clipPath><mask><use><title><desc><symbol><pattern>';
            $svg = strip_tags($svg, $allowedTagsString);
            return $this->iN_SanitizeSvgAttributes($svg);
        }

        $xpath = new DOMXPath($doc);
        $nodes = $xpath->query('//*');
        if ($nodes !== false) {
            foreach ($nodes as $node) {
                $tag = strtolower($node->nodeName);
                if (!in_array($tag, $allowedTags, true)) {
                    if ($node->parentNode) {
                        $node->parentNode->removeChild($node);
                    }
                    continue;
                }

                if ($node->hasAttributes()) {
                    $attrNames = array();
                    foreach ($node->attributes as $attr) {
                        $attrNames[] = $attr->nodeName;
                    }
                    foreach ($attrNames as $attrName) {
                        $attr = $node->getAttributeNode($attrName);
                        if (!$attr) {
                            continue;
                        }
                        $attrLower = strtolower($attrName);
                        if (strpos($attrLower, 'on') === 0) {
                            $node->removeAttributeNode($attr);
                            continue;
                        }
                        if (!in_array($attrLower, $allowedAttrs, true)) {
                            $node->removeAttributeNode($attr);
                            continue;
                        }
                        $value = trim($attr->nodeValue);
                        if ($value === '') {
                            continue;
                        }
                        $valueLower = strtolower($value);
                        if (strpos($valueLower, 'javascript:') !== false || strpos($valueLower, 'vbscript:') !== false || strpos($valueLower, 'data:') !== false) {
                            $node->removeAttributeNode($attr);
                            continue;
                        }
                        if (($attrLower === 'href' || $attrLower === 'xlink:href') && $value[0] !== '#') {
                            $node->removeAttributeNode($attr);
                            continue;
                        }
                        if (strpos($valueLower, 'url(') !== false && !preg_match('/url\s*\(\s*[\'"]?#/i', $value)) {
                            $node->removeAttributeNode($attr);
                            continue;
                        }
                        if ($attrLower === 'style' && preg_match('/(expression|@import|url\s*\(|javascript:|vbscript:|data:)/i', $value)) {
                            $node->removeAttributeNode($attr);
                        }
                    }
                }
            }
        }

        $output = $doc->saveXML($doc->documentElement);
        return $output ? $output : '';
    }
    private function iN_SanitizeSvgAttributes($svg) {
        $svg = preg_replace('/\son\w+\s*=\s*(["\']).*?\1/iu', '', $svg);
        $svg = preg_replace('/\son\w+\s*=\s*[^\s>]+/iu', '', $svg);
        $svg = preg_replace_callback('/\s(xlink:href|href)\s*=\s*(["\'])(.*?)\2/iu', function ($match) {
            $value = trim($match[3]);
            if ($value === '' || $value[0] !== '#') {
                return '';
            }
            return ' ' . $match[1] . '=' . $match[2] . $value . $match[2];
        }, $svg);
        $svg = preg_replace('/\s[\w:-]+\s*=\s*(["\'])\s*(?:javascript:|vbscript:|data:)[^"\']*\1/iu', '', $svg);
        $svg = preg_replace('/\sstyle\s*=\s*(["\']).*?\1/iu', '', $svg);
        $svg = preg_replace('/\s[\w:-]+\s*=\s*(["\']).*?url\s*\(\s*(?:\'|")?\s*(?:javascript:|vbscript:|data:)[^"\']*\)\s*.*?\1/iu', '', $svg);
        return $svg;
    }
