        $now = time();
        $row = DB::one(
            "SELECT * FROM i_live WHERE live_uid_fk = ? AND started_at IS NOT NULL AND finish_time >= ? ORDER BY live_id DESC LIMIT 1",
            [(int)$userID, (int)$now]
        );
        if (!$row) {
            $row = DB::one(
                "SELECT * FROM i_live WHERE live_uid_fk = ? AND scheduled_at IS NOT NULL AND scheduled_status = 'scheduled' ORDER BY scheduled_at ASC, live_id DESC LIMIT 1",
                [(int)$userID]
            );
        }
        if (!$row) {
            $row = DB::one("SELECT * FROM i_live WHERE live_uid_fk = ? ORDER BY live_id DESC LIMIT 1", [(int)$userID]);
        }
        return $row ?: false;
