	/*Create a Free Live Streaming*/
public function iN_CreateAFreeLiveStreaming($userID, $liveStreamingTitle, $freeLiveTime, $channelName) {
        $currentTime = time();
        $finishTime = $currentTime + 60 * $freeLiveTime;
        $l_Time = $this->iN_GetLastLiveFinishTime($userID);
        if ($l_Time) {
            if ($currentTime > $l_Time) {
                DB::exec("INSERT INTO i_live (live_name, started_at, finish_time, live_uid_fk, live_type, live_channel) VALUES (?,?,?,?, 'free', ?)",
                    [(string)$liveStreamingTitle, $currentTime, $finishTime, (int)$userID, (string)$channelName]
                );
                return true;
            } else {
                /*Redirect user from live streaming page*/
                echo '2';
            }
        } else {
            DB::exec("INSERT INTO i_live (live_name, started_at, finish_time, live_uid_fk, live_type, live_channel) VALUES (?,?,?,?, 'free', ?)",
                [(string)$liveStreamingTitle, $currentTime, $finishTime, (int)$userID, (string)$channelName]
            );
            return true;
        }
}
	/*Create a Free Live Streaming*/
	public function iN_CreateAPaidLiveStreaming($userID, $liveStreamingTitle, $freeLiveTime, $channelName, $streamFee) {
		$currentTime = time();
		$finishTime = $currentTime + 60 * $freeLiveTime;
        if ($this->iN_CheckUserExist($userID) == 1) {
            DB::exec("INSERT INTO i_live(live_name, started_at, finish_time, live_uid_fk, live_type, live_channel, live_credit) VALUES(?,?,?,?, 'paid', ?, ?)",
                [(string)$liveStreamingTitle, $currentTime, $finishTime, (int)$userID, (string)$channelName, (string)$streamFee]
            );
            return true;
        } else {
            return false;
        }
	}
    public function iN_CreateScheduledLive(
        $userID,
        $liveStreamingTitle,
        $channelName,
        $liveType,
        $streamFee,
        $scheduledAt,
        $notifyLive,
        $notifyAudience,
        array $notifySelectedIds = []
    ) {
        if ($this->iN_CheckUserExist($userID) != 1) {
            return false;
        }
        $time = time();
        $liveType = ($liveType === 'paid') ? 'paid' : 'free';
        $streamFee = $liveType === 'paid' ? (string)$streamFee : null;
        $notifyLiveVal = ($notifyLive === 1 || $notifyLive === '1') ? '1' : '0';
        $notifyAudience = in_array($notifyAudience, ['followers', 'subscribers', 'selected'], true) ? $notifyAudience : 'followers';
        $notifySelectedIds = array_values(array_unique(array_map('intval', $notifySelectedIds)));
        $notifySelected = !empty($notifySelectedIds) ? implode(',', $notifySelectedIds) : null;
        DB::exec(
            "INSERT INTO i_live (live_name, live_uid_fk, live_type, live_channel, live_credit, scheduled_at, scheduled_status, notify_live, notify_audience, notify_selected_ids, live_time)
             VALUES (?,?,?,?,?,?, 'scheduled', ?, ?, ?, ?)",
            [
                (string)$liveStreamingTitle,
                (int)$userID,
                (string)$liveType,
                (string)$channelName,
                $streamFee,
                (int)$scheduledAt,
                (string)$notifyLiveVal,
                (string)$notifyAudience,
                $notifySelected,
                (int)$time
            ]
        );
        $liveId = (int) DB::lastId();
        return $liveId > 0 ? $liveId : false;
    }
    public function iN_StartScheduledLive($userID, $liveID, $freeLiveTime) {
        if ($this->iN_CheckLiveIDExistAndOwner($userID, $liveID) != 1) {
            return false;
        }
        $time = time();
        $finishTime = $time + 60 * (int)$freeLiveTime;
        DB::exec(
            "UPDATE i_live SET started_at = ?, finish_time = ?, scheduled_status = 'live' WHERE live_id = ? AND live_uid_fk = ?",
            [(int)$time, (int)$finishTime, (int)$liveID, (int)$userID]
        );
        return true;
    }
