    public function iN_GetScheduledLiveByPostId(int $postId): ?array {
        static $cache = [];
        if ($postId <= 0) {
            return null;
        }
        if (array_key_exists($postId, $cache)) {
            return $cache[$postId];
        }
        try {
            $row = DB::one(
                "SELECT live_id, live_uid_fk, live_name, scheduled_at, scheduled_status
                 FROM i_live
                 WHERE scheduled_post_id = ? AND scheduled_status = 'scheduled'
                 LIMIT 1",
                [(int)$postId]
            );
            $cache[$postId] = $row ?: null;
            return $cache[$postId];
        } catch (Throwable $e) {
            $cache[$postId] = null;
            return null;
        }
    }
    public function iN_DeleteScheduledLive(int $userID, int $liveID): bool {
        if ($this->iN_CheckUserExist($userID) != 1) {
            return false;
        }
        $live = DB::one(
            "SELECT live_id, scheduled_post_id
             FROM i_live
             WHERE live_id = ? AND live_uid_fk = ? AND scheduled_status = 'scheduled'
               AND (started_at IS NULL OR started_at = 0)
             LIMIT 1",
            [(int)$liveID, (int)$userID]
        );
        if (!$live) {
            return false;
        }
        try {
            DB::begin();
            DB::exec("DELETE FROM i_live_reminders WHERE live_id = ?", [(int)$liveID]);
            DB::exec("DELETE FROM i_live_pinned_products WHERE live_id = ?", [(int)$liveID]);
            DB::exec("DELETE FROM i_live_questions WHERE live_id = ?", [(int)$liveID]);
            $pollRows = DB::all("SELECT poll_id FROM i_live_polls WHERE live_id = ?", [(int)$liveID]);
            if (!empty($pollRows)) {
                $pollIds = array_map('intval', array_column($pollRows, 'poll_id'));
                $placeholders = implode(',', array_fill(0, count($pollIds), '?'));
                DB::exec("DELETE FROM i_live_poll_votes WHERE poll_id_fk IN ({$placeholders})", $pollIds);
                DB::exec("DELETE FROM i_live_poll_options WHERE poll_id_fk IN ({$placeholders})", $pollIds);
                DB::exec("DELETE FROM i_live_polls WHERE poll_id IN ({$placeholders})", $pollIds);
            }
            $postId = isset($live['scheduled_post_id']) ? (int)$live['scheduled_post_id'] : 0;
            if ($postId > 0) {
                DB::exec("DELETE FROM i_posts WHERE post_id = ? AND post_owner_id = ?", [$postId, (int)$userID]);
            }
            DB::exec("DELETE FROM i_live WHERE live_id = ? AND live_uid_fk = ?", [(int)$liveID, (int)$userID]);
            DB::commit();
            return true;
        } catch (Throwable $e) {
            DB::rollBack();
            return false;
        }
    }
    public function iN_StartCloudRecording($vendor, $region, $bucket, $accessKey, $secretKey, $cname, $uid, $post_id, $agoraAppID, $agoraCustomerID, $agoraCertificate) {
        $providerKey = isset($GLOBALS['rtProvider']) ? $GLOBALS['rtProvider'] : 'agora';
        if ($providerKey === 'livekit') {
            // LiveKit recording is not wired yet; skip gracefully.
            return false;
        }

        $provider = LiveProviderFactory::makeLiveProvider(
            (string)$agoraAppID,
            (string)$agoraCertificate,
            (string)$agoraCustomerID,
            (string)$providerKey,
            (string)($GLOBALS['livekitAPIKey'] ?? ''),
            (string)($GLOBALS['livekitAPISecret'] ?? ''),
            (string)($GLOBALS['livekitWSUrl'] ?? '')
        );

        return $provider->startRecording($cname, (int)$post_id, [
            'vendor' => $vendor,
            'region' => $region,
            'bucket' => $bucket,
            'accessKey' => $accessKey,
            'secretKey' => $secretKey,
            'uid' => $uid,
        ]);
	}
