	/*Buy Post*/
public function iN_BuyLiveStreaming($userID, $userLiveStreamOwnerID, $purchasdLiveStreamID, $amount, $adminEarning, $userEarning, $fee, $credit) {
        if ($this->iN_CheckUserExist($userID) == '1' && $this->iN_CheckUserExist($userLiveStreamOwnerID) == '1' && $this->iN_CheckLiveIDExist($purchasdLiveStreamID) == '1') {
            $time = time();
            $split = $this->iN_CalculateAgencySplit($userLiveStreamOwnerID, $amount, $fee);
            $adminEarning = $split['admin_earning'];
            $userEarning = $split['creator_net'];
            $agencyId = $split['agency_id'];
            $agencyFee = $split['agency_fee'];
            $agencyEarning = $split['agency_earning'];
            DB::exec("INSERT INTO i_user_payments (payer_iuid_fk, payed_iuid_fk, agency_id_fk, payed_live_stream_id_fk, payment_type, payment_time, payment_status, amount, fee, agency_fee, admin_earning, agency_earning, user_earning)
                      VALUES (?,?,?,?, 'live_stream', ?, 'ok', ?, ?, ?, ?, ?, ?)",
                      [(int)$userID, (int)$userLiveStreamOwnerID, $agencyId, (int)$purchasdLiveStreamID, $time, (string)$amount, (string)$fee, (string)$agencyFee, (string)$adminEarning, (string)$agencyEarning, (string)$userEarning]
            );
            $paymentId = (int) DB::lastId();
            DB::exec("UPDATE i_users SET wallet_points = wallet_points - ? WHERE iuid = ?", [(string)$credit, (int)$userID]);
            DB::exec("UPDATE i_users SET wallet_money = wallet_money + ? WHERE iuid = ?", [(string)$userEarning, (int)$userLiveStreamOwnerID]);
            if ($paymentId > 0) {
                $currency = $GLOBALS['defaultCurrency'] ?? 'USD';
                $this->iN_AssignInvoiceToPayment($paymentId, (int)$userID, (float)$amount, $currency);
            }
            return true;
        }
        return false;
}
	/*Free Live Streamings List*/
    public function iN_LiveStreaminsList($liveStyle, $lastPostID, $showingPost) {
        $tree_minutes_ago = time() - (10 * 1);
        $now = time();
        $more = '';
        $params = [(string)$liveStyle, (int)$tree_minutes_ago, (int)$now];
        if ($lastPostID) { $more = ' AND L.live_id < ? '; $params[] = (int)$lastPostID; }
        $showingPost = (int)$showingPost;
        $sql = "SELECT DISTINCT
                L.live_id, L.live_name, L.live_uid_fk, L.finish_time, L.scheduled_at, L.started_at, L.scheduled_status, L.live_credit,
                U.iuid, U.i_username, U.i_user_fullname
            FROM i_live L FORCE INDEX(ix_Live)
            INNER JOIN i_users U FORCE INDEX(ixForceUser)
                ON L.live_uid_fk = U.iuid AND U.uStatus IN('1','3')
            WHERE L.live_type = ?
              AND (
                  (L.finish_time IS NOT NULL AND L.finish_time >= ?)
               OR (L.scheduled_at IS NOT NULL AND L.started_at IS NULL AND L.scheduled_status = 'scheduled' AND L.scheduled_at >= ?)
              ) $more
            ORDER BY L.live_id DESC LIMIT $showingPost";
        $rows = DB::all($sql, $params);
        return !empty($rows) ? $rows : null;
    }
