    private function iN_GetActiveLivePollId($liveID): int {
        $row = DB::one(
            "SELECT poll_id FROM i_live_polls WHERE live_id = ? AND status = 'active' ORDER BY poll_id DESC LIMIT 1",
            [(int)$liveID]
        );
        return $row && isset($row['poll_id']) ? (int)$row['poll_id'] : 0;
    }
    public function iN_GetLivePollDetails($liveID, $currentUserId = null) {
        $pollId = $this->iN_GetActiveLivePollId((int)$liveID);
        if ($pollId <= 0) {
            return null;
        }
        $poll = DB::one("SELECT poll_id, live_id, question, status, created_by, created_at FROM i_live_polls WHERE poll_id = ? LIMIT 1", [$pollId]);
        if (!$poll) {
            return null;
        }
        $options = DB::all(
            "SELECT option_id, option_text, votes_count
             FROM i_live_poll_options WHERE poll_id_fk = ? AND status = 'active'
             ORDER BY option_order ASC, option_id ASC",
            [$pollId]
        );
        $totalVotes = 0;
        if (!empty($options)) {
            foreach ($options as $opt) {
                $totalVotes += (int)($opt['votes_count'] ?? 0);
            }
        }
        $userVote = null;
        if (!empty($currentUserId)) {
            $userVote = DB::col(
                "SELECT option_id_fk FROM i_live_poll_votes WHERE poll_id_fk = ? AND voter_uid_fk = ? LIMIT 1",
                [(int)$pollId, (int)$currentUserId]
            );
        }
        $payload = [
            'poll_id' => (int)$pollId,
            'live_id' => (int)($poll['live_id'] ?? $liveID),
            'question' => (string)($poll['question'] ?? ''),
            'status' => (string)($poll['status'] ?? 'active'),
            'created_by' => (int)($poll['created_by'] ?? 0),
            'created_at' => (int)($poll['created_at'] ?? 0),
            'total_votes' => (int)$totalVotes,
            'user_vote' => $userVote ? (int)$userVote : 0,
            'options' => []
        ];
        if (!empty($options)) {
            foreach ($options as $opt) {
                $votes = (int)($opt['votes_count'] ?? 0);
                $percent = $totalVotes > 0 ? round(($votes / $totalVotes) * 100) : 0;
                $payload['options'][] = [
                    'option_id' => (int)($opt['option_id'] ?? 0),
                    'option_text' => (string)($opt['option_text'] ?? ''),
                    'votes_count' => $votes,
                    'percent' => $percent
                ];
            }
        }
        return $payload;
    }
    public function iN_CreateLivePoll($liveID, $userID, $question, array $options) {
        if ($this->iN_CheckLiveIDExistAndOwner($userID, $liveID) != 1) {
            return ['error' => 'not_allowed'];
        }
        $question = trim((string)$question);
        if ($question === '') {
            return ['error' => 'question_required'];
        }
        $pollMinOptions = isset($GLOBALS['pollMinOptions']) ? (int)$GLOBALS['pollMinOptions'] : 2;
        $pollMaxOptions = isset($GLOBALS['pollMaxOptions']) ? (int)$GLOBALS['pollMaxOptions'] : 6;
        if ($pollMinOptions < 2) { $pollMinOptions = 2; }
        if ($pollMaxOptions < $pollMinOptions) { $pollMaxOptions = $pollMinOptions; }

        $cleanOptions = [];
        foreach ($options as $opt) {
            $opt = trim((string)$opt);
            if ($opt !== '') {
                $cleanOptions[] = $opt;
            }
        }
        $cleanOptions = array_values(array_unique($cleanOptions));
        if (count($cleanOptions) < $pollMinOptions) {
            return ['error' => 'options_min'];
        }
        if (count($cleanOptions) > $pollMaxOptions) {
            $cleanOptions = array_slice($cleanOptions, 0, $pollMaxOptions);
        }
        $time = time();
        DB::begin();
        try {
            DB::exec(
                "UPDATE i_live_polls SET status = 'closed', updated_at = ? WHERE live_id = ? AND status = 'active'",
                [(int)$time, (int)$liveID]
            );
            DB::exec(
                "INSERT INTO i_live_polls (live_id, question, status, created_by, created_at, updated_at) VALUES (?,?,?,?,?,?)",
                [(int)$liveID, (string)$question, 'active', (int)$userID, (int)$time, (int)$time]
            );
            $pollId = (int) DB::lastId();
            $order = 1;
            foreach ($cleanOptions as $opt) {
                DB::exec(
                    "INSERT INTO i_live_poll_options (poll_id_fk, option_text, option_order, votes_count, status, created_at, updated_at)
                     VALUES (?,?,?,?,?,?,?)",
                    [(int)$pollId, (string)$opt, (int)$order, 0, 'active', (int)$time, (int)$time]
                );
                $order++;
            }
            DB::commit();
            return ['poll_id' => $pollId];
        } catch (Throwable $e) {
            DB::rollBack();
            return ['error' => 'create_failed'];
        }
    }
    public function iN_SubmitLivePollVote($pollId, $optionId, $userId) {
        if ($this->iN_CheckUserExist($userId) != 1) {
            return ['error' => 'not_allowed'];
        }
        $poll = DB::one(
            "SELECT poll_id, live_id, status FROM i_live_polls WHERE poll_id = ? LIMIT 1",
            [(int)$pollId]
        );
        if (!$poll || ($poll['status'] ?? '') !== 'active') {
            return ['error' => 'poll_closed'];
        }
        $option = DB::one(
            "SELECT option_id, poll_id_fk, status FROM i_live_poll_options WHERE option_id = ? AND poll_id_fk = ? LIMIT 1",
            [(int)$optionId, (int)$pollId]
        );
        if (!$option || ($option['status'] ?? '') !== 'active') {
            return ['error' => 'invalid_option'];
        }
        $already = DB::col(
            "SELECT option_id_fk FROM i_live_poll_votes WHERE poll_id_fk = ? AND voter_uid_fk = ? LIMIT 1",
            [(int)$pollId, (int)$userId]
        );
        if ($already) {
            return ['error' => 'already_voted'];
        }
        $time = time();
        DB::begin();
        try {
            DB::exec(
                "INSERT INTO i_live_poll_votes (poll_id_fk, option_id_fk, voter_uid_fk, voter_ip, vote_time)
                 VALUES (?,?,?,?,?)",
                [(int)$pollId, (int)$optionId, (int)$userId, (string)($_SERVER['REMOTE_ADDR'] ?? ''), (int)$time]
            );
            DB::exec("UPDATE i_live_poll_options SET votes_count = votes_count + 1 WHERE option_id = ?", [(int)$optionId]);
            DB::commit();
        } catch (Throwable $e) {
            DB::rollBack();
            return ['error' => 'vote_failed'];
        }
        return ['poll_id' => (int)$pollId, 'live_id' => (int)($poll['live_id'] ?? 0)];
    }
    public function iN_CloseLivePoll($liveID, $pollId, $userID): bool {
        if ($this->iN_CheckLiveIDExistAndOwner($userID, $liveID) != 1) {
            return false;
        }
        $time = time();
        DB::exec(
            "UPDATE i_live_polls SET status = 'closed', updated_at = ? WHERE poll_id = ? AND live_id = ?",
            [(int)$time, (int)$pollId, (int)$liveID]
        );
        return true;
    }
    public function iN_CreateLiveQuestion($liveID, $userID, $questionText, $autoApprove = false) {
        if ($this->iN_CheckUserExist($userID) != 1 || $this->iN_CheckLiveIDExist($liveID) != 1) {
            return ['error' => 'not_allowed'];
        }
        $questionText = trim((string)$questionText);
        if ($questionText === '') {
            return ['error' => 'question_required'];
        }
        $status = $autoApprove ? 'approved' : 'pending';
        $time = time();
        DB::exec(
            "INSERT INTO i_live_questions (live_id, user_id, question_text, status, created_at, updated_at) VALUES (?,?,?,?,?,?)",
            [(int)$liveID, (int)$userID, (string)$questionText, (string)$status, (int)$time, (int)$time]
        );
        return ['status' => $status];
    }
    public function iN_GetLiveQuestions($liveID, $isOwner = false): array {
        $statuses = $isOwner ? ['pending', 'approved', 'answered'] : ['approved', 'answered'];
        $placeholders = implode(',', array_fill(0, count($statuses), '?'));
        $params = array_merge([(int)$liveID], $statuses);
        $sql = "SELECT Q.question_id, Q.user_id, Q.question_text, Q.status, Q.created_at, Q.answered_at, Q.answered_by,
                       U.i_username, U.i_user_fullname, U.user_frame
                FROM i_live_questions Q
                INNER JOIN i_users U FORCE INDEX(ixForceUser)
                    ON U.iuid = Q.user_id AND U.uStatus IN('1','3')
                WHERE Q.live_id = ? AND Q.status IN ({$placeholders})
                ORDER BY FIELD(Q.status,'pending','approved','answered'), Q.question_id DESC
                LIMIT 200";
        $rows = DB::all($sql, $params);
        return !empty($rows) ? $rows : [];
    }
    public function iN_UpdateLiveQuestionStatus($liveID, $questionId, $userID, $status): bool {
        if ($this->iN_CheckLiveIDExistAndOwner($userID, $liveID) != 1) {
            return false;
        }
        $allowed = ['approved', 'answered', 'rejected'];
        if (!in_array($status, $allowed, true)) {
            return false;
        }
        $time = time();
        $answeredBy = null;
        $answeredAt = null;
        if ($status === 'answered') {
            $answeredBy = (int)$userID;
            $answeredAt = (int)$time;
        }
        DB::exec(
            "UPDATE i_live_questions SET status = ?, updated_at = ?, answered_by = ?, answered_at = ? WHERE question_id = ? AND live_id = ?",
            [(string)$status, (int)$time, $answeredBy, $answeredAt, (int)$questionId, (int)$liveID]
        );
        return true;
    }
/*Update Email Settings*/
public function iN_UpdateAgoraLiveStreamingSettings(
    $userID,
    $freeLiveStreamingStatus,
    $paidLiveStreamingStatus,
    $liveStatus,
    $freeLiveLimit,
    $agora_AppID,
    $agora_Certificate,
    $agora_CustomerID,
    $liveMinimumFee,
    $rtProvider = 'agora',
    $livekitAPIKey = null,
    $livekitAPISecret = null,
    $livekitWSUrl = null,
    $callProvider = 'agora',
    $isometrikApiKey = null,
    $isometrikApiSecret = null,
    $isometrikProjectId = null,
    $isometrikWsUrl = null,
    $livePollStatus = '1',
    $liveGiftStatus = '1',
    $liveQAStatus = '1',
    $liveChatStatus = '1'
) {
    if ($this->iN_CheckIsAdmin($userID) != 1) {
        return false;
    }

    $providerKey = strtolower((string)$rtProvider);
    if (!in_array($providerKey, ['agora', 'livekit'], true)) {
        $providerKey = 'agora';
    }
    $callProviderKey = strtolower((string)$callProvider);
    if (!in_array($callProviderKey, ['agora', 'livekit', 'isometrik'], true)) {
        $callProviderKey = 'agora';
    }
    $livePollStatus = (string)$livePollStatus === '1' ? '1' : '0';
    $liveGiftStatus = (string)$liveGiftStatus === '1' ? '1' : '0';
    $liveQAStatus = (string)$liveQAStatus === '1' ? '1' : '0';
    $liveChatStatus = (string)$liveChatStatus === '1' ? '1' : '0';

    $updates = [
        'free_live_streaming_status' => (string)$freeLiveStreamingStatus,
        'paid_live_streaming_status' => (string)$paidLiveStreamingStatus,
        'agora_status' => (string)$liveStatus,
        'agora_app_id' => (string)$agora_AppID,
        'agora_certificate' => (string)$agora_Certificate,
        'agora_customer_id' => (string)$agora_CustomerID,
        'free_live_time' => (string)$freeLiveLimit,
        'minimum_live_streaming_fee' => (string)$liveMinimumFee,
    ];
    $optionalUpdates = [
        'rt_provider' => (string)$providerKey,
        'livekit_api_key' => (string)$livekitAPIKey,
        'livekit_api_secret' => (string)$livekitAPISecret,
        'livekit_ws_url' => (string)$livekitWSUrl,
        'call_provider' => (string)$callProviderKey,
        'isometrik_api_key' => (string)$isometrikApiKey,
        'isometrik_api_secret' => (string)$isometrikApiSecret,
        'isometrik_project_id' => (string)$isometrikProjectId,
        'isometrik_ws_url' => (string)$isometrikWsUrl,
        'live_poll_status' => $livePollStatus,
        'live_gift_status' => $liveGiftStatus,
        'live_qa_status' => $liveQAStatus,
        'live_chat_status' => $liveChatStatus,
    ];
    $setParts = [];
    $params = [];
    foreach ($updates as $column => $value) {
        $setParts[] = $column . ' = ?';
        $params[] = $value;
    }
    foreach ($optionalUpdates as $column => $value) {
        if ($this->configColumnExists($column)) {
            $setParts[] = $column . ' = ?';
            $params[] = $value;
        }
    }
    $params[] = 1;
    try {
        DB::exec(
            "UPDATE i_configurations SET " . implode(', ', $setParts) . " WHERE configuration_id = ?",
            $params
        );
        return true;
    } catch (Throwable $e) {
        return false;
    }
}
	/*Hashtags*/
    public function iN_GetTrendingHashtags(int $limit, int $days): array {
        $limit = max(1, min(100, (int)$limit));
        $days = max(1, min(365, (int)$days));
        $scanLimit = max(250, $limit * 250);
        if ($scanLimit > 5000) { $scanLimit = 5000; }

        static $cache = [];
        $cacheKey = $limit . '|' . $days;
        if (isset($cache[$cacheKey])) {
            return $cache[$cacheKey];
        }

        [$scheduledSql, $scheduledParams] = $this->scheduledVisibilityClause(null, 'P');
        $sql = "SELECT P.hashtags
                FROM i_posts P
                WHERE P.post_status = '1'
                  AND P.post_type NOT IN('reels')
                  AND P.hashtags IS NOT NULL
                  AND P.hashtags <> ''
                  AND P.post_created_time >= UNIX_TIMESTAMP(NOW() - INTERVAL $days DAY)
                  AND $scheduledSql
                ORDER BY P.post_id DESC
                LIMIT $scanLimit";
        $rows = DB::all($sql, $scheduledParams);

        $counts = [];
        foreach ($rows as $row) {
            $raw = trim((string)($row['hashtags'] ?? ''));
            if ($raw === '') { continue; }
            $tags = explode(',', $raw);
            foreach ($tags as $tag) {
                $tag = trim($tag);
                if ($tag === '') { continue; }
                if ($tag[0] === '#') {
                    $tag = substr($tag, 1);
                }
                $tag = preg_replace('/[^\p{L}0-9_]+/u', '', $tag);
                if ($tag === '') { continue; }
                $tagKey = function_exists('mb_strtolower')
                    ? mb_strtolower($tag, 'UTF-8')
                    : strtolower($tag);
                if ($tagKey === '') { continue; }
                if (!isset($counts[$tagKey])) {
                    $counts[$tagKey] = 0;
                }
                $counts[$tagKey]++;
            }
        }

        if (empty($counts)) {
            $cache[$cacheKey] = [];
            return $cache[$cacheKey];
        }

        $items = [];
        foreach ($counts as $tag => $count) {
            $items[] = [
                'tag' => $tag,
                'count' => $count
            ];
        }
        usort($items, function ($a, $b) {
            if ($a['count'] === $b['count']) {
                return strcmp($a['tag'], $b['tag']);
            }
            return ($a['count'] > $b['count']) ? -1 : 1;
        });
        $items = array_slice($items, 0, $limit);
        $cache[$cacheKey] = $items;

        return $items;
    }
public function iN_GetHashTagsSearch($hashTag, $lastPostID, $showingPosts) {
        $hashTag = strip_tags(trim($hashTag));
        $hashtags_list = array_filter(array_map('trim', explode(',', $hashTag)));
        $conds = [];
        $params = [];
        foreach ($hashtags_list as $ht) {
            $conds[] = "FIND_IN_SET(LOWER(?), LOWER(hashtags))";
            $params[] = strtolower($ht);
        }
        if (empty($conds)) { return null; }
        $hashtag_query = implode(' AND ', $conds);
        $morequery = '';
        if ($lastPostID) {
            $morequery = ' AND P.post_id < ' . (int)$lastPostID . ' ';
        }
        $showingPosts = (int)$showingPosts;
        [$scheduledSql, $scheduledParams] = $this->scheduledVisibilityClause(null, 'P');
        $linkSelect = $this->iN_PostLinkPreviewSelect();
        $sql = "SELECT DISTINCT P.post_id,P.shared_post_id,P.post_pined,P.comment_status,P.post_owner_id,P.post_text,P.post_file,P.post_created_time,P.scheduled_at,P.scheduled_status,P.who_can_see,P.post_want_status,P.url_slug,P.post_wanted_credit,P.post_status,P.post_type,P.hashtags{$linkSelect},
                        U.iuid,U.i_username,U.payout_method, U.thanks_for_tip, U.i_user_fullname,U.user_avatar,U.user_gender,U.last_login_time,U.user_verified_status
                FROM i_friends F FORCE INDEX(ixFriend)
                INNER JOIN i_posts P FORCE INDEX (ixForcePostOwner) ON P.post_owner_id = F.fr_two
                INNER JOIN i_users U FORCE INDEX (ixForceUser) ON P.post_owner_id = U.iuid AND U.uStatus IN('1','3') AND F.fr_status IN('me', 'flwr', 'subscriber')
                WHERE ($hashtag_query) AND P.post_type NOT IN('reels') AND $scheduledSql $morequery ORDER BY P.post_id DESC LIMIT $showingPosts";
        $rows = DB::all($sql, array_merge($params, $scheduledParams));
        return !empty($rows) ? $rows : null;
}
public function iN_CaltulateHashFromDatabase($hashTag = "") {
        $hashTag = strip_tags(trim($hashTag));
        $hashtags_list = array_filter(array_map('trim', explode(',', $hashTag)));
        if (empty($hashtags_list)) { return '0'; }
        $conds = [];
        $params = [];
        foreach ($hashtags_list as $ht) {
            $conds[] = "FIND_IN_SET(LOWER(?), LOWER(hashtags))";
            $params[] = strtolower($ht);
        }
        $hashtag_query = implode(' AND ', $conds);
        $sql = "SELECT COUNT(*) FROM i_posts WHERE ($hashtag_query)";
        $val = DB::col($sql, $params);
        return $val ? (string)$val : false;
}
