	/*Popular User From Last Week*/
public function iN_PopularUsersFromLastWeekInExplorePageLanding($limit = 3, $viewerId = null, $viewerCountryCode = null) {
        $limit = (int)$limit;
        if ($limit < 1) {
                $limit = 1;
        }
        if ($limit > 24) {
                $limit = 24;
        }
        [$visibilityClauses, $visibilityParams] = $this->iN_BuildUserVisibilityFilter($viewerId, $viewerCountryCode, 'U');
        $visibilitySql = !empty($visibilityClauses) ? ' AND ' . implode(' AND ', $visibilityClauses) : '';
        $sql = "SELECT DISTINCT P.post_owner_id, U.iuid,U.i_username,U.i_user_fullname,U.user_verified_status, U.user_gender , COUNT(P.post_owner_id) as cnt
                FROM i_posts P FORCE INDEX(ixForcePostOwner)
                INNER JOIN i_users U FORCE INDEX(ixForceUser) ON P.post_owner_id = U.iuid AND U.uStatus IN('1','3')
                WHERE WEEK(FROM_UNIXTIME(P.post_created_time)) = WEEK(NOW()) - 1
                $visibilitySql
                GROUP BY P.post_owner_id ORDER BY cnt DESC LIMIT " . $limit;
        $rows = DB::all($sql, $visibilityParams);
        return !empty($rows) ? $rows : null;
}
	/*Update Theme*/
public function iN_UpdateTheme($userID, $theme) {
        if ($this->iN_CheckIsAdmin($userID) == 1) {
            $theme = (string)$theme;
            if (strpos($theme, 'plugin:') === 0) {
                $slug = preg_replace('/[^a-z0-9_-]/i', '', substr($theme, 7));
                if ($slug === '') {
                    return false;
                }
                DB::exec("UPDATE i_configurations SET landing_page_type = '4', landing_page_plugin = ? WHERE configuration_id = 1", [$slug]);
                return true;
            }
            if (!in_array($theme, ['1', '2', '3', '4', '5'], true)) {
                return false;
            }
            DB::exec("UPDATE i_configurations SET landing_page_type = ?, landing_page_plugin = NULL WHERE configuration_id = 1", [$theme]);
            return true;
        } else {
            return false;
        }
}
