	/*Remove Youtubelink from Post Text*/
	public function iN_RemoveYoutubelink($postText){
		if($postText){
			$remove = preg_replace("/\s*[a-zA-Z\/\/:\.]*youtube.com\/watch\?v=([a-zA-Z0-9\-_]+)([a-zA-Z0-9\/\*\-\_\?\&\;\%\=\.]*)/i","",$postText);
		}else{
			$remove = $postText;
		}
		return $remove;
	}
    /*Suggestion Creators*/
    public function iN_SuggestionCreatorsList($uid, $numberShow, $viewerId = null, $viewerCountryCode = null) {
        $numberShow = (int)$numberShow;
        $viewerId = $viewerId !== null ? (int)$viewerId : (int)$uid;
        [$visibilityClauses, $visibilityParams] = $this->iN_BuildUserVisibilityFilter($viewerId, $viewerCountryCode, 'iu');
        $visibilitySql = !empty($visibilityClauses) ? ' AND ' . implode(' AND ', $visibilityClauses) : '';
        $sql = "SELECT iu.*
                FROM i_users iu
                LEFT JOIN i_friends ifr ON iu.iuid = ifr.fr_two AND ifr.fr_one = ?
                WHERE iu.uStatus = '3'
                  AND iu.certification_status = '2'
                  AND iu.validation_status = '2'
                  AND iu.condition_status = '2'
                  AND iu.fees_status = '2'
                  AND ifr.fr_two IS NULL
                  $visibilitySql
                ORDER BY RAND()
                LIMIT $numberShow";
        $rows = DB::all($sql, array_merge([(int)$uid], $visibilityParams));
        return !empty($rows) ? $rows : null;
    }
	/*Suggestion Creators*/
    public function iN_SuggestionCreatorsListOut($numberShow, $viewerId = null, $viewerCountryCode = null) {
        $numberShow = (int)$numberShow;
        [$visibilityClauses, $visibilityParams] = $this->iN_BuildUserVisibilityFilter($viewerId, $viewerCountryCode, 'U');
        $visibilitySql = !empty($visibilityClauses) ? ' AND ' . implode(' AND ', $visibilityClauses) : '';
        $sql = "SELECT U.* FROM i_users U WHERE U.uStatus IN('3') AND U.certification_status = '2' AND U.validation_status = '2' AND U.condition_status = '2' AND U.fees_status = '2' $visibilitySql ORDER BY RAND() LIMIT $numberShow";
        $rows = DB::all($sql, $visibilityParams);
        return !empty($rows) ? $rows : null;
    }
