		/*Update Reported Message Checked Status*/
	    public function iN_UpdateReportedMessageCheckedStatus($userID, $mod, $rID, $adminNote = '') {
	        if ($this->iN_CheckIsAdmin($userID) == 1 && $this->iN_CheckReportMessageIDExist($rID) == 1) {
	            $time = time();
	            $availableColumns = [
	                'admin_note' => false,
	                'admin_action_time' => false,
	                'admin_action_by' => false
	            ];
	
	            try {
	                $columnRows = DB::all(
	                    "SELECT COLUMN_NAME FROM INFORMATION_SCHEMA.COLUMNS
	                     WHERE TABLE_SCHEMA = DATABASE()
	                       AND TABLE_NAME = 'i_message_reports'
	                       AND COLUMN_NAME IN ('admin_note','admin_action_time','admin_action_by')"
	                );
	                if (is_array($columnRows)) {
	                    foreach ($columnRows as $columnRow) {
	                        $columnName = (string)($columnRow['COLUMN_NAME'] ?? '');
	                        if ($columnName !== '' && array_key_exists($columnName, $availableColumns)) {
	                            $availableColumns[$columnName] = true;
	                        }
	                    }
	                }
	            } catch (Throwable $e) {
	                $availableColumns = [
	                    'admin_note' => false,
	                    'admin_action_time' => false,
	                    'admin_action_by' => false
	                ];
	            }
	
	            $setParts = ["report_status = ?"];
	            $params = [(string)$mod];
	            if ($availableColumns['admin_note']) {
	                $setParts[] = "admin_note = ?";
	                $params[] = (string)$adminNote;
	            }
	            if ($availableColumns['admin_action_time']) {
	                $setParts[] = "admin_action_time = ?";
	                $params[] = (int)$time;
	            }
	            if ($availableColumns['admin_action_by']) {
	                $setParts[] = "admin_action_by = ?";
	                $params[] = (int)$userID;
	            }
	            $params[] = (int)$rID;
	
	            try {
	                DB::exec(
	                    "UPDATE i_message_reports SET " . implode(', ', $setParts) . " WHERE p_report_id = ?",
	                    $params
	                );
	                return true;
	            } catch (Throwable $e) {
	                try {
	                    DB::exec(
	                        "UPDATE i_message_reports SET report_status = ? WHERE p_report_id = ?",
	                        [(string)$mod, (int)$rID]
	                    );
	                    return true;
	                } catch (Throwable $innerException) {
	                    return false;
	                }
	            }
	        }
	        return false;
	    }
