	/*Notify Reporter About Message Report Update*/
	public function iN_InsertMessageReportUpdateNotification($adminID, array $reportData, $action, $note = '') {
        $adminID = (int)$adminID;
        $reporterID = (int)($reportData['iuid_fk'] ?? 0);
        $reportID = (int)($reportData['p_report_id'] ?? 0);
        $chatID = (int)($reportData['reported_chat_id_fk'] ?? 0);
        $action = trim((string)$action);
        $note = trim((string)$note);
        if ($adminID <= 0 || $reporterID <= 0 || $reportID <= 0) {
            return false;
        }
        if (!in_array($action, ['checked', 'deleted'], true)) {
            return false;
        }

        $payloadData = [
            'report_id' => $reportID,
            'chat_id' => $chatID,
            'action' => $action,
            'note' => $note
        ];
        $payload = json_encode($payloadData, JSON_UNESCAPED_UNICODE);
        if ($payload === false) {
            $payload = '';
        }

        $hasPayloadColumn = false;
        try {
            $hasPayloadColumn = (bool) DB::col(
                "SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'i_user_notifications' AND COLUMN_NAME = 'not_payload' LIMIT 1"
            );
        } catch (Throwable $e) {
            $hasPayloadColumn = false;
        }

        $time = time();
        if ($hasPayloadColumn) {
            DB::exec(
                "INSERT INTO i_user_notifications (not_iuid, not_post_id, not_own_iuid, not_type, not_payload, not_not_type, not_time) VALUES (?,?,?,?,?,?,?)",
                [$adminID, $chatID, $reporterID, 'text', $payload, 'message_report_update', $time]
            );
        } else {
            $legacyText = $note !== '' ? $note : $action;
            DB::exec(
                "INSERT INTO i_user_notifications (not_iuid, not_post_id, not_own_iuid, not_type, not_not_type, not_time) VALUES (?,?,?,?,?,?)",
                [$adminID, $chatID, $reporterID, $legacyText, 'message_report_update', $time]
            );
        }
        DB::exec("UPDATE i_users SET notification_read_status = '1' WHERE iuid = ?", [$reporterID]);
        return true;
    }
