	/*Insert User Subscription Using Point*/
public function iN_InsertUserSubscriptionWithPoint($userID, $subscribedUserID, $planType, $subscriberName, $planAmount, $adminEarning, $userNetEarning, $planCurrency, $planinterval, $planIntervalCount, $subscriberEmail, $plancreated, $current_period_start, $current_period_end, $planStatus,$UpdateCurrentPoint) {
		if ($this->iN_CheckUserExist($userID) == 1 && $this->iN_CheckUserExist($subscribedUserID) == 1) {
            $planAmountValue = (float)$planAmount;
            $adminFeeRate = isset($GLOBALS['adminFee']) ? (float)$GLOBALS['adminFee'] : 0.0;
            $split = $this->iN_CalculateAgencySplit($subscribedUserID, $planAmountValue, $adminFeeRate);
            $adminEarning = $split['admin_earning'];
            $userNetEarning = $split['creator_net'];
            $agencyId = $split['agency_id'];
            $agencyFee = $split['agency_fee'];
            $agencyEarning = $split['agency_earning'];
			try {
				DB::begin();
				DB::exec(
					"INSERT INTO i_user_subscriptions(iuid_fk, subscribed_iuid_fk, subscriber_name, payment_method, plan_amount, admin_earning, agency_earning, user_net_earning, plan_amount_currency, plan_interval, plan_interval_count, payer_email, created, plan_period_start, plan_period_end, status, subscription_scope, subscription_ref_id, agency_id_fk, fee, agency_fee)
					 VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)",
					[
						(int)$userID, (int)$subscribedUserID, (string)$subscriberName, (string)$planType, (string)$planAmount,
						(string)$adminEarning, (string)$agencyEarning, (string)$userNetEarning, (string)$planCurrency, (string)$planinterval, (string)$planIntervalCount,
						(string)$subscriberEmail, (string)$plancreated, (string)$current_period_start, (string)$current_period_end, (string)$planStatus,
						'profile', null, $agencyId, (string)$adminFeeRate, (string)$agencyFee
					]
				);
				$time = time();
				$exists = (bool) DB::col("SELECT 1 FROM i_friends WHERE fr_one = ? AND fr_two = ? AND (fr_status = 'flwr' OR fr_status = 'subscriber') LIMIT 1", [(int)$userID,(int)$subscribedUserID]);
				if ($exists) {
					DB::exec("UPDATE i_friends SET fr_status = 'subscriber', fr_time = ? WHERE fr_one = ? AND fr_two = ?", [$time, (int)$userID,(int)$subscribedUserID]);
				} else {
					DB::exec("INSERT INTO i_friends(fr_one, fr_two, fr_status, fr_time) VALUES(?, ?, 'subscriber', ?)", [(int)$userID,(int)$subscribedUserID,$time]);
				}
				DB::exec("UPDATE i_users SET wallet_money = wallet_money + ? WHERE iuid = ?", [(string)$userNetEarning,(int)$subscribedUserID]);
				DB::exec("UPDATE i_users SET wallet_points = wallet_points - ? WHERE iuid = ?", [(string)$planAmount,(int)$userID]);
				DB::exec(
					"UPDATE i_user_subscriptions SET plan_period_start = ?, plan_period_end = ? WHERE iuid_fk = ? AND subscribed_iuid_fk = ? AND subscription_scope = 'profile'",
					[(string)$current_period_end, (string)$current_period_start, (int)$userID, (int)$subscribedUserID]
				);
				DB::commit();
				return true;
			} catch (Throwable $e) { DB::rollBack(); return false; }
		}
}
	/*Update Users Wallets*/
public function iN_UpdateUsersWallets($userID, $tiSendingUserID, $tipAmount, $netUserEarning,$adminFee,$adminEarning,$userNetEarning){
		if ($this->iN_CheckUserExist($userID) == 1 && $this->iN_CheckUserExist($tiSendingUserID) == 1) {
			$time = time();
			$paymentId = 0;
			try { DB::begin();
                $split = $this->iN_CalculateAgencySplit($tiSendingUserID, $netUserEarning, $adminFee);
                $adminEarning = $split['admin_earning'];
                $userNetEarning = $split['creator_net'];
                $agencyId = $split['agency_id'];
                $agencyFee = $split['agency_fee'];
                $agencyEarning = $split['agency_earning'];
				DB::exec("UPDATE i_users SET wallet_points = wallet_points - ? WHERE iuid = ?", [(string)$tipAmount,(int)$userID]);
				DB::exec("UPDATE i_users SET wallet_money = wallet_money + ? WHERE iuid = ?", [(string)$userNetEarning,(int)$tiSendingUserID]);
				DB::exec("INSERT INTO i_user_payments(payer_iuid_fk, payed_iuid_fk, agency_id_fk, payment_type, payment_option, payment_time, payment_status, amount, user_earning, admin_earning, agency_earning, fee, agency_fee)
					VALUES(?, ?, ?, 'tips', 'wallet', ?, 'ok', ?, ?, ?, ?, ?, ?)",
					[(int)$userID, (int)$tiSendingUserID, $agencyId, $time, (string)$netUserEarning, (string)$userNetEarning, (string)$adminEarning, (string)$agencyEarning, (string)$adminFee, (string)$agencyFee]
				);
				$paymentId = (int) DB::lastId();
				DB::commit();
				if ($paymentId > 0) {
					$currency = $GLOBALS['defaultCurrency'] ?? 'USD';
					$this->iN_AssignInvoiceToPayment($paymentId, $userID, (float)$netUserEarning, $currency);
					try {
						$isAnonymous = false;
						$isAnonymous = ((int) DB::col(
							"SELECT is_anonymous FROM i_user_payments WHERE payment_id = ? LIMIT 1",
							[$paymentId]
						)) === 1;
						$payerName = null;
						if (!$isAnonymous) {
							$payerName = '';
							$payerData = $this->iN_GetUserDetails($userID);
							if ($payerData) {
								$payerName = trim((string)($payerData['i_user_fullname'] ?? ''));
								if ($payerName === '') {
									$payerName = trim((string)($payerData['i_username'] ?? ''));
								}
							}
							$payerName = strip_tags($payerName);
							if (strlen($payerName) > 200) {
								$payerName = substr($payerName, 0, 200);
							}
							$payerName = $payerName !== '' ? $payerName : null;
						}
						$overlays = DB::all(
							"SELECT obs_overlay_id FROM i_obs_overlays WHERE creator_id_fk = ? AND is_active = '1'",
							[(int)$tiSendingUserID]
						);
						if (!empty($overlays)) {
							foreach ($overlays as $overlayRow) {
								$overlayId = (int)($overlayRow['obs_overlay_id'] ?? 0);
								if ($overlayId <= 0) {
									continue;
								}
								DB::exec(
									"INSERT IGNORE INTO i_obs_support_events (overlay_id, creator_id, payer_id, payer_name, payment_id, payment_type, amount, created_at, meta_json)
									 VALUES (?, ?, ?, ?, ?, 'tips', ?, ?, ?)",
									[
										$overlayId,
										(int)$tiSendingUserID,
										(int)$userID,
										$payerName,
										$paymentId,
										(string)$netUserEarning,
										$time,
										null
									]
								);
							}
						}
					} catch (Throwable $e) {
						// Ignore overlay event insert failures to avoid blocking payments.
					}
				}
				return true;
			} catch (Throwable $e) { DB::rollBack(); return false; }
		}
}
