	/*Update Users Wallets*/
public function iN_UpdateUsersWalletsForLiveGift($userID, $cLiveID, $tiSendingUserID, $giftDataID, $liveWantedCoin, $adminFee, $liveWantedMoney) {
        if ($this->iN_CheckUserExist($userID) == 1 && $this->CheckLivePlanExist($giftDataID) == 1 && $this->iN_CheckUserExist($tiSendingUserID) == 1) {
            $time = time();
            $paymentId = 0;
            try {
                DB::begin();
                $split = $this->iN_CalculateAgencySplit($tiSendingUserID, $liveWantedMoney, $adminFee);
                $adminEarning = $split['admin_earning'];
                $netUserEarning = $split['creator_net'];
                $agencyId = $split['agency_id'];
                $agencyFee = $split['agency_fee'];
                $agencyEarning = $split['agency_earning'];
                DB::exec("UPDATE i_users SET wallet_points = wallet_points - ? WHERE iuid = ?", [(string)$liveWantedCoin,(int)$userID]);
                DB::exec("UPDATE i_users SET wallet_money = wallet_money + ? WHERE iuid = ?", [(string)$netUserEarning,(int)$tiSendingUserID]);
                DB::exec("INSERT INTO i_user_payments(payer_iuid_fk, payed_iuid_fk, agency_id_fk, payment_type, payment_time, payment_status, amount, admin_earning, agency_earning, user_earning, fee, agency_fee) VALUES(?, ?, ?, 'live_gift', ?, 'ok', ?, ?, ?, ?, ?, ?)",
                         [(int)$userID, (int)$tiSendingUserID, $agencyId, $time, (string)$liveWantedMoney, (string)$adminEarning, (string)$agencyEarning, (string)$netUserEarning, (string)$adminFee, (string)$agencyFee]);
                $paymentId = (int) DB::lastId();
                DB::exec("INSERT INTO i_live_chat(cm_live_id, cm_iuid_fk, cm_gift_type, cm_time) VALUES(?,?,?,?)", [(int)$cLiveID,(int)$userID,(int)$giftDataID,$time]);
                DB::commit();
            } catch (Throwable $e) { DB::rollBack(); return false; }
            if ($paymentId > 0) {
                $currency = $GLOBALS['defaultCurrency'] ?? 'USD';
                $this->iN_AssignInvoiceToPayment($paymentId, (int)$userID, (float)$liveWantedMoney, $currency);
                try {
                    $isAnonymous = false;
                    $isAnonymous = ((int) DB::col(
                        "SELECT is_anonymous FROM i_user_payments WHERE payment_id = ? LIMIT 1",
                        [$paymentId]
                    )) === 1;
                    $payerName = null;
                    if (!$isAnonymous) {
                        $payerName = '';
                        $payerData = $this->iN_GetUserDetails($userID);
                        if ($payerData) {
                            $payerName = trim((string)($payerData['i_user_fullname'] ?? ''));
                            if ($payerName === '') {
                                $payerName = trim((string)($payerData['i_username'] ?? ''));
                            }
                        }
                        $payerName = strip_tags($payerName);
                        if (strlen($payerName) > 200) {
                            $payerName = substr($payerName, 0, 200);
                        }
                        $payerName = $payerName !== '' ? $payerName : null;
                    }
                    $overlays = DB::all(
                        "SELECT obs_overlay_id FROM i_obs_overlays WHERE creator_id_fk = ? AND is_active = '1'",
                        [(int)$tiSendingUserID]
                    );
                    if (!empty($overlays)) {
                        foreach ($overlays as $overlayRow) {
                            $overlayId = (int)($overlayRow['obs_overlay_id'] ?? 0);
                            if ($overlayId <= 0) {
                                continue;
                            }
                            DB::exec(
                                "INSERT IGNORE INTO i_obs_support_events (overlay_id, creator_id, payer_id, payer_name, payment_id, payment_type, amount, created_at, meta_json)
                                 VALUES (?, ?, ?, ?, ?, 'live_gift', ?, ?, ?)",
                                [
                                    $overlayId,
                                    (int)$tiSendingUserID,
                                    (int)$userID,
                                    $payerName,
                                    $paymentId,
                                    (string)$liveWantedMoney,
                                    $time,
                                    null
                                ]
                            );
                        }
                    }
                } catch (Throwable $e) {
                    // Ignore overlay event insert failures to avoid blocking payments.
                }
            }
            return true;
        }
	}
