	public function iN_OneSignalPushNotificationSend($msg_body, $msg_title, $url, $device_id, $oneSignalApi, $oneSignalRestApi) {
		$content = array(
			"en" => $msg_body,
		);
		$heading = array(
			"en" => $msg_title,
		);
		$include_player_id = array(
			$device_id,
		);

		$msg_img = '';
		$fields = array(
			'app_id' => $oneSignalApi,
			'contents' => $content,
			'headings' => $heading,
			'data' => array("foo" => "bar"),
			'small_icon' => "ic_launcher",
			'large_icon' => "ic_launcher",
			'image' => $msg_img,
			'include_player_ids' => $include_player_id,
			'url' => $url,
		);
		$fields = json_encode($fields);
		$ch = curl_init();
		curl_setopt($ch, CURLOPT_URL, "https://onesignal.com/api/v1/notifications");
		curl_setopt($ch, CURLOPT_HTTPHEADER, array('Content-Type: application/json',
			'Authorization: Basic ' . $oneSignalRestApi . ''));
		curl_setopt($ch, CURLOPT_RETURNTRANSFER, TRUE);
		curl_setopt($ch, CURLOPT_HEADER, FALSE);
		curl_setopt($ch, CURLOPT_POST, TRUE);
		curl_setopt($ch, CURLOPT_POSTFIELDS, $fields);
		curl_setopt($ch, CURLOPT_SSL_VERIFYPEER, FALSE);

		$response = curl_exec($ch);
		curl_close($ch);

		return $response;
	}

    public function iN_WebPushSchemaReady(): bool {
        if (!$this->tableColumnExists('i_users', 'web_push_enabled')) {
            return false;
        }
        if (!$this->tableColumnExists('i_user_web_push_subscriptions', 'subscription_id')) {
            return false;
        }
        if ($this->iN_ConfigColumnsExist([
            'web_push_status',
            'web_push_vapid_public',
            'web_push_vapid_private',
            'web_push_vapid_subject',
            'web_push_ttl',
            'web_push_event_live_started',
            'web_push_event_tip_received',
            'web_push_event_post_like',
            'web_push_event_comment',
            'web_push_event_follow',
            'web_push_event_subscription',
            'web_push_event_announcement',
        ])) {
            return true;
        }
        return $this->settingsKvTableReady();
    }

    public function iN_SaveWebPushSubscription($userID, array $subscription): bool {
        if ($this->iN_CheckUserExist($userID) != 1 || !$this->iN_WebPushSchemaReady()) {
            return false;
        }

        $endpoint = trim((string)($subscription['endpoint'] ?? ''));
        if ($endpoint === '' || filter_var($endpoint, FILTER_VALIDATE_URL) === false) {
            return false;
        }
        $scheme = strtolower((string)parse_url($endpoint, PHP_URL_SCHEME));
        if ($scheme !== 'https') {
            return false;
        }

        $p256dh = dizzy_webpush_normalize_base64url((string)($subscription['p256dh'] ?? ''));
        $auth = dizzy_webpush_normalize_base64url((string)($subscription['auth'] ?? ''));
        if ($p256dh === '' || $auth === '') {
            return false;
        }

        $contentEncoding = strtolower(trim((string)($subscription['content_encoding'] ?? 'aes128gcm')));
        if (!in_array($contentEncoding, ['aes128gcm', 'aesgcm'], true)) {
            $contentEncoding = 'aes128gcm';
        }

        $userAgent = trim((string)($subscription['user_agent'] ?? ''));
        $deviceLabel = trim((string)($subscription['device_label'] ?? ''));
        $userAgent = $this->clampStringLength($userAgent, 255);
        $deviceLabel = $this->clampStringLength($deviceLabel, 120);
        $endpointHash = hash('sha256', $endpoint);
        $now = time();

        DB::exec(
            "INSERT INTO i_user_web_push_subscriptions
             (iuid_fk, endpoint, endpoint_hash, p256dh, auth, content_encoding, user_agent, device_label, status, failure_count, created_at, updated_at, last_seen_at)
             VALUES (?, ?, ?, ?, ?, ?, ?, ?, 'active', 0, ?, ?, ?)
             ON DUPLICATE KEY UPDATE
                iuid_fk = VALUES(iuid_fk),
                endpoint = VALUES(endpoint),
                p256dh = VALUES(p256dh),
                auth = VALUES(auth),
                content_encoding = VALUES(content_encoding),
                user_agent = VALUES(user_agent),
                device_label = VALUES(device_label),
                status = 'active',
                failure_count = 0,
                updated_at = VALUES(updated_at),
                last_seen_at = VALUES(last_seen_at)",
            [
                (int)$userID,
                (string)$endpoint,
                (string)$endpointHash,
                (string)$p256dh,
                (string)$auth,
                (string)$contentEncoding,
                (string)$userAgent,
                (string)$deviceLabel,
                (int)$now,
                (int)$now,
                (int)$now,
            ]
        );

        return true;
    }

    public function iN_RemoveWebPushSubscription($userID, ?string $endpoint = null): bool {
        if ($this->iN_CheckUserExist($userID) != 1 || !$this->iN_WebPushSchemaReady()) {
            return false;
        }

        $now = time();
        $endpoint = trim((string)$endpoint);
        if ($endpoint !== '') {
            $endpointHash = hash('sha256', $endpoint);
            DB::exec(
                "UPDATE i_user_web_push_subscriptions
                 SET status = 'inactive', updated_at = ?, last_seen_at = ?
                 WHERE iuid_fk = ? AND endpoint_hash = ?",
                [(int)$now, (int)$now, (int)$userID, (string)$endpointHash]
            );
            return true;
        }

        DB::exec(
            "UPDATE i_user_web_push_subscriptions
             SET status = 'inactive', updated_at = ?, last_seen_at = ?
             WHERE iuid_fk = ?",
            [(int)$now, (int)$now, (int)$userID]
        );
        return true;
    }

    public function iN_GetWebPushActiveSubscriptions($userID): array {
        if ($this->iN_CheckUserExist($userID) != 1 || !$this->iN_WebPushSchemaReady()) {
            return [];
        }

        $rows = DB::all(
            "SELECT subscription_id, endpoint, p256dh, auth, content_encoding
             FROM i_user_web_push_subscriptions
             WHERE iuid_fk = ? AND status = 'active'
             ORDER BY updated_at DESC",
            [(int)$userID]
        );

        return is_array($rows) ? $rows : [];
    }

    public function iN_SendWebPushToUser(int $recipientId, array $payload = []): bool {
        if ($recipientId < 1 || !$this->iN_WebPushSchemaReady()) {
            return false;
        }
        if ($this->iN_GetUserWebPushStatus($recipientId) !== '1') {
            return false;
        }

        $status = (string)$this->iN_GetSetting('web_push_status', '0');
        if ($status !== '1') {
            return false;
        }

        $vapidPublic = trim((string)$this->iN_GetSetting('web_push_vapid_public', ''));
        $vapidPrivate = trim((string)$this->iN_GetSetting('web_push_vapid_private', ''));
        $vapidSubject = trim((string)$this->iN_GetSetting('web_push_vapid_subject', ''));
        $ttl = (int)$this->iN_GetSetting('web_push_ttl', 60);
        if ($ttl < 30) {
            $ttl = 30;
        }
        if ($ttl > 86400) {
            $ttl = 86400;
        }

        if ($vapidPublic === '' || $vapidPrivate === '' || $vapidSubject === '') {
            return false;
        }

        $title = trim((string)($payload['title'] ?? ''));
        $body = trim((string)($payload['body'] ?? ''));
        $url = trim((string)($payload['url'] ?? ''));
        if ($title === '' && $body === '') {
            return false;
        }

        $messagePayload = [
            'title' => $title,
            'body' => $body,
            'url' => $url,
            'tag' => trim((string)($payload['tag'] ?? 'dizzy_notification')),
            'icon' => trim((string)($payload['icon'] ?? '')),
            'badge' => trim((string)($payload['badge'] ?? '')),
        ];

        $subscriptions = $this->iN_GetWebPushActiveSubscriptions($recipientId);
        if (empty($subscriptions)) {
            return false;
        }

        $settings = [
            'vapid_public' => $vapidPublic,
            'vapid_private' => $vapidPrivate,
            'vapid_subject' => $vapidSubject,
            'ttl' => $ttl,
        ];

        $now = time();
        $sent = false;
        foreach ($subscriptions as $subscription) {
            $subscriptionId = (int)($subscription['subscription_id'] ?? 0);
            if ($subscriptionId < 1) {
                continue;
            }

            try {
                $result = dizzy_webpush_send_notification($subscription, $messagePayload, $settings);
            } catch (Throwable $e) {
                $result = ['success' => false, 'status' => 0, 'error' => 'exception'];
            }
            if (!empty($result['success'])) {
                $sent = true;
                DB::exec(
                    "UPDATE i_user_web_push_subscriptions
                     SET last_success_at = ?, last_seen_at = ?, updated_at = ?, failure_count = 0, last_error = NULL, status = 'active'
                     WHERE subscription_id = ?",
                    [(int)$now, (int)$now, (int)$now, (int)$subscriptionId]
                );
            } else {
                $httpStatus = isset($result['status']) ? (int)$result['status'] : 0;
                $nextStatus = in_array($httpStatus, [404, 410], true) ? 'invalid' : 'active';
                $lastError = trim((string)($result['error'] ?? 'send_failed'));
                DB::exec(
                    "UPDATE i_user_web_push_subscriptions
                     SET last_failure_at = ?, last_seen_at = ?, updated_at = ?, failure_count = failure_count + 1, last_error = ?, status = ?
                     WHERE subscription_id = ?",
                    [(int)$now, (int)$now, (int)$now, (string)$lastError, (string)$nextStatus, (int)$subscriptionId]
                );
            }
        }

        return $sent;
    }
