	/*Get Register Affilate Details*/
    public function iN_GetRegisterAffilateData($type, $affilateID){
        $type = trim((string)$type);
        $affiliateID = (int)$affilateID;
        if ($type === '' || $affiliateID < 1) {
            return false;
        }
        if (self::$affiliateDataCache === null) {
            self::$affiliateDataCache = [];
            $rows = DB::all("SELECT * FROM i_configuration_affilate WHERE i_af_status = 'yes'");
            if (!empty($rows)) {
                foreach ($rows as $row) {
                    $rowID = isset($row['i_af_id']) ? (int)$row['i_af_id'] : 0;
                    $rowType = isset($row['i_af_type']) ? trim((string)$row['i_af_type']) : '';
                    if ($rowID < 1 || $rowType === '') {
                        continue;
                    }
                    if (!isset(self::$affiliateDataCache[$rowID])) {
                        self::$affiliateDataCache[$rowID] = [];
                    }
                    self::$affiliateDataCache[$rowID][$rowType] = $row;
                }
            }
        }
        return self::$affiliateDataCache[$affiliateID][$type] ?? false;
    }
