	/*Update EPD*/
    public function iN_EPDUpdate($userID, $maxPoint, $registerStatus, $commentStatus, $newPostStatus, $commentLikeStatus, $postLikeStatus, $registerAmount, $commentAmount, $commentLikeAmount, $newPostAmount, $postLikeAmount) {
        if ($this->iN_CheckIsAdmin($userID) != 1) {
            return 'not_admin';
        }
        $updates = [
            ['type' => 'register',     'status' => $registerStatus,     'amount' => $registerAmount],
            ['type' => 'comment',      'status' => $commentStatus,      'amount' => $commentAmount],
            ['type' => 'post_like',    'status' => $postLikeStatus,     'amount' => $postLikeAmount],
            ['type' => 'comment_like', 'status' => $commentLikeStatus,  'amount' => $commentLikeAmount],
            ['type' => 'new_post',     'status' => $newPostStatus,      'amount' => $newPostAmount],
        ];
        $map = [
            ['type' => 'register',     'status' => $registerStatus,     'amount' => $registerAmount,    'id' => 1, 'ica' => 'af'],
            ['type' => 'comment',      'status' => $commentStatus,      'amount' => $commentAmount,     'id' => 2, 'ica' => 'po'],
            ['type' => 'post_like',    'status' => $postLikeStatus,     'amount' => $postLikeAmount,    'id' => 3, 'ica' => 'po'],
            ['type' => 'comment_like', 'status' => $commentLikeStatus,  'amount' => $commentLikeAmount, 'id' => 4, 'ica' => 'po'],
            ['type' => 'new_post',     'status' => $newPostStatus,      'amount' => $newPostAmount,     'id' => 5, 'ica' => 'po'],
        ];
        try {
            DB::begin();
            foreach ($map as $row) {
                $existing = DB::one("SELECT i_af_id FROM i_configuration_affilate WHERE i_af_type = ? LIMIT 1", [(string)$row['type']]);
                if ($existing && isset($existing['i_af_id'])) {
                    DB::exec(
                        "UPDATE i_configuration_affilate SET i_af_amount = ?, i_af_status = ? WHERE i_af_id = ?",
                        [
                            (string)$row['amount'],
                            (string)$row['status'],
                            (int)$existing['i_af_id'],
                        ]
                    );
                } else {
                    DB::exec(
                        "REPLACE INTO i_configuration_affilate (i_af_id, i_af_type, i_af_amount, i_af_status, ica_type) VALUES (?, ?, ?, ?, ?)",
                        [
                            (int)$row['id'],
                            (string)$row['type'],
                            (string)$row['amount'],
                            (string)$row['status'],
                            (string)$row['ica'],
                        ]
                    );
                }
            }
            $updatedConfig = false;
            try {
                DB::exec("UPDATE i_configurations SET max_point_in_a_day = ? WHERE configuration_id = 1", [(string)$maxPoint]);
                $updatedConfig = true;
            } catch (Throwable $configError) {
                if (stripos($configError->getMessage(), 'max_point_in_a_day') !== false) {
                    try {
                        DB::exec("ALTER TABLE i_configurations ADD COLUMN max_point_in_a_day varchar(20) DEFAULT '1'");
                        DB::exec("UPDATE i_configurations SET max_point_in_a_day = ? WHERE configuration_id = 1", [(string)$maxPoint]);
                        $updatedConfig = true;
                    } catch (Throwable $alterError) {
                        DB::rollBack();
                        return 'db_error:'.$alterError->getMessage();
                    }
                } else {
                    DB::rollBack();
                    return 'db_error:'.$configError->getMessage();
                }
            }
            DB::commit();
            return $updatedConfig ? true : 'db_error:max_point_update_failed';
        } catch (Throwable $e) {
            DB::rollBack();
            return 'db_error:'.$e->getMessage();
        }
    }
