	/*Update Storie Status*/
	public function iN_NormalizeStoryPrivacy($privacy): string {
		$privacy = strtolower(trim((string)$privacy));
		if (!in_array($privacy, ['followers', 'subscribers', 'everyone'], true)) {
			$privacy = 'followers';
		}
		return $privacy;
	}

	public function iN_GetStoryAccessInfo($viewerId, array $storyData): array {
		$viewerId = (int)$viewerId;
		$ownerId = (int)($storyData['uid_fk'] ?? 0);
		$privacy = $this->iN_NormalizeStoryPrivacy($storyData['story_privacy'] ?? 'followers');
		if ($ownerId <= 0) {
			return ['allowed' => false, 'privacy' => $privacy, 'reason' => $privacy];
		}
		if ($viewerId > 0 && ($viewerId === $ownerId || $this->iN_CheckIsAdmin($viewerId) == 1)) {
			return ['allowed' => true, 'privacy' => $privacy, 'reason' => ''];
		}
		if ($privacy === 'everyone') {
			return ['allowed' => true, 'privacy' => $privacy, 'reason' => ''];
		}
		if ($viewerId <= 0) {
			return ['allowed' => false, 'privacy' => $privacy, 'reason' => $privacy];
		}
		$relation = (string)$this->iN_GetRelationsipBetweenTwoUsers($viewerId, $ownerId);
		if ($privacy === 'followers') {
			$allowed = in_array($relation, ['flwr', 'subscriber', 'me'], true);
			return ['allowed' => $allowed, 'privacy' => $privacy, 'reason' => $allowed ? '' : 'followers'];
		}
		if ($privacy === 'subscribers') {
			$allowed = $relation === 'subscriber';
			return ['allowed' => $allowed, 'privacy' => $privacy, 'reason' => $allowed ? '' : 'subscribers'];
		}
		return ['allowed' => false, 'privacy' => $privacy, 'reason' => $privacy];
	}

	public function iN_CanViewStory($viewerId, array $storyData): bool {
		$info = $this->iN_GetStoryAccessInfo($viewerId, $storyData);
		return (bool)($info['allowed'] ?? false);
	}

	public function iN_NormalizeStoryQuickReplies($raw): array {
		$list = [];
		if (is_array($raw)) {
			$list = $raw;
		} elseif (is_string($raw)) {
			$raw = trim($raw);
			if ($raw !== '') {
				$decoded = json_decode($raw, true);
				if (is_array($decoded)) {
					$list = $decoded;
				} else {
					$list = preg_split('/\r\n|\r|\n/', $raw);
				}
			}
		}
		$clean = [];
		if (!empty($list)) {
			foreach ($list as $item) {
				$text = trim((string)$item);
				if ($text === '') {
					continue;
				}
				if (function_exists('mb_substr')) {
					$text = mb_substr($text, 0, 120, 'UTF-8');
				} else {
					$text = substr($text, 0, 120);
				}
				if (!in_array($text, $clean, true)) {
					$clean[] = $text;
				}
				if (count($clean) >= 5) {
					break;
				}
			}
		}
		return $clean;
	}

	public function iN_DecodeStoryQuickReplies($raw): array {
		if ($raw === null || $raw === '') {
			return [];
		}
		$decoded = json_decode((string)$raw, true);
		if (is_array($decoded)) {
			return $this->iN_NormalizeStoryQuickReplies($decoded);
		}
		return $this->iN_NormalizeStoryQuickReplies((string)$raw);
	}

	public function iN_SanitizeStoryOverlayLink($link): string {
		$link = trim((string)$link);
		if ($link === '') {
			return '';
		}
		if (!preg_match('#^https?://#i', $link)) {
			return '';
		}
		if (filter_var($link, FILTER_VALIDATE_URL) === false) {
			return '';
		}
		if (function_exists('mb_substr')) {
			return mb_substr($link, 0, 255, 'UTF-8');
		}
		return substr($link, 0, 255);
	}

	public function iN_SanitizeStoryOverlayMention($mention): string {
		$mention = trim((string)$mention);
		$mention = ltrim($mention, '@');
		if ($mention === '') {
			return '';
		}
		if (!preg_match('/^[a-zA-Z0-9_.]{2,60}$/', $mention)) {
			return '';
		}
		$user = $this->iN_GetUserDetailsFromUsername($mention);
		if (!$user || empty($user['i_username'])) {
			return '';
		}
		return (string)$user['i_username'];
	}

	public function iN_SanitizeStoryOverlayStickerId($stickerId): int {
		$stickerId = (int)$stickerId;
		if ($stickerId <= 0) {
			return 0;
		}
		if ($this->iN_CheckStickerIDExist($stickerId) != 1) {
			return 0;
		}
		return $stickerId;
	}

	public function iN_SanitizeStoryAudioId($audioId): int {
		$audioId = (int)$audioId;
		if ($audioId <= 0) {
			return 0;
		}
		$audio = $this->iN_GetStoryAudioById($audioId);
		if (!$audio || (string)($audio['status'] ?? '0') !== '1') {
			return 0;
		}
		return $audioId;
	}

	public function iN_InsertMyStorie($userID, $storieID, $storieText, $privacy = 'followers', $overlayLink = '', $overlayMention = '', $overlayStickerId = 0, $overlayAudioId = 0, $quickReplies = []) {
		if ($this->iN_CheckUserExist($userID) == 1) {
			$privacy = $this->iN_NormalizeStoryPrivacy($privacy);
			$overlayLink = $this->iN_SanitizeStoryOverlayLink($overlayLink);
			$overlayMention = $this->iN_SanitizeStoryOverlayMention($overlayMention);
			$overlayStickerId = $this->iN_SanitizeStoryOverlayStickerId($overlayStickerId);
			$overlayAudioId = $this->iN_SanitizeStoryAudioId($overlayAudioId);
			$quickReplies = $this->iN_NormalizeStoryQuickReplies($quickReplies);
			$updates = ["status = '2'"];
			$params = [];
			if ($storieText !== null && $storieText !== '') {
				$updates[] = 'text = ?';
				$params[] = (string)$storieText;
			}
			$updates[] = 'story_privacy = ?';
			$params[] = (string)$privacy;
			$updates[] = 'story_overlay_link = ?';
			$params[] = $overlayLink !== '' ? (string)$overlayLink : null;
			$updates[] = 'story_overlay_mention = ?';
			$params[] = $overlayMention !== '' ? (string)$overlayMention : null;
			$updates[] = 'story_overlay_sticker_id = ?';
			$params[] = $overlayStickerId > 0 ? (int)$overlayStickerId : 0;
			$updates[] = 'story_audio_id = ?';
			$params[] = $overlayAudioId > 0 ? (int)$overlayAudioId : 0;
			$updates[] = 'story_quick_replies = ?';
			$params[] = !empty($quickReplies)
				? json_encode(array_values($quickReplies), JSON_UNESCAPED_UNICODE)
				: null;
			$params[] = (int)$storieID;
			$params[] = (int)$userID;
			$sql = "UPDATE i_user_stories SET " . implode(', ', $updates) . " WHERE s_id = ? AND uid_fk = ?";
			DB::exec($sql, $params);
			return true;
		}
	}
	public function iN_UserHasPublicStory($ownerId): bool {
		$ownerId = (int)$ownerId;
		if ($ownerId <= 0) {
			return false;
		}
		static $cache = [];
		if (array_key_exists($ownerId, $cache)) {
			return $cache[$ownerId];
		}
		$exists = DB::col(
			"SELECT 1 FROM i_user_stories S
			 JOIN i_users U ON S.uid_fk = U.iuid
			 WHERE S.uid_fk = ? AND S.story_privacy = 'everyone' AND S.status IN('1','2')
			   AND FROM_UNIXTIME(S.created) > (NOW() - INTERVAL 24 HOUR)
			   AND U.uStatus = '3'
			 LIMIT 1",
			[(int)$ownerId]
		);
		$cache[$ownerId] = (bool)$exists;
		return $cache[$ownerId];
	}
