	public function iN_GetPublicStoryItemsByUser($ownerId): array {
		$ownerId = (int)$ownerId;
		if ($ownerId <= 0) {
			return [];
		}
		$rows = DB::all(
			"SELECT S.s_id,
			        S.text,
			        S.text_style,
			        S.uploaded_file_path,
			        S.upload_tumbnail_file_path,
			        S.uploaded_file_ext,
			        S.created,
			        S.story_privacy,
			        S.story_overlay_link,
			        S.story_overlay_mention,
			        S.story_overlay_sticker_id,
			        S.story_audio_id,
			        S.story_quick_replies
			 FROM i_user_stories S
			 JOIN i_users U ON S.uid_fk = U.iuid
			 WHERE S.uid_fk = ? AND S.story_privacy = 'everyone' AND S.status IN('1','2')
			   AND FROM_UNIXTIME(S.created) > (NOW() - INTERVAL 24 HOUR)
			   AND U.uStatus = '3'
			 ORDER BY S.s_id ASC",
			[(int)$ownerId]
		);
		if (empty($rows)) {
			return [];
		}
		global $base_url;
		$items = [];
		foreach ($rows as $row) {
			$src = $row['uploaded_file_path'] ?? '';
			$thumbnail = $row['upload_tumbnail_file_path'] ?? '';
			if ($src !== '') {
				if (function_exists('storage_public_url')) {
					$src = storage_public_url($src);
				} else {
					$src = $base_url . $src;
				}
			}
			if ($thumbnail !== '') {
				if (function_exists('storage_public_url')) {
					$thumbnail = storage_public_url($thumbnail);
				} else {
					$thumbnail = $base_url . $thumbnail;
				}
			}
			$ext = $row['uploaded_file_ext'] ?? '';
			if ($ext === '' && !empty($row['uploaded_file_path'])) {
				$ext = pathinfo($row['uploaded_file_path'], PATHINFO_EXTENSION);
			}
			$overlayLink = $row['story_overlay_link'] ?? '';
			$overlayMention = $row['story_overlay_mention'] ?? '';
			$overlayStickerUrl = '';
			$overlayStickerId = (int)($row['story_overlay_sticker_id'] ?? 0);
			if ($overlayStickerId > 0) {
				$stickerData = $this->iN_GetStickerDetailsFromID($overlayStickerId);
				$overlayStickerUrl = $stickerData['sticker_url'] ?? '';
			}
			$storyAudioUrl = '';
			$storyAudioTitle = '';
			$storyAudioArtist = '';
			$storyAudioId = (int)($row['story_audio_id'] ?? 0);
			if ($storyAudioId > 0) {
				$audioData = $this->iN_GetStoryAudioById($storyAudioId);
				if ($audioData && (string)($audioData['status'] ?? '0') === '1') {
					$audioPath = $audioData['audio_url'] ?? '';
					if ($audioPath !== '') {
						if (function_exists('storage_public_url')) {
							$storyAudioUrl = storage_public_url($audioPath);
						} else {
							$storyAudioUrl = $base_url . $audioPath;
						}
					}
					$storyAudioTitle = $audioData['title'] ?? '';
					$storyAudioArtist = $audioData['artist'] ?? '';
				}
			}
			if (in_array($ext, ['mp4', 'MP4'], true)) {
				$storyAudioUrl = '';
				$storyAudioTitle = '';
				$storyAudioArtist = '';
			}
			$items[] = [
				'id' => (int)($row['s_id'] ?? 0),
				'text' => $row['text'] ?? '',
				'text_style' => $row['text_style'] ?? 'not',
				'uploaded_file_ext' => $ext,
				'created' => $row['created'] ?? 0,
				'src' => $src,
				'thumbnail' => $thumbnail,
				'privacy' => $row['story_privacy'] ?? 'everyone',
				'overlay_link' => $overlayLink,
				'overlay_mention' => $overlayMention,
				'overlay_sticker' => $overlayStickerUrl,
				'audio_url' => $storyAudioUrl,
				'audio_title' => $storyAudioTitle,
				'audio_artist' => $storyAudioArtist,
				'quick_replies' => $this->iN_DecodeStoryQuickReplies($row['story_quick_replies'] ?? ''),
				'can_view' => '1',
				'access_reason' => ''
			];
		}
		return $items;
	}
public function iN_FriendStoryPost($userID) {
    if ($this->iN_CheckUserExist($userID) == 1) {
        $sql = "SELECT S.uid_fk,
                       GROUP_CONCAT(S.s_id) as pics,
                       MAX(S.s_id) as s_id,
                       MAX(S.uploaded_file_path) as uploaded_file_path,
                       MAX(S.upload_tumbnail_file_path) as upload_tumbnail_file_path,
                       MAX(S.uploaded_x_file_path) as uploaded_x_file_path,
                       MAX(S.uploaded_file_ext) as uploaded_file_ext,
                       MAX(S.text) as text,
                       MAX(S.text_style) as text_style,
                       MAX(S.created) as created,
                       MAX(S.story_type) as story_type,
                       MAX(U.iuid) as iuid,
                       MAX(U.i_username) as i_username,
                       MAX(U.i_user_fullname) as i_user_fullname,
                       MAX(U.user_avatar) as user_avatar,
                       MAX(U.user_verified_status) as user_verified_status
                FROM i_user_stories S
                JOIN i_users U ON S.uid_fk = U.iuid
                JOIN i_friends F ON S.uid_fk = F.fr_two
                WHERE U.uStatus = '3'
                  AND FROM_UNIXTIME(S.created) > (NOW() - INTERVAL 24 HOUR)
                  AND F.fr_one = ?
                  AND (F.fr_status IN ('fri','me','1','flwr','subscriber'))
                GROUP BY S.uid_fk
                ORDER BY S.uid_fk ASC LIMIT 20";
        $rows = DB::all($sql, [(int)$userID]);
        return !empty($rows) ? $rows : null;
    }
}
