	/*Save Story Reaction*/
    public function iN_SaveStoryReaction($storyID, $userID, $reaction, array $allowedReactions = []): array {
        $storyID = (int)$storyID;
        $userID = (int)$userID;
        $reaction = trim((string)$reaction);
        if ($storyID <= 0 || $userID <= 0 || $reaction === '') {
            return ['status' => 'invalid'];
        }
        if (!empty($allowedReactions) && !in_array($reaction, $allowedReactions, true)) {
            return ['status' => 'invalid'];
        }
        $time = time();
        try {
            $row = DB::one(
                "SELECT reaction FROM i_story_reactions WHERE story_id_fk = ? AND iuid_fk = ? LIMIT 1",
                [$storyID, $userID]
            );
            if ($row && isset($row['reaction'])) {
                $current = (string)$row['reaction'];
                if ($current === $reaction) {
                    DB::exec(
                        "DELETE FROM i_story_reactions WHERE story_id_fk = ? AND iuid_fk = ?",
                        [$storyID, $userID]
                    );
                    return ['status' => 'removed'];
                }
                DB::exec(
                    "UPDATE i_story_reactions SET reaction = ?, updated_at = ? WHERE story_id_fk = ? AND iuid_fk = ?",
                    [$reaction, $time, $storyID, $userID]
                );
                return ['status' => 'updated', 'reaction' => $reaction];
            }
            DB::exec(
                "INSERT INTO i_story_reactions (story_id_fk, iuid_fk, reaction, created_at, updated_at) VALUES (?,?,?,?,?)",
                [$storyID, $userID, $reaction, $time, $time]
            );
            return ['status' => 'added', 'reaction' => $reaction];
        } catch (Throwable $e) {
            return ['status' => 'error'];
        }
    }

    private function iN_NormalizeHighlightTitle($title): string {
        $title = trim((string)$title);
        if ($title === '') {
            return '';
        }
        $maxLength = 120;
        if (function_exists('mb_substr')) {
            $title = mb_substr($title, 0, $maxLength, 'UTF-8');
        } else {
            $title = substr($title, 0, $maxLength);
        }
        return $title;
    }

    private function iN_FilterHighlightStoryIds(int $ownerId, array $storyIds): array {
        $clean = [];
        foreach ($storyIds as $storyId) {
            $storyId = (int)$storyId;
            if ($storyId <= 0) {
                continue;
            }
            if (in_array($storyId, $clean, true)) {
                continue;
            }
            $row = DB::one(
                "SELECT s_id FROM i_user_stories WHERE s_id = ? AND uid_fk = ? AND status = '2' LIMIT 1",
                [$storyId, $ownerId]
            );
            if ($row && isset($row['s_id'])) {
                $clean[] = $storyId;
            }
        }
        return $clean;
    }

