    public function iN_CreateStoryHighlight($ownerId, $title, array $storyIds = [], $coverStoryId = 0, $coverImagePath = null) {
        $ownerId = (int)$ownerId;
        if ($this->iN_CheckUserExist($ownerId) != 1) {
            return false;
        }
        $title = $this->iN_NormalizeHighlightTitle($title);
        if ($title === '') {
            return false;
        }
        $storyIds = $this->iN_FilterHighlightStoryIds($ownerId, $storyIds);
        if (empty($storyIds)) {
            return false;
        }
        $coverStoryId = (int)$coverStoryId;
        if ($coverStoryId <= 0 || !in_array($coverStoryId, $storyIds, true)) {
            $coverStoryId = $storyIds[0];
        }
        $coverImagePath = $coverImagePath !== null ? trim((string)$coverImagePath) : null;
        if ($coverImagePath === '') {
            $coverImagePath = null;
        }
        $maxOrder = DB::col("SELECT COALESCE(MAX(sort_order), 0) FROM i_story_highlights WHERE owner_id = ?", [$ownerId]);
        $sortOrder = (int)$maxOrder + 1;
        $time = time();
        DB::exec(
            "INSERT INTO i_story_highlights (owner_id, title, cover_story_id, cover_image, sort_order, status, created_at, updated_at)
             VALUES (?,?,?,?,?, 'active', ?, ?)",
            [$ownerId, $title, $coverStoryId, $coverImagePath, $sortOrder, $time, $time]
        );
        $highlightId = (int)DB::lastId();
        if ($highlightId <= 0) {
            return false;
        }
        if (!$this->iN_UpdateHighlightStories($ownerId, $highlightId, $storyIds, $coverStoryId)) {
            return false;
        }
        return $highlightId;
    }

    public function iN_UpdateStoryHighlight($ownerId, $highlightId, $title, array $storyIds = [], $coverStoryId = 0, $coverImagePath = null): bool {
        $ownerId = (int)$ownerId;
        $highlightId = (int)$highlightId;
        if ($ownerId <= 0 || $highlightId <= 0) {
            return false;
        }
        $row = DB::one(
            "SELECT id FROM i_story_highlights WHERE id = ? AND owner_id = ? AND status = 'active' LIMIT 1",
            [$highlightId, $ownerId]
        );
        if (!$row) {
            return false;
        }
        $title = $this->iN_NormalizeHighlightTitle($title);
        if ($title === '') {
            return false;
        }
        $storyIds = $this->iN_FilterHighlightStoryIds($ownerId, $storyIds);
        if (empty($storyIds)) {
            return false;
        }
        $coverStoryId = (int)$coverStoryId;
        if ($coverStoryId <= 0 || !in_array($coverStoryId, $storyIds, true)) {
            $coverStoryId = $storyIds[0];
        }
        $coverImagePath = $coverImagePath !== null ? trim((string)$coverImagePath) : null;
        if ($coverImagePath === '') {
            $coverImagePath = null;
        }
        $time = time();
        $sqlParts = ['title = ?', 'cover_story_id = ?', 'updated_at = ?'];
        $params = [$title, $coverStoryId, $time];
        if ($coverImagePath !== null) {
            $sqlParts[] = 'cover_image = ?';
            $params[] = $coverImagePath;
        }
        $params[] = $highlightId;
        $params[] = $ownerId;
        DB::exec(
            "UPDATE i_story_highlights SET " . implode(', ', $sqlParts) . " WHERE id = ? AND owner_id = ?",
            $params
        );
        return $this->iN_UpdateHighlightStories($ownerId, $highlightId, $storyIds, $coverStoryId);
    }

    public function iN_UpdateHighlightStories($ownerId, $highlightId, array $storyIds = [], $coverStoryId = 0): bool {
        $ownerId = (int)$ownerId;
        $highlightId = (int)$highlightId;
        if ($ownerId <= 0 || $highlightId <= 0) {
            return false;
        }
        $storyIds = $this->iN_FilterHighlightStoryIds($ownerId, $storyIds);
        if (empty($storyIds)) {
            return false;
        }
        $coverStoryId = (int)$coverStoryId;
        if ($coverStoryId <= 0 || !in_array($coverStoryId, $storyIds, true)) {
            $coverStoryId = $storyIds[0];
        }
        $time = time();
        try {
            DB::begin();
            DB::exec("DELETE FROM i_story_highlight_items WHERE highlight_id = ?", [$highlightId]);
            $order = 1;
            foreach ($storyIds as $storyId) {
                DB::exec(
                    "INSERT INTO i_story_highlight_items (highlight_id, story_id, sort_order, added_at) VALUES (?,?,?,?)",
                    [$highlightId, (int)$storyId, $order, $time]
                );
                $order++;
            }
            DB::exec(
                "UPDATE i_story_highlights SET cover_story_id = ?, updated_at = ? WHERE id = ? AND owner_id = ?",
                [$coverStoryId, $time, $highlightId, $ownerId]
            );
            DB::commit();
            return true;
        } catch (Throwable $e) {
            DB::rollBack();
            return false;
        }
    }

    public function iN_DeleteStoryHighlight($ownerId, $highlightId): bool {
        $ownerId = (int)$ownerId;
        $highlightId = (int)$highlightId;
        if ($ownerId <= 0 || $highlightId <= 0) {
            return false;
        }
        $row = DB::one(
            "SELECT cover_image FROM i_story_highlights WHERE id = ? AND owner_id = ? LIMIT 1",
            [$highlightId, $ownerId]
        );
        $coverImagePath = $row['cover_image'] ?? '';
        try {
            DB::begin();
            DB::exec(
                "UPDATE i_story_highlights SET status = 'deleted', updated_at = ? WHERE id = ? AND owner_id = ?",
                [time(), $highlightId, $ownerId]
            );
            DB::exec("DELETE FROM i_story_highlight_items WHERE highlight_id = ?", [$highlightId]);
            DB::commit();
            $coverImagePath = trim((string)$coverImagePath);
            if ($coverImagePath !== '' && strpos($coverImagePath, 'uploads/') === 0) {
                $useRemote = function_exists('storage_is_remote') ? storage_is_remote() : false;
                if ($useRemote && function_exists('storage_delete')) {
                    @storage_delete($coverImagePath);
                } else {
                    $full = dirname(__DIR__) . '/' . ltrim($coverImagePath, '/');
                    @unlink($full);
                }
            }
            return true;
        } catch (Throwable $e) {
            DB::rollBack();
            return false;
        }
    }
