            DB::exec(
                "INSERT INTO i_user_product_posts (pr_name, pr_price, pr_files, pr_desc, pr_desc_info, pr_created_time, iuid_fk, pr_status, pr_seen_time, pr_number_of_sales, pr_name_slug, product_type, pr_downlodable_files)
