	/*Update Story Audio*/
	public function iN_UpdateStoryAudio($userID, $audioID, $title, $artist, $audioUrl = null) {
		if ($this->iN_CheckIsAdmin($userID) == 1 && $this->iN_CheckStoryAudioIdExist($audioID) == 1) {
			$updates = ['title = ?', 'artist = ?'];
			$params = [
				(string)$title,
				$artist !== '' ? (string)$artist : null
			];
			if ($audioUrl !== null) {
				$updates[] = 'audio_url = ?';
				$params[] = (string)$audioUrl;
			}
			$params[] = (int)$audioID;
			$sql = "UPDATE i_story_audio SET " . implode(', ', $updates) . " WHERE id = ?";
			DB::exec($sql, $params);
			return true;
		}
		return false;
	}
