	/*Share My Text Story*/
    public function iN_InsertTextStory($userID, $bgID ,$storyText, $privacy = 'followers', $overlayLink = '', $overlayMention = '', $overlayStickerId = 0, $overlayAudioId = 0, $quickReplies = []) {
        if($this->iN_CheckStoryBgIdExist($bgID) == 1 && $this->iN_CheckUserExist($userID) == 1){
            $time = time();
            $bgImage = $this->iN_GetBgImageByID($bgID);
			$privacy = $this->iN_NormalizeStoryPrivacy($privacy);
			$overlayLink = $this->iN_SanitizeStoryOverlayLink($overlayLink);
			$overlayMention = $this->iN_SanitizeStoryOverlayMention($overlayMention);
			$overlayStickerId = $this->iN_SanitizeStoryOverlayStickerId($overlayStickerId);
			$overlayAudioId = $this->iN_SanitizeStoryAudioId($overlayAudioId);
			$quickReplies = $this->iN_NormalizeStoryQuickReplies($quickReplies);
            DB::exec(
                "INSERT INTO i_user_stories (uid_fk, uploaded_file_path, upload_tumbnail_file_path, uploaded_x_file_path, uploaded_file_ext, text, text_style, created, status, story_type, story_privacy, story_overlay_link, story_overlay_mention, story_overlay_sticker_id, story_audio_id, story_quick_replies)
                 VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)",
                [
                    (int)$userID,
                    (string)$bgImage,
                    (string)$bgImage,
                    (string)$bgImage,
                    'png',
                    (string)$storyText,
                    'one',
                    $time,
                    '1',
                    'textStory',
					(string)$privacy,
					$overlayLink !== '' ? (string)$overlayLink : null,
					$overlayMention !== '' ? (string)$overlayMention : null,
					$overlayStickerId > 0 ? (int)$overlayStickerId : 0,
					$overlayAudioId > 0 ? (int)$overlayAudioId : 0,
					!empty($quickReplies) ? json_encode(array_values($quickReplies), JSON_UNESCAPED_UNICODE) : null
                ]
            );
            return true;
        }
    }
