    public function iN_TotalProductByUserMap(array $userIDs) {
        $ids = $this->iN_NormalizePositiveIntList($userIDs);
        if (empty($ids)) {
            return [];
        }
        $placeholders = implode(',', array_fill(0, count($ids), '?'));
        $rows = DB::all(
            "SELECT iuid_fk AS uid, COUNT(*) AS total
             FROM i_user_product_posts
             WHERE iuid_fk IN ($placeholders)
             GROUP BY iuid_fk",
            $ids
        );
        $map = [];
        if (!empty($rows)) {
            foreach ($rows as $row) {
                $uid = isset($row['uid']) ? (int)$row['uid'] : 0;
                if ($uid > 0) {
                    $map[$uid] = isset($row['total']) ? (int)$row['total'] : 0;
                }
            }
        }
        return $map;
    }
