            $params = [$like, $like];
        }
        if ($this->iN_CheckIsAdmin($userID) == 1) {
            $sql = "SELECT P.*, U.*
                    FROM i_user_product_posts P FORCE INDEX(ixProduct)
                    INNER JOIN i_users U FORCE INDEX(ixForceUser) ON P.iuid_fk = U.iuid AND U.uStatus IN('1','3')
