	/*Unlock Message*/
    public function iN_UnLockMessage($userID, $messageID, $chatID, $adminEarning, $userEarning,$messageOwnerID, $translatePointToMoney, $adminFee, $messagePrice){
        if($this->iN_CheckUserExist($userID) == 1 && $this->iN_CheckMesageIDExistForUnLock($messageID, $chatID) == 1){
            $time = time();
            $paymentId = 0;
            try {
                $column = DB::one("SHOW COLUMNS FROM i_user_payments LIKE 'payment_type'");
                if (!empty($column['Type']) && strpos((string)$column['Type'], "'unlockmessage'") === false) {
                    preg_match_all("/'((?:[^'\\\\]|\\\\.)*)'/", (string)$column['Type'], $matches);
                    $options = $matches[1] ?? [];
                    $options[] = 'unlockmessage';
                    $options = array_values(array_unique($options));
                    $escapedOptions = array_map(static function ($opt) {
                        return str_replace("'", "\\'", $opt);
                    }, $options);
                    $enumList = "'" . implode("','", $escapedOptions) . "'";
                    DB::exec("ALTER TABLE i_user_payments MODIFY `payment_type` enum($enumList) COLLATE utf8mb4_general_ci NOT NULL");
                }
            } catch (Throwable $e) {
                // Allow unlock flow to continue; insert will fail if enum is still missing.
            }
            try {
                DB::begin();
                $split = $this->iN_CalculateAgencySplit($messageOwnerID, $translatePointToMoney, $adminFee);
                $adminEarning = $split['admin_earning'];
                $userEarning = $split['creator_net'];
                $agencyId = $split['agency_id'];
                $agencyFee = $split['agency_fee'];
                $agencyEarning = $split['agency_earning'];
                if ((float)$messagePrice > 0) {
                    $walletUpdated = DB::exec(
                        "UPDATE i_users SET wallet_points = wallet_points - ? WHERE iuid = ? AND wallet_points >= ?",
                        [(string)$messagePrice, (int)$userID, (string)$messagePrice]
                    );
                    if ($walletUpdated !== 1) {
                        DB::rollBack();
                        return false;
                    }
                }
                DB::exec("INSERT INTO i_user_payments (payer_iuid_fk, payed_iuid_fk, agency_id_fk, unlocked_message_id, payment_type, payment_time, payment_status, amount, fee, agency_fee, admin_earning, agency_earning, user_earning) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?)",
                    [(int)$userID, (int)$messageOwnerID, $agencyId, (int)$messageID, 'unlockmessage', $time, 'ok', (string)$translatePointToMoney, (string)$adminFee, (string)$agencyFee, (string)$adminEarning, (string)$agencyEarning, (string)$userEarning]
                );
                $paymentId = (int) DB::lastId();
                DB::exec("UPDATE i_users SET wallet_money = wallet_money + ? WHERE iuid = ?", [(string)$userEarning, (int)$messageOwnerID]);
                DB::exec("UPDATE i_chat_conversations SET private_status = 'opened' WHERE con_id = ? AND chat_id_fk = ?", [(int)$messageID, (int)$chatID]);
                DB::commit();
            } catch (Throwable $e) { DB::rollBack(); return false; }
            if ($paymentId > 0) {
                $currency = $GLOBALS['defaultCurrency'] ?? 'USD';
                $this->iN_AssignInvoiceToPayment($paymentId, (int)$userID, (float)$translatePointToMoney, $currency);
            }

            $data = DB::one("SELECT * FROM i_chat_conversations WHERE con_id = ? AND chat_id_fk = ?", [(int)$messageID, (int)$chatID]);
            return $data ?: false;
        }else{
            return FALSE;
        }
    }
