		/*Check user Is Creator*/
	    public function iN_NormalizeRegistrationRoleMode($mode): string {
	        $mode = strtolower(trim((string)$mode));
	        $allowedModes = ['legacy', 'user_agency', 'user_agency_creator'];
	        if (!in_array($mode, $allowedModes, true)) {
	            return 'legacy';
	        }
	        return $mode;
	    }

	    public function iN_NormalizeSignupIntent($intent): string {
	        $intent = strtolower(trim((string)$intent));
	        $allowedIntents = ['user', 'agency', 'creator'];
	        if (!in_array($intent, $allowedIntents, true)) {
	            return 'user';
	        }
	        return $intent;
	    }

	    public function iN_GetEffectiveSignupIntentForMode($intent, $registrationRoleMode): string {
	        $intent = $this->iN_NormalizeSignupIntent($intent);
	        $registrationRoleMode = $this->iN_NormalizeRegistrationRoleMode($registrationRoleMode);
	        if ($registrationRoleMode === 'legacy') {
	            return 'user';
	        }
	        if ($registrationRoleMode === 'user_agency' && $intent === 'creator') {
	            return 'user';
	        }
	        return $intent;
	    }

	    public function iN_CanUserAccessAgencyOnboarding($userID, $signupIntent, $registrationRoleMode): bool {
	        $userID = (int)$userID;
	        if ($userID <= 0) {
	            return false;
	        }
	        if ($this->iN_CheckUserIsCreator($userID) == 1) {
	            return true;
	        }
	        $registrationRoleMode = $this->iN_NormalizeRegistrationRoleMode($registrationRoleMode);
	        if (!in_array($registrationRoleMode, ['user_agency', 'user_agency_creator'], true)) {
	            return false;
	        }
	        $effectiveIntent = $this->iN_GetEffectiveSignupIntentForMode($signupIntent, $registrationRoleMode);
	        return $effectiveIntent === 'agency';
	    }

	    public function iN_GetSignupRedirectPath($signupIntent, $registrationRoleMode): string {
	        $effectiveIntent = $this->iN_GetEffectiveSignupIntentForMode($signupIntent, $registrationRoleMode);
	        if ($effectiveIntent === 'agency') {
	            return 'settings?tab=agencies';
	        }
	        if ($effectiveIntent === 'creator') {
	            return 'creator/becomeCreator';
	        }
	        return 'settings';
	    }

	    public function iN_CheckUserIsCreator($userID){
	        $exists = (bool) DB::col(
	            "SELECT 1 FROM i_users WHERE iuid = ? AND certification_status = '2' AND validation_status = '2' AND condition_status = '2' AND fees_status = '2' AND payout_status = '2' LIMIT 1",
            [(int)$userID]
        );
        return $exists;
    }
