        return $this->iN_CheckUserIsCreator($creatorUserId) == 1;
    }

    public function iN_CreateAgencyRequest($agencyId, $creatorUserId, $requestedBy) {
        $agencyId = (int)$agencyId;
        $creatorUserId = (int)$creatorUserId;
        $requestedBy = (string)$requestedBy;
        if ($agencyId <= 0 || $creatorUserId <= 0) {
            return false;
        }
        if (!in_array($requestedBy, ['agency', 'creator'], true)) {
            return false;
        }
        $agencyRow = DB::one("SELECT agency_status FROM i_agencies WHERE agency_id = ? LIMIT 1", [$agencyId]);
        if (!$agencyRow || ($agencyRow['agency_status'] ?? '') !== 'active') {
            return false;
        }
        if ($this->iN_IsCreatorEligibleForAgency($creatorUserId) !== true) {
            return false;
        }
        if ($this->iN_IsAgencyOwner($creatorUserId)) {
            return false;
        }
        $pendingCreate = DB::col(
            "SELECT 1 FROM i_agency_create_requests WHERE owner_iuid_fk = ? AND status = 'pending' LIMIT 1",
            [$creatorUserId]
        );
        if ($pendingCreate) {
            return false;
        }
        $alreadyMember = DB::col("SELECT 1 FROM i_agency_members WHERE creator_iuid_fk = ? LIMIT 1", [$creatorUserId]);
        if ($alreadyMember) {
            return false;
        }
        $pending = DB::col("SELECT 1 FROM i_agency_requests WHERE agency_id_fk = ? AND creator_iuid_fk = ? AND status = 'pending' LIMIT 1", [$agencyId, $creatorUserId]);
        if ($pending) {
            return false;
        }
        $time = time();
        $cooldownSeconds = 60;
        $recent = DB::col(
            "SELECT 1 FROM i_agency_requests WHERE creator_iuid_fk = ? AND created_at >= ? LIMIT 1",
            [$creatorUserId, $time - $cooldownSeconds]
        );
        if ($recent) {
            return false;
        }
        DB::exec(
            "INSERT INTO i_agency_requests (agency_id_fk, creator_iuid_fk, requested_by, status, created_at, updated_at) VALUES (?,?,?,?,?,?)",
            [$agencyId, $creatorUserId, $requestedBy, 'pending', $time, $time]
        );
        return (int) DB::lastId();
    }

    public function iN_UpdateAgencyRequestStatus($requestId, $status): bool {
        $requestId = (int)$requestId;
        $status = (string)$status;
        if ($requestId <= 0) {
            return false;
        }
        if (!in_array($status, ['pending', 'approved', 'rejected', 'canceled'], true)) {
            return false;
        }
        $time = time();
        $updated = DB::exec(
            "UPDATE i_agency_requests SET status = ?, updated_at = ? WHERE ar_id = ?",
            [$status, $time, $requestId]
        );
        return $updated > 0;
    }

    public function iN_AddCreatorToAgency($agencyId, $creatorUserId): bool {
        $agencyId = (int)$agencyId;
