    public function iN_CalculateAgencySplit($creatorUserId, $grossAmount, $adminFeePercent): array {
        $grossAmount = (float) $grossAmount;
        $adminFeePercent = (float) $adminFeePercent;
        if ($grossAmount < 0) { $grossAmount = 0.0; }
        if ($adminFeePercent < 0) { $adminFeePercent = 0.0; }
        if ($adminFeePercent > 100) { $adminFeePercent = 100.0; }
        $grossAmount = round($grossAmount, 2);
        $adminEarning = round(($adminFeePercent * $grossAmount) / 100, 2);
        $agencyId = null;
        $agencyFeePercent = 0.0;
        $agencyEarning = 0.0;
        $agency = $this->iN_GetActiveAgencyForCreator($creatorUserId);
        if ($agency && (int)($agency['owner_iuid_fk'] ?? 0) !== (int)$creatorUserId) {
            $agencyFeePercent = isset($agency['agency_fee']) ? (float)$agency['agency_fee'] : 0.0;
            if ($agencyFeePercent < 0) { $agencyFeePercent = 0.0; }
            if ($agencyFeePercent > 100) { $agencyFeePercent = 100.0; }
            $agencyEarning = round(($agencyFeePercent * $grossAmount) / 100, 2);
            $agencyId = (int)($agency['agency_id'] ?? 0);
        }
        $creatorNet = round($grossAmount - $adminEarning - $agencyEarning, 2);
        $drift = round($grossAmount - ($adminEarning + $agencyEarning + $creatorNet), 2);
        if (abs($drift) >= 0.01) {
            $creatorNet = round($creatorNet + $drift, 2);
        }
        return [
            'agency_id' => $agencyId,
            'agency_fee' => $agencyFeePercent,
            'agency_earning' => $agencyEarning,
            'admin_earning' => $adminEarning,
            'creator_net' => $creatorNet,
        ];
    }

