    public function iN_SaveAgencySocialLinks(int $agencyId, array $links): bool {
        $agencyId = (int)$agencyId;
        if ($agencyId <= 0) {
            return false;
        }
        $time = time();
        foreach ($links as $networkId => $link) {
            $networkId = (int)$networkId;
            if ($networkId <= 0 || $this->iN_CheckSocialSiteIdExist($networkId) != 1) {
                continue;
            }
            $link = trim((string)$link);
            if ($link === '') {
                DB::exec(
                    "DELETE FROM i_agency_social_profiles WHERE agency_id_fk = ? AND isw_id_fk = ?",
                    [$agencyId, $networkId]
                );
                continue;
            }
            DB::exec(
                "INSERT INTO i_agency_social_profiles (agency_id_fk, isw_id_fk, s_link, created_at, updated_at)
                 VALUES (?,?,?,?,?)
                 ON DUPLICATE KEY UPDATE s_link = VALUES(s_link), updated_at = VALUES(updated_at)",
                [$agencyId, $networkId, $link, $time, $time]
            );
        }
        return true;
    }

