    public function iN_ExpireAgencyBoosts(?int $agencyId = null): int {
        $now = time();
        $params = [$now, $now];
        $where = "status = 'active' AND end_at IS NOT NULL AND end_at > 0 AND end_at <= ?";
        if (!empty($agencyId)) {
            $where .= " AND agency_id_fk = ?";
            $params[] = (int)$agencyId;
        }
        $sql = "UPDATE i_agency_boosts SET status = 'expired', updated_at = ? WHERE $where";
        return (int) DB::exec($sql, $params);
    }

    public function iN_GetActiveAgencyBoosts(int $agencyId, int $limit = 0): ?array {
        $agencyId = (int)$agencyId;
        if ($agencyId <= 0) {
            return null;
        }
        $this->iN_ExpireAgencyBoosts($agencyId);
        $now = time();
        $limitClause = '';
        if ($limit > 0) {
            $limitClause = ' LIMIT ' . (int)$limit;
        }
        $sql = "SELECT B.*, U.i_username, U.i_user_fullname,
                       COUNT(C.abc_id) AS click_count
                FROM i_agency_boosts B
                INNER JOIN i_users U ON U.iuid = B.creator_iuid_fk AND U.uStatus IN('1','3')
                LEFT JOIN i_agency_boost_clicks C ON C.ab_id_fk = B.ab_id
                WHERE B.agency_id_fk = ? AND B.status = 'active' AND B.end_at > ?
                GROUP BY B.ab_id
                ORDER BY B.end_at DESC{$limitClause}";
        $rows = DB::all($sql, [$agencyId, $now]);
        return !empty($rows) ? $rows : null;
    }

    public function iN_GetActiveAgencyBoostedCreators(int $limit = 0, $viewerId = null, $viewerCountryCode = null): ?array
    {
        $limit = (int)$limit;
        if ($limit < 1) {
            $limit = 8;
        }
        $this->iN_ExpireAgencyBoosts();
        $now = time();
        [$visibilityClauses, $visibilityParams] = $this->iN_BuildUserVisibilityFilter($viewerId, $viewerCountryCode, 'U');
        $visibilitySql = !empty($visibilityClauses) ? ' AND ' . implode(' AND ', $visibilityClauses) : '';
        $sql = "SELECT B.ab_id, B.agency_id_fk, B.creator_iuid_fk, B.end_at,
                       U.iuid, U.i_username, U.i_user_fullname, U.user_gender, U.user_verified_status,
                       (SELECT COUNT(*) FROM i_friends F WHERE F.fr_two = U.iuid AND F.fr_status = 'flwr') AS follower_count
                FROM i_agency_boosts B
                INNER JOIN i_users U ON U.iuid = B.creator_iuid_fk AND U.uStatus IN('1','3')
                INNER JOIN i_agencies A ON A.agency_id = B.agency_id_fk AND A.agency_status = 'active'
                WHERE B.status = 'active' AND B.end_at > ? $visibilitySql
                ORDER BY B.end_at DESC
                LIMIT $limit";
        $rows = DB::all($sql, array_merge([$now], $visibilityParams));
        return !empty($rows) ? $rows : null;
    }

