    public function iN_CreateAgencyBoost(
        int $agencyId,
        int $creatorUserId,
        int $createdByUserId,
        int $durationDays,
        bool $isAdmin = false
    ): ?int {
        $agencyId = (int)$agencyId;
        $creatorUserId = (int)$creatorUserId;
        $createdByUserId = (int)$createdByUserId;
        if ($agencyId <= 0 || $creatorUserId <= 0 || $createdByUserId <= 0) {
            return null;
        }
        $agency = DB::one(
            "SELECT agency_id, owner_iuid_fk, agency_status FROM i_agencies WHERE agency_id = ? LIMIT 1",
            [$agencyId]
        );
        if (!$agency || ($agency['agency_status'] ?? '') !== 'active') {
            return null;
        }
        if (!$isAdmin && (int)($agency['owner_iuid_fk'] ?? 0) !== $createdByUserId) {
            return null;
        }
        if ($this->iN_IsAgencyMember($agencyId, $creatorUserId) !== true) {
            return null;
        }
        if ($this->iN_CheckUserIsCreator($creatorUserId) != 1) {
            return null;
        }
        $this->iN_ExpireAgencyBoosts($agencyId);
        $now = time();
        $maxActive = (int)$this->iN_GetSetting('agency_boost_max_active', 3);
        if ($maxActive > 0) {
            $activeCount = (int) DB::col(
                "SELECT COUNT(*) FROM i_agency_boosts WHERE agency_id_fk = ? AND status = 'active' AND end_at > ?",
                [$agencyId, $now]
            );
            if ($activeCount >= $maxActive) {
                return null;
            }
        }
        $existingActive = DB::col(
            "SELECT 1 FROM i_agency_boosts WHERE agency_id_fk = ? AND creator_iuid_fk = ? AND status = 'active' AND end_at > ? LIMIT 1",
            [$agencyId, $creatorUserId, $now]
        );
        if ($existingActive) {
            return null;
        }
        $defaultDays = (int)$this->iN_GetSetting('agency_boost_default_days', 7);
        $durationDays = (int)$durationDays;
        if ($durationDays < 1 || $durationDays > 365) {
            $durationDays = $defaultDays;
        }
        if ($durationDays < 1) {
            $durationDays = 1;
        }
        if ($durationDays > 365) {
            $durationDays = 365;
        }
        $startAt = $now;
        $endAt = $startAt + ($durationDays * 86400);
        DB::exec(
            "INSERT INTO i_agency_boosts (agency_id_fk, creator_iuid_fk, created_by_iuid_fk, duration_days, start_at, end_at, status, created_at, updated_at)
             VALUES (?,?,?,?,?,?,'active',?,?)",
            [$agencyId, $creatorUserId, $createdByUserId, $durationDays, $startAt, $endAt, $now, $now]
        );
        return (int) DB::lastId();
    }

    public function iN_DisableAgencyBoost(int $boostId, int $actorId, bool $isAdmin = false): bool {
        $boostId = (int)$boostId;
        $actorId = (int)$actorId;
        if ($boostId <= 0 || $actorId <= 0) {
            return false;
        }
        $boost = DB::one(
            "SELECT ab_id, agency_id_fk FROM i_agency_boosts WHERE ab_id = ? LIMIT 1",
            [$boostId]
        );
        if (!$boost) {
            return false;
        }
        if (!$isAdmin && !$this->iN_IsAgencyOwnerForAgency((int)$boost['agency_id_fk'], $actorId)) {
            return false;
        }
        $updated = DB::exec(
            "UPDATE i_agency_boosts SET status = 'disabled', updated_at = ? WHERE ab_id = ?",
            [time(), $boostId]
        );
        return $updated > 0;
    }

    public function iN_LogAgencyBoostClick(
        int $boostId,
        int $agencyId,
        int $creatorId,
        ?int $viewerId,
        string $ip
    ): bool {
        $boostId = (int)$boostId;
        $agencyId = (int)$agencyId;
        $creatorId = (int)$creatorId;
        $viewerId = $viewerId !== null ? (int)$viewerId : null;
        if ($boostId <= 0 || $agencyId <= 0 || $creatorId <= 0) {
            return false;
        }
        $boost = $this->iN_GetAgencyBoostById($boostId);
        if (!$boost) {
            return false;
        }
        if ((int)($boost['agency_id_fk'] ?? 0) !== $agencyId || (int)($boost['creator_iuid_fk'] ?? 0) !== $creatorId) {
            return false;
        }
        if (($boost['status'] ?? '') !== 'active') {
            return false;
        }
        $endAt = isset($boost['end_at']) ? (int)$boost['end_at'] : 0;
        if ($endAt > 0 && $endAt <= time()) {
            $this->iN_ExpireAgencyBoosts($agencyId);
            return false;
        }
        $time = time();
        if (!empty($viewerId)) {
            $inserted = DB::exec(
                "INSERT IGNORE INTO i_agency_boost_clicks (ab_id_fk, agency_id_fk, creator_iuid_fk, iuid_fk, ip, clicked_at)
                 VALUES (?,?,?,?,?,?)",
                [$boostId, $agencyId, $creatorId, $viewerId, null, $time]
            );
            return $inserted > 0;
        }
        $ip = trim($ip);
        if ($ip === '') {
            return false;
        }
        $inserted = DB::exec(
            "INSERT IGNORE INTO i_agency_boost_clicks (ab_id_fk, agency_id_fk, creator_iuid_fk, iuid_fk, ip, clicked_at)
             VALUES (?,?,?,?,?,?)",
            [$boostId, $agencyId, $creatorId, null, $ip, $time]
        );
        return $inserted > 0;
    }

    public function iN_TotalAgencyBoosts($userId, $filter = 'all', $search = '') {
        if ($this->iN_CheckIsAdmin($userId) != 1) {
            return '0';
        }
        $this->iN_ExpireAgencyBoosts();
        $filter = (string)$filter;
        if (!in_array($filter, ['all', 'active', 'expired', 'disabled'], true)) {
            $filter = 'all';
        }
        $search = trim((string)$search);
        $numericSearch = (ctype_digit($search) ? (int)$search : null);
        $where = "WHERE 1=1";
        $params = [];
        if ($filter === 'active') {
            $where .= " AND B.status = 'active'";
        } elseif ($filter === 'expired') {
            $where .= " AND B.status = 'expired'";
        } elseif ($filter === 'disabled') {
            $where .= " AND B.status = 'disabled'";
        }
        if ($search !== '') {
            $where .= " AND (A.agency_name LIKE ? OR U.i_username LIKE ? OR U.i_user_fullname LIKE ?"
                . ($numericSearch !== null ? " OR B.ab_id = ? OR B.agency_id_fk = ? OR B.creator_iuid_fk = ?" : "")
                . ")";
            $params[] = '%' . $search . '%';
            $params[] = '%' . $search . '%';
            $params[] = '%' . $search . '%';
            if ($numericSearch !== null) {
                $params[] = $numericSearch;
                $params[] = $numericSearch;
                $params[] = $numericSearch;
            }
        }
        $sql = "SELECT COUNT(*)
                FROM i_agency_boosts B
                INNER JOIN i_agencies A ON A.agency_id = B.agency_id_fk
                INNER JOIN i_users U ON U.iuid = B.creator_iuid_fk AND U.uStatus IN('1','3')
                $where";
        $val = DB::col($sql, $params);
        return $val !== false ? $val : '0';
    }

    public function iN_ShowAllAgencyBoosts($userId, $paginationLimit, $page, $filter = 'all', $search = ''): ?array {
        if ($this->iN_CheckIsAdmin($userId) != 1) {
            return null;
        }
        $this->iN_ExpireAgencyBoosts();
        $startFrom = ((int)$page - 1) * (int)$paginationLimit;
        $limit = (int)$paginationLimit;
        $filter = (string)$filter;
        if (!in_array($filter, ['all', 'active', 'expired', 'disabled'], true)) {
            $filter = 'all';
        }
        $search = trim((string)$search);
        $numericSearch = (ctype_digit($search) ? (int)$search : null);
        $where = "WHERE 1=1";
        $params = [];
        if ($filter === 'active') {
            $where .= " AND B.status = 'active'";
        } elseif ($filter === 'expired') {
            $where .= " AND B.status = 'expired'";
        } elseif ($filter === 'disabled') {
            $where .= " AND B.status = 'disabled'";
        }
        if ($search !== '') {
            $where .= " AND (A.agency_name LIKE ? OR U.i_username LIKE ? OR U.i_user_fullname LIKE ?"
                . ($numericSearch !== null ? " OR B.ab_id = ? OR B.agency_id_fk = ? OR B.creator_iuid_fk = ?" : "")
                . ")";
            $params[] = '%' . $search . '%';
            $params[] = '%' . $search . '%';
            $params[] = '%' . $search . '%';
            if ($numericSearch !== null) {
                $params[] = $numericSearch;
                $params[] = $numericSearch;
                $params[] = $numericSearch;
            }
        }
        $sql = "SELECT B.*, A.agency_name, A.owner_iuid_fk,
                       U.i_username, U.i_user_fullname,
                       O.i_username AS owner_username, O.i_user_fullname AS owner_fullname,
                       COUNT(C.abc_id) AS click_count
                FROM i_agency_boosts B
                INNER JOIN i_agencies A ON A.agency_id = B.agency_id_fk
                INNER JOIN i_users U ON U.iuid = B.creator_iuid_fk AND U.uStatus IN('1','3')
                LEFT JOIN i_users O ON O.iuid = A.owner_iuid_fk
                LEFT JOIN i_agency_boost_clicks C ON C.ab_id_fk = B.ab_id
                $where
                GROUP BY B.ab_id
                ORDER BY B.ab_id DESC
                LIMIT $startFrom, $limit";
        $rows = DB::all($sql, $params);
        return !empty($rows) ? $rows : null;
    }

    public function iN_AdminCleanupAgencyBoosts(int $userId) {
        if ($this->iN_CheckIsAdmin($userId) != 1) {
            return false;
        }
        $expired = $this->iN_ExpireAgencyBoosts();
        return [
            'expired' => (int)$expired
        ];
    }

    /*Bulk Messaging*/
    public function iN_CreateBulkCampaign(array $data) {
        $creatorId = isset($data['created_by_iuid_fk']) ? (int)$data['created_by_iuid_fk'] : 0;
        $targetType = isset($data['target_type']) ? (string)$data['target_type'] : '';
        if ($creatorId <= 0 || $this->iN_CheckUserExist($creatorId) != 1) {
            return false;
        }
        $allowedTargets = ['all_users', 'subscribers_of_creator', 'subscribers_of_agency_creators', 'followers_of_creator'];
        if (!in_array($targetType, $allowedTargets, true)) {
            return false;
        }
        $messageText = isset($data['message_text']) ? trim((string)$data['message_text']) : '';
        if ($messageText === '') {
            return false;
        }
        $targetCreator = isset($data['target_creator_iuid_fk']) ? (int)$data['target_creator_iuid_fk'] : null;
        $targetAgency = isset($data['target_agency_id_fk']) ? (int)$data['target_agency_id_fk'] : null;
        if ($targetType === 'subscribers_of_creator' && (int)$targetCreator <= 0) {
            return false;
        }
        if ($targetType === 'subscribers_of_agency_creators' && (int)$targetAgency <= 0) {
            return false;
        }
        $attachmentPath = isset($data['attachment_path']) ? trim((string)$data['attachment_path']) : null;
        $privatePrice = isset($data['private_price']) && $data['private_price'] !== '' ? (float)$data['private_price'] : null;
        $privateStatus = (isset($data['private_status']) && (int)$data['private_status'] === 1 && $privatePrice !== null && $privatePrice > 0) ? 1 : 0;
        $rateLimit = isset($data['rate_limit_per_run']) ? (int)$data['rate_limit_per_run'] : 25;
        if ($rateLimit < 1) {
            $rateLimit = 25;
        }
        $time = time();
        DB::exec(
            "INSERT INTO i_bulk_campaigns (created_by_iuid_fk, target_type, target_creator_iuid_fk, target_agency_id_fk, message_text, attachment_path, private_price, private_status, status, rate_limit_per_run, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?, 'draft', ?, ?, ?)",
            [$creatorId, $targetType, $targetCreator, $targetAgency, $messageText, $attachmentPath, $privatePrice, $privateStatus, $rateLimit, $time, $time]
        );
        return (int) DB::lastId();
    }

    public function iN_BuildBulkRecipientList($campaign): int {
        if (empty($campaign) || !isset($campaign['bc_id'])) {
            return 0;
        }
        $bcId = (int)$campaign['bc_id'];
        $targetType = (string)($campaign['target_type'] ?? '');
        $created = 0;
        $time = time();
        $senderId = (int)($campaign['created_by_iuid_fk'] ?? 0);
        if ($targetType === 'subscribers_of_creator' && !empty($campaign['target_creator_iuid_fk'])) {
            $senderId = (int)$campaign['target_creator_iuid_fk'];
        } elseif ($targetType === 'subscribers_of_agency_creators' && !empty($campaign['target_agency_id_fk'])) {
            $agencyRow = DB::one("SELECT owner_iuid_fk FROM i_agencies WHERE agency_id = ? LIMIT 1", [(int)$campaign['target_agency_id_fk']]);
            if ($agencyRow && !empty($agencyRow['owner_iuid_fk'])) {
                $senderId = (int)$agencyRow['owner_iuid_fk'];
            }
        }

        if ($targetType === 'all_users') {
            $rows = DB::all("SELECT iuid FROM i_users WHERE uStatus IN('1','3') AND userType <> '2'");
        } elseif ($targetType === 'subscribers_of_creator') {
            $creatorId = (int)($campaign['target_creator_iuid_fk'] ?? 0);
            if ($creatorId <= 0) {
                return 0;
            }
            $rows = DB::all(
                "SELECT DISTINCT S.iuid_fk AS iuid
                 FROM i_user_subscriptions S
                 INNER JOIN i_users U ON U.iuid = S.iuid_fk
                 WHERE S.subscribed_iuid_fk = ? AND S.status = 'active' AND S.finished = '0' AND S.subscription_scope = 'profile'
                   AND U.uStatus IN('1','3') AND U.userType <> '2'",
                [$creatorId]
            );
        } elseif ($targetType === 'subscribers_of_agency_creators') {
            $agencyId = (int)($campaign['target_agency_id_fk'] ?? 0);
            if ($agencyId <= 0) {
                return 0;
            }
            $rows = DB::all(
                "SELECT DISTINCT S.iuid_fk AS iuid
                 FROM i_user_subscriptions S
                 INNER JOIN i_agency_members AM ON AM.creator_iuid_fk = S.subscribed_iuid_fk AND AM.status = 'active'
                 INNER JOIN i_users U ON U.iuid = S.iuid_fk
                 WHERE AM.agency_id_fk = ? AND S.status = 'active' AND S.finished = '0' AND S.subscription_scope = 'profile'
                   AND U.uStatus IN('1','3') AND U.userType <> '2'",
                [$agencyId]
            );
        } elseif ($targetType === 'followers_of_creator') {
            $creatorId = (int)($campaign['created_by_iuid_fk'] ?? 0);
            if ($creatorId <= 0) {
                return 0;
            }
            $rows = DB::all(
                "SELECT DISTINCT F.fr_one AS iuid
                 FROM i_friends F
                 INNER JOIN i_users U ON U.iuid = F.fr_one
                 WHERE F.fr_two = ? AND F.fr_status = 'flwr' AND U.uStatus IN('1','3') AND U.userType <> '2'",
                [$creatorId]
            );
        } else {
            return 0;
        }

        foreach ($rows as $row) {
            $recipientId = (int)($row['iuid'] ?? 0);
            if ($recipientId <= 0 || ($senderId > 0 && $recipientId === $senderId)) {
                continue;
            }
            $inserted = DB::exec(
                "INSERT IGNORE INTO i_bulk_campaign_queue (bc_id_fk, recipient_iuid_fk, status, attempts, created_at, updated_at) VALUES (?,?, 'queued', 0, ?, ?)",
                [$bcId, $recipientId, $time, $time]
            );
            if ($inserted > 0) {
                $created++;
            }
        }

        DB::exec("UPDATE i_bulk_campaigns SET updated_at = ? WHERE bc_id = ?", [$time, $bcId]);
        return $created;
    }

    public function iN_ProcessBulkCampaign($bcId, $limitPerRun): bool {
        $bcId = (int)$bcId;
        $limit = (int)$limitPerRun;
        if ($bcId <= 0) {
            return false;
        }
        if ($limit < 1) {
            $limit = 10;
        }
        $campaign = DB::one("SELECT * FROM i_bulk_campaigns WHERE bc_id = ? LIMIT 1", [$bcId]);
        if (!$campaign) {
            return false;
        }
        $createdBy = (int)($campaign['created_by_iuid_fk'] ?? 0);
        if ($createdBy > 0 && $this->iN_CheckIsAdmin($createdBy) != 1 && $this->iN_CheckUserIsCreator($createdBy) == 1 && !$this->iN_IsCreatorBulkEnabled()) {
            $currentStatus = (string)($campaign['status'] ?? '');
            if (!in_array($currentStatus, ['paused', 'canceled', 'completed'], true)) {
                DB::exec("UPDATE i_bulk_campaigns SET status = 'paused', updated_at = ? WHERE bc_id = ?", [time(), $bcId]);
            }
            return false;
        }
        $status = (string)($campaign['status'] ?? '');
        if (in_array($status, ['paused', 'canceled', 'completed'], true)) {
            return false;
        }
        $time = time();
        if ($status === 'queued') {
            DB::exec("UPDATE i_bulk_campaigns SET status = 'sending', updated_at = ? WHERE bc_id = ?", [$time, $bcId]);
        }

        $senderId = (int)($campaign['created_by_iuid_fk'] ?? 0);
        $targetType = (string)($campaign['target_type'] ?? '');
        if ($targetType === 'subscribers_of_creator' && !empty($campaign['target_creator_iuid_fk'])) {
            $senderId = (int)$campaign['target_creator_iuid_fk'];
        } elseif ($targetType === 'subscribers_of_agency_creators' && !empty($campaign['target_agency_id_fk'])) {
            $agencyRow = DB::one("SELECT owner_iuid_fk FROM i_agencies WHERE agency_id = ? LIMIT 1", [(int)$campaign['target_agency_id_fk']]);
            if ($agencyRow && !empty($agencyRow['owner_iuid_fk'])) {
                $senderId = (int)$agencyRow['owner_iuid_fk'];
            }
        }
        if ($senderId <= 0 || $this->iN_CheckUserExist($senderId) != 1) {
            return false;
        }

        $queueRows = DB::all(
            "SELECT * FROM i_bulk_campaign_queue WHERE bc_id_fk = ? AND status = 'queued' ORDER BY bq_id ASC LIMIT $limit",
            [$bcId]
        );

        if (empty($queueRows)) {
            DB::exec("UPDATE i_bulk_campaigns SET status = 'completed', updated_at = ? WHERE bc_id = ?", [$time, $bcId]);
            return true;
        }

        $messageText = (string)($campaign['message_text'] ?? '');
        $attachmentPath = isset($campaign['attachment_path']) ? trim((string)$campaign['attachment_path']) : '';
        $privatePrice = isset($campaign['private_price']) ? (float)$campaign['private_price'] : null;
        $privateStatus = isset($campaign['private_status']) && (int)$campaign['private_status'] === 1;

        foreach ($queueRows as $row) {
            $queueId = (int)$row['bq_id'];
            $recipientId = (int)$row['recipient_iuid_fk'];
            $queueTime = time();
            if ($recipientId <= 0 || $recipientId === $senderId) {
                DB::exec(
                    "UPDATE i_bulk_campaign_queue SET status = 'skipped', attempts = attempts + 1, last_error = ?, updated_at = ? WHERE bq_id = ?",
                    ['invalid_recipient', $queueTime, $queueId]
                );
                continue;
            }

            $recipient = DB::one(
                "SELECT iuid, uStatus, userType, who_can_message, who_can_send_message, message_status FROM i_users WHERE iuid = ? LIMIT 1",
                [$recipientId]
            );
            if (!$recipient || !in_array((string)$recipient['uStatus'], ['1', '3'], true) || (string)$recipient['userType'] === '2') {
                DB::exec(
                    "UPDATE i_bulk_campaign_queue SET status = 'skipped', attempts = attempts + 1, last_error = ?, updated_at = ? WHERE bq_id = ?",
                    ['inactive_recipient', $queueTime, $queueId]
                );
                continue;
            }
            if ($this->iN_CheckUserBlocked($senderId, $recipientId) == '1' || $this->iN_CheckUserBlockedVisitor($recipientId, $senderId) == '1') {
                DB::exec(
                    "UPDATE i_bulk_campaign_queue SET status = 'skipped', attempts = attempts + 1, last_error = ?, updated_at = ? WHERE bq_id = ?",
                    ['blocked', $queueTime, $queueId]
                );
                continue;
            }

            $messageStatus = (string)($recipient['message_status'] ?? '1');
            $whoCanSend = (string)($recipient['who_can_send_message'] ?? '0');
            $whoCanMessage = (string)($recipient['who_can_message'] ?? '0');
            if ($whoCanSend !== $whoCanMessage) {
                $whoCanMessage = $whoCanSend;
            }
            if ($messageStatus !== '1') {
                DB::exec(
                    "UPDATE i_bulk_campaign_queue SET status = 'skipped', attempts = attempts + 1, last_error = ?, updated_at = ? WHERE bq_id = ?",
                    ['recipient_disabled_messages', $queueTime, $queueId]
                );
                continue;
            }
            if ($whoCanSend === '1' || $whoCanMessage === '1') {
                $relation = $this->iN_GetRelationsipBetweenTwoUsers($senderId, $recipientId);
                if ($relation !== 'subscriber') {
                    DB::exec(
                        "UPDATE i_bulk_campaign_queue SET status = 'skipped', attempts = attempts + 1, last_error = ?, updated_at = ? WHERE bq_id = ?",
                        ['preference_blocked', $queueTime, $queueId]
                    );
                    continue;
                }
            }

            $chatId = $this->iN_GetConverationID($senderId, $recipientId);
            $fileIds = '';
            $lockMessage = ($privateStatus && $privatePrice !== null && $privatePrice > 0);

            $sent = false;
            if ($chatId) {
                if ($attachmentPath !== '') {
                    $ext = strtolower(pathinfo($attachmentPath, PATHINFO_EXTENSION));
                    $uploadId = $this->iN_INSERTUploadedMessageFiles($senderId, (int)$chatId, $attachmentPath, $attachmentPath, $ext);
                    if ($uploadId) {
                        $fileIds = (string)$uploadId;
                    }
                }
                $insert = $this->iN_InsertNewMessage($senderId, (int)$chatId, $messageText, '', '', $fileIds, $lockMessage ? (string)$privatePrice : '');
                $sent = $insert ? true : false;
            } else {
                $newChatId = $this->iN_CreateConverationAndInsertFirstMessage($senderId, $recipientId, $messageText);
                if ($newChatId) {
                    $chatId = (int)$newChatId;
                    if ($attachmentPath !== '') {
                        $ext = strtolower(pathinfo($attachmentPath, PATHINFO_EXTENSION));
                        $uploadId = $this->iN_INSERTUploadedMessageFiles($senderId, $chatId, $attachmentPath, $attachmentPath, $ext);
                        if ($uploadId) {
                            $fileIds = (string)$uploadId;
                        }
                    }
                    $messageRow = DB::one("SELECT con_id FROM i_chat_conversations WHERE chat_id_fk = ? ORDER BY con_id DESC LIMIT 1", [$chatId]);
                    if ($messageRow && isset($messageRow['con_id'])) {
                        $updates = [];
                        $params = [];
                        if ($fileIds !== '') {
                            $updates[] = "file = ?";
                            $params[] = $fileIds;
                        }
                        if ($lockMessage) {
                            $updates[] = "private_status = 'closed'";
                            $updates[] = "private_price = ?";
                            $params[] = (string)$privatePrice;
                        }
                        if (!empty($updates)) {
                            $params[] = (int)$messageRow['con_id'];
                            $params[] = $chatId;
                            DB::exec(
                                "UPDATE i_chat_conversations SET " . implode(', ', $updates) . " WHERE con_id = ? AND chat_id_fk = ?",
                                $params
                            );
                        }
                    }
                    DB::exec("UPDATE i_chat_users SET last_message_time = ? WHERE chat_id = ?", [$queueTime, $chatId]);
                    DB::exec("UPDATE i_users SET message_notification_read_status = '1' WHERE iuid = ?", [$recipientId]);
                    $sent = true;
                }
            }

            if ($sent) {
                DB::exec(
                    "UPDATE i_bulk_campaign_queue SET status = 'sent', attempts = attempts + 1, last_error = NULL, updated_at = ? WHERE bq_id = ?",
                    [$queueTime, $queueId]
                );
            } else {
                DB::exec(
                    "UPDATE i_bulk_campaign_queue SET status = 'failed', attempts = attempts + 1, last_error = ?, updated_at = ? WHERE bq_id = ?",
                    ['send_failed', $queueTime, $queueId]
                );
            }
        }

        DB::exec("UPDATE i_bulk_campaigns SET updated_at = ? WHERE bc_id = ?", [time(), $bcId]);
        return true;
    }

    /*Creator Auto Message*/
    public function iN_GetCreatorAutoMessage($creatorId) {
        $creatorId = (int)$creatorId;
        if ($creatorId <= 0) {
            return null;
        }
        $row = DB::one("SELECT * FROM i_creator_auto_messages WHERE creator_iuid_fk = ? LIMIT 1", [$creatorId]);
        return $row ?: null;
    }

    public function iN_SaveCreatorAutoMessage($creatorId, $enabled, $messageText = '', $attachmentPath = null): bool {
        $creatorId = (int)$creatorId;
        if ($creatorId <= 0 || $this->iN_CheckUserExist($creatorId) != 1) {
            return false;
        }
        $enabled = ((int)$enabled === 1) ? 1 : 0;
        $messageText = trim((string)$messageText);
        $attachmentPath = $attachmentPath !== null ? trim((string)$attachmentPath) : '';
        $attachmentPath = $attachmentPath !== '' ? $attachmentPath : null;
        $time = time();

        $existing = DB::one("SELECT cam_id FROM i_creator_auto_messages WHERE creator_iuid_fk = ? LIMIT 1", [$creatorId]);
        if ($existing && isset($existing['cam_id'])) {
            DB::exec(
                "UPDATE i_creator_auto_messages SET is_enabled = ?, message_text = ?, attachment_path = ?, updated_at = ? WHERE creator_iuid_fk = ?",
                [$enabled, $messageText, $attachmentPath, $time, $creatorId]
            );
            return true;
        }

        $inserted = DB::exec(
            "INSERT INTO i_creator_auto_messages (creator_iuid_fk, is_enabled, message_text, attachment_path, created_at, updated_at) VALUES (?,?,?,?,?,?)",
            [$creatorId, $enabled, $messageText, $attachmentPath, $time, $time]
        );
        return $inserted > 0;
    }

    public function iN_HasCreatorAutoMessageBeenSent($creatorId, $visitorId): bool {
        $creatorId = (int)$creatorId;
        $visitorId = (int)$visitorId;
        if ($creatorId <= 0 || $visitorId <= 0) {
            return false;
        }
        return (bool) DB::col(
            "SELECT 1 FROM i_creator_auto_message_log WHERE creator_iuid_fk = ? AND visitor_iuid_fk = ? LIMIT 1",
            [$creatorId, $visitorId]
        );
    }

    public function iN_LogCreatorAutoMessageSent($creatorId, $visitorId): bool {
        $creatorId = (int)$creatorId;
        $visitorId = (int)$visitorId;
        if ($creatorId <= 0 || $visitorId <= 0) {
            return false;
        }
        $time = time();
        DB::exec(
            "INSERT IGNORE INTO i_creator_auto_message_log (creator_iuid_fk, visitor_iuid_fk, sent_at) VALUES (?,?,?)",
            [$creatorId, $visitorId, $time]
        );
        return true;
    }

    public function iN_SendCreatorAutoMessageIfEligible($creatorId, $visitorId): bool {
        $creatorId = (int)$creatorId;
        $visitorId = (int)$visitorId;
        if ($creatorId <= 0 || $visitorId <= 0 || $creatorId === $visitorId) {
            return false;
        }
        if ($this->iN_CheckUserExist($creatorId) != 1 || $this->iN_CheckUserExist($visitorId) != 1) {
            return false;
        }
        if ($this->iN_CheckUserIsCreator($creatorId) != 1) {
            return false;
        }
        if ($this->iN_CheckUserIsInFLWR($visitorId, $creatorId) || $this->iN_CheckUserIsInSubscriber($visitorId, $creatorId)) {
            return false;
        }
        $activeSubscription = (bool) DB::col(
            "SELECT 1 FROM i_user_subscriptions WHERE iuid_fk = ? AND subscribed_iuid_fk = ? AND status = 'active' AND finished = '0' AND subscription_scope = 'profile' LIMIT 1",
            [$visitorId, $creatorId]
        );
        if ($activeSubscription) {
            return false;
        }
        if ($this->iN_HasCreatorAutoMessageBeenSent($creatorId, $visitorId)) {
            return false;
        }
        if ($this->iN_CheckUserBlocked($creatorId, $visitorId) == '1' || $this->iN_CheckUserBlockedVisitor($visitorId, $creatorId) == '1') {
            return false;
        }

        $autoMessage = $this->iN_GetCreatorAutoMessage($creatorId);
        if (!$autoMessage || (int)($autoMessage['is_enabled'] ?? 0) !== 1) {
            return false;
        }
        $messageText = trim((string)($autoMessage['message_text'] ?? ''));
        if ($messageText === '') {
            return false;
        }

        $recipient = DB::one(
            "SELECT iuid, uStatus, userType, who_can_message, who_can_send_message, message_status FROM i_users WHERE iuid = ? LIMIT 1",
            [$visitorId]
        );
        if (
            !$recipient ||
            !in_array((string)($recipient['uStatus'] ?? ''), ['1', '3'], true) ||
            (string)($recipient['userType'] ?? '') === '2'
        ) {
            return false;
        }

        $messageStatus = (string)($recipient['message_status'] ?? '1');
        $whoCanSend = (string)($recipient['who_can_send_message'] ?? '0');
        $whoCanMessage = (string)($recipient['who_can_message'] ?? '0');
        if ($whoCanSend !== $whoCanMessage) {
            $whoCanMessage = $whoCanSend;
        }
        if ($messageStatus !== '1') {
            return false;
        }
        if ($whoCanSend === '1' || $whoCanMessage === '1') {
            $relation = $this->iN_GetRelationsipBetweenTwoUsers($creatorId, $visitorId);
            if ($relation !== 'subscriber') {
                return false;
            }
        }

        $attachmentPath = isset($autoMessage['attachment_path']) ? trim((string)$autoMessage['attachment_path']) : '';
        $fileIds = '';
        $chatId = $this->iN_GetConverationID($creatorId, $visitorId);
        $time = time();
        $sent = false;

        if ($chatId) {
            if ($attachmentPath !== '') {
                $ext = strtolower(pathinfo($attachmentPath, PATHINFO_EXTENSION));
                $uploadId = $this->iN_INSERTUploadedMessageFiles($creatorId, (int)$chatId, $attachmentPath, $attachmentPath, $ext);
                if ($uploadId) {
                    $fileIds = (string)$uploadId;
                }
            }
            $insert = $this->iN_InsertNewMessage($creatorId, (int)$chatId, $messageText, '', '', $fileIds, '');
            $sent = $insert ? true : false;
        } else {
            $newChatId = $this->iN_CreateConverationAndInsertFirstMessage($creatorId, $visitorId, $messageText);
            if ($newChatId) {
                $chatId = (int)$newChatId;
                if ($attachmentPath !== '') {
                    $ext = strtolower(pathinfo($attachmentPath, PATHINFO_EXTENSION));
                    $uploadId = $this->iN_INSERTUploadedMessageFiles($creatorId, $chatId, $attachmentPath, $attachmentPath, $ext);
                    if ($uploadId) {
                        $fileIds = (string)$uploadId;
                    }
                }
                if ($fileIds !== '') {
                    $messageRow = DB::one("SELECT con_id FROM i_chat_conversations WHERE chat_id_fk = ? ORDER BY con_id DESC LIMIT 1", [$chatId]);
                    if ($messageRow && isset($messageRow['con_id'])) {
                        DB::exec(
                            "UPDATE i_chat_conversations SET file = ? WHERE con_id = ? AND chat_id_fk = ?",
                            [$fileIds, (int)$messageRow['con_id'], $chatId]
                        );
                    }
                }
                DB::exec("UPDATE i_chat_users SET last_message_time = ? WHERE chat_id = ?", [$time, $chatId]);
                DB::exec("UPDATE i_users SET message_notification_read_status = '1' WHERE iuid = ?", [$visitorId]);
                $sent = true;
            }
        }

        if ($sent) {
            $this->iN_LogCreatorAutoMessageSent($creatorId, $visitorId);
            return true;
        }
        return false;
    }
