    /*Update Epoch details*/
    public function iN_UpdateEpochDetails($userID, $piCode, $currency, $testEndpoint, $liveEndpoint, $postbackSecret, $postbackAllowlist, $returnMode, $template, $postbackEnabled) {
        if ($this->iN_CheckIsAdmin($userID) == 1) {
            $returnMode = in_array((string)$returnMode, ['pending', 'status'], true) ? (string)$returnMode : 'pending';
            $postbackEnabled = ((string)$postbackEnabled === '1') ? '1' : '0';
            try {
                DB::exec(
                    "UPDATE i_payment_methods
                     SET epoch_pi_code = ?, epoch_currency = ?, epoch_test_endpoint = ?, epoch_live_endpoint = ?, epoch_postback_secret = ?, epoch_postback_allowlist = ?, epoch_return_mode = ?, epoch_template = ?, epoch_postback_enabled = ?
                     WHERE payment_method_id = 1",
                    [
                        (string)$piCode,
                        (string)$currency,
                        (string)$testEndpoint,
                        (string)$liveEndpoint,
                        (string)$postbackSecret,
                        (string)$postbackAllowlist,
                        (string)$returnMode,
                        (string)$template,
                        (string)$postbackEnabled,
                    ]
                );
            } catch (Throwable $e) {
                if (stripos($e->getMessage(), 'epoch') !== false) {
                    $this->iN_EnsureEpochColumns();
                    DB::exec(
                        "UPDATE i_payment_methods
                         SET epoch_pi_code = ?, epoch_currency = ?, epoch_test_endpoint = ?, epoch_live_endpoint = ?, epoch_postback_secret = ?, epoch_postback_allowlist = ?, epoch_return_mode = ?, epoch_template = ?, epoch_postback_enabled = ?
                         WHERE payment_method_id = 1",
                        [
                            (string)$piCode,
                            (string)$currency,
                            (string)$testEndpoint,
                            (string)$liveEndpoint,
                            (string)$postbackSecret,
                            (string)$postbackAllowlist,
                            (string)$returnMode,
                            (string)$template,
                            (string)$postbackEnabled,
                        ]
                    );
                } else {
                    throw $e;
                }
            }
            return true;
        }
        return false;
    }

