                    "UPDATE i_payment_methods SET paysafecard_api_key = ?, paysafecard_currency = ? WHERE payment_method_id = 1",
                    [(string)$apiKey, (string)$currency]
                );
            } catch (Throwable $e) {
                if (stripos($e->getMessage(), 'paysafecard') !== false) {
                    $this->iN_EnsurePaysafecardColumns();
                    DB::exec(
                        "UPDATE i_payment_methods SET paysafecard_api_key = ?, paysafecard_currency = ? WHERE payment_method_id = 1",
                        [(string)$apiKey, (string)$currency]
                    );
                } else {
                    throw $e;
                }
            }
            return true;
        }
        return false;
    }

