	/*Insert Boost Payment*/
	    public function iN_BoostInsert($userID, $boostPostID, $planAmount,$boostPlanID,$viewTime) {
	        if($this->iN_CheckUserExist($userID) == '1'){
	            $time = time();
	            $expireDays = $this->iN_GetBoostExpireDays();
	            $endAt = $expireDays > 0 ? ($time + ($expireDays * 86400)) : null;
                $paymentId = 0;
	            try {
	                DB::begin();
	                DB::exec("INSERT INTO i_boosted_posts (iuid_fk, post_id_fk, boost_type, view_count, status, started_at, end_at) VALUES (?,?,?,?, 'yes', ?, ?)",
	                    [(int)$userID, (int)$boostPostID, (int)$boostPlanID, (int)$viewTime, $time, $endAt]
	                );
	                $row = DB::one("SELECT boost_id FROM i_boosted_posts WHERE iuid_fk = ? ORDER BY boost_id DESC LIMIT 1", [(int)$userID]);
	                $boostID = $row['boost_id'] ?? null;
	                DB::exec("INSERT INTO i_user_payments (payer_iuid_fk, payed_post_id_fk, payment_type, payment_time, payment_status, amount) VALUES (?,?, 'boostPost', ?, 'ok', ?)",
	                    [(int)$userID, (int)$boostPostID, $time, (string)$planAmount]
	                );
                    $paymentId = (int) DB::lastId();
	                DB::exec("UPDATE i_users SET wallet_points = wallet_points - ? WHERE iuid = ?", [(string)$planAmount, (int)$userID]);
	                if ($boostID) {
	                    DB::exec("UPDATE i_posts SET boosted_status = '1', boost_id_fk = ? WHERE post_id = ? AND post_owner_id = ?", [(int)$boostID, (int)$boostPostID, (int)$userID]);
	                }
	                DB::commit();
                    if ($paymentId > 0) {
                        $currency = $GLOBALS['defaultCurrency'] ?? 'USD';
                        $this->iN_AssignInvoiceToPayment($paymentId, (int)$userID, (float)$planAmount, $currency);
                    }
	                return true;
	            } catch (Throwable $e) { DB::rollBack(); return false; }

	        }
	    }

	    private function iN_GetBoostExpireDays(): int
	    {
	        $inc = $this->iN_Configurations();
	        $days = isset($inc['boost_post_expire_days']) ? (int) $inc['boost_post_expire_days'] : 30;
	        if ($days < 1) {
	            $days = 30;
	        }

	        return $days;
	    }

		    public function iN_UpdateBoostExpireDaysSetting($userID, int $days): bool
		    {
		        if ($this->iN_CheckIsAdmin($userID) != 1) {
		            return false;
		        }

	        if ($days < 1) {
	            $days = 1;
	        }

	        if ($days > 365) {
	            $days = 365;
	        }

		        try {
		            DB::exec("UPDATE i_configurations SET boost_post_expire_days = ? WHERE configuration_id = 1", [(int) $days]);
		            return true;
		        } catch (Throwable $e) {
		            return false;
		        }
		    }

