		        }
		    }

	    private function iN_AutoExpireBoostedPostsByTime(): void
	    {
	        $expireDays = $this->iN_GetBoostExpireDays();
	        $expireSeconds = $expireDays > 0 ? ($expireDays * 86400) : 0;
	        if ($expireSeconds < 1) {
	            return;
	        }

	        $now = time();

	        // Fill missing end_at for active boosts (backwards-compatible for older rows)
	        DB::exec(
	            "UPDATE i_boosted_posts
	             SET end_at = started_at + ?
	             WHERE status = 'yes'
	               AND started_at IS NOT NULL AND started_at > 0
	               AND (end_at IS NULL OR end_at = 0)",
	            [(int) $expireSeconds]
	        );

	        // Expire boosts by time
	        DB::exec(
	            "UPDATE i_boosted_posts
	             SET status = 'no'
	             WHERE status = 'yes'
	               AND end_at IS NOT NULL AND end_at > 0
	               AND end_at <= ?",
	            [(int) $now]
	        );

	        // Expire boosts by view limit (set-based, avoids stuck boosts)
	        DB::exec(
	            "UPDATE i_boosted_posts B
	             INNER JOIN (
	               SELECT bp_id_fk, COUNT(*) AS seen_count
	               FROM i_boosted_post_seen_counter
	               GROUP BY bp_id_fk
	             ) S ON S.bp_id_fk = B.boost_id
	             SET B.status = 'no'
	             WHERE B.status = 'yes'
	               AND B.view_count IS NOT NULL AND B.view_count > 0
	               AND S.seen_count >= B.view_count"
	        );

	        // Keep i_posts flags in sync for expired boosts
	        DB::exec(
	            "UPDATE i_posts P
	             INNER JOIN i_boosted_posts B ON P.boost_id_fk = B.boost_id
	             SET P.boosted_status = '0', P.boost_id_fk = '0'
	             WHERE P.boosted_status = '1' AND B.status = 'no'"
	        );
	    }

	    private function iN_CanActivateBoost(int $boostID): bool
	    {
	        $row = DB::one("SELECT boost_id, started_at, end_at, view_count FROM i_boosted_posts WHERE boost_id = ? LIMIT 1", [(int) $boostID]);
	        if (!$row) {
	            return false;
	        }

	        $now = time();
	        $startedAt = isset($row['started_at']) ? (int) $row['started_at'] : 0;
	        $endAt = isset($row['end_at']) ? (int) $row['end_at'] : 0;

	        if ($endAt < 1 && $startedAt > 0) {
	            $expireDays = $this->iN_GetBoostExpireDays();
	            $expireSeconds = $expireDays > 0 ? ($expireDays * 86400) : 0;
	            if ($expireSeconds > 0) {
	                $endAt = $startedAt + $expireSeconds;
	                DB::exec(
	                    "UPDATE i_boosted_posts SET end_at = ? WHERE boost_id = ? AND (end_at IS NULL OR end_at = 0)",
	                    [(int) $endAt, (int) $boostID]
	                );
	            }
	        }

	        if ($endAt > 0 && $endAt <= $now) {
	            return false;
	        }

	        $viewCount = isset($row['view_count']) ? (int) $row['view_count'] : 0;
	        if ($viewCount > 0) {
	            $seenCount = (int) DB::col("SELECT COUNT(*) FROM i_boosted_post_seen_counter WHERE bp_id_fk = ?", [(int) $boostID]);
	            if ($seenCount >= $viewCount) {
	                return false;
	            }
	        }

	        return true;
	    }

	    private function iN_SyncBoostAndPost(int $boostID): void
	    {
	        $row = DB::one("SELECT * FROM i_boosted_posts WHERE boost_id = ? LIMIT 1", [(int) $boostID]);
	        if (!$row) {
	            return;
	        }

	        $now = time();
	        $status = isset($row['status']) ? (string) $row['status'] : 'no';
	        $postID = isset($row['post_id_fk']) ? (int) $row['post_id_fk'] : 0;
	        $ownerID = isset($row['iuid_fk']) ? (int) $row['iuid_fk'] : 0;
	        $viewCount = isset($row['view_count']) ? (int) $row['view_count'] : 0;
	        $startedAt = isset($row['started_at']) ? (int) $row['started_at'] : 0;
	        $endAt = isset($row['end_at']) ? (int) $row['end_at'] : 0;

	        if ($endAt < 1 && $startedAt > 0) {
	            $expireDays = $this->iN_GetBoostExpireDays();
	            $expireSeconds = $expireDays > 0 ? ($expireDays * 86400) : 0;
	            if ($expireSeconds > 0) {
	                $endAt = $startedAt + $expireSeconds;
	                DB::exec(
	                    "UPDATE i_boosted_posts SET end_at = ? WHERE boost_id = ? AND (end_at IS NULL OR end_at = 0)",
	                    [(int) $endAt, (int) $boostID]
	                );
	            }
	        }

	        $seenCount = 0;
	        if ($viewCount > 0) {
	            $seenCount = (int) DB::col("SELECT COUNT(*) FROM i_boosted_post_seen_counter WHERE bp_id_fk = ?", [(int) $boostID]);
	        }

	        $expiredByTime = ($endAt > 0 && $endAt <= $now);
	        $expiredByViews = ($viewCount > 0 && $seenCount >= $viewCount);

	        if ($status === 'yes' && ($expiredByTime || $expiredByViews)) {
	            DB::exec("UPDATE i_boosted_posts SET status = 'no' WHERE boost_id = ?", [(int) $boostID]);
	            $status = 'no';
	        }

	        if ($status !== 'yes') {
	            // Keep post flags cleared for paused/expired boosts
	            DB::exec(
	                "UPDATE i_posts SET boosted_status = '0', boost_id_fk = '0' WHERE boost_id_fk = ?",
	                [(int) $boostID]
	            );
	            return;
	        }

	        // Ensure post points to the current active boost
	        if ($postID > 0 && $ownerID > 0) {
	            DB::exec(
	                "UPDATE i_posts SET boosted_status = '1', boost_id_fk = ? WHERE post_id = ? AND post_owner_id = ?",
	                [(int) $boostID, (int) $postID, (int) $ownerID]
	            );
	        }
	    }
    /*Check Post Is Currently Boosted*/
    public function iN_CheckPostBoostedBefore($userID, $postID)
    {
        if ($this->iN_CheckUserExist($userID) !== '1' || $this->iN_CheckPostIDExist($postID) !== '1') {
            return false;
        }

        $now = time();
        $expireDays = $this->iN_GetBoostExpireDays();
        $expireSeconds = $expireDays > 0 ? ($expireDays * 86400) : 0;
        $sql = "SELECT 1
                FROM i_boosted_posts B
                WHERE B.post_id_fk = ? AND B.iuid_fk = ? AND B.status = 'yes'
                  AND (
                        (B.end_at IS NOT NULL AND B.end_at > 0 AND B.end_at > ?)
                        OR (
                            (B.end_at IS NULL OR B.end_at = 0)
                            AND (? > 0)
                            AND B.started_at IS NOT NULL AND B.started_at > 0
                            AND (B.started_at + ?) > ?
                        )
                      )
                  AND (B.view_count IS NULL OR B.view_count = 0 OR B.view_count > (
                        SELECT COUNT(*) FROM i_boosted_post_seen_counter S WHERE S.bp_id_fk = B.boost_id
                      ))
                ORDER BY B.boost_id DESC
                LIMIT 1";
        return (bool) DB::col($sql, [(int) $postID, (int) $userID, (int) $now, (int) $expireSeconds, (int) $expireSeconds, (int) $now]);
    }
