    public function iN_AllUserForBoostedPosts($uid, $lastPostID, $showingPost) {
        $params = [(int)$uid];
        $morePost = '';
        [$scheduledSql, $scheduledParams] = $this->scheduledVisibilityClause((int)$uid, 'P');
        if (!empty($lastPostID)) { $morePost = ' AND P.post_id < ?'; $params[] = (int)$lastPostID; }
        $limit = (int)$showingPost;
        $sql = "SELECT P.*, U.*
                FROM i_friends F
                INNER JOIN i_posts P ON P.post_owner_id = F.fr_two
                INNER JOIN i_users U ON P.post_owner_id = U.iuid
                WHERE P.post_owner_id = ? AND P.boosted_status = '1' AND $scheduledSql $morePost
                  AND U.uStatus IN ('1','3') AND F.fr_status IN ('me')
                ORDER BY P.post_id DESC
                LIMIT $limit";
        $rows = DB::all($sql, array_merge($params, $scheduledParams));
        return !empty($rows) ? $rows : null;
    }

	/*Check boost ID Exist*/
    public function iN_CheckBoostIDExist($userID, $boostPostID){
        $exists = (bool) DB::col("SELECT 1 FROM i_boosted_posts WHERE boost_id = ? AND iuid_fk = ? LIMIT 1", [(int)$boostPostID, (int)$userID]);
        return $exists ? true : false;
    }
	/*Update Boost Post Status*/
		    public function iN_UpdateBoosPostStatus($userID, $bPostID, $bpStatus){
		        if ($this->iN_CheckUserExist($userID) !== true) {
		            return false;
		        }

		        $row = DB::one("SELECT boost_id, iuid_fk FROM i_boosted_posts WHERE boost_id = ? LIMIT 1", [(int)$bPostID]);
		        if (!$row) {
		            return false;
		        }

		        $isOwner = ((int)($row['iuid_fk'] ?? 0) === (int)$userID);
		        $isAdmin = ($this->iN_CheckIsAdmin($userID) == 1);
		        if (!$isOwner && !$isAdmin) {
		            return false;
		        }

		        $bpStatus = ($bpStatus === 'yes') ? 'yes' : 'no';
		        if ($bpStatus === 'yes' && !$this->iN_CanActivateBoost((int) $bPostID)) {
		            $this->iN_SyncBoostAndPost((int) $bPostID);
		            return false;
		        }

		        DB::exec(
		            "UPDATE i_boosted_posts SET status = ? WHERE boost_id = ?",
		            [(string) $bpStatus, (int) $bPostID]
		        );
		        $this->iN_SyncBoostAndPost((int) $bPostID);
		        return true;
		    }
    /*Check Boosted Post Seen Before*/
    public function iN_CheckBoostedPostSeenBefore($userID, $ip, $boostID){
        $exists = (bool) DB::col("SELECT 1 FROM i_boosted_post_seen_counter WHERE bp_id_fk = ? AND iuid_fk = ? AND ip = ? LIMIT 1", [(int)$boostID, (int)$userID, (string)$ip]);
        return $exists ? false : true;
    }
	/*Boost Seen Counter*/
	    public function iN_BoostPostSeenCounter($userID, $boostID, $ip){
	        if(!is_numeric($boostID) || empty($boostID)){
	            return false;
	        }

	        if ($this->iN_CheckuserExist($userID) == '1' && $this->iN_CheckBoostedPostSeenBefore($userID, $ip, $boostID) == '1') {
	            $boostRow = DB::one("SELECT status FROM i_boosted_posts WHERE boost_id = ? LIMIT 1", [(int) $boostID]);
	            if (!$boostRow || (string) ($boostRow['status'] ?? 'no') !== 'yes') {
	                $this->iN_SyncBoostAndPost((int) $boostID);
	                return false;
	            }
	            if (!$this->iN_CanActivateBoost((int) $boostID)) {
	                $this->iN_SyncBoostAndPost((int) $boostID);
	                return false;
	            }

	            $time = time();
	            DB::exec("INSERT INTO i_boosted_post_seen_counter (iuid_fk, bp_id_fk, ip, bp_seen_time) VALUES (?,?,?,?)", [(int)$userID, (int)$boostID, (string)$ip, $time]);
	            $this->iN_SyncBoostAndPost((int) $boostID);
	            return true;
	        }else{
	            return false;
	        }
	    }
	/*Show Boosted Post*/
		    public function iN_ShowBoostedPost($userID, $showingPost) {
		        $this->iN_AutoExpireBoostedPostsByTime();
		        // Soft-sync: ensure active boosts point to their posts (prevents missing boosted_status flags)
		        DB::exec(
		            "UPDATE i_posts P
		             INNER JOIN i_boosted_posts B ON P.post_id = B.post_id_fk
		             SET P.boosted_status = '1', P.boost_id_fk = B.boost_id
		             WHERE B.status = 'yes'
		               AND P.post_owner_id = B.iuid_fk
		               AND (P.boosted_status <> '1' OR P.boost_id_fk <> B.boost_id)"
		        );
		        $now = time();
		        $sql = "SELECT P.*, U.*, B.*
		                FROM i_posts P
		                INNER JOIN i_users U ON P.post_owner_id = U.iuid
		                INNER JOIN i_boosted_posts B
		                  ON P.boost_id_fk = B.boost_id
		                 AND B.status = 'yes'
		                 AND (B.end_at IS NULL OR B.end_at = 0 OR B.end_at > ?)
		                 AND (B.view_count IS NULL OR B.view_count = 0 OR B.view_count > (
		                       SELECT COUNT(*) FROM i_boosted_post_seen_counter S WHERE S.bp_id_fk = B.boost_id
		                     ))
		                WHERE P.boosted_status = '1'
		                  AND P.post_owner_id <> ?
		                  AND U.uStatus IN ('1','3')
		                ORDER BY RAND()
		                LIMIT 1";
		        $rows = DB::all($sql, [(int) $now, (int) $userID]);
		        if (empty($rows)) {
		            // Fallback: try deterministic latest boost if random returns empty (safety net)
		            $sql = "SELECT P.*, U.*, B.*
		                    FROM i_posts P
		                    INNER JOIN i_users U ON P.post_owner_id = U.iuid
		                    INNER JOIN i_boosted_posts B
		                      ON P.boost_id_fk = B.boost_id
		                     AND B.status = 'yes'
		                     AND (B.end_at IS NULL OR B.end_at = 0 OR B.end_at > ?)
		                     AND (B.view_count IS NULL OR B.view_count = 0 OR B.view_count > (
		                           SELECT COUNT(*) FROM i_boosted_post_seen_counter S WHERE S.bp_id_fk = B.boost_id
		                         ))
		                    WHERE P.boosted_status = '1'
		                      AND P.post_owner_id <> ?
		                      AND U.uStatus IN ('1','3')
		                    ORDER BY B.boost_id DESC
		                    LIMIT 1";
		            $rows = DB::all($sql, [(int) $now, (int) $userID]);
		        }
		        return !empty($rows) ? $rows : null;
		    }
		/*Show Boosted Post (force fallback, no friend filter)*/
		    public function iN_ShowBoostedPostFallback($userID = 0) {
		        $this->iN_AutoExpireBoostedPostsByTime();
		        DB::exec(
		            "UPDATE i_posts P
		             INNER JOIN i_boosted_posts B ON P.post_id = B.post_id_fk
		             SET P.boosted_status = '1', P.boost_id_fk = B.boost_id
		             WHERE B.status = 'yes'
		               AND P.post_owner_id = B.iuid_fk
		               AND (P.boosted_status <> '1' OR P.boost_id_fk <> B.boost_id)"
		        );
		        $now = time();
		        $sql = "SELECT P.*, U.*, B.*
		                FROM i_posts P
		                INNER JOIN i_users U ON P.post_owner_id = U.iuid
		                INNER JOIN i_boosted_posts B
		                  ON P.boost_id_fk = B.boost_id
		                 AND B.status = 'yes'
		                 AND (B.end_at IS NULL OR B.end_at = 0 OR B.end_at > ?)
		                     AND (B.view_count IS NULL OR B.view_count = 0 OR B.view_count > (
		                       SELECT COUNT(*) FROM i_boosted_post_seen_counter S WHERE S.bp_id_fk = B.boost_id
		                     ))
		                WHERE P.boosted_status = '1'
		                  AND U.uStatus IN ('1','3')"
		                . ($userID ? " AND P.post_owner_id <> ?" : "") . "
		                ORDER BY B.boost_id DESC
		                LIMIT 1";
		        $params = $userID ? [(int) $now, (int) $userID] : [(int) $now];
		        $rows = DB::all($sql, $params);
		        if (empty($rows) || !is_array($rows)) {
		            return null;
		        }
		        // Ensure numeric array of rows
		        if (isset($rows['post_id'])) {
		            return [$rows];
		        }
		        return $rows;
		    }
