		/*Total Boost Records (Admin)*/
	    public function iN_TotalBoostedPost($userID, $filter = 'all', $search = '')
	    {
	        if ($this->iN_CheckIsAdmin($userID) != 1) {
	            return '0';
	        }

	        $this->iN_AutoExpireBoostedPostsByTime();

	        $filter = (string) $filter;
	        $allowedFilters = ['all', 'active', 'passive', 'orphan'];
	        if (!in_array($filter, $allowedFilters, true)) {
	            $filter = 'all';
	        }

	        $search = trim((string) $search);
	        $numericSearch = (ctype_digit($search) ? (int) $search : null);

	        if ($filter === 'orphan') {
	            $where = "WHERE P.boosted_status = '1'
	                      AND (P.boost_id_fk IS NULL OR P.boost_id_fk = 0 OR B.boost_id IS NULL OR B.status <> 'yes')";
	            $params = [];
	            if ($search !== '') {
	                $where .= " AND (U.i_username LIKE ? OR U.i_user_fullname LIKE ?"
	                    . ($numericSearch !== null ? " OR P.post_id = ? OR P.boost_id_fk = ?" : "")
	                    . ")";
	                $params[] = '%' . $search . '%';
	                $params[] = '%' . $search . '%';
	                if ($numericSearch !== null) {
	                    $params[] = $numericSearch;
	                    $params[] = $numericSearch;
	                }
	            }
	            $sql = "SELECT COUNT(*)
	                    FROM i_posts P
	                    INNER JOIN i_users U ON P.post_owner_id = U.iuid AND U.uStatus IN('1','3')
	                    LEFT JOIN i_boosted_posts B ON P.boost_id_fk = B.boost_id
	                    $where";
	            $val = DB::col($sql, $params);
	            return $val !== false ? $val : '0';
	        }

	        $where = "WHERE EXISTS (SELECT 1 FROM i_posts WHERE post_id = B.post_id_fk)";
	        $params = [];
	        if ($filter === 'active') {
	            $where .= " AND B.status = 'yes'";
	        } elseif ($filter === 'passive') {
	            $where .= " AND B.status = 'no'";
	        }

	        if ($search !== '') {
	            $where .= " AND (U.i_username LIKE ? OR U.i_user_fullname LIKE ?"
	                . ($numericSearch !== null ? " OR B.boost_id = ? OR B.post_id_fk = ?" : "")
	                . ")";
	            $params[] = '%' . $search . '%';
	            $params[] = '%' . $search . '%';
	            if ($numericSearch !== null) {
	                $params[] = $numericSearch;
	                $params[] = $numericSearch;
	            }
	        }

	        $sql = "SELECT COUNT(*)
	                FROM i_boosted_posts B
	                INNER JOIN i_users U ON B.iuid_fk = U.iuid AND U.uStatus IN('1','3')
	                $where";
	        $val = DB::col($sql, $params);
	        return $val !== false ? $val : '0';
	    }
