		/*Show Boost Records (Admin)*/
	    public function iN_ShowAllBoostedPost($userID, $paginationLimit, $page, $filter = 'all', $search = '')
	    {
	        if ($this->iN_CheckIsAdmin($userID) != 1) {
	            return null;
	        }

	        $this->iN_AutoExpireBoostedPostsByTime();

	        $startFrom = ((int) $page - 1) * (int) $paginationLimit;
	        $limit = (int) $paginationLimit;

	        $filter = (string) $filter;
	        $allowedFilters = ['all', 'active', 'passive', 'orphan'];
	        if (!in_array($filter, $allowedFilters, true)) {
	            $filter = 'all';
	        }

	        $search = trim((string) $search);
	        $numericSearch = (ctype_digit($search) ? (int) $search : null);

	        if ($filter === 'orphan') {
	            $where = "WHERE P.boosted_status = '1'
	                      AND (P.boost_id_fk IS NULL OR P.boost_id_fk = 0 OR B.boost_id IS NULL OR B.status <> 'yes')";
	            $params = [];
	            if ($search !== '') {
	                $where .= " AND (U.i_username LIKE ? OR U.i_user_fullname LIKE ?"
	                    . ($numericSearch !== null ? " OR P.post_id = ? OR P.boost_id_fk = ?" : "")
	                    . ")";
	                $params[] = '%' . $search . '%';
	                $params[] = '%' . $search . '%';
	                if ($numericSearch !== null) {
	                    $params[] = $numericSearch;
	                    $params[] = $numericSearch;
	                }
	            }
	            $sql = "SELECT P.*, U.*, B.*, COUNT(S.bp_seen_id) AS seen_count
	                    FROM i_posts P
	                    INNER JOIN i_users U ON P.post_owner_id = U.iuid AND U.uStatus IN('1','3')
	                    LEFT JOIN i_boosted_posts B ON P.boost_id_fk = B.boost_id
	                    LEFT JOIN i_boosted_post_seen_counter S ON S.bp_id_fk = B.boost_id
	                    $where
	                    GROUP BY P.post_id
	                    ORDER BY P.post_id DESC
	                    LIMIT $startFrom, $limit";
	            $rows = DB::all($sql, $params);
	            return !empty($rows) ? $rows : null;
	        }

	        $where = "WHERE EXISTS (SELECT 1 FROM i_posts WHERE post_id = B.post_id_fk)";
	        $params = [];
	        if ($filter === 'active') {
	            $where .= " AND B.status = 'yes'";
	        } elseif ($filter === 'passive') {
	            $where .= " AND B.status = 'no'";
	        }
	        if ($search !== '') {
	            $where .= " AND (U.i_username LIKE ? OR U.i_user_fullname LIKE ?"
	                . ($numericSearch !== null ? " OR B.boost_id = ? OR B.post_id_fk = ?" : "")
	                . ")";
	            $params[] = '%' . $search . '%';
	            $params[] = '%' . $search . '%';
	            if ($numericSearch !== null) {
	                $params[] = $numericSearch;
	                $params[] = $numericSearch;
	            }
	        }

	        $sql = "SELECT B.*, P.url_slug, P.post_owner_id, P.post_id, P.boosted_status AS post_boosted_status,
	                       P.boost_id_fk AS post_boost_id_fk, U.i_username, U.i_user_fullname,
	                       COUNT(S.bp_seen_id) AS seen_count
	                FROM i_boosted_posts B
	                INNER JOIN i_posts P ON P.post_id = B.post_id_fk
	                INNER JOIN i_users U ON B.iuid_fk = U.iuid AND U.uStatus IN('1','3')
	                LEFT JOIN i_boosted_post_seen_counter S ON S.bp_id_fk = B.boost_id
	                $where
	                GROUP BY B.boost_id
	                ORDER BY B.boost_id DESC
	                LIMIT $startFrom, $limit";
	        $rows = DB::all($sql, $params);
	        return !empty($rows) ? $rows : null;
	    }

	    /**
	     * @return array|false
	     */
	    public function iN_AdminCleanupBoostedPosts($userID)
	    {
	        if ($this->iN_CheckIsAdmin($userID) != 1) {
	            return false;
	        }

	        $expireDays = $this->iN_GetBoostExpireDays();
	        $expireSeconds = $expireDays > 0 ? ($expireDays * 86400) : 0;
	        $now = time();

	        try {
	            DB::begin();

	            $filledEndAt = 0;
	            if ($expireSeconds > 0) {
	                $filledEndAt = DB::exec(
	                    "UPDATE i_boosted_posts
	                     SET end_at = started_at + ?
	                     WHERE started_at IS NOT NULL AND started_at > 0
	                       AND (end_at IS NULL OR end_at = 0)",
	                    [(int) $expireSeconds]
	                );
	            }

	            $expiredByTime = DB::exec(
	                "UPDATE i_boosted_posts
	                 SET status = 'no'
	                 WHERE status = 'yes'
	                   AND end_at IS NOT NULL AND end_at > 0
	                   AND end_at <= ?",
	                [(int) $now]
	            );

	            $expiredByViews = DB::exec(
	                "UPDATE i_boosted_posts B
	                 INNER JOIN (
	                   SELECT bp_id_fk, COUNT(*) AS seen_count
	                   FROM i_boosted_post_seen_counter
	                   GROUP BY bp_id_fk
	                 ) S ON S.bp_id_fk = B.boost_id
	                 SET B.status = 'no'
	                 WHERE B.status = 'yes'
	                   AND B.view_count IS NOT NULL AND B.view_count > 0
	                   AND S.seen_count >= B.view_count"
	            );

	            $clearedOrphanPosts = DB::exec(
	                "UPDATE i_posts P
	                 LEFT JOIN i_boosted_posts B ON P.boost_id_fk = B.boost_id
	                 SET P.boosted_status = '0', P.boost_id_fk = '0'
	                 WHERE P.boosted_status = '1'
	                   AND (P.boost_id_fk IS NULL OR P.boost_id_fk = 0 OR B.boost_id IS NULL OR B.status <> 'yes')"
	            );

	            $linkedActiveBoosts = DB::exec(
	                "UPDATE i_posts P
	                 INNER JOIN i_boosted_posts B ON P.post_id = B.post_id_fk
	                 SET P.boosted_status = '1', P.boost_id_fk = B.boost_id
	                 WHERE B.status = 'yes'
	                   AND P.post_owner_id = B.iuid_fk
	                   AND (P.boost_id_fk IS NULL OR P.boost_id_fk = 0 OR P.boosted_status <> '1')"
	            );

	            DB::commit();

	            return [
	                'filled_end_at' => $filledEndAt,
	                'expired_by_time' => $expiredByTime,
	                'expired_by_views' => $expiredByViews,
	                'cleared_orphan_posts' => $clearedOrphanPosts,
	                'linked_active_boosts' => $linkedActiveBoosts,
	            ];
	        } catch (Throwable $e) {
	            DB::rollBack();
	            return false;
	        }
	    }
