	/*Delete Boosted Post*/
	    public function iN_DeleteBoostedPost($userID, $boostID){
	        if ($this->iN_CheckIsAdmin($userID) == 1) {
	            $bData = $this->iN_GetBoostedDetailsByID($boostID);
	            if (!$bData) {
	                return false;
	            }

	            $boostedPostID = isset($bData['post_id_fk']) ? (int) $bData['post_id_fk'] : 0;
	            $boostOwnerID = isset($bData['iuid_fk']) ? (int) $bData['iuid_fk'] : 0;

	            DB::exec("UPDATE i_posts SET boosted_status = '0', boost_id_fk = '0' WHERE boost_id_fk = ?", [(int) $boostID]);
	            DB::exec("DELETE FROM i_boosted_posts WHERE boost_id = ?", [(int) $boostID]);
	            if ($boostedPostID > 0) {
	                DB::exec(
	                    "DELETE FROM i_user_payments WHERE payed_post_id_fk = ? AND payer_iuid_fk = ? AND payment_type = 'boostPost'",
	                    [(int) $boostedPostID, (int) $boostOwnerID]
	                );
	            }
	            return true;
	        } else {
	            return false;
	        }
	    }
