	/*Community Subscriptions List (Admin)*/
    public function iN_CommunitySubscriptionsListData($userID, $paginationLimit, $page, $scope = 'all', $status = 'all', $dateFrom = '', $dateTo = '') {
        $start_from = ((int)$page - 1) * (int)$paginationLimit;
        if ($this->iN_CheckIsAdmin($userID) != 1) {
            return null;
        }
        $limit = (int)$paginationLimit;
        $scope = strtolower(trim((string)$scope));
        if (!in_array($scope, ['all', 'community', 'community_plan'], true)) {
            $scope = 'all';
        }
        $status = strtolower(trim((string)$status));
        if (!in_array($status, ['all', 'active', 'inactive', 'declined', 'pending'], true)) {
            $status = 'all';
        }
        $normalizeDate = static function ($dateValue): string {
            $dateValue = trim((string)$dateValue);
            if ($dateValue === '' || !preg_match('/^(\d{4})-(\d{2})-(\d{2})$/', $dateValue, $m)) {
                return '';
            }
            if (!checkdate((int)$m[2], (int)$m[3], (int)$m[1])) {
                return '';
            }
            return $dateValue;
        };
        $dateFrom = $normalizeDate($dateFrom);
        $dateTo = $normalizeDate($dateTo);

        $communitySelect = "NULL AS community_title, NULL AS community_slug";
        $communityJoin = '';
        if ($this->iN_TableExists('communities')) {
            $communitySelect = "C.title AS community_title, C.slug AS community_slug";
            $communityJoin = "LEFT JOIN communities C ON S.subscription_scope = 'community' AND S.subscription_ref_id = C.id";
        }

        $where = [];
        $params = [];
        if ($scope === 'all') {
            $where[] = "S.subscription_scope IN('community','community_plan')";
        } else {
            $where[] = "S.subscription_scope = ?";
            $params[] = $scope;
        }
        if ($status !== 'all') {
            $where[] = "S.status = ?";
            $params[] = $status;
        }
        if ($dateFrom !== '') {
            $where[] = "S.created >= ?";
            $params[] = $dateFrom . ' 00:00:00';
        }
        if ($dateTo !== '') {
            $where[] = "S.created <= ?";
            $params[] = $dateTo . ' 23:59:59';
        }

        $sql = "SELECT S.*,
                       SU.i_username AS subscriber_username,
                       SU.i_user_fullname AS subscriber_fullname,
                       OU.i_username AS owner_username,
                       OU.i_user_fullname AS owner_fullname,
                       {$communitySelect}
                FROM i_user_subscriptions S
                LEFT JOIN i_users SU ON SU.iuid = S.iuid_fk
                LEFT JOIN i_users OU ON OU.iuid = S.subscribed_iuid_fk
                {$communityJoin}";
        if (!empty($where)) {
            $sql .= " WHERE " . implode(' AND ', $where);
        }
        $sql .= " ORDER BY S.subscription_id DESC LIMIT $start_from, $limit";
        $rows = DB::all($sql, $params);
        return !empty($rows) ? $rows : null;
    }
	/*Total Community Subscription Payments*/
    public function iN_TotalCommunitySubscriptionPayments($userID, $scope = 'all', $status = 'all', $dateFrom = '', $dateTo = '') {
        if ($this->iN_CheckIsAdmin($userID) != 1) {
            return '0';
        }
        $scope = strtolower(trim((string)$scope));
        if (!in_array($scope, ['all', 'community', 'community_plan'], true)) {
            $scope = 'all';
        }
        $status = strtolower(trim((string)$status));
        if (!in_array($status, ['all', 'ok', 'pending', 'declined'], true)) {
            $status = 'all';
        }
        $normalizeDate = static function ($dateValue): string {
            $dateValue = trim((string)$dateValue);
            if ($dateValue === '' || !preg_match('/^(\d{4})-(\d{2})-(\d{2})$/', $dateValue, $m)) {
                return '';
            }
            if (!checkdate((int)$m[2], (int)$m[3], (int)$m[1])) {
                return '';
            }
            return $dateValue;
        };
        $dateFrom = $normalizeDate($dateFrom);
        $dateTo = $normalizeDate($dateTo);
        $fromTs = $dateFrom !== '' ? strtotime($dateFrom . ' 00:00:00') : false;
        $toTs = $dateTo !== '' ? strtotime($dateTo . ' 23:59:59') : false;
        if ($fromTs !== false && $toTs !== false && $fromTs > $toTs) {
            $swap = $fromTs;
            $fromTs = $toTs;
            $toTs = $swap;
        }

        $where = ["P.payment_type = 'subscription'"];
        $params = [];
        $hasPaymentScope = $this->tableColumnExists('i_user_payments', 'subscription_scope');

        if ($hasPaymentScope) {
            if ($scope === 'all') {
                $where[] = "P.subscription_scope IN('community','community_plan')";
            } else {
                $where[] = "P.subscription_scope = ?";
                $params[] = $scope;
            }
        } else {
            $scopeWhereAll = "(P.order_key LIKE 'community_sub_%'
                               OR P.order_key LIKE 'community_plan_%'
                               OR EXISTS (
                                    SELECT 1 FROM i_user_subscriptions S
                                    WHERE S.iuid_fk = P.payer_iuid_fk
                                      AND S.subscribed_iuid_fk = P.payed_iuid_fk
                                      AND S.subscription_scope IN('community','community_plan')
                                    LIMIT 1
                               ))";
            $scopeWhereCommunity = "(P.order_key LIKE 'community_sub_%'
                                     OR EXISTS (
                                         SELECT 1 FROM i_user_subscriptions S
                                         WHERE S.iuid_fk = P.payer_iuid_fk
                                           AND S.subscribed_iuid_fk = P.payed_iuid_fk
                                           AND S.subscription_scope = 'community'
                                         LIMIT 1
                                     ))";
            $scopeWhereCommunityPlan = "(P.order_key LIKE 'community_plan_%'
                                         OR EXISTS (
                                             SELECT 1 FROM i_user_subscriptions S
                                             WHERE S.iuid_fk = P.payer_iuid_fk
                                               AND S.subscribed_iuid_fk = P.payed_iuid_fk
                                               AND S.subscription_scope = 'community_plan'
                                             LIMIT 1
                                         ))";
            if ($scope === 'community') {
                $where[] = $scopeWhereCommunity;
            } elseif ($scope === 'community_plan') {
                $where[] = $scopeWhereCommunityPlan;
            } else {
                $where[] = $scopeWhereAll;
            }
        }

        if ($status !== 'all') {
            $where[] = "P.payment_status = ?";
            $params[] = $status;
        }
        if ($fromTs !== false) {
            $where[] = "P.payment_time >= ?";
            $params[] = (int)$fromTs;
        }
        if ($toTs !== false) {
            $where[] = "P.payment_time <= ?";
            $params[] = (int)$toTs;
        }

        $sql = "SELECT COUNT(*) FROM i_user_payments P";
        if (!empty($where)) {
            $sql .= " WHERE " . implode(' AND ', $where);
        }
        $val = DB::col($sql, $params);
        return $val !== false ? $val : '0';
    }
	/*Calculate Community Subscription Payments By Status*/
    public function iN_CalculateCommunitySubscriptionPaymentsByStatus($userID, $status, $scope = 'all', $dateFrom = '', $dateTo = '') {
        return $this->iN_TotalCommunitySubscriptionPayments($userID, $scope, (string)$status, $dateFrom, $dateTo);
    }
	/*Community Subscription Payments List (Admin)*/
    public function iN_CommunitySubscriptionPaymentsList($userID, $paginationLimit, $page, $scope = 'all', $status = 'all', $dateFrom = '', $dateTo = '') {
        $start_from = ((int)$page - 1) * (int)$paginationLimit;
        if ($this->iN_CheckIsAdmin($userID) != 1) {
            return null;
        }
        $limit = (int)$paginationLimit;
        $scope = strtolower(trim((string)$scope));
        if (!in_array($scope, ['all', 'community', 'community_plan'], true)) {
            $scope = 'all';
        }
        $status = strtolower(trim((string)$status));
        if (!in_array($status, ['all', 'ok', 'pending', 'declined'], true)) {
            $status = 'all';
        }
        $normalizeDate = static function ($dateValue): string {
            $dateValue = trim((string)$dateValue);
            if ($dateValue === '' || !preg_match('/^(\d{4})-(\d{2})-(\d{2})$/', $dateValue, $m)) {
                return '';
            }
            if (!checkdate((int)$m[2], (int)$m[3], (int)$m[1])) {
                return '';
            }
            return $dateValue;
        };
        $dateFrom = $normalizeDate($dateFrom);
        $dateTo = $normalizeDate($dateTo);
        $fromTs = $dateFrom !== '' ? strtotime($dateFrom . ' 00:00:00') : false;
        $toTs = $dateTo !== '' ? strtotime($dateTo . ' 23:59:59') : false;
        if ($fromTs !== false && $toTs !== false && $fromTs > $toTs) {
            $swap = $fromTs;
            $fromTs = $toTs;
            $toTs = $swap;
        }

        $hasPaymentScope = $this->tableColumnExists('i_user_payments', 'subscription_scope');
        $hasPaymentScopeRef = $this->tableColumnExists('i_user_payments', 'subscription_ref_id');

        if ($hasPaymentScope) {
            $resolvedScope = "P.subscription_scope AS resolved_subscription_scope";
        } else {
            $resolvedScope = "CASE
                                WHEN P.order_key LIKE 'community_plan_%' THEN 'community_plan'
                                WHEN P.order_key LIKE 'community_sub_%' THEN 'community'
                                ELSE (
                                    SELECT S.subscription_scope
                                    FROM i_user_subscriptions S
                                    WHERE S.iuid_fk = P.payer_iuid_fk
                                      AND S.subscribed_iuid_fk = P.payed_iuid_fk
                                      AND S.subscription_scope IN('community','community_plan')
                                    ORDER BY S.subscription_id DESC
                                    LIMIT 1
                                )
                              END AS resolved_subscription_scope";
        }

        if ($hasPaymentScopeRef) {
            $resolvedScopeRef = "P.subscription_ref_id AS resolved_subscription_ref_id";
        } else {
            $resolvedScopeRef = "(SELECT S.subscription_ref_id
                                  FROM i_user_subscriptions S
                                  WHERE S.iuid_fk = P.payer_iuid_fk
                                    AND S.subscribed_iuid_fk = P.payed_iuid_fk
                                    AND S.subscription_scope IN('community','community_plan')
                                  ORDER BY S.subscription_id DESC
                                  LIMIT 1) AS resolved_subscription_ref_id";
        }

        $where = ["P.payment_type = 'subscription'"];
        $params = [];
        if ($hasPaymentScope) {
            if ($scope === 'all') {
                $where[] = "P.subscription_scope IN('community','community_plan')";
            } else {
                $where[] = "P.subscription_scope = ?";
                $params[] = $scope;
            }
        } else {
            $scopeWhereAll = "(P.order_key LIKE 'community_sub_%'
                               OR P.order_key LIKE 'community_plan_%'
                               OR EXISTS (
                                    SELECT 1 FROM i_user_subscriptions S
                                    WHERE S.iuid_fk = P.payer_iuid_fk
                                      AND S.subscribed_iuid_fk = P.payed_iuid_fk
                                      AND S.subscription_scope IN('community','community_plan')
                                    LIMIT 1
                               ))";
            $scopeWhereCommunity = "(P.order_key LIKE 'community_sub_%'
                                     OR EXISTS (
                                         SELECT 1 FROM i_user_subscriptions S
                                         WHERE S.iuid_fk = P.payer_iuid_fk
                                           AND S.subscribed_iuid_fk = P.payed_iuid_fk
                                           AND S.subscription_scope = 'community'
                                         LIMIT 1
                                     ))";
            $scopeWhereCommunityPlan = "(P.order_key LIKE 'community_plan_%'
                                         OR EXISTS (
                                             SELECT 1 FROM i_user_subscriptions S
                                             WHERE S.iuid_fk = P.payer_iuid_fk
                                               AND S.subscribed_iuid_fk = P.payed_iuid_fk
                                               AND S.subscription_scope = 'community_plan'
                                             LIMIT 1
                                         ))";
            if ($scope === 'community') {
                $where[] = $scopeWhereCommunity;
            } elseif ($scope === 'community_plan') {
                $where[] = $scopeWhereCommunityPlan;
            } else {
                $where[] = $scopeWhereAll;
            }
        }
        if ($status !== 'all') {
            $where[] = "P.payment_status = ?";
            $params[] = $status;
        }
        if ($fromTs !== false) {
            $where[] = "P.payment_time >= ?";
            $params[] = (int)$fromTs;
        }
        if ($toTs !== false) {
            $where[] = "P.payment_time <= ?";
            $params[] = (int)$toTs;
        }

        $sql = "SELECT P.*,
                       {$resolvedScope},
                       {$resolvedScopeRef},
                       PU.i_username AS payer_username,
                       PU.i_user_fullname AS payer_fullname,
                       UU.i_username AS payed_username,
                       UU.i_user_fullname AS payed_fullname
                FROM i_user_payments P
                LEFT JOIN i_users PU ON PU.iuid = P.payer_iuid_fk
                LEFT JOIN i_users UU ON UU.iuid = P.payed_iuid_fk";
        if (!empty($where)) {
            $sql .= " WHERE " . implode(' AND ', $where);
        }
        $sql .= " ORDER BY P.payment_id DESC LIMIT $start_from, $limit";
        $rows = DB::all($sql, $params);
        return !empty($rows) ? $rows : null;
    }
