    /*Campaign Donations Total*/
    public function iN_UserTotalCampaignDonations($userID, $search = '', $dateFrom = '', $dateTo = '') {
        if ($this->iN_CheckIsAdmin($userID) == 1) {
            $search = trim((string)$search);
            $dateFrom = trim((string)$dateFrom);
            $dateTo = trim((string)$dateTo);
            $where = [
                "P.payment_type = 'campaign_donate'",
                "P.payment_status = 'ok'",
            ];
            $params = [];

            if ($search !== '') {
                $searchLike = '%' . $search . '%';
                if (ctype_digit($search)) {
                    $searchID = (int)$search;
                    $where[] = "(P.payment_id = ? OR C.campaign_id = ? OR P.payed_post_id_fk = ? OR C.title LIKE ?)";
                    $params[] = $searchID;
                    $params[] = $searchID;
                    $params[] = $searchID;
                    $params[] = $searchLike;
                } else {
                    $where[] = "C.title LIKE ?";
                    $params[] = $searchLike;
                }
            }

            $fromTimestamp = null;
            $toTimestamp = null;

            if ($dateFrom !== '' && preg_match('/^\d{4}-\d{2}-\d{2}$/', $dateFrom)) {
                $fromTs = strtotime($dateFrom . ' 00:00:00');
                if ($fromTs !== false) {
                    $fromTimestamp = (int)$fromTs;
                }
            }
            if ($dateTo !== '' && preg_match('/^\d{4}-\d{2}-\d{2}$/', $dateTo)) {
                $toTs = strtotime($dateTo . ' 23:59:59');
                if ($toTs !== false) {
                    $toTimestamp = (int)$toTs;
                }
            }
            if ($fromTimestamp !== null && $toTimestamp !== null && $fromTimestamp > $toTimestamp) {
                $tmpTimestamp = $fromTimestamp;
                $fromTimestamp = $toTimestamp;
                $toTimestamp = $tmpTimestamp;
            }
            if ($fromTimestamp !== null) {
                $where[] = "P.payment_time >= ?";
                $params[] = $fromTimestamp;
            }
            if ($toTimestamp !== null) {
                $where[] = "P.payment_time <= ?";
                $params[] = $toTimestamp;
            }

            $sql = "SELECT COUNT(DISTINCT P.payment_id)
                    FROM i_user_payments P FORCE INDEX(ixPayment)
                    LEFT JOIN i_campaigns C
                      ON C.post_id_fk = P.payed_post_id_fk
                    WHERE " . implode(' AND ', $where);
            $val = DB::col($sql, $params);
            return $val !== false ? $val : '0';
        }
    }
