                    FROM i_user_payments P FORCE INDEX(ixPayment)
                    INNER JOIN i_users PU FORCE INDEX(ixForceUser)
                      ON P.payer_iuid_fk = PU.iuid AND PU.uStatus IN('1','3')
                    LEFT JOIN i_campaigns C
                      ON C.post_id_fk = P.payed_post_id_fk
                    LEFT JOIN i_users OU FORCE INDEX(ixForceUser)
                      ON OU.iuid = IFNULL(C.owner_uid_fk, P.payed_iuid_fk) AND OU.uStatus IN('1','3')
                    WHERE " . implode(' AND ', $where) . "
                    ORDER BY P.payment_id DESC
                    LIMIT $start_from, $limit";
