	/*Get Image By ID*/
public function iN_GetImageByID($base_url, $userID , $ImageID){
        if($this->iN_CheckIsAdmin($userID) == 1){
            $data = DB::one("SELECT uploaded_file_path FROM i_user_uploads WHERE upload_id = ?", [(int)$ImageID]);
            if($data){
                $imageFile = $data['uploaded_file_path'] ?? null;
                if ($imageFile && function_exists('storage_public_url')) {
                    return storage_public_url((string) $imageFile);
                }
                $s3 = DB::one("SELECT s3_status, was_status, ocean_status, s3_bucket, s3_region, was_bucket, was_region, ocean_space_name, ocean_region FROM i_configurations WHERE configuration_id = 1");
                $s3Status = $s3['s3_status'] ?? '0';
                $wasStatus = $s3['was_status'] ?? '0';
                $oceanStatus = $s3['ocean_status'] ?? '0';
                if ($s3Status == 1) {
                    return 'https://' . $s3['s3_bucket'] . '.s3.' . $s3['s3_region'] . '.amazonaws.com/' . $imageFile;
                }else if($wasStatus == 1){
                    return 'https://' . $s3['was_bucket'] . '.s3.' . $s3['was_region'] . '.wasabisys.com/' . $imageFile;
                }else if($oceanStatus == 1){
                    return 'https://'.$s3['ocean_space_name'].'.'.$s3['ocean_region'].'.digitaloceanspaces.com/'. $imageFile;
                } else {
                    return $base_url . $imageFile;
                }
            }
        }
        }
	/*Approve PAYMENT*/
    public function iN_InsertApprove($userID, $payerID, $planID, $imageID,$paymentIDD){
        if($this->iN_CheckIsAdmin($userID) == 1 && $this->iN_CheckUserExist($userID) == 1){
            $paymentRow = DB::one(
                "SELECT payment_id, payment_type, agency_id_fk, payed_profile_id_fk, payed_iuid_fk, agency_boost_duration_days, amount
                 FROM i_user_payments
                 WHERE payment_id = ? AND payer_iuid_fk = ? AND bank_payment_image = ? LIMIT 1",
                [(int)$paymentIDD, (int)$payerID, (int)$imageID]
            );
            if ($paymentRow && ($paymentRow['payment_type'] ?? '') === 'agency_boost') {
                $agencyId = (int) ($paymentRow['agency_id_fk'] ?? 0);
                $creatorId = (int) ($paymentRow['payed_profile_id_fk'] ?? ($paymentRow['payed_iuid_fk'] ?? 0));
                $durationDays = (int) ($paymentRow['agency_boost_duration_days'] ?? 0);
                if ($durationDays < 1 || $durationDays > 365) {
                    $durationDays = (int) $this->iN_GetSetting('agency_boost_default_days', 7);
                    if ($durationDays < 1) {
                        $durationDays = 1;
                    }
                    if ($durationDays > 365) {
                        $durationDays = 365;
                    }
                }
                $amount = isset($paymentRow['amount']) ? (float) $paymentRow['amount'] : 0.0;
                $amountString = number_format($amount, 2, '.', '');
                try {
                    DB::begin();
                    DB::exec("UPDATE i_bank_payments SET request_status = 'yes' WHERE iuid_fk = ? AND screen_photo = ?", [(int)$payerID, (int)$imageID]);
                    $updated = DB::exec(
                        "UPDATE i_user_payments SET payment_status = 'ok', fee = '0', agency_fee = '0', admin_earning = ?, agency_earning = '0', user_earning = '0' WHERE payment_id = ? AND payer_iuid_fk = ? AND bank_payment_image = ?",
                        [$amountString, (int)$paymentIDD, (int)$payerID, (int)$imageID]
                    );
                    if ($updated !== 1) {
                        DB::rollBack();
                        return false;
                    }
                    $boostId = $this->iN_CreateAgencyBoost($agencyId, $creatorId, (int) $payerID, $durationDays, false);
                    if (!$boostId) {
                        DB::rollBack();
                        return false;
                    }
                    DB::commit();
                } catch (Throwable $th) {
                    DB::rollBack();
                    return false;
                }
                $paymentId = (int) ($paymentRow['payment_id'] ?? 0);
                if ($paymentId > 0) {
                    $currency = $GLOBALS['defaultCurrency'] ?? 'USD';
                    $this->iN_AssignInvoiceToPayment($paymentId, (int) $payerID, $amount, $currency);
                }
                return true;
            }
            if ($this->CheckPlanExist($planID) == 1) {
                DB::exec("UPDATE i_bank_payments SET request_status = 'yes' WHERE iuid_fk = ? AND screen_photo = ?", [(int)$payerID, (int)$imageID]);
                DB::exec("UPDATE i_user_payments SET payment_status = 'ok' WHERE payment_id = ? AND payer_iuid_fk = ? AND bank_payment_image = ?", [(int)$paymentIDD, (int)$payerID, (int)$imageID]);
                $planData = $this->GetPlanDetails($planID);
                $planCreditAmount = isset($planData['plan_amount']) ? $planData['plan_amount'] : NULL;
                $planMoneyAmount = isset($planData['amount']) ? (float)$planData['amount'] : 0.0;
                if($planCreditAmount){
                    DB::exec("UPDATE i_users SET wallet_points = wallet_points + ? WHERE iuid = ?", [(string)$planCreditAmount, (int)$payerID]);
                }
                if ($paymentIDD > 0 && $planMoneyAmount > 0) {
                    $currency = $GLOBALS['defaultCurrency'] ?? 'USD';
                    $this->iN_AssignInvoiceToPayment((int)$paymentIDD, (int)$payerID, $planMoneyAmount, $currency);
                }
                return true;
            }
        }
    }
	/*Delete PAYMENT*/
    public function iN_DeclineBankPaymentRequest($userID, $payerID, $planID, $imageID,$paymentIDD){
        if($this->iN_CheckIsAdmin($userID) == 1 && $this->iN_CheckUserExist($userID) == 1){
            $paymentRow = DB::one(
                "SELECT payment_type FROM i_user_payments WHERE payment_id = ? AND payer_iuid_fk = ? AND bank_payment_image = ? LIMIT 1",
                [(int)$paymentIDD, (int)$payerID, (int)$imageID]
            );
            if ($paymentRow && ($paymentRow['payment_type'] ?? '') === 'agency_boost') {
                DB::exec("DELETE FROM i_user_payments WHERE payment_id = ?", [(int)$paymentIDD]);
                DB::exec("DELETE FROM i_bank_payments WHERE iuid_fk = ? AND screen_photo = ?", [(int)$payerID, (int)$imageID]);
                DB::exec("DELETE FROM i_user_uploads WHERE iuid_fk = ? AND upload_id = ?", [(int)$payerID, (int)$imageID]);
                return true;
            }
            if ($this->CheckPlanExist($planID) == 1) {
                DB::exec("DELETE FROM i_user_payments WHERE payment_id = ?", [(int)$paymentIDD]);
                DB::exec("DELETE FROM i_bank_payments WHERE iuid_fk = ? AND screen_photo = ?", [(int)$payerID, (int)$imageID]);
                DB::exec("DELETE FROM i_user_uploads WHERE iuid_fk = ? AND upload_id = ?", [(int)$payerID, (int)$imageID]);
                return true;
            }
        }
    }
