    /*Get global tax settings*/
    public function iN_GetTaxSettings() {
        return [
            'enabled'      => isset($GLOBALS['taxStatus']) ? (string)$GLOBALS['taxStatus'] === '1' : false,
            'rate'         => isset($GLOBALS['taxRate']) ? (float)$GLOBALS['taxRate'] : 0.0,
            'label'        => $GLOBALS['taxLabel'] ?? 'VAT',
            'company_name' => $GLOBALS['taxCompanyName'] ?? ($GLOBALS['campany'] ?? null),
            'company_address' => $GLOBALS['taxCompanyAddress'] ?? ($GLOBALS['businessAddress'] ?? null),
            'registration_number' => $GLOBALS['taxRegistrationNumber'] ?? null,
            'invoice_prefix' => $GLOBALS['taxInvoicePrefix'] ?? 'INV',
        ];
    }

    /*Calculate tax for a given amount (assuming gross price includes tax)*/
    public function iN_CalculateTaxForAmount($amount) {
        $grossAmount = (float)$amount;
        if ($grossAmount <= 0) {
            return [
                'tax_rate'   => 0.0,
                'tax_amount' => 0.0,
                'net_amount' => 0.0,
                'gross_amount' => 0.0,
            ];
        }
        $taxEnabled = isset($GLOBALS['taxStatus']) ? (string)$GLOBALS['taxStatus'] === '1' : false;
        $rate = isset($GLOBALS['taxRate']) ? (float)$GLOBALS['taxRate'] : 0.0;
        if (!$taxEnabled || $rate <= 0) {
            return [
                'tax_rate'   => 0.0,
                'tax_amount' => 0.0,
                'net_amount' => round($grossAmount, 2),
                'gross_amount' => round($grossAmount, 2),
            ];
        }
        $taxAmount = round(($grossAmount * $rate) / (100 + $rate), 2);
        $netAmount = round($grossAmount - $taxAmount, 2);
        return [
            'tax_rate'   => $rate,
            'tax_amount' => $taxAmount,
            'net_amount' => $netAmount,
            'gross_amount' => round($grossAmount, 2),
        ];
    }

    /*Generate incremental invoice numbers*/
    protected function iN_CreateInvoiceNumber() {
        $fallbackPrefix = $GLOBALS['taxInvoicePrefix'] ?? 'INV';
        try {
            DB::begin();
            $row = DB::one("SELECT tax_invoice_prefix, tax_next_invoice_number FROM i_configurations WHERE configuration_id = 1 FOR UPDATE");
            $prefix = $row['tax_invoice_prefix'] ?? $fallbackPrefix;
            $current = isset($row['tax_next_invoice_number']) ? (int)$row['tax_next_invoice_number'] : 1;
            if ($current < 1) {
                $current = 1;
            }
            $next = $current + 1;
            DB::exec("UPDATE i_configurations SET tax_next_invoice_number = ? WHERE configuration_id = 1", [$next]);
            DB::commit();
            return $prefix . str_pad((string)$current, 6, '0', STR_PAD_LEFT);
        } catch (\Throwable $th) {
            DB::rollBack();
            try {
                $token = bin2hex(random_bytes(3));
            } catch (\Throwable $e) {
                $token = bin2hex(openssl_random_pseudo_bytes(3));
            }
            return $fallbackPrefix . strtoupper($token);
        }
    }

    /*Attach invoice + tax details to payment*/
    public function iN_AssignInvoiceToPayment($paymentID, $payerID, $amount, $currency = null) {
        $paymentID = (int)$paymentID;
        if ($paymentID <= 0) {
            return false;
        }
        $paymentRow = DB::one("SELECT invoice_number, invoice_token, payment_type, payment_option FROM i_user_payments WHERE payment_id = ?", [$paymentID]);
        if (!$paymentRow) {
            return false;
        }
        $invoiceNumber = $paymentRow['invoice_number'] ?? null;
        $invoiceToken = $paymentRow['invoice_token'] ?? null;
        if (!$invoiceNumber) {
            $invoiceNumber = $this->iN_CreateInvoiceNumber();
        }
        if (!$invoiceToken) {
            try {
                $invoiceToken = bin2hex(random_bytes(18));
            } catch (\Throwable $th) {
                $invoiceToken = bin2hex(openssl_random_pseudo_bytes(18));
            }
        }
        $userData = $this->iN_GetUserDetails($payerID);
        $billingName = $userData['i_user_fullname'] ?? '';
        $billingEmail = $userData['i_user_email'] ?? '';
        $taxDetails = $this->iN_CalculateTaxForAmount($amount);
        $paymentCurrency = $currency ?: ($GLOBALS['defaultCurrency'] ?? 'USD');
        DB::exec(
            "UPDATE i_user_payments SET tax_rate = ?, tax_amount = ?, currency = ?, invoice_number = ?, invoice_token = ?, billing_name = ?, billing_email = ? WHERE payment_id = ?",
            [
                (float)$taxDetails['tax_rate'],
                (string)$taxDetails['tax_amount'],
                (string)$paymentCurrency,
                (string)$invoiceNumber,
                (string)$invoiceToken,
                (string)$billingName,
                (string)$billingEmail,
                $paymentID
            ]
        );
        return true;
    }

