    public function iN_UpdateAiAPIData($userID, $aiKey, $aiPerAmount, array $extra = []) {
        if ($this->iN_CheckIsAdmin($userID) != 1) {
            return false;
        }
        $updates = [];
        $params = [];

        $aiKey = is_string($aiKey) ? trim($aiKey) : '';
        $aiPerAmount = is_numeric($aiPerAmount) ? (string)$aiPerAmount : '0';

        if ($aiKey !== '' && !preg_match('/\\*{3,}/', $aiKey)) {
            if ($this->configColumnExists('openai_api_key')) {
                $updates[] = 'openai_api_key = ?';
                $params[] = $aiKey;
            }
        }

        if ($this->configColumnExists('per_ai_use_credit')) {
            $updates[] = 'per_ai_use_credit = ?';
            $params[] = $aiPerAmount;
        }

        $model = isset($extra['model']) ? trim((string)$extra['model']) : '';
        if ($model !== '' && $this->configColumnExists('openai_model')) {
            $safeModel = preg_replace('/[^a-zA-Z0-9._-]/', '', $model);
            $updates[] = 'openai_model = ?';
            $params[] = $safeModel;
        }

        $fallbackModel = isset($extra['fallback_model']) ? trim((string)$extra['fallback_model']) : '';
        if ($fallbackModel !== '' && $this->configColumnExists('openai_fallback_model')) {
            $safeFallback = preg_replace('/[^a-zA-Z0-9._-]/', '', $fallbackModel);
            $updates[] = 'openai_fallback_model = ?';
            $params[] = $safeFallback;
        }

        if (array_key_exists('temperature', $extra) && $this->configColumnExists('openai_temperature')) {
            $temperature = is_numeric($extra['temperature']) ? (float)$extra['temperature'] : 0.8;
            if ($temperature < 0) {
                $temperature = 0.0;
            }
            if ($temperature > 2) {
                $temperature = 2.0;
            }
            $updates[] = 'openai_temperature = ?';
            $params[] = number_format($temperature, 2, '.', '');
        }

        if (array_key_exists('max_tokens', $extra) && $this->configColumnExists('openai_max_tokens')) {
            $maxTokens = (int)$extra['max_tokens'];
            if ($maxTokens < 1) {
                $maxTokens = 1;
            }
            if ($maxTokens > 4096) {
                $maxTokens = 4096;
            }
            $updates[] = 'openai_max_tokens = ?';
            $params[] = $maxTokens;
        }

        if (array_key_exists('prompt_max_length', $extra) && $this->configColumnExists('openai_prompt_max_length')) {
            $promptMaxLength = (int)$extra['prompt_max_length'];
            if ($promptMaxLength < 50) {
                $promptMaxLength = 50;
            }
            if ($promptMaxLength > 2000) {
                $promptMaxLength = 2000;
            }
            $updates[] = 'openai_prompt_max_length = ?';
            $params[] = $promptMaxLength;
        }

        if (array_key_exists('rate_limit_minute', $extra) && $this->configColumnExists('openai_rate_limit_per_minute')) {
            $limit = (int)$extra['rate_limit_minute'];
            if ($limit < 0) {
                $limit = 0;
            }
            $updates[] = 'openai_rate_limit_per_minute = ?';
            $params[] = $limit;
        }

        if (array_key_exists('rate_limit_hour', $extra) && $this->configColumnExists('openai_rate_limit_per_hour')) {
            $limit = (int)$extra['rate_limit_hour'];
            if ($limit < 0) {
                $limit = 0;
            }
            $updates[] = 'openai_rate_limit_per_hour = ?';
            $params[] = $limit;
        }

        if (array_key_exists('rate_limit_day', $extra) && $this->configColumnExists('openai_rate_limit_per_day')) {
            $limit = (int)$extra['rate_limit_day'];
            if ($limit < 0) {
                $limit = 0;
            }
            $updates[] = 'openai_rate_limit_per_day = ?';
            $params[] = $limit;
        }

        if (array_key_exists('forbidden_terms', $extra) && $this->configColumnExists('openai_forbidden_terms')) {
            $terms = trim((string)$extra['forbidden_terms']);
            $updates[] = 'openai_forbidden_terms = ?';
            $params[] = $terms;
        }

        if (empty($updates)) {
            return false;
        }
        $sql = "UPDATE i_configurations SET " . implode(', ', $updates) . " WHERE configuration_id = 1";
        DB::exec($sql, $params);
        return true;
    }

    public function iN_UpdateAiLastError(string $message, ?int $timestamp = null): void {
        if (!$this->configColumnExists('openai_last_error')) {
            return;
        }
        $timestamp = $timestamp ?? time();
        $updates = ['openai_last_error = ?'];
        $params = [trim($message)];
        if ($this->configColumnExists('openai_last_error_at')) {
            $updates[] = 'openai_last_error_at = ?';
            $params[] = (int)$timestamp;
        }
        DB::exec(
            "UPDATE i_configurations SET " . implode(', ', $updates) . " WHERE configuration_id = 1",
            $params
        );
    }

    public function iN_LogAiUsage(int $userID, array $data): void {
        if ($userID <= 0) {
            return;
        }
        try {
            $status = isset($data['status']) ? (string)$data['status'] : 'success';
            $status = in_array($status, ['success', 'error', 'blocked', 'rate_limited'], true) ? $status : 'success';
            DB::exec(
                "INSERT INTO i_ai_usage (iuid_fk, prompt_length, model, temperature, max_tokens, variants, tokens_used, credit_used, status, error_code, error_message, created_at)
                 VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
                [
                    (int)$userID,
                    isset($data['prompt_length']) ? (int)$data['prompt_length'] : 0,
                    isset($data['model']) ? (string)$data['model'] : null,
                    isset($data['temperature']) ? (string)$data['temperature'] : '0.80',
                    isset($data['max_tokens']) ? (int)$data['max_tokens'] : 150,
                    isset($data['variants']) ? (int)$data['variants'] : 1,
                    isset($data['tokens_used']) ? (int)$data['tokens_used'] : 0,
                    isset($data['credit_used']) ? (int)$data['credit_used'] : 0,
                    $status,
                    isset($data['error_code']) ? (string)$data['error_code'] : null,
                    isset($data['error_message']) ? (string)$data['error_message'] : null,
                    isset($data['created_at']) ? (int)$data['created_at'] : time(),
                ]
            );
        } catch (Throwable $e) {
            // Ignore logging failures to avoid breaking the request flow.
        }
    }

